import { Injectable } from "@angular/core";
import { SohoMessageService } from "ids-enterprise-ng";
import {
	CoreBase,
	DataService,
	ICatalogRequest,
	ICatalogResponse,
	IOperationRequest,
	IOperationResponse,
	LanguageService,
	OperationResponse,
} from "lime/core";
import { Observable } from "rxjs";
import { map } from "rxjs/operators";
import { IStringMap } from "standard-widgets/infor.mingle.custommenu/types";
import {
	IMemoData,
	IMemoListRequest,
	IMemoListResponse,
	IMemoRequest,
	IMemoResponse,
	Memo,
} from "./core";

interface IMemoDataRequest extends IOperationRequest {
	content?: IMemoData;
}

interface IMemoDataResponse extends IOperationResponse {
	maxCountAllowed: number;
	memoCount: number;
}

interface IMemoDataListRequest extends ICatalogRequest {}

interface IMemoDataListResponse extends ICatalogResponse {
	accessTitles?: IStringMap;
	maxCountAllowed: number;
	memoCount: number;
}

@Injectable({
	providedIn: "root",
})
export class MemoAdminService extends CoreBase {
	constructor(
		messageService: SohoMessageService,
		languageService: LanguageService,
		private readonly dataService: DataService,
	) {
		super("MemoAdminService", messageService, languageService);
	}

	list(request: IMemoListRequest): Observable<IMemoListResponse> {
		return this.dataService.post(this.getPath("list"), request).pipe(
			map((r: IMemoDataResponse) => {
				return this.toListResponse(r);
			}),
		);
	}

	create(request: IMemoRequest): Observable<IMemoResponse> {
		return this.post(this.getPath("create"), request);
	}

	read(request: IMemoRequest): Observable<IMemoResponse> {
		return this.post(this.getPath("read"), request);
	}

	update(request: IMemoRequest): Observable<IMemoResponse> {
		return this.post(this.getPath("update"), request);
	}

	delete(request: IMemoRequest): Observable<IMemoResponse> {
		return this.post(this.getPath("delete"), request);
	}

	export(keys?: string[]): void {
		let query = "";
		if (keys) {
			for (const key of keys) {
				query += (query.length === 0 ? "?" : "&") + "keys=" + key;
			}
		}
		const url =
			this.dataService.getUrl("admin/memo/export/announcements.json") + query;
		window.open(url, "_blank");
	}

	private post(path: string, request: IMemoRequest): Observable<IMemoResponse> {
		return this.dataService.post(path, this.toRequest(request)).pipe(
			map((r: IMemoDataResponse) => {
				return this.toResponse(r);
			}),
		);
	}

	private getPath(operation: string): string {
		return "/admin/memo/" + operation;
	}

	private toRequest(request: IMemoRequest): IMemoDataRequest {
		return { content: request.content.toData() };
	}

	private toResponse(dataResponse: IMemoDataResponse): IMemoResponse {
		return new OperationResponse(dataResponse.content) as IMemoResponse;
	}

	private toListResponse(
		dataResponse: IMemoDataListResponse,
	): IMemoListResponse {
		const dataItems = dataResponse.content || [];
		const items = dataItems.map((data: IMemoData) => new Memo(data));

		const response = new OperationResponse(items) as IMemoListResponse;
		response.paging = dataResponse.paging;
		response.accessTitles = dataResponse.accessTitles;
		response.maxCountAllowed = dataResponse.maxCountAllowed;
		response.memoCount = dataResponse.memoCount;
		return response;
	}
}
