import { Component, OnInit, ViewChild, ViewContainerRef } from "@angular/core";
import { SohoMessageService, SohoModalDialogRef } from "ids-enterprise-ng";
import { ArrayUtil, NumUtil } from "lime";
import {
	CoreBase,
	CoreUtil,
	IPage,
	IPageData,
	ISettingItem,
	SettingItemType,
	SettingsNames,
} from "lime/core";
import { SettingUtil } from "../admin";
import { AdminService, AdminUtil } from "../service";

@Component({
	templateUrl: "./setting-value.html",
})
export class SettingSetValueComponent extends CoreBase implements OnInit {
	private static pageSeparator = ",";
	@ViewChild("setValueView", { read: ViewContainerRef, static: false })
	setValueView: ViewContainerRef;

	dialog: SohoModalDialogRef<SettingSetValueComponent>;
	parameter: any;
	isBusy: boolean;
	item: ISettingItem;
	sortableOptions: any;
	maxCountNumbers = [];
	isMultiple = false;
	originalValue: any;

	constructor(
		private adminService: AdminService,
		messageService: SohoMessageService,
	) {
		super("SettingSetValueComponent", messageService);
	}

	ngOnInit(): void {
		const settingItem: ISettingItem = CoreUtil.copy(this.parameter.setting);
		let settingValue = settingItem.value;
		this.originalValue = settingValue;
		this.item = settingItem;
		const types = SettingItemType;

		// If the display value is the same as the ID, the page has been deleted
		if (
			settingItem.displayValue === settingValue &&
			settingItem.type !== types.typeString &&
			settingItem.type !== types.typeInt &&
			settingItem.type !== types.typeIntSelector &&
			settingItem.type !== SettingsNames.adminContactInfo
		) {
			settingValue = "";
		}

		// Set missing boolean value to false
		if (settingItem.type === types.typeBool && !settingValue) {
			settingValue = false;
		}

		if (settingItem.type === types.typeInt && !settingValue) {
			settingValue = 1;
		}

		// Set value back for bindings
		this.item.value = settingValue;

		// Create count array for int typeselector
		if (settingItem.type === types.typeIntSelector) {
			let i = 0;
			while (i < this.parameter.maxCount) {
				const value = (i + 1).toString();
				this.maxCountNumbers.push(value);
				i++;
			}
		}
	}

	onOk(): void {
		const item = CoreUtil.copy(this.item);
		item.changeDate = AdminUtil.getPendingChangeDate();
		item.changedByName = this.parameter.userName;
		item.setting.isChanged = true;

		// Don't allow empty values for int selector
		const value = item.value;
		const types = SettingItemType;
		if (item.type === types.typeIntSelector && !NumUtil.isNumber(value)) {
			item.value = this.originalValue || 1;
		}

		item.displayValue = SettingUtil.getDisplayValue(item, item.value);

		this.dialog.close({ value: item });
	}

	removePage(page: IPage): void {
		ArrayUtil.remove(this.item.value, page);
	}

	private getPageIdString(value: string): string {
		// TODO Temporary function...

		if (!value) {
			return "";
		}

		if (value.indexOf("{") < 0) {
			return value;
		}

		const setting = JSON.parse(value);
		if (!setting || !setting.pages) {
			return "";
		}

		return setting.pages
			.map((item) => {
				return item.id;
			})
			.join(SettingSetValueComponent.pageSeparator);
	}

	private createPageValuesList(idList: string, pages: IPage[]): void {
		// TODO Temporary

		if (!idList) {
			return;
		}

		if (idList.indexOf("{") < 0) {
			this.createPageValuesListLegacy(idList, pages);
			return;
		}
		this.createPageValuesListJson(idList, pages);
	}

	private createPageValuesListJson(idList: string, pages: IPage[]): void {
		const setting = JSON.parse(idList);
		const items = setting.pages;
		if (!items) {
			return;
		}

		const valueArray: IPage[] = [];
		for (const item of items) {
			const id = item.id;
			const page = pages
				? ArrayUtil.find(pages, (item) => {
						return item.data.id === id;
				  })
				: null;
			if (page) {
				valueArray.push(page);
			} else {
				valueArray.push(this.createDummyPage(id));
			}
		}
		this.item.value = valueArray;
	}

	private createPageValuesListLegacy(idList: string, pages: IPage[]): void {
		const idArray = idList.split(SettingSetValueComponent.pageSeparator);
		const valueArray: IPage[] = [];
		for (let i = 0; i < idArray.length; i++) {
			const id = idArray[i];
			const page = pages
				? ArrayUtil.find(pages, (item) => {
						return item.data.id === id;
				  })
				: null;
			if (page) {
				valueArray.push(page);
			} else {
				valueArray.push(this.createDummyPage(id));
			}
		}
		this.item.value = valueArray;
	}

	private createDummyPage(id: string): IPage {
		const pageData: IPageData = {
			id: id,
			title: `Missing page (${id})`,
		};
		return { data: pageData };
	}
}
