import { ViewContainerRef } from "@angular/core";
import { SohoModalDialogService } from "ids-enterprise-ng";
import { IDynamicPreviewOptions, IUserInfo } from "lime/core";
import { AdminService } from "../../service";
import { PreviewDialog } from "./editor/preview-dialog";
import { DynamicPageAdminService } from "./service";

// FUTURE This could be turned into a service but there is currently some kind of dependency issue
// that breaks injection for AdminService & DynamicPageAdminService.

export class DynamicPreviewer {
	constructor(
		private readonly viewContainerRef: ViewContainerRef,
		private readonly dialogService: SohoModalDialogService,
		private readonly adminService: AdminService,
		private readonly pageService: DynamicPageAdminService,
	) {}

	previewAsUser(options?: IDynamicPreviewOptions) {
		const observable = this.adminService.openUserSearchDialog(
			"Preview as User",
			this.viewContainerRef,
			"Select a user to preview the page as",
			"Recently previewed as",
			this.pageService.getRecentUserSearches(),
		);

		options = options || {};
		observable.subscribe((selectedUser?: IUserInfo) => {
			if (selectedUser) {
				this.pageService.addUserToRecentSearch(selectedUser);
				options.userInfo = selectedUser;
				this.pageService.preview(options);
			}
		});
	}

	previewAsPolicy() {
		const dialog = this.dialogService
			.modal(PreviewDialog, this.viewContainerRef)
			.title("Preview using Security Policies")
			.id("lm-dp-preview-policy-dialog")
			.buttons([
				{
					text: "Cancel",
					id: "lm-dp-preview-policy-dialog-cancel",
					click: () => dialog.close(),
				},
				{
					text: "OK",
					id: "lm-dp-preview-policy-dialog-ok",
					isDefault: true,
					click: () => {
						dialog.close();
						this.pageService.preview(
							dialog.componentDialog.getPreviewOptions(),
						);
					},
				},
			])
			.open();
	}
}
