import {
	AfterViewInit,
	Component,
	Input,
	OnInit,
	Output,
	ViewChild,
	ViewContainerRef,
} from "@angular/core";
import { FormControl, FormGroup, Validators } from "@angular/forms";
import {
	SohoColorPickerComponent,
	SohoMessageService,
	SohoModalDialogRef,
	SohoModalDialogService,
} from "ids-enterprise-ng";
import {
	Constants,
	CoreUtil,
	DynamicSettingsDialogBase,
	IDynamicEntityLocalization,
	IDynamicEntityLocalizationMap,
	IDynamicPageSetting,
	UIUtil,
} from "lime/core";
import { Observable } from "rxjs";
import { filter, map } from "rxjs/operators";
import { AdminService, IExpInfo } from "../../../../service";
import { DynamicPageAdminService } from "../../service";
import { DynamicPageSettingValidator, DynamicUtil } from "../../util";
import { DynamicPermissionsDialogComponent } from "../permissions/permissions-dialog";

@Component({
	selector: "lm-dynamic-page-settings-basic",
	templateUrl: "./basic.html",
	styles: [
		`
			:host {
				display: flex;
				flex-direction: column;
				flex-wrap: wrap;
			}
		`,
	],
})
export class DynamicPageSettingsBasic implements AfterViewInit {
	@ViewChild(SohoColorPickerComponent, { static: false })
	colorpicker: SohoColorPickerComponent;

	settingsForm = new FormGroup({
		title: new FormControl("", Validators.required),
		description: new FormControl("", Validators.required),
		color: new FormControl(UIUtil.numberToHexCode(0)),
		enableMemo: new FormControl(false),
		memoDuration: new FormControl(0),
		enableAnimation: new FormControl(true),
	});

	pageTitleMaxLength = Constants.pageTitleLength;
	pageDescriptionMaxLength = Constants.pageDescriptionLength;
	availableColors = UIUtil.getPageColorPickerOptions().colors;
	allowedMemoDuration = Constants.allowedMemoDuration;

	@Output() valueChanges: Observable<IDynamicPageSetting> =
		this.settingsForm.valueChanges.pipe(
			map((values) => {
				const color = values.color;
				const colorHex =
					color && color.indexOf("#") === 0
						? color
						: this.colorpicker.getHexValue();
				return {
					t: values.title,
					d: values.description,
					cl: UIUtil.hexCodeToNumber(colorHex),
					em: Number(values.enableMemo),
					md: Number(values.memoDuration),
					dma: Number(!values.enableAnimation),
				};
			}),
			filter(() => this.settingsForm.valid),
		);

	@Output() validated = this.settingsForm.statusChanges.pipe(
		map((status) => status === "VALID"),
	);

	@Input() settings: IDynamicPageSetting;

	@Input() showDescription: boolean;

	ngAfterViewInit(): void {
		if (!this.showDescription) {
			this.settingsForm.setControl(
				"description",
				new FormControl("", Validators.nullValidator),
			);
		}

		const settings = this.settings;
		if (settings) {
			this.settingsForm.patchValue({
				title: settings.t,
				description: settings.d,
				color: UIUtil.numberToHexCode(settings.cl),
				enableMemo: Boolean(settings.em),
				memoDuration: settings.md || 0,
				enableAnimation: settings.dma !== 1,
			});
		}
	}

	formatMemoDuration(value: number): string {
		return value === 0 ? "Off" : `${value}`;
	}
}
@Component({
	templateUrl: "./settings-dialog.html",
	styles: [
		`
			.permission-container {
				display: flex;
				flex-direction: column;
				border-top: 1px solid #bdbdbd;
				padding-top: 20px;
				margin-bottom: 10px;
			}

			.permission-edit {
				display: flex;
				flex-direction: row;
				margin-top: 5px;
			}

			.permission-edit h2 {
				flex: 1 1 auto;
				font-weight: bold;
				margin-top: 5px;
				vertical-align: middle;
			}

			.permission-edit svg {
				top: 3px;
			}
		`,
	],
})
export class DynamicPageSettingsDialog
	extends DynamicSettingsDialogBase
	implements OnInit
{
	@ViewChild("dynamicSettings", { read: ViewContainerRef, static: true })
	viewRef: ViewContainerRef;
	modalDialog: SohoModalDialogRef<DynamicPageSettingsDialog>;
	editedSetting: IDynamicPageSetting;
	isCreate: boolean;
	isCreatePage: boolean;
	isEdit: boolean;
	isEnabled = true;
	settings?: IDynamicPageSetting;
	expressions?: IExpInfo[];
	editInfo: { setting: IDynamicPageSetting; openPermissions: boolean };
	settingsAreValid: boolean;
	isDefault: boolean;

	private isSaved: boolean;
	private isPermissionsOpen: boolean;

	constructor(
		private dynamicPageService: DynamicPageAdminService,
		private readonly dialogService: SohoModalDialogService,
		private adminService: AdminService,
		sohoMessageService: SohoMessageService,
	) {
		super("DynamicPageSettingsDialog", sohoMessageService);
	}

	ngOnInit(): void {
		this.isDefault =
			this.isCreatePage ||
			(this.isEdit && !DynamicUtil.hasAccess(this.settings));
		this.initModalDialog();

		const editInfo = this.editInfo;
		if (editInfo && editInfo.openPermissions) {
			this.openPermissionsDialog();
		}
		this.setEditedSetting(this.settings);
		this.setOptionsItems();
	}

	onTabChange() {
		const titleItemIndex = this.getTranslationItemIndex("t");
		if (titleItemIndex < 0 || !this.optionsItems) {
			this.setOptionsItems();
		} else {
			this.optionsItems[titleItemIndex].defaultValue = this.editedSetting.t;
			const descriptionItemIndex = this.getTranslationItemIndex("d");
			if (this.isDefault && descriptionItemIndex > -1) {
				this.optionsItems[descriptionItemIndex].defaultValue =
					this.editedSetting.d;
			}
		}
	}

	setOptionsItems() {
		this.optionsItems = [];
		this.optionsItems.push({
			name: "t",
			label: "Title",
			labelId: "lm-a-dps-at-t-lbl",
			valueId: "lm-a-dps-at-t-inp",
			isRequired: true,
			maxLength: Constants.pageTitleLength,
			defaultValue: this.editedSetting.t,
		});
		if (this.isDefault) {
			this.optionsItems.push({
				name: "d",
				label: "Description",
				labelId: "lm-a-dps-at-d-lbl",
				valueId: "lm-a-dps-at-d-inp",
				isRequired: true,
				maxLength: Constants.pageDescriptionLength,
				defaultValue: this.editedSetting.d,
			});
		}
	}

	getAccessText(): string {
		return DynamicUtil.expAccessText(this.expressions);
	}

	onLocalizationChange(translationData: IDynamicEntityLocalizationMap) {
		this.containerLznEdited = translationData || {};
	}

	setEditedSetting(setting: IDynamicPageSetting) {
		this.editedSetting = {
			...this.settings,
			...this.editedSetting,
			...setting,
		};
	}

	saveDisabled(): boolean {
		return !(
			(this.isCreate || this.expressionValid() || this.isDefault) &&
			this.settingsAreValid
		);
	}

	openPermissionsDialog() {
		if (this.isPermissionsOpen) {
			return;
		}
		this.isPermissionsOpen = true;

		const dialogRef = this.dialogService
			.modal(DynamicPermissionsDialogComponent, this.viewRef)
			.id("dyn-settings-perm-mdl")
			.title("Select Security Policy")
			.afterClose((result) => {
				this.isPermissionsOpen = false;
				if (result && result.value) {
					const expressions = result.value;
					const operator = result.operator;

					this.editedSetting = {
						...this.settings,
						...this.editedSetting,
						...{
							as: 1,
							ais: DynamicUtil.toIds(expressions),
							op: operator,
						},
					};
					this.expressions = expressions;
				}
			});

		dialogRef
			.apply((component: DynamicPermissionsDialogComponent) => {
				component.modalDialog = dialogRef;
				component.listLabel =
					"Choose which set of users this configuration should be applied to.";
				component.selectedExpressions = this.expressions;
				component.isRequired = true;
				component.showOperator = true;
				component.operator = (this.editedSetting || this.editInfo.setting).op;
			})
			.open();
	}

	save() {
		if (!this.isEnabled) {
			return;
		}
		const setting = CoreUtil.copy(this.editedSetting);
		if (!new DynamicPageSettingValidator().validate(setting)) {
			this.setCanClose(false);
			return;
		}
		if (!setting.em) {
			setting.md = 0;
			setting.dma = 0;
		}

		// TODO Consider a more generic solution for duplicate save prevention if necessary
		if (this.isSaved && !this.hasSubmitError) {
			return;
		}
		this.isSaved = true;
		setting.lzn = this.containerLznEdited ? this.containerLznEdited : null;
		if (this.isCreate) {
			this.submitSafe(
				this.dynamicPageService.createPage(
					setting.t,
					setting.d,
					setting.cl,
					setting.lzn,
					setting.em,
					setting.md,
					setting.dma,
				),
			).subscribe();
		} else {
			if (this.isEdit) {
				this.submitSafe(
					this.dynamicPageService.updateSetting(setting, this.settings),
				).subscribe();
			} else {
				this.submitSafe(
					this.dynamicPageService.addSetting(setting),
				).subscribe();
			}
		}
	}

	hasInvalidTranslation(lang: IDynamicEntityLocalization): boolean {
		return false; // Has no optional translations
	}
	deleteTranslation(lang: IDynamicEntityLocalization): void {
		// Has no optional translations to delete
	}

	private expressionValid(): boolean {
		return (
			(!!this.settings && DynamicUtil.hasAccess(this.settings)) ||
			(!!this.editedSetting && DynamicUtil.hasAccess(this.editedSetting))
		);
	}
}
