import {
	Component,
	EventEmitter,
	Input,
	Output,
	ViewChild,
} from "@angular/core";
import { SohoSearchFieldComponent } from "ids-enterprise-ng";
import { fromEvent } from "rxjs";

@Component({
	selector: "filter-search",
	template: `
		<input
			soho-searchfield
			id="lm-a-dp-policy-inp"
			class="context filter-search"
			placeholder="Search for policies..."
			[clearable]="true"
			[(ngModel)]="query"
			(ngModelChange)="onChange()" />
	`,
})
export class DynamicFilterSearch {
	@ViewChild(SohoSearchFieldComponent, { static: false })
	searchField: SohoSearchFieldComponent;
	@Input() query: string;
	@Output() queryChange = new EventEmitter<string>();

	ngAfterViewInit() {
		fromEvent(
			(this.searchField as any).jQueryElement as JQuery,
			"cleared",
		).subscribe(() => this.clearSearch());
	}

	clearSearch() {
		this.query = "";
		this.onChange();
	}

	onChange() {
		this.queryChange.emit(this.query);
	}
}
