import { Component, OnInit } from "@angular/core";
import { SohoMessageService } from "ids-enterprise-ng";
import { DialogService } from "lime";
import {
	IArchiveRequest,
	LanguageService,
	ModalDialogBase,
	OperationResponse,
} from "lime/core";
import { of } from "rxjs";
import { catchError, tap } from "rxjs/operators";
import { AdminService } from "../../service";

@Component({
	templateUrl: "./create.html",
})
export class ArchiveCreateDialog extends ModalDialogBase implements OnInit {
	entityId: string;
	comment: string;
	baseUrl: string;
	entityTitle: string;
	isCreated: boolean;

	constructor(
		private readonly adminService: AdminService,
		private readonly dialogService: DialogService,
		messageService: SohoMessageService,
		languageService: LanguageService,
	) {
		super("ArchiveCreateDialog", messageService, languageService);
	}

	ngOnInit(): void {
		this.initModalDialog();
	}

	createArchive(): void {
		const request: IArchiveRequest = {
			entityId: this.entityId,
			comment: this.comment,
		};
		if (this.isCreated && !this.hasSubmitError) {
			return;
		}
		this.isCreated = true;
		this.submitSafe(
			this.adminService.createArchive(request, this.baseUrl),
			true,
		)
			.pipe(
				catchError((reponse: OperationResponse) => {
					this.showError(
						"Archive",
						`Unable to add the page to the archive. ${reponse.getErrorMessages()}`,
					);
					return of();
				}),
				tap(() => {
					this.dialogService.showToast({
						title: "Archive created",
						message: `Page '${this.entityTitle}' has been archived.`,
					});
					this.adminService.raiseArchiveCreated();
				}),
			)
			.subscribe();
	}
}
