import {
	Component,
	EventEmitter,
	Output,
	ViewChild,
	ViewContainerRef,
} from "@angular/core";
import { SohoMessageService, SohoModalDialogService } from "ids-enterprise-ng";
import { AdminPages, CoreBase, IStringToAnyMap } from "lime/core";
import { AdminFeatureService } from "./admin-feature.service";
import {
	IMessageBannerOptions,
	MessageBannerLevel,
} from "./common/message-banner";
import {
	AdminContext,
	AdminService,
	AdminUtil,
	IBulkDeleteRequest,
	IBulkDeleteResponse,
} from "./service";

@Component({
	selector: "lm-admin-bulk-delete",
	templateUrl: "./bulk-delete.html",
})
export class AdminBulkDeleteComponent extends CoreBase {
	@ViewChild("lmaBulkDeleteView", { read: ViewContainerRef, static: false })
	content: ViewContainerRef;
	@Output() onGoToExport = new EventEmitter<AdminPages>();

	isBusy = false;
	isAllSelected = false;
	showDynamic = false;

	includeOptions: IStringToAnyMap = {
		includeUserSettings: false,
		includePrivatePages: false,
		includePublishedPages: false,
		includePublishedWidgets: false,
		includeMemos: false,
		includeSecurityPolicies: false,
		includeDynamicPages: false,
		includeDynamicPageArchives: false,
		includeSettings: false,
		includeSettingsRules: false,
	};

	warningMessageOptions: IMessageBannerOptions = {
		message:
			"Bulk delete will permanently remove all data in the selected categories. Before performing this action it is recommended to backup the content by exporting all data.",
		level: MessageBannerLevel.Warning,
		actions: [
			{
				icon: "export",
				text: "Export",
				execute: () => this.onGoToExport.emit(AdminPages.Export),
			},
		],
	};

	constructor(
		protected adminContext: AdminContext,
		public adminService: AdminService,
		messageService: SohoMessageService,
		protected sohoModalDialogService: SohoModalDialogService,
		readonly featureService: AdminFeatureService,
	) {
		super("AdminBulkDeleteComponent", messageService);

		featureService
			.isFeatureEnabled(AdminPages.DynamicPages)
			.subscribe((enabled) => {
				this.showDynamic = enabled;
				if (!enabled) {
					this.excludeDynamic();
				}
			});
	}

	onSelectDeselectAll(include: boolean) {
		const options = this.includeOptions;
		const keys = Object.keys(options);
		for (const key of keys) {
			options[key] = include;
		}
		if (include && !this.showDynamic) {
			this.excludeDynamic();
		}
	}

	onClickDelete(): void {
		const request = this.createRequest();
		if (!request) {
			this.showMessage(
				"No category selected",
				"Select at least one category to delete.",
			);
			return;
		}

		this.showConfirm(
			"Confirm bulk delete",
			"Are you sure that you want to delete all data in the selected categories?",
		).subscribe(() => {
			this.executeDelete(request);
		});
	}

	private excludeDynamic(): void {
		this.includeOptions.includeDynamicPages = false;
		this.includeOptions.includeDynamicPageArchives = false;
	}

	private executeDelete(request: IBulkDeleteRequest): void {
		this.isBusy = true;
		this.adminService.deleteBulk(request).subscribe(
			(response: IBulkDeleteResponse) => {
				this.isBusy = false;
				const message = this.createSuccessMessage(request, response);
				this.showMessage("Bulk delete complete", message);
			},
			() => {
				this.isBusy = false;
				this.showError("Unable to delete", "An error occured when deleting.");
			},
		);
	}

	private createSuccessMessage(
		request: IBulkDeleteRequest,
		response: IBulkDeleteResponse,
	): string {
		let message = "";
		const append = (entityName: string, count: number) => {
			if (message.length > 0) {
				message += ", ";
			}
			message += count + " " + AdminUtil.pluralize(entityName, count);
		};

		if (request.includeUserSettings) {
			append("user setting", response.userSettingsCount);
		}
		if (request.includePrivatePages) {
			append("private page", response.privatePagesCount);
		}
		if (request.includePublishedPages) {
			append("published page", response.publishedPagesCount);
		}
		if (request.includePublishedWidgets) {
			append("published widget", response.publishedWidgetsCount);
		}
		if (request.includeMemos) {
			append("announcement", response.memosCount);
		}
		if (request.includeSecurityPolicies) {
			append("security policy", response.securityPoliciesCount);
		}
		if (request.includeDynamicPages) {
			append("dynamic page", response.dynamicPagesCount);
		}
		if (request.includeDynamicPageArchives) {
			append("dynamic page archive", response.dynamicPageArchivesCount);
		}
		if (request.includeSettingsRules) {
			append("settings rule", response.settingsRulesCount);
		}
		if (request.includeSettings) {
			append("setting", response.settingsCount);
		}

		return (
			"The following data was deleted from the selected categories: " + message
		);
	}

	private createRequest(): IBulkDeleteRequest {
		const options = this.includeOptions;
		const request = {};
		const keys = Object.keys(options);
		let hasSelection = false;
		for (const key of keys) {
			if (options[key]) {
				request[key] = true;
				hasSelection = true;
			}
		}
		return hasSelection ? request : null;
	}
}
