import { Component, OnInit, ViewChild, ViewContainerRef } from "@angular/core";
import { SohoMessageService, SohoModalDialogService } from "ids-enterprise-ng";
import { Log } from "lime";
import {
	ArchiveType,
	IStringMap,
	LanguageService,
	ModalDialogBase,
} from "lime/core";
import { AdminConstants } from "../../service";
import { IDynamicPageInfo, IDynamicPageInfoResponseAdmin } from "../dyn/core";
import { DynamicPageImportDialog } from "../dyn/dynamic-page-import-dialog";
import { DynamicPageAdminService } from "../dyn/service";
import { ArchiveSelectorDialog } from "./selector";

@Component({
	templateUrl: "./restore.html",
})
export class ArchiveRestoreDialog extends ModalDialogBase implements OnInit {
	@ViewChild("restoreTemplateRef", { read: ViewContainerRef, static: false })
	restoreTemplateRef: ViewContainerRef;
	archiveId: string;
	archiveType: ArchiveType;
	baseUrl: string;
	restoreStrategy: RestoreStrategy;
	lookupEntity: IDynamicPageInfo;
	originalEntity: IDynamicPageInfo;
	originalEid: string;
	isRestoreToDisabled: boolean;
	isBusy: boolean;
	originalTitle: string;

	private readonly title = "Restore archive";

	constructor(
		public dynamicPageService: DynamicPageAdminService,
		public sohoModalDialogService: SohoModalDialogService,
		messageService: SohoMessageService,
		languageService: LanguageService,
	) {
		super("ArchiveRestoreDialog", messageService, languageService);
	}

	ngOnInit(): void {
		this.initModalDialog();
		this.checkArchivedFrom();
	}

	openArchiveSelect(): void {
		const dialog = this.sohoModalDialogService
			.modal(ArchiveSelectorDialog, this.restoreTemplateRef)
			.title("Restore Dynamic Page")
			.id("lm-a-arc-rst-selectpage-dialog")
			.afterClose((selected: IDynamicPageInfo) => {
				this.lookupEntity = selected;
			});

		dialog
			.apply((comp) => {
				comp.title = "Select a dynamic page";
				comp.dialog = dialog;
				comp.archiveType = this.archiveType;
			})
			.open();
	}

	showConfirmRestore(): void {
		const restoreStrategy = this.restoreStrategy;
		if (restoreStrategy === RestoreStrategy.Original) {
			this.confirmRestoreOriginal();
		} else if (restoreStrategy === RestoreStrategy.OtherPage) {
			this.confirmRestoreOther();
		} else {
			this.startRestoreOperation();
		}
	}

	private confirmRestoreOriginal(): void {
		const originalEntity = this.originalEntity;
		let message: string;

		if (originalEntity.lock === 1 && !originalEntity.lockedByUser) {
			message = `The page '${originalEntity.title}' can not be overwritten as it is checked out by another user.`;
			this.showError(this.title, message);
			return;
		}

		if (originalEntity.lockedByUser) {
			message = `This restore will replace '${originalEntity.title}'. Are you sure you want to continue?`;
			this.showConfirm(this.title, message).subscribe(() => {
				this.startRestoreOperation();
			});
			return;
		}

		message = `This restore will replace '${originalEntity.title}'. Are you sure you want to continue?`;
		this.showConfirm(this.title, message).subscribe(() => {
			this.dynamicPageService.checkOutPage(originalEntity.pageId).subscribe(
				() => {
					this.startRestoreOperation();
				},
				() => {
					this.logDebug("Unable to check out page before restore");
				},
			);
		});
	}

	private confirmRestoreOther(): void {
		const message = `This restore will replace ${this.lookupEntity.title}. Are you sure you want to continue?`;
		this.showConfirm(this.title, message).subscribe(() => {
			this.startRestoreOperation();
		});
	}

	private startRestoreOperation(): void {
		this.logDebug("Starting restore operation");
		const paramMap: IStringMap = {};
		paramMap[AdminConstants.archiveIdKey] = this.archiveId;
		if (this.restoreStrategy === RestoreStrategy.Original) {
			paramMap[AdminConstants.entityIdKey] = this.originalEntity.pageId;
		} else if (this.restoreStrategy === RestoreStrategy.OtherPage) {
			paramMap[AdminConstants.entityIdKey] = this.lookupEntity.pageId;
		}

		const dialog = this.sohoModalDialogService
			.modal(DynamicPageImportDialog, this.restoreTemplateRef)
			.title("Restoring")
			.id("lm-a-arc-op-result-dialog")
			.afterClose((r) => {
				if (r) {
					this.modalDialog.close(r);
				}
			});

		dialog
			.apply((component) => {
				component.modalDialog = dialog;
				component.pageIdMap = paramMap;
				component.operation = "restore";
			})
			.open();
	}

	private checkArchivedFrom(): void {
		if (this.originalEid) {
			this.isBusy = true;
			this.dynamicPageService.getExistingInfo(this.originalEid).subscribe(
				(response: IDynamicPageInfoResponseAdmin) => {
					try {
						if (response && response.content) {
							this.originalEntity = response.content;
							this.originalTitle = this.originalEntity.title;
							const isValidToRestore = this.isValidToRestore(response.content);
							if (!isValidToRestore) {
								this.isRestoreToDisabled = true;
								this.restoreStrategy = RestoreStrategy.New;
								Log.info("The page is currently checked out by someone else");
							} else {
								this.isRestoreToDisabled = false;
								this.restoreStrategy = RestoreStrategy.Original;
							}
						} else {
							this.restoreStrategy = RestoreStrategy.New;
						}
					} catch (ex) {
						Log.error("Failed to get page information " + JSON.stringify(ex));
					} finally {
						this.isBusy = false;
					}
				},
				() => {
					this.isBusy = false;
				},
			);
		} else {
			this.restoreStrategy = RestoreStrategy.New;
		}
	}

	isValidToRestore(content: IDynamicPageInfo) {
		if (!content) {
			return false;
		}
		const isLocked = content.lock === 1;
		if (!isLocked) {
			return true;
		}

		// It might still be OK if you are the one with the lock
		return content.lockedByUser === true;
	}
}

export enum RestoreStrategy {
	Original,
	New,
	OtherPage,
}
