import { Log } from "lime";

export class DateRangeFormatter {
	static alertLimitMilliSeconds = 43200000; // 12 hours

	static format(options: DateRangeFormatterOptions): string {
		const from = options.fromDate || 0;
		const to = options.toDate || 0;
		const toIsSet = to > 0;
		const fromIsSet = from > 0;
		if (!options.status) {
			const hasRange = fromIsSet || toIsSet;
			if (!hasRange) {
				return "";
			}
		}

		return this.getTemplate(options);
	}

	private static getTemplate(options: DateRangeFormatterOptions): string {
		const status = this.calculateStatus(options);
		let text: string;
		let iconClass = "";

		switch (status) {
			case DateRangeStatus.Future:
				text = options.isFutureMessage;
				break;
			case DateRangeStatus.Active:
				text = options.isActiveMessage;
				iconClass = "icon-success";
				break;
			case DateRangeStatus.ActiveBeforeExpire:
				text = options.isActiveCloseExpireMessage;
				iconClass = "icon-alert";
				break;
			case DateRangeStatus.Expired:
				text = options.isExpiredMessage;
				iconClass = "icon-error";
				break;
		}
		const iconName = options.iconName || "clock";

		const template = `
			<div title="${text}" class="lm-text-align-c">
				<svg class="icon datagrid-alert-icon ${iconClass}" focusable="false" aria-hidden="true" role="presentation">
					<use xmlns:xlink="http://www.w3.org/1999/xlink" xlink:href="#icon-${iconName}"/>
				</svg>
				<span class="audible">${text}</span>
			</div>
		`;
		return template;
	}

	private static calculateStatus(options: DateRangeFormatterOptions): number {
		if (options.status) {
			return options.status;
		}

		const from = options.fromDate || 0;
		const to = options.toDate || 0;
		const toIsSet = to > 0;
		const now = new Date().getTime();

		const hasStarted = now > from;
		const hasEnded = toIsSet && now > to;

		if (hasEnded) {
			return DateRangeStatus.Expired;
		} else if (hasStarted) {
			const setCloseToEnd = options.isActiveCloseExpireMessage ? true : false;
			let isCloseToEnd = false;
			if (setCloseToEnd) {
				const limit =
					options.closeToEndLimitMilliSeconds > 0
						? options.closeToEndLimitMilliSeconds
						: this.alertLimitMilliSeconds;
				isCloseToEnd = toIsSet && to - now < limit;
			}
			if (setCloseToEnd && isCloseToEnd) {
				return DateRangeStatus.ActiveBeforeExpire;
			} else {
				return DateRangeStatus.Active;
			}
		} else {
			return DateRangeStatus.Future;
		}
	}
}

export class DateRangeStatus {
	static Unknown = 0;
	static Future = 1;
	static Active = 2;
	static ActiveBeforeExpire = 3;
	static Expired = 4;
}

export class DateRangeFormatterOptions {
	/**
	 * Date in milliseconds
	 */
	fromDate?: number;
	/**
	 * Date in milliseconds
	 */
	toDate?: number;

	/**
	 * Status can be used instead of dates to reflect if the item is active etc.
	 */
	status?: number;

	isActiveMessage: string;
	isFutureMessage: string;
	isActiveCloseExpireMessage?: string;
	isExpiredMessage: string;
	closeToEndLimitMilliSeconds?: number;

	iconName?: string;
}

/**
 * @since 1.0.34
 */
export class DateUtil {
	/**
	 * Parses a date and then converts to a string on the current locale format using Soho / IDS.
	 */
	static parseToString(value: number | string): string {
		return value ? DateUtil.dateToString(new Date(value)) : "";
	}

	static dateToString(date: Date): string {
		const options: { date: string; fromGregorian?: boolean } = {
			date: "datetime",
		};
		try {
			if ((Soho.Locale as any).isIslamic()) {
				options.fromGregorian = true;
			}
		} catch (ex) {
			Log.warning(
				"Soho.Locale.isIslamic() is no longer available. Date will not be formatted correctly.",
				ex,
			);
		}
		return Soho.Locale.formatDate(date, options);
	}

	static parseLocaleDate(value: string): Date {
		if (!value) {
			return new Date();
		}

		const localeFormat = Soho.Locale.calendar().dateFormat.datetime;
		const parsedDate: Date | number[] = Soho.Locale.parseDate(
			value,
			localeFormat,
			true,
		);
		let localeDate = parsedDate;
		if (Array.isArray(parsedDate)) {
			// Array Date means it's not using gregorian calendar.
			try {
				localeDate = (Soho.Locale as any).umalquraToGregorian(localeDate);
			} catch (ex) {
				Log.warning(
					"Soho.Locale.umalquraToGregorian() is no longer available. Date will not be parsed correctly.",
					ex,
				);
			}
		}
		return localeDate;
	}

	static today(): Date {
		const date = new Date();
		date.setHours(0, 0);
		return date;
	}

	/**
	 * Gets a date a week from now (minus one minute to avoid "midnight confusion").
	 */
	static weekFromNow(): Date {
		const date = DateUtil.today();
		const weekInMilliseconds = 7 * 24 * 60 * 60 * 1000;
		date.setTime(date.getTime() + weekInMilliseconds - 60000);
		return date;
	}
}
