import { Component, OnInit, ViewChild, ViewContainerRef } from "@angular/core";
import { SohoMessageService, SohoModalDialogService } from "ids-enterprise-ng";
import { ArrayUtil, DialogButtonType, StringUtil } from "lime";
import { ModalDialogBase } from "lime/core";
import { AdminService, IExpInfo } from "../../service";
import { IDynamicPageInfo } from "./core";
import { DynamicPermissionsDialogComponent } from "./editor/permissions/permissions-dialog";
import { DynamicPageAdminService } from "./service";
import { DynamicUtil } from "./util";

// TODO Styles are duplicated from basic.ts

@Component({
	template: `
		<div
			soho-busyindicator
			[transparentOverlay]="false"
			[blockUI]="true"
			[displayDelay]="0"
			[activated]="isBusy">
			<div #dynamicPublishView class="permission-container lm-brd">
				<p class="lm-margin-lg-b">
					{{
						isRestricted
							? "This page will be available for users within the selected security policy."
							: "This page will be available for all users."
					}}
				</p>

				<div class="permission-edit">
					<h2 [title]="accessTextTooltip" soho-tooltip>
						<svg soho-icon [icon]="isRestricted ? 'locked' : 'url'"></svg
						>{{ accessText }}
					</h2>
					<button
						soho-button="tertiary"
						icon="edit"
						id="lm-a-dp-publish-edit"
						(click)="openPermissionsDialog()">
						Edit
					</button>
					<button
						*ngIf="isRestricted"
						soho-button="tertiary"
						icon="delete"
						id="lm-a-dp-publish-cancel"
						(click)="clearPermission()">
						Clear
					</button>
				</div>
			</div>
		</div>

		<div class="modal-buttonset">
			<button
				type="button"
				class="btn-modal"
				id="lm-a-dp-publish-cancel"
				(click)="cancel()">
				Cancel
			</button>
			<button
				type="button"
				class="btn-modal-primary"
				[disabled]="!canPublish"
				id="lm-a-dp-publish-ok"
				(click)="publish()">
				Publish
			</button>
		</div>
	`,
	styles: [
		`
			.permission-container {
				display: flex;
				flex-direction: column;
				border-top: 1px solid;
				padding-top: 20px;
				margin-bottom: 10px;
			}

			.permission-edit {
				display: flex;
				flex-direction: row;
				margin-top: 5px;
			}

			.permission-edit h2 {
				flex: 1 1 auto;
				font-weight: bold;
				margin-top: 5px;
				vertical-align: middle;
			}

			.permission-edit svg {
				top: 3px;
			}
		`,
	],
})
export class DynamicPublishDialogComponent
	extends ModalDialogBase
	implements OnInit
{
	@ViewChild("dynamicPublishView", { read: ViewContainerRef, static: false })
	view: ViewContainerRef;

	page: IDynamicPageInfo;
	canPublish = false;
	isRestricted = false;
	expressions: IExpInfo[];
	accessText: string;
	accessTextTooltip: string;

	constructor(
		messageService: SohoMessageService,
		private readonly dialogService: SohoModalDialogService,
		private readonly adminService: AdminService,
		private readonly pageService: DynamicPageAdminService,
	) {
		super("DynamicPublishDialogComponent", messageService);
	}

	ngOnInit(): void {
		this.initModalDialog();
		this.loadPublishInfo();
	}

	publish(): void {
		const page = this.page;
		const expressions = this.expressions;
		if (expressions && expressions.length) {
			page.accesses = [];
			for (const exp of expressions) {
				page.accesses.push({ exid: exp.expressionId, as: 1 });
			}
		} else {
			page.accesses = null;
		}
		this.closeWithResult(DialogButtonType.Ok, page);
	}

	cancel(): void {
		this.setCanClose(true);
		this.close();
	}

	clearPermission(): void {
		this.isRestricted = false;
		this.expressions = null;
		this.updateAccessText();
	}

	updateAccessText(): void {
		let length = 0;
		const hasAccess = this.expressions && this.expressions.length > 0;
		if (hasAccess) {
			length = this.expressions.length;
			// Sort access by title
			ArrayUtil.sortByProperty(this.expressions, "title");
		}
		const title: string = hasAccess ? this.expressions[0].title : null;
		this.accessText = DynamicUtil.accessText(title, length);
		this.accessTextTooltip = hasAccess
			? StringUtil.join(this.expressions, (ex) => ex.title, ", ")
			: DynamicUtil.allUsersText;
	}

	openPermissionsDialog() {
		const dialogRef = this.dialogService
			.modal(DynamicPermissionsDialogComponent, this.view)
			.id("dyn-publ-mdl")
			.title("Select Security Policy")
			.afterClose((result) => {
				if (result && result.value) {
					const expressions = result.value;
					this.expressions = expressions;
					this.isRestricted = !!expressions;
					this.updateAccessText();
				}
			});

		dialogRef
			.apply((component: DynamicPermissionsDialogComponent) => {
				component.modalDialog = dialogRef;
				component.listLabel =
					"Choose which security policy that should restrict access to this page.";
				component.selectedExpressions = this.expressions;
				component.isRequired = true;
				component.showRecent = false;
				component.showOperator = false;
			})
			.open();
	}

	private loadPublishInfo(): void {
		this.submitSafe(
			this.pageService.getPublishInfo(this.page.pageId),
			false,
			true,
		).subscribe((response) => {
			this.onLoadPublishInfo(response);
		});
	}

	private onLoadPublishInfo(response): void {
		const page = response.content as IDynamicPageInfo;
		this.page = page;
		const accesses = page.accesses;

		if (accesses) {
			this.expressions = [];
			for (const access of accesses) {
				const expInfo: IExpInfo = {
					expressionId: access.exid,
					title: access.t,
				};
				this.expressions.push(expInfo);
			}
		}
		this.isRestricted = !!this.page.accesses;
		this.canPublish = true;
		this.updateAccessText();
	}
}
