import {
	Component,
	NgZone,
	OnInit,
	ViewChild,
	ViewContainerRef,
} from "@angular/core";
import {
	SohoDataGridComponent,
	SohoMessageService,
	SohoModalDialogRef,
	SohoModalDialogService,
} from "ids-enterprise-ng";
import {
	EntityFilter,
	EntitySortBy,
	IArchiveEntity,
	IArchiveListRequest,
	IArchiveListResponse,
	LanguageService,
	SortOrder,
} from "lime/core";
import { CustomFormatters } from "../../admin";
import { AdminListComponent } from "../../admin-list.component";
import { AdminContext, AdminService } from "../../service";
import { DynamicPageAdminService } from "../dyn/service";
import { ArchiveRestoreDialog } from "./restore";

@Component({
	templateUrl: "./single-entity.html",
})
export class ArchiveSingleEntityDialog
	extends AdminListComponent<IArchiveEntity>
	implements OnInit
{
	@ViewChild("archiveSEDatagrid", { static: false })
	dataGrid: SohoDataGridComponent;
	@ViewChild("archiveSEViewRef", { read: ViewContainerRef, static: false })
	archiveSEViewRef: ViewContainerRef;
	baseUrl = "/admin/dynamic/page"; // Can be changed when other archive types are implemented
	dialog: SohoModalDialogRef<ArchiveSingleEntityDialog>;
	entityId: string;

	constructor(
		messageService: SohoMessageService,
		languageService: LanguageService,
		adminService: AdminService,
		sohoModalDialogService: SohoModalDialogService,
		zone: NgZone,
		public dynamicPageService: DynamicPageAdminService,
		protected readonly adminContext: AdminContext,
	) {
		super(
			"ArchiveSingleEntityDialog",
			"archived version",
			messageService,
			languageService,
			adminService,
			sohoModalDialogService,
			zone,
			{
				isFilter: true,
				isOwnerFilter: false,
				isOtherUserFilter: false,
				isUserFilter: false,
				isRestrictionFilter: false,
				filters: [{ name: "Archived by me", type: EntityFilter.OwnedByMe }],
			},
		);
		this.orderBy = {
			order: SortOrder.Descending,
			entity: EntitySortBy.ChangeDate,
			name: "Newest",
		};

		this.initGrid();
	}

	ngOnInit(): void {
		const tool = this.adminContext.get();
		if (tool) {
			this.currentUser = tool.userId;
		}
		this.refresh();
	}

	getDataGrid(): SohoDataGridComponent {
		return this.dataGrid;
	}

	onClickRestore(archive: IArchiveEntity): void {
		const id = archive.archiveId;

		const dialog = this.sohoDialogService
			.modal(ArchiveRestoreDialog, this.archiveSEViewRef)
			.title("Restore Archive")
			.id("lm-a-se-restore-dialog")
			.afterClose((r) => {
				if (r) {
					this.dialog.close(r);
				}
			});

		dialog
			.apply((component) => {
				component.originalEid = this.entityId;
				component.modalDialog = dialog;
				component.archiveId = id;
				component.archiveType = archive.archiveType;
				component.baseUrl = this.baseUrl;
			})
			.open();
	}

	onClickDelete(archive: IArchiveEntity): void {
		const title = "Confirm delete";
		const description = `Are you sure that you want to delete this archived version of '${archive.title}'?`;
		this.showConfirm(title, description).subscribe(() => {
			const id = archive.archiveId;
			this.logDebug(`Deleting archive ${id}`);

			const observable = this.adminService.deleteArchive(id, this.baseUrl);
			this.withBusy(observable).subscribe(
				() => {
					const updatedArchiveList = this.removeFromArchive(id);
					this.updateItems(updatedArchiveList);
				},
				() => {
					this.showError("Delete", "Unable to delete archived page.");
				},
			);
		});
	}

	listItems(reload: boolean): void {
		const request = this.createRequest(reload) as IArchiveListRequest;
		if (!request) {
			return;
		}
		request.entityId = this.entityId;
		const observable = this.adminService.listArchive(request, this.baseUrl);
		this.withBusy(observable).subscribe(
			(response: IArchiveListResponse) => {
				this.addItems(response.content, response.paging);
			},
			(r: IArchiveListResponse) => {
				this.onError(r);
			},
		);
	}

	protected getColumns(): SohoDataGridColumn[] {
		return [
			this.getSelectionColumn(),
			{
				width: 230,
				id: "lm-a-arc-se-col-c",
				field: "comment",
				name: "Comment",
				sortable: false,
				resizable: true,
			},
			{
				width: 160,
				id: "lm-a-arc-se-col-cd",
				field: "createdDate",
				name: "Created date",
				sortable: false,
				resizable: true,
				formatter: CustomFormatters.date,
			},
			{
				width: 130,
				id: "lm-a-arc-se-col-cbn",
				field: "createdByName",
				name: "Archived by",
				sortable: false,
				resizable: true,
				formatter: CustomFormatters.displayName,
			},
		];
	}

	protected getEmptyMessage(): string {
		return "No archived entities found";
	}

	protected initGrid(): void {
		const options = this.defaultOptions();
		options.selectable = "single" as SohoDataGridSelectable;
		options.expandableRow = false;
		this.datagridOptions = options;
	}

	private removeFromArchive(archiveId: string): IArchiveEntity[] {
		return this.items.filter((archive) => archive.archiveId !== archiveId);
	}
}
