import { Component, ViewChild } from "@angular/core";
import { SohoMessageService, SohoModalDialogRef } from "ids-enterprise-ng";
import { CoreBase } from "lime/core";
import { IExpInfo } from "../../../../service";
import { DynamicPermissionsComponent } from "./permissions";

@Component({
	templateUrl: "./permissions-dialog.html",
})
export class DynamicPermissionsDialogComponent extends CoreBase {
	@ViewChild(DynamicPermissionsComponent, { static: false })
	permissionsComponent: DynamicPermissionsComponent;
	modalDialog: SohoModalDialogRef<DynamicPermissionsDialogComponent>;
	selectedExpressions: IExpInfo[];
	selected: IExpInfo[];
	listLabel: string;
	searchVisible = true;
	showRecent = true;
	showOperator = true;
	isRequired = false;
	isEditable = true;

	private _operator = "||";

	get operator(): string {
		return this._operator;
	}

	set operator(operator: string) {
		this._operator = operator === "&&" ? operator : "||";
	}

	constructor(messageService: SohoMessageService) {
		super("DynamicPermissionsDialogComponent", messageService);
	}

	ngOnInit() {
		this.modalDialog.afterOpen(() => {
			this.permissionsComponent.attachListClickHandler();
		});
	}

	save(): void {
		if (!this.isEditable) {
			return;
		}
		this.modalDialog.close({
			value: this.selected,
			operator: this.permissionsComponent.operator,
		});
	}

	onSelected(selected: IExpInfo[]): void {
		this.selected = selected;
	}
}
