import { Injectable } from "@angular/core";
import { AdminPages, CoreBase } from "lime/core";
import { map } from "rxjs/operators";
import { AdminContext } from "./service";

@Injectable({
	providedIn: "root",
})
export class AdminFeatureService extends CoreBase {
	constructor(private context: AdminContext) {
		super("AdminFeatureService");
	}

	isFeatureEnabled(page: AdminPages) {
		return this.context.tool$.pipe(
			map((tool) => {
				switch (page) {
					case AdminPages.DynamicPages:
						return tool.featureGlobalDynamicPages && tool.featureDynamicPages;
					case AdminPages.Archive:
						return tool.featureGlobalDynamicPages && tool.featureDynamicPages;
					case AdminPages.TenantWidgets:
						return tool.featureTenantWidgets;
					case AdminPages.FeaturedBannerWidgets:
						return tool.featureBanner;
					default:
						return true;
				}
			}),
		);
	}
}
