import { Component, OnInit, ViewChild } from "@angular/core";
import { SohoColorPickerComponent } from "ids-enterprise-ng";
import { IWidgetSize } from "lime";
import {
	BrowserStorageService,
	Constants,
	ContextService,
	CoreBase,
	MemoPreviewMode,
	UIUtil,
} from "lime/core";
import { WidgetSizeDisplayComponent } from "scripts/lime/core/components/widget-size-display/widget-size-display";

export interface IMemoPreviewSettings {
	mode: MemoPreviewMode;
	color: string;
	size: IWidgetSize;
}

export class MemoPreviewProvider {
	private key = "MemoPreviewProviderSettings";

	constructor(
		private readonly storageService: BrowserStorageService,
		private readonly isBannerFeature: boolean,
	) {}

	get settings(): IMemoPreviewSettings {
		const settings =
			this.storageService.getLocalStorageItem<IMemoPreviewSettings>(this.key) ||
			this.getDefaultSettings();
		if (!this.isBannerFeature && settings.mode === "banner") {
			settings.mode = "regular";
		}
		return settings;
	}

	set settings(settings: IMemoPreviewSettings) {
		this.storageService.setLocalStorageItem(this.key, settings);
	}

	private getDefaultSettings(): IMemoPreviewSettings {
		return {
			mode: "top",
			color: Constants.defaultColor,
			size: { cols: 1, rows: 1 },
		};
	}
}

@Component({
	templateUrl: "./preview.html",
})
export class MemoPreviewDialog extends CoreBase implements OnInit {
	@ViewChild(SohoColorPickerComponent, { static: false })
	colorpicker: SohoColorPickerComponent;

	@ViewChild(WidgetSizeDisplayComponent, { static: false })
	sizeSelector: WidgetSizeDisplayComponent;

	settings: IMemoPreviewSettings;
	colorpickerOptions = UIUtil.getPageColorPickerOptions();
	maxSize: IWidgetSize = null;
	isBannerFeature: boolean;

	private previewProvier: MemoPreviewProvider;
	private _color: string;

	constructor(
		storageService: BrowserStorageService,
		contextService: ContextService,
	) {
		super("MemoPreviewDialog");
		this.isBannerFeature = contextService
			.getContext()
			.settings.isFeatureHeroWidget();
		this.previewProvier = new MemoPreviewProvider(
			storageService,
			this.isBannerFeature,
		);
	}

	ngOnInit(): void {
		this.settings = this.previewProvier.settings;
		this._color = this.settings.color;
		this.onModeChange();
	}

	save(): void {
		this.previewProvier.settings = this.settings;
	}

	setSize(size: IWidgetSize) {
		this.settings.size = size;
	}

	get mode(): MemoPreviewMode {
		return this.settings.mode;
	}

	set mode(mode: MemoPreviewMode) {
		this.settings.mode = mode;
		this.onModeChange();
	}

	get showSize(): boolean {
		return this.settings.mode !== "top";
	}

	get size(): IWidgetSize {
		return this.settings.size;
	}

	get color(): string {
		return this._color;
	}

	set color(color: string) {
		this._color = color;
		this.settings.color = this.colorpicker.getHexValue() as string;
	}

	private onModeChange(): void {
		this.validateMode();
		if (this.mode === "banner") {
			const size = this.settings.size;
			if (size.rows > 1) {
				this.settings.size = this.sizeSelector.availableSizes.find(
					(item) => item.rows === 1 && item.cols === size.cols,
				);
			}
			this.maxSize = { cols: 4, rows: 1 };
		} else {
			this.maxSize = null;
		}
	}

	private validateMode() {
		if (!this.isBannerFeature && this.mode === "banner") {
			this.mode = "regular";
		}
	}
}
