import { Component, OnInit } from "@angular/core";
import { SohoModalDialogRef } from "ids-enterprise-ng";
import { CoreBase, IWidgetDefinition } from "lime/core";
import {
	AdminContext,
	AdminService,
	IWidgetDeployInfoResponse,
} from "../service";

export interface IDeployInfo {
	schemaVersion?: string;
	registryUpdateDate?: Date;
	syncDate?: Date;
	applicationVersion?: string;
	currentVersion?: string;
}

export interface ITenantInfo {
	signed: string;
	signTimestamp: string;
}

@Component({
	templateUrl: "./widget-details-dialog.html",
	styleUrls: ["./widget-details-dialog.scss"],
})
export class WidgetDetailsDialogComponent extends CoreBase implements OnInit {
	dialog: SohoModalDialogRef<WidgetDetailsDialogComponent>;
	widgetId: string;
	version: string;

	isBusy: boolean;
	definition: IWidgetDefinition;
	deployInfo: IDeployInfo;
	tenantInfo: ITenantInfo;

	constructor(
		private adminService: AdminService,
		private context: AdminContext,
	) {
		super("WidgetDetailsDialogComponent");
	}

	ngOnInit(): void {
		this.setBusy(true);
		this.adminService
			.getWidgetDeployInfo({ id: this.widgetId, v: this.version })
			.subscribe(
				(response) => {
					this.onResponse(response);
					this.setBusy(false);
				},
				(r) => {
					this.setBusy(false);
					this.adminService.handleError(r);
				},
			);
	}

	setBusy(isBusy: boolean): void {
		this.isBusy = isBusy;
	}

	close(): void {
		this.dialog.close();
	}

	private onResponse(response: IWidgetDeployInfoResponse): void {
		const data = response.content;
		const definition = data.definition;
		this.definition = definition;

		if (definition.isTenant) {
			this.tenantInfo = this.createTenantInfo(definition);
		} else if (data.deployInfo) {
			this.deployInfo = this.createDeployInfo(data.deployInfo);
		}

		// Remove long and unnecessary manifest info
		delete definition.cacheArg;
		delete definition.description;
	}

	private createDeployInfo(deployInfo: string): IDeployInfo {
		const info: IDeployInfo = {};
		// Will be a semicolon-separated string
		try {
			const infoItems = deployInfo.split(";");
			info.schemaVersion = infoItems[0];
			info.registryUpdateDate = this.toDate(infoItems[1]);
			info.syncDate = this.toDate(infoItems[2]);
			info.applicationVersion = infoItems[3];
			info.currentVersion = this.context.get().version;
		} catch (ex) {
			this.logError("createDeployInfo", ex);
		}
		return info;
	}

	private toDate(value: string): Date {
		if (!value) {
			return null;
		}
		return new Date(parseInt(value, 10));
	}

	private createTenantInfo(definition: IWidgetDefinition): ITenantInfo {
		const signed = definition.signed;

		let signedText = "No";
		if (signed === 1) {
			signedText = "Yes";
		} else if (definition.signed === 2) {
			signedText = "Yes (expired certificate)";
		}

		return {
			signed: signedText,
			signTimestamp: definition.signTimestamp,
		};
	}
}
