import {
	Component,
	NgZone,
	OnInit,
	ViewChild,
	ViewContainerRef,
} from "@angular/core";
import {
	SohoDataGridComponent,
	SohoMessageService,
	SohoModalDialogService,
} from "ids-enterprise-ng";
import { DialogButtonType, IDialogResult } from "lime";
import {
	DialogResponseCode,
	EntityFilter,
	IEntityAccess,
	IImportOptions,
	IIntegerResponse,
	IOperationResponse,
	IWidgetCatalogRequest,
	IWidgetCatalogResponse,
	IWidgetInfo,
	IWidgetInfoResponse,
	LanguageService,
} from "lime/core";
import { take } from "rxjs/operators";
import { CustomFormatters, GridUtil, WidgetUtilAdmin } from "../admin";
import { AdminListComponent } from "../admin-list.component";
import {
	IMessageBannerOptions,
	MessageBannerLevel,
} from "../common/message-banner";
import { AdminContext, AdminService } from "../service";
import { WidgetDetailsDialogComponent } from "./widget-details-dialog";

@Component({
	selector: "lm-admin-tenant-widgets",
	templateUrl: "./tenant-widgets.html",
	styleUrls: ["./tenant-widgets.scss"],
})
export class AdminTenantWidgetsComponent
	extends AdminListComponent<IWidgetInfo>
	implements OnInit
{
	@ViewChild("tenantWidgetsDatagrid", { static: false })
	dataGrid: SohoDataGridComponent;

	accessCopy: IEntityAccess[];
	widgetsGridOptions: any;
	includeAll = false;
	isCloud: boolean;
	showUnsignedInformation = false;
	messageBanner?: IMessageBannerOptions;

	constructor(
		languageService: LanguageService,
		adminService: AdminService,
		zone: NgZone,
		sohoModalDialogService: SohoModalDialogService,
		messageService: SohoMessageService,
		private readonly adminContext: AdminContext,
		readonly viewRef: ViewContainerRef,
	) {
		super(
			"AdminTenantWidgetsComponent",
			"widget",
			messageService,
			languageService,
			adminService,
			sohoModalDialogService,
			zone,
			{
				isFilter: true,
				isUserFilter: false,
				filters: [
					{
						name: "Mobile",
						propertyName: "includeMobileOnly",
						value: true,
						type: EntityFilter.Custom,
					},
				],
			},
		);

		this.datagridOptions = this.defaultOptions();
	}

	ngOnInit(): void {
		if (this.initializing) {
			this.adminContext.tool$.pipe(take(1)).subscribe((tool) => {
				this.maxCount = tool.maxCountTenantWidgets || 0;
				this.isCloud = tool.isCloud;
				this.showUnsignedInformation = tool.isUnsignedTenantWidgetsEnabled;
			});
		}
		if (this.showUnsignedInformation) {
			this.messageBanner = {
				title: "Installation of unsigned widgets is enabled",
				message:
					"IMPORTANT NOTICE: The use of unsigned widgets has been enabled for this tenant. Unsigned widgets have not been reviewed and approved by Infor or an authorized agent thereof so you might experience technical difficulties as a result of their use. Infor is not responsible for any technical difficulties or data loss that occurs through the use of unsigned widgets.",
				level: MessageBannerLevel.Info,
			};
		}

		this.refresh();
	}

	getDataGrid(): SohoDataGridComponent {
		return this.dataGrid;
	}

	listItems(reload: boolean): void {
		if (this.isBusy) {
			return;
		}

		const self = this;
		const adminService = self.adminService;
		this.setBusy(true);

		if (reload) {
			this.hasMore = true;
			this.paging = null;
			this.items = [];
			this.clearSelection();
		}

		const orderBy = this.orderBy;
		const request: IWidgetCatalogRequest = {
			paging: this.paging,
			pageSize: this.pageSize,
			sortOrder: orderBy.order,
			sortBy: orderBy.entity,
			query: this.query,
		};

		// Set common active request filters
		this.setRequestFilters(request);

		if (this.includeAll) {
			request.includeAll = true;
		}

		adminService.listTenantWidgets(request).subscribe(
			(response: IWidgetCatalogResponse) => {
				const newItems = response.content;
				self.addItems(newItems, response.paging);
				self.updateCount(response.count, this.maxCount);
				self.setBusy(false);
			},
			(r: IOperationResponse) => {
				self.setBusy(false);
				self.onError(r);
			},
		);
	}

	/**
	 * Opens the widget access dialog.
	 */
	editAccess(): void {
		const widget = this.getSelectedItem();
		this.adminService.openWidgetAccessDialog(
			widget,
			(resp: IWidgetInfoResponse) => {
				if (resp && resp.content) {
					this.refresh();
				} else {
					this.onError(resp);
				}
			},
			this.viewRef,
		);
	}

	/**
	 * Copy access rights of a widget.
	 */
	copyAccess(): void {
		const widget = this.getSelectedItem();
		const self = this;
		const adminService = self.adminService;

		this.setBusy(true);
		adminService
			.getWidgetAccess({ id: widget.widgetId, accessList: [] })
			.subscribe(
				(r: IOperationResponse) => {
					self.accessCopy = WidgetUtilAdmin.getAccessCopy(r.content.accessList);
					self.setBusy(false);
				},
				(r: IOperationResponse) => {
					self.adminService.handleError(r);
					self.setBusy(false);
				},
			);
	}

	/**
	 * Apply Access Copy
	 *
	 * Apply copied acces rights to selected widget(s).
	 *
	 * @params widget to edit. Otherwise use selected widgets in grid.
	 */
	applyAccessCopy(): void {
		const items = this.getSelectedItems();
		this.adminService.applyWidgetAccess(items, this.accessCopy, () => {
			this.refresh();
		});
	}

	/**
	 * Clear Or Replace With Access Copy
	 *
	 * If indicated with "isReplace", replaces access rights.
	 * Otherwise clear access rights of selected widgets.
	 *
	 * @params isReplace Boolean, true: replace, false: clear.
	 */
	clearOrReplaceWithAccessCopy(isReplace?: boolean): void {
		const items = this.getSelectedItems();
		this.adminService.clearOrReplaceWidgetAccess(
			items,
			isReplace,
			() => {
				this.refresh();
			},
			this.accessCopy,
		);
	}

	/**
	 * Install new and/or upgrade a tenant widget.
	 */
	install(): void {
		const dialogTitle = "Install Tenant Widget";
		const adminService = this.adminService;
		const options: IImportOptions = {
			title: dialogTitle,
			operation: "importtenantwidget",
			disclaimer: this.showUnsignedInformation
				? "DISCLAIMER: If the widget you are attempting to import is unsigned you should cancel this upload unless you trust its source. Infor is not responsible for any technical difficulties or data loss that occurs through the use of unsigned widgets."
				: null,
		};

		const self = this;
		adminService
			.openImportFilesDialog(options, this.viewRef)
			.subscribe((r: IDialogResult) => {
				const value = r.value;
				if (
					r.button === DialogButtonType.Yes &&
					value.responseCode === DialogResponseCode.Success
				) {
					this.adminService
						.showUploadCompleteDialog(dialogTitle, value.message)
						.subscribe((result: IDialogResult) => {
							if (result.button === DialogButtonType.Ok) {
								self.refresh();
							}
						});
				} else if (
					r.button === DialogButtonType.Yes &&
					value.responseCode === DialogResponseCode.Fail
				) {
					adminService.showUploadCompleteDialog(
						dialogTitle,
						value.message,
						true,
					);
				}
			});
	}

	onClickDelete(): void {
		const items = this.getSelectedItems();

		if (!items || items.length !== 1) {
			this.logWarning("Invalid selection count");
			return;
		}

		const selected = items[0];
		const widget = {
			widgetId: selected.widgetId,
			version: selected.version,
			frameworkVersion: selected.frameworkVersion,
		};

		const title = "Delete Widget";
		const message = this.getDeleteMessage(selected);

		this.showConfirm(title, message).subscribe(() => {
			this.deleteWidget(widget, title);
		});
	}

	getDeleteMessage(widget: IWidgetInfo): string {
		const version = widget.displayVersion || widget.version;
		let message = `Are you sure that you want to remove the widget '${widget.title}', with version ${version}?`;
		if (widget.isActive) {
			message +=
				" It will be removed for all users, as well as any published widget based on this widget.";
		}
		return message;
	}

	/**
	 * Delete Standard
	 *
	 * Displays confirmation message to the user and deletes provided widgets on confirm.
	 *
	 * @params widgets List of widget IDs to delete, or single WidgetInfo of widget to delete.
	 */
	deleteWidget(widget: IWidgetInfo, title: string): void {
		this.setBusy(true);

		this.adminService.deleteTenantWidget(widget).subscribe(
			(r: IIntegerResponse) => {
				let responseMessage = "";

				const messageList = r.errorList || r.messageList;
				if (messageList) {
					for (const msg of messageList) {
						responseMessage += msg.message;
					}
				}
				this.adminService
					.showUploadCompleteDialog(title, responseMessage)
					.subscribe((result: IDialogResult) => {
						if (result.button === DialogButtonType.Ok) {
							if (r.content && r.content > 0) {
								this.refresh();
							}
						}
					});
				this.setBusy(false);
			},
			(r: IOperationResponse) => {
				this.setBusy(false);
				this.adminService.handleError(r, r.getErrorMessages());
			},
		);
	}

	onExpandRow(event: { detail: any; item: any }): void {
		const item = event.item;
		const container = $(event.detail)
			.find(".datagrid-row-detail-padding")
			.empty();
		let template = `<div class="datagrid-cell-layout">
				<span class="datagrid-textarea lm-white-space-normal">${this.escape(
					item.description,
				)}
				<p>Framework version: ${item.frameworkVersion}</p></span>`;

		if (item.widgetErrorInfo) {
			template += this.getErrorMessageTemplate(
				GridUtil.formatError(item.widgetErrorInfo.message),
			);
		}

		template += "</div>";
		$(container).append($(template));
	}

	onClickExport(): void {
		const items = this.getSelectedItems();
		if (!items) {
			this.logWarning("No selection to export");
			return;
		}
		if (items.length !== 1) {
			this.logWarning("Invalid selection to export. Multiselect not supported");
			return;
		}

		const widgetInfo = items[0];
		const title = "Export widget";
		const message = `Are you sure that you want to export ${widgetInfo.title}?`;

		this.showConfirm(title, message).subscribe(() => {
			this.adminService.exportTenantWidget(widgetInfo);
		});
	}

	onClickViewDetails(): void {
		const widget = this.getSelectedItem();
		const dialog = this.sohoDialogService
			.modal(WidgetDetailsDialogComponent, this.viewRef)
			.title("Widget Details")
			.id("lm-a-tw-details-dialog");

		dialog
			.apply((component) => {
				component.dialog = dialog;
				component.widgetId = widget.widgetId;
				component.version = widget.version;
			})
			.open();
	}

	protected getColumns(): SohoDataGridColumn[] {
		const self = this;
		return [
			this.getSelectionColumn(),
			{
				width: 335,
				id: "adm-sw-col-t",
				field: "title",
				name: "Title",
				sortable: false,
				formatter: Formatters.Expander,
			},
			{
				width: 250,
				id: "adm-sw-col-wi",
				field: "widgetId",
				name: "Widget ID",
				sortable: false,
				formatter: (row: number, cell, value: string) => {
					const error = self.items[row].widgetErrorInfo;
					if (error) {
						return GridUtil.formatError(value);
					}
					return value;
				},
			},
			{
				width: 160,
				id: "adm-sw-col-cd",
				field: "changeDate",
				name: "Change date",
				sortable: false,
				formatter: CustomFormatters.date,
			},
			{
				width: 100,
				id: "adm-sw-col-s",
				field: "version",
				name: "Version",
				sortable: false,
				formatter: (row: number, cell, value) => {
					return self.items[row].displayVersion || self.items[row].version;
				},
			},
			{
				width: 90,
				id: "adm-sw-col-ac",
				field: "isActive",
				name: "Active",
				sortable: false,
				formatter: (row: number, cell, value) => {
					return self.items[row].isActive ? "Yes" : "No";
				},
			},
			{
				width: 150,
				id: "adm-sw-col-cbn",
				field: "changedByName",
				name: "Changed by",
				sortable: false,
				formatter: CustomFormatters.displayName,
			},
			{
				width: 110,
				id: "adm-sw-col-hr",
				field: "hasRestrictions",
				name: "Permissions",
				sortable: false,
				formatter: CustomFormatters.restricted,
			},
		];
	}

	protected getEmptyMessage(): string {
		return "No tenant widgets found";
	}
}
