import { Directive, NgZone, ViewContainerRef } from "@angular/core";
import {
	SohoDataGridComponent,
	SohoMessageService,
	SohoModalDialogService,
} from "ids-enterprise-ng";
import { HtmlUtil, IAutocompleteEntity, IDialogResult } from "lime";
import {
	BrowserStorageService,
	Constants,
	CoreBase,
	EntityFilter,
	EntitySortBy,
	ICatalogRequest,
	IOperationResponse,
	IOrderBy,
	IPagingInfo,
	LanguageService,
	PermissionFilter,
	SortOrder,
} from "lime/core";
import { Observable } from "rxjs";
import { finalize } from "rxjs/operators";
import { AdminUserSelectorComponent } from "./pages/user-selector";
import { AdminConstants, AdminService, AdminUtil } from "./service";

export interface IAdminListOptions {
	/**
	 * Gets or sets a value that indicates if filters are used.
	 * The default value is false.
	 */
	isFilter?: boolean;

	/**
	 * Gets or sets a value that indicates if user filters should be included when filters are enabled.
	 * The default value is true if filters are enabled.
	 */
	isUserFilter?: boolean;

	isOtherUserFilter?: boolean;

	isOwnerFilter?: boolean;

	isRestrictionFilter?: boolean;

	sortUsedBy?: boolean;

	sortPriority?: boolean;

	filters?: IAdminEntityFilter[];
}

export interface IAdminEntityFilter {
	type: number;
	name?: string;
	selected?: boolean;
	isUser?: boolean;
	propertyName?: string;
	value?: any;
}

@Directive()
export class AdminListComponent<T = any> extends CoreBase {
	private get orderByKey(): string {
		return this.className + "OrderBy";
	}

	private get filterKey(): string {
		return this.className + "Filter";
	}

	private get browserStorageService(): BrowserStorageService {
		return this.adminService.browserStorageService;
	}
	datagridOptions: SohoDataGridOptions;
	orderByItems: IOrderBy[];
	orderBy: IOrderBy;
	pageSize: number;
	paging: IPagingInfo;
	items: T[] = [];
	selection: SohoDataGridSelectedRow[];
	selected: T;
	selectionCount = 0;
	isSearchActive: boolean;
	toolbarDisabled = true;
	isBusy: boolean;
	query: string;
	hasMore = false;
	initializing = true;
	currentUser: string;
	isFiltered: boolean;
	filterTooltip: string;
	filterItems: IAdminEntityFilter[];
	filter: IAdminEntityFilter = { type: 0 };
	filterUser: IAutocompleteEntity;
	toolbarOptions = { maxVisibleButtons: 5, rightAligned: true };
	toolbarTitle: string;
	quotaTitle: string;
	isCloseToMaxQuota: boolean;
	isMaxQuota: boolean;
	count: number;
	maxCount: number;
	activeQuery: string;
	isReadOnly = false;

	constructor(
		className: string,
		protected entityName: string,
		messageService: SohoMessageService,
		languageService: LanguageService,
		public adminService: AdminService,
		public sohoDialogService: SohoModalDialogService,
		protected readonly ngZone: NgZone,
		private readonly options?: IAdminListOptions,
	) {
		super(className, messageService, languageService);

		const items = [
			{
				order: SortOrder.Ascending,
				entity: EntitySortBy.Title,
				name: "Title A-Z",
			},
			{
				order: SortOrder.Descending,
				entity: EntitySortBy.Title,
				name: "Title Z-A",
			},
			{
				order: SortOrder.Descending,
				entity: EntitySortBy.ChangeDate,
				name: "Newest",
			},
			{
				order: SortOrder.Ascending,
				entity: EntitySortBy.ChangeDate,
				name: "Oldest",
			},
		];

		if (options) {
			if (options.sortUsedBy) {
				items.push({
					order: SortOrder.Descending,
					entity: EntitySortBy.UsedBy,
					name: "Most used",
				});
				items.push({
					order: SortOrder.Ascending,
					entity: EntitySortBy.UsedBy,
					name: "Least used",
				});
			}
			if (options.sortPriority) {
				items.push({
					order: SortOrder.Descending,
					entity: EntitySortBy.Priority,
					name: "High priority",
				});
				items.push({
					order: SortOrder.Ascending,
					entity: EntitySortBy.Priority,
					name: "Low priority",
				});
			}

			if (options.isFilter) {
				const types = EntityFilter;
				let filterItems: IAdminEntityFilter[] = [
					{ name: "None", selected: true, type: types.None },
				];

				if (options.isUserFilter !== false) {
					filterItems.push({ name: "Changed by me", type: types.ChangedByMe });
					if (options.isOtherUserFilter !== false) {
						filterItems.push({
							name: "Changed by user...",
							isUser: true,
							type: types.ChangedByUser,
						});
					}
					if (options.isOwnerFilter !== false) {
						filterItems.push({ name: "Owned by me", type: types.OwnedByMe });
						filterItems.push({
							name: "Owned by user...",
							isUser: true,
							type: types.OwnedByUser,
						});
					}
				}

				if (options.isRestrictionFilter !== false) {
					filterItems.push({
						name: "No restrictions",
						type: types.NoRestrictions,
					});
					filterItems.push({ name: "Restrictions", type: types.Restrictions });
				}

				if (options.filters) {
					filterItems = filterItems.concat(options.filters);
				}

				this.filterItems = filterItems;
				this.setDefaultFilter();
			}
		}

		this.orderByItems = items;
		this.setDefaultOrderBy();

		this.pageSize = AdminConstants.gridPageSize;
	}

	setBusy(isBusy: boolean): void {
		this.isBusy = isBusy;
		if (!isBusy) {
			this.initializing = false;
		}
	}

	isEmpty(): boolean {
		return this.items.length === 0 && !this.initializing && !this.isBusy;
	}

	onError(error: IOperationResponse): void {
		this.adminService.handleError(error);
		this.setBusy(false);
	}

	getItemCountText(): string {
		return AdminUtil.getItemCountText(this.entityName, this.items.length);
	}

	refresh(): void {
		this.clearSelection();
		this.listItems(true);
	}

	listItems(reload?: boolean): void {
		// Override in subclass
	}

	hasActiveFilters(): boolean {
		return this.isSearchActive || (this.filter && this.filter.type > 0);
	}

	more(): void {
		this.listItems(false);
	}

	hasSelection(): boolean {
		const items = this.selection;
		return items && items.length > 0;
	}

	getSelectedItem(): T {
		const items = this.selection;
		return items && items.length > 0 ? (items[0].data as T) : null;
	}

	getSelectedItems(): T[] {
		const pages = [];
		const items = this.selection;
		if (items) {
			for (const item of items) {
				pages.push(item.data);
			}
		}
		return pages;
	}

	clearSelection(): void {
		try {
			const grid = this.getDataGrid();

			if (grid && grid["datagrid"]) {
				grid.unSelectAllRows();
				this.updateSelection([]);
			}
		} catch (ex) {
			this.logError("Failed to clear selection", ex);
		}
	}

	selectItem(item: T): void {
		this.setSelection([{ data: item } as SohoDataGridSelectedRow]);
	}

	updateSelection(args: SohoDataGridSelectedRow[]): void {
		if (this.isBusy) {
			return;
		}
		this.setSelection(args);
	}

	setOrderBy(item: IOrderBy) {
		if (item && this.orderBy !== item) {
			this.orderBy = item;
			this.saveOrderBy(item);
			this.refresh();
		}
	}

	search(): void {
		// Don't search for whitespace
		const query = (this.query || "").trim();
		this.query = query;
		const hasQuery = !!query;

		// Clear any existing search if searching for blank / whitespace
		if (!hasQuery && this.isSearchActive) {
			this.clearSearch();
			return;
		}

		if (hasQuery) {
			this.isSearchActive = true;
			this.activeQuery = query;
			this.paging = null;
			this.refresh();
			return;
		}
	}

	clearSearch(refresh = true): void {
		this.ngZone.run(() => {
			if (!this.isSearchActive) {
				return;
			}
			this.setDefaultSearch();
			if (refresh) {
				this.refresh();
			}
		});
	}

	clearAllFilters(): void {
		this.clearAllFiltersOptional(true);
	}

	clearAllFiltersOptional(clearCustom: boolean): void {
		this.deleteValue(this.filterKey);
		this.setDefaultSearch();
		this.setDefaultOrderBy();
		this.setDefaultFilter();
		if (clearCustom) {
			this.clearCustomFilter();
		}
		this.refresh();
	}

	getQuery(): string {
		return this.query ? this.query.trim() : "";
	}

	onFilter(
		filter: IAdminEntityFilter,
		viewRef: ViewContainerRef,
		event?: Event,
	): void {
		// Skip if the same filter was selected, unless it is one of the special cases
		const currentFilter = this.filter;
		const type = filter.type;
		if (currentFilter.type === type) {
			const isDialog = filter.name.indexOf("..") > 0;
			const isCustom =
				type === EntityFilter.Custom &&
				(currentFilter.propertyName !== filter.propertyName ||
					currentFilter.value !== filter.value);
			if (!isDialog && !isCustom) {
				return;
			}
		}

		if (this.isUserFilter(filter)) {
			this.selectFilterUser(filter, viewRef, event);
			return;
		}

		this.filterUser = null;
		this.applyFilter(filter);
	}

	selectFilterUser(
		filter: IAdminEntityFilter,
		viewRef: ViewContainerRef,
		event?: Event,
	): void {
		const dialog = this.sohoDialogService
			.modal(AdminUserSelectorComponent, viewRef)
			.id("lm-a-selectuser-dialog")
			.title("Select user")
			.afterClose((r: IDialogResult) => {
				if (r && r.value) {
					this.filterUser = r.value as IAutocompleteEntity;
					this.applyFilter(filter);
				} else if (event) {
					setTimeout(() => {
						this.restoreFilterSelection(event);
					}, 10);
				}
			});
		dialog
			.apply((component) => {
				component.dialog = dialog;
			})
			.open();
	}

	restoreFilterSelection(event: Event): void {
		// FUTURE This is a hack since there does not seem to be a way to change the selection
		// check boxes in the menu items in IDS 4.21.x and 6.0.x.
		const className = "is-checked";
		const menuElement = $(event.target).parent().parent();
		menuElement.find("." + className).removeClass(className);
		const filterName = this.filter.name;
		menuElement
			.find("a")
			.filter((index, element) => {
				return $(element).text() === filterName;
			})
			.parent()
			.addClass(className);
	}

	setRequestFilters(request: ICatalogRequest): void {
		// Check for any active filters
		const user = this.getFilterUser();
		const filter = this.filter;
		const types = EntityFilter;
		const type = filter ? filter.type : types.None;
		if (type === types.ChangedByMe || type === types.ChangedByUser) {
			request.changedById = user;
		} else if (type === types.OwnedByMe || type === types.OwnedByUser) {
			request.ownerId = user;
		} else if (type === types.Restrictions) {
			request.permissionFilter = PermissionFilter.Restrictions;
		} else if (type === types.NoRestrictions) {
			request.permissionFilter = PermissionFilter.NoRestrictions;
		} else if (type === types.Custom) {
			request[filter.propertyName] = filter.isUser ? user : filter.value;
		}
	}

	getErrorMessageTemplate(message: string): string {
		return `<div class="lm-margin-lg-t lm-admin-error-description">${message}</div>`;
	}

	getLinkTemplate(link: string): string {
		return `<a class="lm-margin-lg-t hyperlink" name="lm-help-URL" href="${link}" target="_blank" soho-tooltip [title]="${link}">Help</a>`;
	}

	hasReplacementTemplate(link: string): boolean {
		if (link) {
			const start = link.indexOf("{");
			const end = link.indexOf("}");
			if (start === -1 || end === -1) {
				return false;
			}
			return start < end;
		} else {
			return false;
		}
	}

	onSearchfieldFocus(): void {
		this.activeQuery = this.getQuery();
	}

	onSearchfieldFocusLost(): void {
		this.query = this.activeQuery;
	}

	protected escape(text: string): string {
		return HtmlUtil.escapeStringForHtml(text);
	}

	protected saveValue<U>(key: string, value: U): void {
		this.browserStorageService.setLocalStorageItem(key, value);
	}

	protected loadValue<U>(key: string): U {
		return this.browserStorageService.getLocalStorageItem(key);
	}

	protected deleteValue(key: string): void {
		this.browserStorageService.deleteLocalStorageItem(key);
	}

	protected addItems(newItems: T[], paging: IPagingInfo): void {
		this.paging = paging;
		this.hasMore = newItems.length >= this.pageSize;
		const hasItems = this.items.length > 0;
		const items = this.items.concat(newItems);
		this.toolbarDisabled = !items.length && !this.hasActiveFilters();
		this.items = items;

		if (hasItems) {
			this.appendItems(newItems);
		}
		this.updateGridData();
	}

	protected updateItems(newItems: T[]): void {
		this.items = newItems;
		this.updateGridData();
	}

	protected appendItems(newItems: T[]): void {
		const grid = this.getDataGrid();
		if (grid) {
			for (const item of newItems) {
				grid.addRow(item, "bottom");
			}
		}
	}

	protected getDataGrid(): SohoDataGridComponent {
		return null;
	}

	protected getColumns(): SohoDataGridColumn[] {
		return null;
	}

	protected getSelectionColumn(): SohoDataGridColumn {
		return {
			width: 50,
			id: "selectionCheckbox",
			field: "",
			name: "",
			resizable: false,
			sortable: false,
			formatter: Formatters.SelectionCheckbox,
			align: "center",
		};
	}

	protected getEmptyMessage(): string {
		return null;
	}

	protected getRowTemplate(): string {
		return null;
	}

	protected updateGridData(): void {
		this.datagridOptions.dataset = this.items;
	}

	protected createRequest(reload?: boolean): null | ICatalogRequest {
		if (this.isBusy) {
			return null;
		}

		if (reload) {
			this.hasMore = true;
			this.paging = null;
			this.items = [];
			this.clearSelection();
		}

		if (this.getQuery()) {
			this.isSearchActive = true;
		}

		const orderBy = this.orderBy;
		const request = {
			paging: this.paging,
			pageSize: this.pageSize,
			sortOrder: orderBy.order,
			sortBy: orderBy.entity,
			query: this.query,
		};
		this.setRequestFilters(request);

		return request;
	}

	protected withBusy<T>(observable: Observable<T>): Observable<T> {
		this.setBusy(true);
		return observable.pipe(
			finalize(() => {
				this.setBusy(false);
			}),
		);
	}

	protected clearCustomFilter() {}

	protected updateCount(count: number, maxCount: number) {
		this.count = count = count || 0;
		this.maxCount = maxCount = maxCount || 0;
		if (maxCount > 0) {
			this.isCloseToMaxQuota = count / maxCount >= 0.9;
			this.isMaxQuota = count >= maxCount;
		}
		const entityName = AdminUtil.pluralize(this.entityName, count);
		this.toolbarTitle = `You have ${count} of maximally ${maxCount} ${entityName}.`;
		this.quotaTitle = this.isMaxQuota
			? `You have reached your max allowed quota of ${entityName}!`
			: `You are near your max allowed quota of ${entityName}!`;
	}

	protected defaultOptions(): SohoDataGridOptions {
		const options = {
			selectable: "multiple" as SohoDataGridSelectable,
			expandableRow: true,
			disableRowDeactivation: true,
			clickToSelect: false,
			dataset: [],
			showNewRowIndicator: false,
		} as any as SohoDataGridOptions;

		const columns = this.getColumns();
		if (columns) {
			options.columns = columns;
		}

		const emptyMessage = this.getEmptyMessage();
		if (emptyMessage) {
			options.emptyMessage = {
				title: emptyMessage,
				icon: Constants.adminEmptyDatagridIcon,
			};
		}

		const rowTemplate = this.getRowTemplate();
		if (rowTemplate) {
			(options as any).rowTemplate = rowTemplate;
		}

		return options;
	}

	private getFilterUser(): string {
		return this.filterUser
			? (this.filterUser.value as string)
			: this.currentUser;
	}

	private saveOrderBy(value: IOrderBy): void {
		this.saveValue(this.orderByKey, value);
	}

	private loadOrderBy(): IOrderBy {
		const value = this.loadValue<IOrderBy>(this.orderByKey);
		return value
			? this.orderByItems.find(
					(item) => item.entity === value.entity && item.order === value.order,
			  )
			: null;
	}

	private saveFilter(value: IAdminEntityFilter): void {
		if (value.isUser) {
			this.deleteValue(this.filterKey);
		} else {
			this.saveValue(this.filterKey, value);
		}
	}

	private loadFilter(): IAdminEntityFilter {
		const filter = this.loadValue<IAdminEntityFilter>(this.filterKey);
		return filter ? this.findFilter(filter.type, filter.value) : null;
	}

	private setSelection(args: SohoDataGridSelectedRow[]): void {
		const newCount = args.length;
		this.selectionCount = newCount;
		this.selection = args;
		this.selected = args && newCount === 1 ? (args[0].data as T) : null;
	}

	private isUserFilter(filter: IAdminEntityFilter): boolean {
		const types = EntityFilter;
		return (
			filter.isUser ||
			filter.type === types.OwnedByUser ||
			filter.type === types.ChangedByUser
		);
	}

	private applyFilter(filter: IAdminEntityFilter): void {
		const currentFilter = this.filter;
		if (currentFilter) {
			currentFilter.selected = false;
		}
		filter.selected = true;
		this.setFilter(filter);
		this.saveFilter(filter);
		this.refresh();
	}

	private setDefaultOrderBy() {
		this.orderBy = this.loadOrderBy() || this.orderByItems[0];
	}

	private setDefaultFilter() {
		if (this.filterItems) {
			const filter = this.loadFilter() || this.findFilter(EntityFilter.None);
			this.filterItems.forEach((item) => (item.selected = false));
			filter.selected = true;
			this.filterUser = null;
			this.setFilter(filter);
		}
	}

	private setFilter(filter: IAdminEntityFilter): void {
		this.filter = filter;
		this.isFiltered = filter.type > 0;
		this.filterTooltip = this.isFiltered ? "Filter active" : null;
	}

	private findFilter(filterType: number, value?: any): IAdminEntityFilter {
		return this.filterItems
			? this.filterItems.find((filter) => {
					if (filter.type === filterType) {
						if (filter.type === EntityFilter.Custom) {
							return filter.value === value;
						}
						return true;
					}
					return false;
			  })
			: null;
	}

	private setDefaultSearch() {
		this.isSearchActive = false;
		this.paging = null;
		this.query = "";
		this.activeQuery = "";
	}
}
