import {
	Component,
	EventEmitter,
	Input,
	OnChanges,
	OnInit,
	Output,
	SimpleChanges,
} from "@angular/core";
import { ArrayUtil, ITranslationItem } from "lime";
import {
	Constants,
	EntityCategory,
	EntityOperation,
	IDynamicEntity,
	IDynamicEntityLocalization,
	IDynamicEntityLocalizationMap,
	ILocalizationParameter,
	IStringMap,
	IStringMapMap,
	ITranslationData,
} from "lime/core";
import { DynamicPageAdminService } from "../service";

@Component({
	selector: "lm-dynamic-page-translations",
	template: `
		<p *ngIf="isAddDisabled">There is nothing to translate.</p>
		<lm-translations-component
			*ngIf="!isAddDisabled"
			[parameter]="translationEntity"
			[category]="entityCategory"
			(localizationChange)="
				onLocalizationChange($event)
			"></lm-translations-component>
	`,
})
export class DynamicPageTranslationsComponent implements OnInit, OnChanges {
	@Input("localizations") lznEntityMap: IDynamicEntityLocalizationMap;
	@Input() entityId: string;
	@Input() optionsItems: ITranslationItem[];
	@Input() isAddDisabled = false;
	// Emits created, updated and/or deleted translations.
	@Output() localizationChange =
		new EventEmitter<IDynamicEntityLocalizationMap>();
	entityCategory = EntityCategory.dynamicPage;
	translationEntity: ILocalizationParameter;
	private pageLangs: string[];

	constructor(private pageService: DynamicPageAdminService) {}

	ngOnInit() {
		const page = this.pageService.getPage();
		this.pageLangs = page ? page.lngs : null;
		if (!this.optionsItems) {
			this.optionsItems = [
				{
					label: "placeholder",
					name: "placeholder",
					maxLength: Constants.dynPageDefaultMaxLength,
				},
			];
		}
		const items = this.optionsItems;
		const lznMap = this.lznEntityMap
			? this.convertToLocalizationStringMap(this.lznEntityMap)
			: {};
		this.addExistingLanguagesOnPage(lznMap);

		this.translationEntity = {
			translationOptions: {
				items: items,
			},
			localizationMap: lznMap,
			enablePortation: false,
		};
	}

	ngOnChanges(changes: SimpleChanges) {
		if (changes.entity && !changes.entity.firstChange) {
			const entityCurrent: IDynamicEntity = changes.entity.currentValue;
			const items = this.translationEntity.translationOptions.items;

			// Set default values for translation options.
			for (const key of Object.keys(entityCurrent)) {
				const item = ArrayUtil.itemByProperty(items, "name", key);
				if (item) {
					item.defaultValue = entityCurrent[key];
				}
			}
		}
		if (changes.optionsItems && !changes.optionsItems.firstChange) {
			this.translationEntity.translationOptions.items = <ITranslationItem[]>(
				changes.optionsItems.currentValue
			);
			this.translationEntity = { ...this.translationEntity };
		}
	}

	onLocalizationChange(translationData: ITranslationData[]) {
		const convertedData = this.convertToEntityLocalizationMap(translationData);
		this.localizationChange.emit(convertedData);
	}

	/**
	 * Converts localizations to a format that fits the translations component.
	 * Does not return localizations with operation Delete.
	 * @param dynLocalization
	 */
	private convertToLocalizationStringMap(
		dynLocalization: IDynamicEntityLocalizationMap,
	): IStringMapMap {
		const convertedLocalization: IStringMapMap = {};
		for (const lang of Object.keys(dynLocalization)) {
			const languageLocalizations: IDynamicEntityLocalization =
				dynLocalization[lang];
			if (languageLocalizations.op !== EntityOperation.Delete) {
				const items = this.optionsItems
					.filter((item) => item.name && item.name.length)
					.reduce((acc, item) => {
						acc[item.name] = languageLocalizations[item.name] || "";
						return acc;
					}, {});
				convertedLocalization[lang] = items;
			}
		}
		return convertedLocalization;
	}

	/**
	 * Converts localization to the format that fits the server request.
	 * Does not include translations that have not been changed.
	 * @param translationData
	 */
	private convertToEntityLocalizationMap(
		editedTranslations: ITranslationData[],
	): IDynamicEntityLocalizationMap {
		const settingLocalizations = {};

		// Convert localization and mark as Update.
		for (const editedTranslation of editedTranslations) {
			this.addLocalizationForLanguage(editedTranslation, settingLocalizations);
		}

		// Set operation to Delete if applicable.
		if (this.lznEntityMap) {
			for (const lang of Object.keys(this.lznEntityMap)) {
				// If the translation does not exist, the user has deleted it.
				const isAlreadyDeleted =
					this.lznEntityMap[lang] &&
					this.lznEntityMap[lang].op === EntityOperation.Delete;
				if (
					!ArrayUtil.itemByProperty(editedTranslations, "language", lang) &&
					!isAlreadyDeleted
				) {
					settingLocalizations[lang] = {
						op: EntityOperation.Delete,
					};
				}
			}
		}
		return settingLocalizations;
	}

	private addLocalizationForLanguage(
		editedTranslation: ITranslationData,
		settingLocalizations: IDynamicEntityLocalizationMap,
	) {
		const language = editedTranslation.language;
		const localization = editedTranslation.localization;

		// Skip placeholder if it got no value
		if (this.isExistingLanguage(language) && this.isPlaceholder(localization)) {
			return;
		}

		// Draft translation reflects server data.
		const existingLzn = this.lznEntityMap ? this.lznEntityMap[language] : null;
		if (!existingLzn || this.isNewLocalization(existingLzn, localization)) {
			settingLocalizations[language] =
				this.createEntityLocalization(localization);
		}
	}

	private createEntityLocalization(
		localization: IStringMap,
	): IDynamicEntityLocalization {
		const translations = this.optionsItems
			.filter((item) => item.name && item.name.length)
			.reduce((acc, item) => {
				acc[item.name] = localization[item.name];
				return acc;
			}, {});

		return {
			...translations,
			eid: this.entityId,
			op: EntityOperation.Update,
		};
	}

	private isExistingLanguage(language: string): boolean {
		return this.pageLangs && this.pageLangs.indexOf(language) > -1;
	}

	private isPlaceholder(localization: IStringMap): boolean {
		for (const itemName of this.optionsItems.map((item) => item.name)) {
			if (localization[itemName] && localization[itemName].length) {
				return false;
			}
		}
		return true;
	}

	private isNewLocalization(
		existingLzn: IDynamicEntityLocalization,
		localization: IStringMap,
	): boolean {
		for (const itemName of this.optionsItems.map((item) => item.name)) {
			if (existingLzn[itemName] !== localization[itemName]) {
				return true;
			}
		}
		return false;
	}

	/**
	 * Adds all languages the already exists on the page, if they don't exist on the component already.
	 * @param lznMap
	 */
	private addExistingLanguagesOnPage(lznMap: IStringMapMap) {
		const langs = this.pageLangs;
		if (langs) {
			for (const lang of langs) {
				const hasLznForLang = lznMap[lang];
				if (!hasLznForLang) {
					lznMap[lang] = { placeholder: "" }; // Needs to have some value for lzn button to be pressable
				}
			}
		}
	}
}
