import { Component, Input, NgZone, OnInit, ViewChild } from "@angular/core";
import {
	SohoDataGridComponent,
	SohoMessageService,
	SohoModalDialogRef,
	SohoModalDialogService,
} from "ids-enterprise-ng";
import { ArrayUtil, DialogButtonType, HtmlUtil } from "lime";
import {
	Constants,
	CoreUtil,
	IOperationResponse,
	IPage,
	IPageCatalogRequest,
	IPageCatalogResponse,
	LanguageService,
	PageError,
	UIUtil,
} from "lime/core";
import { CustomFormatters, GridUtil } from "../admin";
import { AdminListComponent } from "../admin-list.component";
import { AdminConstants, AdminService, IPageSelectorOptions } from "../service";

@Component({
	selector: "lm-admin-page-selector",
	templateUrl: "./page-selector.html",
})
export class AdminPageSelectorComponent
	extends AdminListComponent<IPage>
	implements OnInit
{
	@ViewChild("pageSelectorDatagrid", { static: false })
	dataGrid: SohoDataGridComponent;

	@Input() dialog: SohoModalDialogRef<AdminPageSelectorComponent>;
	@Input() pageSelectorOptions: IPageSelectorOptions;

	isMultiSelect = false;
	title: string;
	defaultButtonText: string;
	showToolbar: boolean;
	callback;

	private noShow: string[];
	private excludeDynamic: boolean;
	private includePublished = true;
	private includeStandard = true;
	private canClose = true;

	constructor(
		messageService: SohoMessageService,
		languageService: LanguageService,
		adminService: AdminService,
		dialogService: SohoModalDialogService,
		zone: NgZone,
	) {
		super(
			"AdminPageSelectorComponent",
			"page",
			messageService,
			languageService,
			adminService,
			dialogService,
			zone,
		);
	}

	ngOnInit(): void {
		this.pageSize = AdminConstants.gridPageSize;
		this.dialog.beforeClose(() => this.canClose);
		this.dialog.afterOpen(() => {
			this.showToolbar = true;

			// Set focus to search field as workaround for IE11 issue with disappearing menu button
			setTimeout(() => $("#a-ps-searchfield").focus(), 1);
		});

		const options = this.pageSelectorOptions;
		if (options) {
			this.isMultiSelect = options.isMultiSelect || false;
			this.title = options.title || "";

			const initialSelected = options.selectedPages || [];
			if (initialSelected.length) {
				this.updateSelection(
					initialSelected.map(
						(selected) => ({ data: selected }) as SohoDataGridSelectedRow,
					),
				);
			}
			this.noShow = options.noShowIds || [];
			this.includePublished = options.includePublished !== false;
			this.includeStandard = options.includeStandard !== false;
			this.excludeDynamic = options.excludeDynamic;
			this.defaultButtonText = options.defaultButtonText || "Add";
		}

		this.initGrid();

		UIUtil.refreshSvgIcons($("#admin-page-selector-sort"));

		this.refresh();
	}

	getDataGrid(): SohoDataGridComponent {
		return this.dataGrid;
	}

	listItems(reload: boolean): void {
		if (this.isBusy) {
			return;
		}
		this.setBusy(true);

		if (reload) {
			this.hasMore = true;
			this.paging = null;
			this.items = [];
			this.clearSelection();
		}

		const orderBy = this.orderBy;
		const request: IPageCatalogRequest = {
			paging: this.paging,
			pageSize: this.pageSize,
			sortOrder: orderBy.order,
			sortBy: orderBy.entity,
			query: this.query,
			includePublished: this.includePublished,
			includeStandard: this.includeStandard,
		};
		if (this.excludeDynamic) {
			request.excludeDynamic = true;
		}

		if (CoreUtil.isGuid(request.query)) {
			request.entityId = request.query;
			request.query = null;
			// If is a query for a GUID there should be no hits in standard pages
			request.includeStandard = false;
		}

		const self = this;
		this.adminService.listPages(request).subscribe(
			(response: IPageCatalogResponse) => {
				const newItems = response.content;
				newItems.forEach((item) => {
					(item.data as any).escapedTitle = HtmlUtil.escapeStringForHtml(
						item.data.title,
					);
				});

				self.addItems(newItems, response.paging);

				const selected = this.getSelectedItems();
				if (selected.length) {
					this.selectPageRows(selected);
				}

				self.setBusy(false);
			},
			(r: IOperationResponse) => {
				self.setBusy(false);
				self.onError(r);
			},
		);
	}

	close() {
		this.dialog.close({ button: DialogButtonType.Cancel });
	}

	add() {
		const items = this.selection.map((item) => item.data);
		const self = this;
		if (this.callback) {
			this.setBusy(true);
			this.canClose = false;
			this.callback(items).subscribe(
				() => {
					this.canClose = true;
					self.dialog.close({ button: DialogButtonType.Ok });
				},
				() => {
					this.setBusy(false);
					this.canClose = true;
				},
			);
		} else {
			self.dialog.close({ button: DialogButtonType.Ok, value: items });
		}
	}

	onExpandRow(event: { detail: any; item: IPage }): void {
		const item = event.item;
		const data = item.data;
		const container = $(event.detail)
			.find(".datagrid-row-detail-padding")
			.empty();

		let template = `<div class="datagrid-cell-layout"><span class="datagrid-textarea lm-white-space-normal">${this.escape(
			data.description,
		)}</span>`;

		if (item.err && item.err.pageError === PageError.DynamicPagesFeatureOff) {
			template += this.getErrorMessageTemplate(
				GridUtil.formatAlert(Constants.dynPageFeatureOffMsg, true),
			);
		}

		template += `</div>`;
		$(container).append($(template));
	}

	protected getColumns(): SohoDataGridColumn[] {
		const isVisible = (
			row: number,
			cell: HTMLElement,
			rowData: Object,
			columnDef: SohoDataGridColumn,
			item: any,
		) => {
			return !ArrayUtil.contains(this.noShow, item.data.id);
		};

		return [
			this.getSelectionColumn(),
			{
				width: 350,
				id: "adm-ps-col-t",
				field: "data.escapedTitle",
				name: "Title",
				resizable: true,
				filterType: "text",
				sortable: false,
				formatter: CustomFormatters.dynamicDisabledExpander,
			},
			{
				width: 250,
				id: "adm-ps-col-cd",
				field: "data.changeDate",
				name: "Change date",
				resizable: true,
				sortable: false,
				formatter: CustomFormatters.date,
			},
			{
				width: 250,
				id: "adm-ps-col-cbn",
				field: "data.changedByName",
				name: "Changed by",
				resizable: true,
				sortable: false,
				formatter: CustomFormatters.displayName,
			},
		];
	}

	private selectPageRows(selected): void {
		const pageDataArray = this.items.map((item) => item.data);

		let index: number;

		for (const page of selected) {
			index = ArrayUtil.indexByProperty(pageDataArray, "id", page.data.id);
			if (index !== -1) {
				this.dataGrid.selectRow(index);
			}
		}
	}

	private initGrid(): void {
		const options = this.defaultOptions();
		options.selectable = this.isMultiSelect ? "multiple" : "single";
		options.rowHeight = "medium";
		this.datagridOptions = options;
	}
}
