import {
	AfterViewInit,
	Component,
	NgZone,
	OnDestroy,
	OnInit,
	ViewChild,
	ViewContainerRef,
} from "@angular/core";
import {
	SohoDataGridComponent,
	SohoMessageService,
	SohoModalDialogService,
	SohoToastService,
} from "ids-enterprise-ng";
import { DialogButtonType, IDialogResult } from "lime";
import {
	AccessUtil,
	AdminPages,
	Constants,
	ContainerService,
	CoreUtil,
	DialogResponseCode,
	EntityCategory,
	EntityOperation,
	IImportOptions,
	IIntegerResponse,
	IOperationResponse,
	IPage,
	IPageAccess,
	IPageAccessResponse,
	IPageCatalogRequest,
	IPageCatalogResponse,
	IPageData,
	IPagePreviewOptions,
	LanguageService,
	PageError,
	PageService,
	ProgressService,
} from "lime/core";
import { AsyncSubject, Subscription } from "rxjs";
import { take } from "rxjs/operators";
import { CustomFormatters, GridUtil } from "../admin";
import { AdminListComponent } from "../admin-list.component";
import {
	AdminContext,
	AdminService,
	AdminUtil,
	IChangeOwnerDialogOptions,
	IPageSelectorOptions,
	PageType,
} from "../service";

@Component({
	selector: "lm-admin-published-pages",
	templateUrl: "./published-pages.html",
})
export class AdminPublishedPagesComponent
	extends AdminListComponent<IPage>
	implements AfterViewInit, OnInit, OnDestroy
{
	@ViewChild("publishedPagesDatagrid", { static: false })
	dataGrid: SohoDataGridComponent;

	accessCopy: IPageAccess;

	private unsubscriber: Subscription;
	private accessCopyPageId: string;

	constructor(
		messageService: SohoMessageService,
		languageService: LanguageService,
		adminService: AdminService,
		sohoModalDialogService: SohoModalDialogService,
		zone: NgZone,
		private adminContext: AdminContext,
		private toastService: SohoToastService,
		private pageService: PageService,
		private readonly progressService: ProgressService,
		private readonly containerService: ContainerService,
		readonly viewRef: ViewContainerRef,
	) {
		super(
			"AdminPublishedPagesComponent",
			"page",
			messageService,
			languageService,
			adminService,
			sohoModalDialogService,
			zone,
			{ sortUsedBy: true, isFilter: true },
		);
		this.datagridOptions = this.defaultOptions();
	}

	ngOnInit() {
		if (this.initializing) {
			this.adminContext.tool$.pipe(take(1)).subscribe((tool) => {
				this.currentUser = tool.userId;
				this.maxCount = tool.maxCountPublishedPage || 0;
				this.isReadOnly = AdminUtil.isReadOnlyUser(tool);
			});
		}

		this.refresh();
	}

	ngAfterViewInit() {
		// Subscribe to the selected event as workaround to prevent selection of dynamic pages in the list
		const grid = this.getDataGrid();
		if (grid) {
			this.unsubscriber = grid.selected.subscribe((e) => {
				this.deSelectDynamic(e.rows);
			});
		}
	}

	ngOnDestroy(): void {
		if (this.unsubscriber) {
			this.unsubscriber.unsubscribe();
		}
	}

	getDataGrid(): SohoDataGridComponent {
		return this.dataGrid;
	}

	listItems(reload?: boolean): void {
		const request = this.createRequest(reload) as IPageCatalogRequest;
		if (!request) {
			return;
		}

		const query = request.query;
		if (CoreUtil.isGuid(query)) {
			request.entityId = query;
			request.query = null;
			request.includeStandard = false;
		}

		const self = this;
		const adminService = self.adminService;
		const observable = adminService.listPublishedPages(request);
		this.withBusy(observable).subscribe(
			(response: IPageCatalogResponse) => {
				const newItems = response.content;
				self.addItems(newItems, response.paging);
				self.updateCount(response.count, this.maxCount);
			},
			(r: IOperationResponse) => {
				adminService.handleError(r);
			},
		);
	}

	/**
	 * Opens a dialog for importing published pages.
	 */
	onImport(): void {
		const dialogTitle = "Import Published Pages";
		const adminService = this.adminService;
		const options: IImportOptions = {
			title: dialogTitle,
			operation: EntityCategory.publishedPage.toString(),
			showStrategySelector: true,
		};

		const self = this;
		adminService
			.openImportFilesDialog(options, this.viewRef)
			.subscribe((r: IDialogResult) => {
				const value = r.value;
				if (
					r.button === DialogButtonType.Yes &&
					value.responseCode === DialogResponseCode.Success
				) {
					this.adminService
						.showUploadCompleteDialog(dialogTitle, value.message)
						.subscribe((result: IDialogResult) => {
							if (result.button === DialogButtonType.Ok) {
								self.refresh();
							}
						});
				} else if (
					r.button === DialogButtonType.Yes &&
					value.responseCode === DialogResponseCode.Fail
				) {
					adminService.showUploadCompleteDialog(
						dialogTitle,
						value.message,
						true,
					);
				}
			});
	}

	/**
	 * Exports the selected published pages.
	 */
	onExport(): void {
		const pagesToExport = this.getSelectedItems();
		this.adminService.exportPublishedPages(pagesToExport);
		this.clearSelection();
	}

	/**
	 * Exports all published pages.
	 */
	exportAll(): void {
		const title = "Confirm export all";
		const message = "Are you sure that you want to export all published pages?";
		this.showConfirm(title, message).subscribe(() => {
			this.adminService.exportPublishedPages();
		});
	}

	/**
	 * Deletes the selected pages.
	 */
	onDelete(): void {
		const pages = this.getSelectedItems();
		const options = this.adminService.getDeletePageOptions(pages, false);
		this.showConfirm(options.title, options.message).subscribe(() => {
			this.deletePublishedPage(pages);
		});
	}

	/**
	 * Changes the owner of the selected page to the current user.
	 */
	takeOwnership(): void {
		const page = this.getSelectedItem();
		const self = this;
		this.setBusy(true);
		this.adminService.updatePageOwner({ id: page.data.id }).subscribe(
			() => {
				this.setBusy(false);
				this.refresh();
			},
			(e) => {
				self.onError(e);
			},
		);
	}

	changeOwnership(): void {
		const page = this.getSelectedItem();
		const dialogOptions: IChangeOwnerDialogOptions = {
			title: page.data.title,
			currentOwnerId: page.data.ownerId,
			itemId: page.data.id,
			callback: () => this.refresh(),
			isWidget: false,
		};
		this.adminService.openChangeOwnerDialog(dialogOptions, this.viewRef);
	}

	/**
	 * Edit page access for the first selected published page.
	 */
	editAccess(): void {
		const page = this.getSelectedItem();
		if (page) {
			const options = AccessUtil.publishedPages(this.languageService, page);
			options.callback = () => this.refresh();
			this.adminService.openPageAccessDialog(options, this.viewRef);
		}
	}

	/**
	 * Copy page access.
	 */
	copyAccess(): void {
		const page = this.getSelectedItem();
		const self = this;
		const adminService = self.adminService;

		this.setBusy(true);
		adminService.getPageAccess(page.data.id).subscribe(
			(r: IPageAccessResponse) => {
				self.accessCopy = self.setDefaultCreateOperation(r.content);
				self.accessCopyPageId = page.data.id;
				self.setBusy(false);
			},
			(r: IPageAccessResponse) => {
				adminService.handleError(r);
				self.setBusy(false);
			},
		);
	}

	/**
	 * Apply copied acces rights to selected widget(s).
	 */
	applyAccessCopy(): void {
		const pages = this.getSelectedItems();
		this.adminService.applyPageAccess(pages, this.accessCopy, () => {
			this.refresh();
		});
	}

	clearPageAccess(): void {
		const targetPageIds = this.getSelectedIds();
		if (targetPageIds.length === 0) {
			return;
		}
		// TODO weird use of Observable - possible memory leak if error is triggered?
		this.adminService.clearPageAccessPages(targetPageIds).subscribe(
			null,
			(error) => {
				this.logError("Clear page access error", error);
				this.refresh();
			},
			() => {
				this.logInfo("Clear page access complete");
				this.refresh();
			},
		);
	}

	replacePageAccess(): void {
		try {
			const source = this.accessCopy;
			const targetPageIds = this.getSelectedIds();
			this.validatePageCopyAccessSelection(source, targetPageIds);

			this.adminService
				.replacePageAccess(source, targetPageIds, targetPageIds.length)
				.subscribe(
					() => {},
					() => {},
					() => {
						this.refresh();
					},
				);
		} catch (ex) {
			this.logError("Failed to replace page access", ex);
		}
	}

	publishExisting(): void {
		const page = this.getSelectedItem();
		const options = {
			title: "Select published page",
			isMultiSelect: false,
			pageType: PageType.Published,
			noShowIds: [page.data.id],
			includeStandard: false,
			excludeDynamic: true,
			defaultButtonText: "Save",
		} as IPageSelectorOptions;

		const callback = (selectedPages) => {
			const subject = new AsyncSubject<any>();
			const targetId = selectedPages[0].data.id;
			const sourceId = page.data.id;
			if (sourceId === targetId) {
				this.adminService.showError(
					"Unable to publish to existing page",
					"Same source as target",
				);
				subject.error(null);
			} else {
				const self = this;

				this.adminService.publishToExisting(sourceId, targetId).subscribe(
					(response: IOperationResponse) => {
						if (response.hasError()) {
							const message = `Unable to publish page with id:${sourceId} to existing page with id:${targetId}`;
							self.adminService.handleError(response, message);
							subject.error(null);
						} else {
							self.clearSelection();
							self.toastService.show({
								title: "Published to Existing",
								message: "Published page was succesfully updated.",
								position: SohoToastService.BOTTOM_RIGHT,
							});
							subject.next(null);
							subject.complete();
						}
					},
					() => {
						self.adminService.showError(
							"Unable to publish to existing page",
							"The requested operation failed.",
						);
						subject.error(null);
					},
				);
			}

			return subject.asObservable();
		};

		this.adminService
			.openPageSelectorDialog(
				options,
				"Publish to existing Page",
				this.viewRef,
				callback,
			)
			.subscribe((result) => {
				if (result && result.button === DialogButtonType.Ok) {
					this.refresh();
				}
			});
	}

	preview(): void {
		const page = this.getSelectedItem();
		const service = this.containerService;
		const options = {
			pageId: page.data.id,
			isDuplicatable: true,
			isAddable: true,
			notifyMingle: true,
			onClose: () => {
				service.showAdmin();
			},
		} as IPagePreviewOptions;

		this.progressService.onNextNotBusy(() =>
			service.hideAdmin(AdminPages.PublishedPages),
		);
		this.pageService.previewPage(options);
	}

	onExpandRow(event: { detail: any; item: IPage }): void {
		const item = event.item;
		const data = item.data;
		const container = $(event.detail)
			.find(".datagrid-row-detail-padding")
			.empty();
		let template = `<div class="datagrid-cell-layout">
				<span class="datagrid-textarea lm-white-space-normal">${this.escape(
					data.description,
				)}</span>`;

		if (data.tags) {
			template += `<div class="lm-margin-lg-t"><span>`;
			const tagsArray = data.tags.split("#");
			tagsArray.shift();

			for (const tag of tagsArray) {
				template += `<a class="tag lm-margin-sm-r">${tag}</a>`;
			}

			template += `</span></div>`;
		}

		if (item.err && item.err.pageError === PageError.DynamicPagesFeatureOff) {
			template += this.getErrorMessageTemplate(
				GridUtil.formatAlert(Constants.dynPageFeatureOffMsg, true),
			);
		}

		template += `</div>`;
		$(container).append($(template));
	}

	openInCatalog() {
		this.pageService.showPageCatalog(this.getSelectedItem());
		this.containerService.hideAdmin(this.adminService.getLastVisitedTab());
	}

	protected getColumns(): SohoDataGridColumn[] {
		const selectionFormatter = (row, cell, value, col, item, api): string => {
			const data = item.data;
			if (data && data.isDynamic) {
				return "";
			}
			return Formatters.SelectionCheckbox(row, cell, value, col, item, api);
		};

		return [
			{
				...this.getSelectionColumn(),
				formatter: selectionFormatter,
			},
			{
				width: 445,
				id: "adm-pp-col-t",
				field: "data.title",
				name: "Title",
				resizable: true,
				filterType: "text",
				sortable: false,
				formatter: CustomFormatters.dynamicDisabledExpander,
			},
			{
				width: 175,
				id: "adm-pp-col-on",
				field: "data.ownerName",
				name: "Owner",
				resizable: true,
				filterType: "contentes",
				sortable: false,
				formatter: CustomFormatters.displayName,
			},
			{
				width: 200,
				id: "adm-pp-col-cd",
				field: "data.changeDate",
				name: "Change date",
				resizable: true,
				sortable: false,
				formatter: CustomFormatters.date,
			},
			{
				width: 175,
				id: "adm-pp-col-cbn",
				field: "data.changedByName",
				name: "Changed by",
				resizable: true,
				sortable: false,
				formatter: CustomFormatters.displayName,
			},
			{
				width: 90,
				id: "adm-pp-col-p",
				field: "popularity",
				name: "Used by",
				sortable: false,
			},
			{
				width: 110,
				id: "adm-pp-col-as",
				field: "accessState",
				name: "Permissions",
				sortable: false,
				formatter: CustomFormatters.accessState,
			},
		];
	}

	protected getEmptyMessage(): string {
		return "No published pages found";
	}

	private deSelectDynamic(rows: SohoDataGridSelectedRow[]): void {
		// Clear the selection of any dynamic page that are not allowed to be selected
		if (rows) {
			const grid = this.getDataGrid();
			for (const row of rows) {
				const pageData = row.data.data;
				if (pageData.isDynamic) {
					grid.unselectRow(row.idx);
				}
			}
		}
	}

	private updateOwner(existing: IPageData, updated: IPageData): void {
		existing.ownerId = updated.ownerId;
		existing.ownerName = updated.ownerName;
		existing.changedByName = updated.changedByName;
		existing.changeDate = updated.changeDate;

		this.clearSelection();
	}

	private setDefaultCreateOperation(pageAccess: IPageAccess): IPageAccess {
		const entities = pageAccess.access;
		if (entities) {
			pageAccess.access = [];
			for (const accessEntity of entities) {
				accessEntity.operation = EntityOperation.Create;
				pageAccess.access.push(accessEntity);
			}
		}
		return pageAccess;
	}

	private validatePageCopyAccessSelection(
		source: IPageAccess,
		selectedIds: string[],
	) {
		if (!source) {
			throw new Error("No data to copy");
		}
		if (!selectedIds || selectedIds.length === 0) {
			throw new Error("No selected pages");
		}
	}

	private getSelectedIds(): string[] {
		const selectedPages = this.getSelectedItems();
		if (!selectedPages) {
			return [];
		}
		const targetPageIds = [] as string[];
		for (const page of selectedPages) {
			targetPageIds.push(page.data.id);
		}

		return targetPageIds;
	}

	private deletePublishedPage(pages: IPage[]): void {
		const adminService = this.adminService;
		this.setBusy(true);
		const self = this;
		const pageList = pages.map((page) => {
			return page.data.id;
		});

		this.pageService.deletePublished(pageList).subscribe(
			(r: IIntegerResponse) => {
				self.setBusy(false);
				if (r.content > 0) {
					self.refresh();
				}
			},
			(r: IOperationResponse) => {
				self.setBusy(false);
				adminService.handleError(r, r.getErrorMessages());
			},
		);
	}
}
