import { Component, Input, OnInit } from "@angular/core";
import {
	ContextService,
	CoreBase,
	DynamicImageAlignment,
	MemoLayout,
	MemoPriority,
} from "lime/core";
import { DateUtil } from "../core";
import { AdminUtil, ITimeZone } from "../service";
import { Memo, MemoConstants } from "./core";

@Component({
	selector: "lm-admin-memo-basic",
	templateUrl: "./basic.html",
	styleUrls: ["./basic.scss"],
})
export class MemoBasicComponent extends CoreBase implements OnInit {
	@Input()
	memo: Memo;

	alignment = DynamicImageAlignment;
	layoutOption = MemoLayout;
	prio = MemoPriority;

	readonly titleMaxLength = MemoConstants.MaxLengthTitle;
	readonly textMaxLength = MemoConstants.MaxLengthText;
	readonly UrlMaxLength = 2048;
	readonly actionTextMaxLength = MemoConstants.MaxLengthActionText;
	textColorIndex: number;
	showActionButton: boolean;
	timeZones: ITimeZone[];

	constructor(private readonly contextService: ContextService) {
		super("MemoBasicComponent");
		this.timeZones = AdminUtil.getTimeZones();
	}

	ngOnInit(): void {
		// if edit
		if (!this.memo.title) {
			this.memo.priority = 0;
			this.memo.imageAlignment = DynamicImageAlignment.Cover;
			this.memo.layout = MemoLayout.BackgroundImage;
			this.memo.textColor = "default";
			this.textColorIndex = 0;
		}
		this.showActionButton = this.memo.actionText ? true : false;

		if (!this.start) {
			this.start = DateUtil.dateToString(DateUtil.today());
		}
		if (!this.end) {
			this.end = DateUtil.dateToString(DateUtil.weekFromNow());
		}
		if (!this.memo.timeZone) {
			this.memo.timeZone =
				this.contextService.getContext().getInforStdTimeZone() || "UTC";
		}
	}

	get imageUrl() {
		return this.memo.imageUrl;
	}

	set imageUrl(url: string) {
		this.memo.imageUrl = url;
		if (!url) {
			this.memo.textColor = "default";
		}
	}

	get layout() {
		return this.memo.layout;
	}

	set layout(layout: MemoLayout) {
		if (!isNaN(layout)) {
			//to avoid the "0:0 update which defaults the text color"
			this.memo.layout = layout;
			if (
				layout !== MemoLayout.BackgroundImage &&
				layout !== MemoLayout.ImageOnly
			) {
				this.memo.textColor = "default";
			}
		}
	}

	get textColorDisabledAttr(): string {
		return this.memo.imageUrl &&
			(this.memo.layout === MemoLayout.BackgroundImage ||
				this.memo.layout === MemoLayout.ImageOnly)
			? null
			: "";
	}

	isImageOnly(): boolean {
		return this.memo.layout === MemoLayout.ImageOnly;
	}

	get start(): string {
		return this.dateMemoToIds(this.memo.startDate);
	}

	set start(value: string) {
		this.memo.startDate = value ? this.dateIdsToMemo(value) : null;
	}

	get end(): string {
		return this.dateMemoToIds(this.memo.endDate);
	}

	set end(value: string) {
		this.memo.endDate = value ? this.dateIdsToMemo(value) : null;
	}

	get timeZone(): string {
		return this.memo.timeZone;
	}

	set timeZone(timeZone: string) {
		this.memo.timeZone = timeZone;
	}

	/**
	 * Transforms a Memo date e.g "YYYY-MM-ddThh:mm:ss.uuuZ" to a IDS locale date e.g "MM/dd/YYYY hh:mm AM"
	 * TODO: Move method to special MemoDate class?
	 */
	private dateMemoToIds(memoDateValue: string): string {
		return DateUtil.parseToString(memoDateValue);
	}

	/**
	 * Reverse of [MemoDateComponent.dateMemoToIds]
	 */
	private dateIdsToMemo(idsValue: string): string {
		const date = DateUtil.parseLocaleDate(idsValue);
		if (date) {
			return AdminUtil.toIsoDateTimeLocal(date);
		}
	}
}
