import {
	Component,
	NgZone,
	OnInit,
	ViewChild,
	ViewContainerRef,
} from "@angular/core";
import {
	SohoDataGridComponent,
	SohoMessageService,
	SohoModalDialogService,
} from "ids-enterprise-ng";
import { DialogButtonType, IDialogResult } from "lime";
import {
	DialogResponseCode,
	EntityCategory,
	IImportOptions,
	IOperationResponse,
	LanguageService,
} from "lime/core";
import { Observable, from } from "rxjs";
import { concatAll, last } from "rxjs/operators";
import { CustomFormatters } from "../admin";
import { AdminListComponent } from "../admin-list.component";
import {
	AdminService,
	IPropertyInfo,
	IPropertyInfoListResponse,
} from "../service";
import { AddEditPropertyComponent } from "./add-edit-property";

@Component({
	selector: "lm-admin-properties",
	templateUrl: "./properties.html",
})
export class AdminPropertiesComponent
	extends AdminListComponent<IPropertyInfo>
	implements OnInit
{
	@ViewChild("propertiesViewRef", { read: ViewContainerRef, static: false })
	propertiesView: ViewContainerRef;
	@ViewChild(SohoDataGridComponent, { static: false })
	propertiesGrid: SohoDataGridComponent;

	datagridOptions: SohoDataGridOptions;
	items: IPropertyInfo[] = [];
	selection: any[];
	selected: any;
	selectionCount = 0;

	constructor(
		messageService: SohoMessageService,
		languageService: LanguageService,
		adminService: AdminService,
		sohoModalDialogService: SohoModalDialogService,
		zone: NgZone,
	) {
		super(
			"AdminPropertiesComponent",
			"property",
			messageService,
			languageService,
			adminService,
			sohoModalDialogService,
			zone,
		);

		this.initGrid();
	}

	ngOnInit(): void {
		this.refresh();
	}

	/**
	 * Get properties from server and update grid.
	 *
	 * @param reload boolean Reload properties or use cached.
	 */
	listItems(reload: boolean): void {
		const adminService = this.adminService;
		this.setBusy(true);

		adminService.listProperties(reload).subscribe(
			(r: IPropertyInfoListResponse) => {
				this.propertiesGrid.clearFilter();
				this.items = r.content;
				this.updateGridData();
				this.setBusy(false);
			},
			(r: IOperationResponse) => {
				this.setBusy(false);
				adminService.handleError(r);
			},
		);
	}

	updateGridSelection(args: any[]): void {
		const newCount = args.length;
		if (newCount !== this.selectionCount) {
			this.selectionCount = args.length;
			this.selection = args;
			this.selected = args && args.length === 1 ? args[0].data : null;
		}
	}

	exportProperties(): void {
		if (this.selectionCount === this.items.length) {
			this.exportAll();
		} else {
			const propertiesToExport = this.getSelectedItems();
			this.adminService.exportProperties(propertiesToExport);
		}
	}

	exportAll(): void {
		this.adminService.exportProperties();
	}

	/**
	 * Import Properties
	 *
	 * Opens a dialog that lets the user select a file for upload.
	 * After a sucessful upload the properties are loaded from the server.
	 */
	importProperties(): void {
		const dialogTitle = "Import Properties";
		const options: IImportOptions = {
			operation: EntityCategory.adHocProperties.toString(),
			title: dialogTitle,
			acceptFileExtension: ".json",
		};

		this.adminService
			.openImportFilesDialog(options, this.propertiesView)
			.subscribe((r: IDialogResult) => {
				const value = r.value;
				if (
					r.button === DialogButtonType.Yes &&
					value.responseCode === DialogResponseCode.Success
				) {
					this.adminService
						.showUploadCompleteDialog(dialogTitle, value.message)
						.subscribe((result: IDialogResult) => {
							if (result.button === DialogButtonType.Ok) {
								this.refresh();
							}
						});
				} else if (
					r.button === DialogButtonType.Yes &&
					value.responseCode === DialogResponseCode.Fail
				) {
					this.adminService.showUploadCompleteDialog(
						dialogTitle,
						value.message,
						true,
					);
				}
			});
	}

	showConfirmDelete(): void {
		const title = "Remove Properties";
		const message =
			"Are you sure that you want to remove the selected properties?";
		this.showConfirm(title, message).subscribe(() => {
			this.deleteProperties();
		});
	}

	deleteProperties(): void {
		if (this.isBusy) {
			return;
		}
		this.setBusy(true);

		const properties = this.getSelectedItems();
		const observables: Observable<IOperationResponse>[] = [];
		for (const property of properties) {
			observables.push(this.adminService.deleteProperty(property.propertyId));
		}

		from(observables)
			.pipe(concatAll(), last())
			.subscribe(
				() => {
					this.clearSelection();
					this.setBusy(false);
					this.refresh();
				},
				(response: IOperationResponse) => {
					this.onDeleteError(response, properties.length > 1);
				},
			);
	}

	addProperty(): void {
		this.openAddEditPropertyConnection(false);
	}

	openAddEditPropertyConnection(isEdit: boolean): void {
		const dialog = this.sohoDialogService
			.modal(AddEditPropertyComponent, this.propertiesView)
			.title(isEdit ? "Edit Property" : "Add Property")
			.id("lm-a-prop-edit-dialog")
			.afterClose((r: IDialogResult) => {
				if (r && r.value) {
					this.refresh();
				}
			});
		dialog
			.apply((component) => {
				(component.modalDialog = dialog),
					(component.parameter = isEdit
						? { isEdit: true, property: this.getSelectedItems()[0] }
						: {
								isEdit: false,
								property: { propertyId: "", propertyValue: "" },
						  });
				component.items = this.items;
			})
			.open();
	}

	protected getDataGrid(): SohoDataGridComponent {
		return this.propertiesGrid;
	}

	protected getEmptyMessage(): string {
		return "No properties found";
	}

	protected getColumns(): SohoDataGridColumn[] {
		return [
			this.getSelectionColumn(),
			{
				width: 235,
				id: "adm-p-col-pid",
				field: "propertyId",
				name: "Name",
				resizable: true,
				sortable: true,
				filterType: "text",
				formatter: CustomFormatters.text,
			},
			{
				width: 200,
				id: "adm-p-col-desc",
				field: "description",
				name: "Description",
				resizable: true,
				sortable: true,
				filterType: "text",
				formatter: CustomFormatters.text,
			},
			{
				width: 200,
				id: "adm-p-col-pv",
				field: "propertyValue",
				name: "Value",
				resizable: true,
				sortable: true,
				filterType: "text",
				formatter: CustomFormatters.text,
			},
			{
				width: 200,
				id: "adm-p-col-cd",
				field: "changeDate",
				name: "Change date",
				resizable: true,
				sortable: true,
				filterType: "text",
				formatter: CustomFormatters.date,
			},
			{
				width: 180,
				id: "adm-p-col-cbn",
				field: "changedByName",
				name: "Changed by",
				resizable: true,
				sortable: true,
				filterType: "text",
				formatter: CustomFormatters.displayName,
			},
			{
				width: 180,
				id: "adm-p-col-area",
				field: "area",
				name: "Area",
				resizable: true,
				sortable: true,
				filterType: "text",
				formatter: CustomFormatters.text,
			},
		];
	}

	private initGrid(): void {
		const options = this.defaultOptions();
		options.filterable = true;
		this.datagridOptions = options;
	}

	private onDeleteError(
		response: IOperationResponse,
		isMultiple: boolean,
	): void {
		const message =
			"Unable to delete " +
			(isMultiple
				? "all of the selected properties."
				: "the selected property.");
		this.adminService.handleError(response, message);
		this.setBusy(false);
		if (isMultiple) {
			this.clearSelection();
			this.refresh();
		}
	}
}
