import { Component, Input, OnInit, ViewContainerRef } from "@angular/core";
import { ArrayUtil } from "lime";
import {
	CoreUtil,
	DynamicImageAlignment,
	ICatalogAddItem,
	ICatalogOptions,
	ICatalogStartService,
	IDynamicContainer,
	IDynamicWidget,
	IWidgetHandle,
	IWidgetInfo,
	LazyTypeService,
	ModalDialogBase,
} from "lime/core";
import { of } from "rxjs";
import { catchError, finalize } from "rxjs/operators";
import { IExpInfo } from "../../../../service";
import { DynamicPageAdminService } from "../../service";
import { DynamicUtil } from "../../util";
import { DynamicContainerListBase } from "./dynamic-container/dynamic-container-list";

@Component({
	selector: "lm-dynamic-widget-list",
	templateUrl: "./dynamic-container/dynamic-container-list.html",
	styleUrls: ["./dynamic-container/dynamic-container-list.scss"],
})
export class DynamicWidgetListComponent
	extends DynamicContainerListBase
	implements OnInit
{
	ngOnInit() {
		const buttonText = "Add Widget";
		const buttonInfoText =
			"This component is empty. Start adding content by clicking " +
			buttonText +
			".";
		this.initItems(buttonText, buttonInfoText, "Widget", "");
		this.update();
	}

	addItem() {
		if (!this.canAdd() || this.isDialogOpen) {
			return;
		}
		this.isDialogOpen = true;

		const dialog = this.dialogService
			.modal(DynamicWidgetDialog, this.viewContainerRef)
			.title("Add Widget")
			.id("lm-a-dp-widget-add-dialog")
			.afterClose((widget) => {
				this.isDialogOpen = false;
				if (widget) {
					this.update();
				}
			});

		dialog
			.apply((component: DynamicWidgetDialog) => {
				component.modalDialog = dialog;
				component.container = this.container;
				component.isEdit = false;
				component.isBanner = this.area == "banner";
			})
			.open();
	}

	editItem(isPermissionTab: boolean, widget: IDynamicWidget): void {
		if (this.isDialogOpen) {
			return;
		}
		this.isDialogOpen = true;

		const expressions = DynamicUtil.toExpressions(widget, this.accessTitles);
		const dialog = this.dialogService
			.modal(DynamicWidgetDialog, this.viewContainerRef)
			.title(`${this.isEditable ? "Edit" : "View"} Widget`)
			.id("lm-a-dp-widget-edit-dialog")
			.afterClose((widget) => {
				this.isDialogOpen = false;
				if (widget) {
					this.update();
				}
			});

		dialog
			.apply((component: DynamicWidgetDialog) => {
				component.modalDialog = dialog;
				component.container = this.container;
				component.oldWidget = widget;
				component.widget = widget;
				component.selectedExpressions = expressions;
				component.isEdit = true;
				component.isBanner = this.area === "banner";
				component.isPermissionTabOnInit = isPermissionTab;
				component.isEditable = this.isEditable;
			})
			.open();
	}

	deleteItems(
		widgets: IDynamicWidget[],
		parentContainer?: IDynamicContainer,
	): void {
		const containerCopy = CoreUtil.copy(parentContainer || this.container);

		for (const widget of widgets) {
			const removeIndex = ArrayUtil.indexByProperty(
				containerCopy.ws,
				"eid",
				widget.eid,
			);
			if (removeIndex > -1) {
				containerCopy.ws.splice(removeIndex, 1);
			}
		}
		this.pageService
			.updateContainer(containerCopy, null, widgets)
			.pipe(
				// Ignore error since it's handled in service
				catchError(() => of()),
			)
			.subscribe(() => this.update());
	}

	getEntityCount(): number {
		return this.container.ws && this.container.ws.length;
	}

	onCopy() {
		this.copySelected(this.container.ws);
	}

	onCut() {
		this.cutSelected(this.container.ws);
	}

	onDeleteSelected() {
		this.deleteSelectedItems(this.container.ws);
	}

	private update() {
		const container = this.container;
		this.isEmpty = !(container.ws && container.ws.length > 0);
		this.clearSelectionCount();
	}
}

@Component({
	templateUrl: "./add-widget.html",
})
export class DynamicWidgetDialog extends ModalDialogBase implements OnInit {
	@Input() isBanner: boolean;

	isEdit: boolean;
	isPermissionTabOnInit: boolean;

	container: IDynamicContainer;
	alignment = DynamicImageAlignment;
	url: string;
	selectedExpressions: IExpInfo[];
	expressions: IExpInfo[];
	listLabel = "Choose which set of users this widget should be visible for.";
	widget: IDynamicWidget;
	oldWidget: IDynamicWidget;
	canSave: boolean;
	isEditable = true;
	private isDialogOpen: boolean;

	constructor(
		public dynamicPageService: DynamicPageAdminService,
		private lazyTypeService: LazyTypeService,
		private view: ViewContainerRef,
	) {
		super("DynamicWidgetDialog");
	}

	ngOnInit(): void {
		this.initModalDialog();
		this.update();
	}

	selectWidget(): void {
		if (this.isDialogOpen) {
			return;
		}
		this.isDialogOpen = true;

		this.lazyTypeService.injectLazyService("CatalogStartService").then(
			(service) => {
				const options = {
					isSelect: true,
					onlyPublished: true,
					isBanner: this.isBanner,
					bannerWidgetCount: 0,
					addCallback: (p: ICatalogAddItem) => {
						service.closeCatalog();
						this.widget = this.toWidget(p.item as IWidgetInfo);
						this.update();
					},
				} as ICatalogOptions;
				this.openCatalog(service, options);
			},
			(e) => {
				this.isDialogOpen = false;
			},
		);
	}

	openCatalog(service: ICatalogStartService, options: ICatalogOptions): void {
		service
			.openWidgetCatalog(options, this.view)
			.pipe(
				finalize(() => {
					this.isDialogOpen = false;
				}),
			)
			.subscribe();
	}

	save() {
		if (!this.isEditable) {
			return;
		}

		const container = this.container;
		const widget = CoreUtil.copy(this.widget);
		if (!widget.eid) {
			widget.eid = DynamicUtil.getNewEntityId(container);
		}

		if (this.expressions) {
			widget.as = 1;
			widget.ais = DynamicUtil.toIds(this.expressions);
			widget.op = DynamicUtil.getOperator(this.expressions);
		} else if (this.selectedExpressions) {
			widget.as = null;
			widget.ais = null;
		}

		if (this.isEdit) {
			this.submitSafe(
				this.dynamicPageService.editContainerEntity(
					this.container,
					widget,
					this.oldWidget,
				),
				false,
				true,
			).subscribe(() => this.modalDialog.close(widget));
		} else {
			this.submitSafe(
				this.dynamicPageService.addContainerEntity(this.container, widget),
				false,
				true,
			).subscribe(() => this.modalDialog.close(widget));
		}
	}

	private update(): void {
		// TODO Check expression...
		this.canSave = !!this.widget;
	}

	private toWidget(info: IWidgetInfo): IDynamicWidget {
		const widget = {
			h: this.toHandle(info),
			t: info.title,
		} as IDynamicWidget;
		if (info.banner) {
			widget.bl = info.banner;
		}
		return widget;
	}

	private toHandle(widget: IWidgetInfo): IWidgetHandle {
		const handle = { id: widget.widgetId } as IWidgetHandle;
		if (widget.standardWidgetId) {
			handle.pid = widget.standardWidgetId;
		}
		return handle;
	}
}
