import { Component, OnInit, ViewChild, ViewContainerRef } from "@angular/core";
import {
	ComponentType,
	SohoModalDialogRef,
	SohoModalDialogService,
} from "ids-enterprise-ng";
import {
	ArrayUtil,
	CommonUtil,
	DialogButtonType,
	IAutocompleteEntity,
	IDialogResult,
	NumUtil,
} from "lime";
import {
	AutoCompleter,
	CommonDataService,
	CoreBase,
	CoreUtil,
	IPage,
	ISettingItem,
	ISettingRule,
	ISettingRuleConnection,
	IUserListResponse,
	PrincipalType,
	SettingItemType,
	SettingsNames,
	Templates,
} from "lime/core";
import { Observable, Subject } from "rxjs";
import { SettingUtil } from "../admin";
import { AdminService, AdminUtil } from "../service";
import { DefaultPagesComponent } from "./default-pages";
import { MandatoryPagesComponent } from "./mandatory-pages";

@Component({
	templateUrl: "./rule.html",
	styleUrls: ["./rule.scss"],
})
export class SettingAddEditRuleComponent extends CoreBase implements OnInit {
	get primaryButtonLabel(): string {
		return this.isEdit ? "Ok" : "Add";
	}

	@ViewChild("ruleDialogView", { read: ViewContainerRef, static: false })
	ruleDialogView: ViewContainerRef;

	dialog: SohoModalDialogRef<SettingAddEditRuleComponent>;
	parameter: any;
	isBusy: boolean;
	isEdit = false;
	setting: ISettingItem;
	value: any;
	originalValue: any;
	pages: IPage[];
	ruleConnections: ISettingRuleConnection[] = [];
	maxCountNumbers = [];
	ruleName: string;
	existsMessage = "";
	existsRoleMessage = "";
	userInput: string;
	roleInput: string;
	roleAutocompleteOptions: any;
	sortableOptions: any;
	autocompleteUserSource: Function;
	autocompleteUserTemplate: string;
	autocompleteRoleSource: Function;
	autocompleteRoleTemplate: string;
	autocompleteRoleFilterMode: string;

	private rule: ISettingRule;
	private userName: string;
	private lastConnection: ISettingRuleConnection;

	constructor(
		private sohoModalDialogService: SohoModalDialogService,
		private adminService: AdminService,
		private commonDataService: CommonDataService,
	) {
		super("SettingAddEditRuleComponent");
		this.initAutocomplete();
	}

	ngOnInit(): void {
		const types = SettingItemType;
		const parameter = this.parameter;
		this.userName = parameter.userName;
		const setting = CoreUtil.copy(parameter.setting) as ISettingItem;
		this.setting = setting;
		const rule: ISettingRule = parameter.rule
			? CoreUtil.copy(parameter.rule)
			: parameter.rule;
		this.rule = rule;
		this.pages = CoreUtil.copy(parameter.pages);

		if (!CommonUtil.isUndefined(rule)) {
			this.value = rule.value;
			this.ruleName = rule.name;
			this.ruleConnections = rule.ruleConnections || [];
			this.isEdit = true;
			this.originalValue = rule.value;
		} else {
			// Client Log Level should never be null (LIME-829)
			if (setting.settingName === SettingsNames.logLevel) {
				this.value = setting.value;
			}
		}

		if (setting.type === types.typeBool && !this.isEdit) {
			this.value = false;
		}

		// Create count array for int typeselector
		if (setting.type === types.typeIntSelector) {
			let i = 0;
			while (i < parameter.maxCount) {
				const value = (i + 1).toString();
				this.maxCountNumbers.push(value);
				i++;
			}
		}
	}

	getExternalType(): string {
		const type = this.setting.type;
		if (
			type === SettingItemType.typeDefaultPages ||
			type === SettingItemType.typeMandatoryPages
		) {
			return type;
		}
		return "";
	}

	onSelectAutocomplete(item: IAutocompleteEntity) {
		if (CommonUtil.isUndefined(item) || CommonUtil.isUndefined(item.value)) {
			return;
		}
		this.addEntity(
			item.value as string,
			item.type as PrincipalType,
			item.label,
			item.info,
		);
	}

	addRole(): void {
		const name = this.roleInput;
		if (!name) {
			return;
		}
		this.addEntity(name, PrincipalType.Role, null, null);
	}

	onOk(): void {
		if (!this.ruleName) {
			return;
		}

		const setting = this.setting;

		if (this.isEdit) {
			this.editRule();
		} else {
			this.addRule();
		}

		this.dialog.close({ value: setting });
	}

	/**
	 * Removes a user or group from connections.
	 */
	remove(connection: ISettingRuleConnection): void {
		const ruleConnections = this.ruleConnections;
		const connectionIndex = ruleConnections.indexOf(connection);
		ruleConnections.splice(connectionIndex, 1);
	}

	openExternalEditor(): void {
		let observable: Observable<IDialogResult>;
		const setting = CoreUtil.copy(this.setting);
		const type = setting.type;
		setting.value = this.value || "";

		if (type === SettingItemType.typeDefaultPages) {
			observable = this.openExternalDialog(setting, DefaultPagesComponent);
		} else if (type === SettingItemType.typeMandatoryPages) {
			observable = this.openExternalDialog(setting, MandatoryPagesComponent);
		}

		if (observable) {
			observable.subscribe((r: IDialogResult) => {
				if (r && r.button === DialogButtonType.Ok) {
					this.value = r.value;
				}
			});
		}
	}

	private initAutocomplete(): void {
		const self = this;

		this.autocompleteUserSource = new AutoCompleter<IUserListResponse>(
			(query) => self.commonDataService.searchUsers(query),
			(response) =>
				CoreUtil.getEntityArray(PrincipalType.User, response.content),
			self.commonDataService,
		).source;
		this.autocompleteUserTemplate = Templates.autocompleteEntity;

		this.autocompleteRoleSource = new AutoCompleter<IAutocompleteEntity[]>(
			(query) => self.adminService.searchRoles(query),
			(response) => ArrayUtil.sortByProperty(response, "label"),
			self.commonDataService,
		).source;
		this.autocompleteRoleTemplate = Templates.autocompleteEntity;
		this.autocompleteRoleFilterMode = "contains";
	}

	private addEntity(
		name: string,
		principalType: PrincipalType,
		label: string,
		info: string,
	): void {
		this.existsMessage = "";
		this.existsRoleMessage = "";

		const isUser = principalType === PrincipalType.User;
		const connection = {
			name: name,
			isUser: isUser,
			displayName: label ? label : name,
			info: info || name,
		} as ISettingRuleConnection;

		const existing = SettingUtil.hasConnection(
			this.ruleConnections,
			connection,
		);
		const isSame = SettingUtil.isSameConnection(
			connection,
			this.lastConnection,
		);
		this.lastConnection = connection;

		if (existing) {
			// Never add duplicates
			// Don't show message if same connection added twice in a row which can happen due to IDS controls
			if (!isSame) {
				if (isUser) {
					this.existsMessage = "User already added";
				} else {
					this.existsRoleMessage = "Role already added";
				}
			}
			return;
		}

		this.ruleConnections.push(connection);
		if (!connection.isUser) {
			this.roleInput = "";
		}
	}

	private addRule(): void {
		// Set change date and by for each new connection
		const userName = this.userName;
		const ruleConnections: ISettingRuleConnection[] = this.ruleConnections;
		ruleConnections.forEach((connection) => {
			connection.displayChangeDate = AdminUtil.getPendingChangeDate();
			connection.changedByName = userName;
		});

		const settingItem = this.setting;
		this.value = this.changeInvalidValue(settingItem, this.value);
		const ruleDisplayValue = SettingUtil.getDisplayValue(
			settingItem,
			this.value,
		);

		const rule = {
			name: this.ruleName,
			sortOrder: 1,
			affectedUsers: ruleConnections.length,
			value: this.value,
			displayValue: ruleDisplayValue,
			isChanged: true,
			ruleConnections: ruleConnections,
			displayChangeDate: AdminUtil.getPendingChangeDate(),
			changedByName: userName,
			changeDate: null,
			changedBy: null,
			mode: null,
			module: null,
			readOnly: null,
			ruleSettingId: null,
			settingName: settingItem.setting.settingName,
		};

		settingItem.rules.forEach((ruleItem) => {
			ruleItem.sortOrder++;
			ruleItem.isChanged = true;
			ruleItem.changedByName = userName;
			ruleItem.displayChangeDate = AdminUtil.getPendingChangeDate();
		});

		settingItem.rules.unshift(rule);
	}

	private editRule(): void {
		const rule = this.rule;
		const ruleConnections: ISettingRuleConnection[] = this.ruleConnections;
		const userName = this.userName;

		// Set changedate and changedby for each new connection
		ruleConnections.forEach((connection: ISettingRuleConnection) => {
			connection.displayChangeDate = AdminUtil.getPendingChangeDate();
			connection.changedByName = userName;
		});

		const item = this.setting;
		const ruleIndex = ArrayUtil.indexByProperty(
			item.rules,
			"sortOrder",
			rule.sortOrder,
		);
		this.value = this.changeInvalidValue(item, this.value);
		const ruleDisplayValue = SettingUtil.getDisplayValue(item, this.value);

		rule.name = this.ruleName;
		rule.value = this.value;
		rule.displayValue = ruleDisplayValue;
		rule.affectedUsers = ruleConnections.length;
		rule.isChanged = true;
		rule.ruleConnections = ruleConnections;
		rule.displayChangeDate = AdminUtil.getPendingChangeDate();
		rule.changedByName = userName;

		if (ruleIndex !== -1) {
			this.setting.rules[ruleIndex] = rule;
		}
	}

	private changeInvalidValue(item: ISettingItem, value: any): any {
		// Resets bad values to prevent undefined ints
		const types = SettingItemType;
		if (item.type === types.typeIntSelector && !NumUtil.isNumber(value)) {
			return this.originalValue ? this.originalValue : 0;
		}
		return value;
	}

	private openExternalDialog(
		setting: ISettingItem,
		componentType: ComponentType<
			MandatoryPagesComponent | DefaultPagesComponent
		>,
	): Observable<IDialogResult> {
		const subject = new Subject<IDialogResult>();

		let isOk = false;
		let componentInstance: MandatoryPagesComponent | DefaultPagesComponent;

		const buttons = [
			{
				text: "Cancel",
				id: "lm-a-set-r-edit-dialog-cancel",
				click: (e, modal: SohoModalStatic) => {
					modal.close();
				},
			},
			{
				text: "OK",
				id: "lm-a-set-r-edit-dialog-ok",
				click: (e, modal: SohoModalStatic) => {
					isOk = true;
					modal.close();
				},
				isDefault: true,
			},
		];

		const dialog = this.sohoModalDialogService
			.modal(componentType, this.ruleDialogView)
			.title("Edit Setting")
			.id("lm-a-set-r-edit-dialog")
			.buttons(buttons)
			.afterClose(() => {
				const result: IDialogResult = {};
				if (isOk) {
					result.button = DialogButtonType.Ok;
					result.value = componentInstance.settingItem.value;
				}
				subject.next(result);
				subject.complete();
			});

		dialog
			.apply((component) => {
				componentInstance = component;
				component.dialog = dialog;
				component.settingItem = setting;
			})
			.open();

		return subject.asObservable();
	}
}
