import { Component, NgZone, OnInit, ViewChild } from "@angular/core";
import {
	SohoDataGridComponent,
	SohoMessageService,
	SohoModalDialogRef,
	SohoModalDialogService,
} from "ids-enterprise-ng";
import { DialogService } from "lime";
import {
	CommonDataService,
	ILanguageInfo,
	LanguageConverter,
	LanguageService,
} from "lime/core";
import { IStringMap } from "standard-widgets/infor.mingle.custommenu/types";
import { AdminListComponent } from "./admin-list.component";
import { AdminContext, AdminService } from "./service";

@Component({
	templateUrl: "./language-selector.html",
})
export class LanguageSelectorDialog
	extends AdminListComponent<ILanguageInfo>
	implements OnInit
{
	@ViewChild("languageDatagrid", { static: false })
	dataGrid: SohoDataGridComponent;

	dialog: SohoModalDialogRef<LanguageSelectorDialog>;
	description: string;
	canSave = false;

	constructor(
		messageService: SohoMessageService,
		languageService: LanguageService,
		private commonDataService: CommonDataService,
		adminService: AdminService,
		sohoModalDialogService: SohoModalDialogService,
		zone: NgZone,
		private readonly adminContext: AdminContext,
		private readonly dialogService: DialogService,
	) {
		super(
			"LanguageSelectorDialog",
			"language",
			messageService,
			languageService,
			adminService,
			sohoModalDialogService,
			zone,
			{},
		);
	}

	ngOnInit(): void {
		this.initGrid();
		this.commonDataService.listLanguages().subscribe(
			(r) => {
				this.updateLanguages(r.content);
			},
			() => {},
		);
	}

	cancel(): void {
		this.dialog.close();
	}

	save(): void {
		const items = this.selection.map((i) => i.data);
		this.dialog.close(items);
	}

	protected getDataGrid(): SohoDataGridComponent {
		return this.dataGrid;
	}

	private updateLanguages(languageMap: IStringMap): void {
		const converter = new LanguageConverter(this.languageService.getLanguage());
		const items = converter.toList(languageMap);
		this.addItems(items, null);
	}

	private initGrid(): void {
		const options = {
			selectable: "multiple" as SohoDataGridSelectable,
			rowHeight: "medium" as SohoDataGridRowHeight,
			disableRowDeactivation: true,
			clickToSelect: false,
			columns: [
				{
					width: 50,
					id: "selectionCheckbox",
					field: "",
					name: "",
					sortable: false,
					resizable: false,
					formatter: Formatters.SelectionCheckbox,
					align: "center",
				},
				{
					width: 200,
					id: "lm-a-ls-col-t",
					field: "name",
					name: "Language",
					sortable: true,
					resizable: true,
				},
				{
					width: 215,
					id: "lm-a-ls-col-c",
					field: "native",
					name: "Description",
					sortable: true,
					resizable: true,
				},
			],
			dataset: this.items || [],
		};
		this.datagridOptions = options;
	}
}
