import { Component, OnInit } from "@angular/core";
import { SohoMessageService } from "ids-enterprise-ng";
import { DialogButtonType } from "lime";
import { ContextService, ModalDialogBase } from "lime/core";
import { DateUtil } from "../core";
import {
	AdminService,
	AdminUtil,
	IDateRangeResponse,
	ITimeZone,
} from "../service";

export interface IDateRange {
	from: string;
	to: string;
	tz: string;
	sts?: number;
}

@Component({
	templateUrl: "./date-range.html",
})
export class DateRangeComponent extends ModalDialogBase implements OnInit {
	dateRange: IDateRange;
	timeZones: ITimeZone[];

	constructor(
		messageService: SohoMessageService,
		private readonly contextService: ContextService,
		private readonly adminService: AdminService,
	) {
		super("DateRangeComponent", messageService);
		this.timeZones = AdminUtil.getTimeZones();
	}

	ngOnInit(): void {
		this.initModalDialog();

		const from = this.dateRange.from;
		const to = this.dateRange.to;

		if (!to && !from) {
			this.from = DateUtil.dateToString(DateUtil.today());
			this.to = DateUtil.dateToString(DateUtil.weekFromNow());
		} else {
			this.from = DateUtil.parseToString(from);
			this.to = DateUtil.parseToString(to);
		}

		this.timeZone =
			this.dateRange.tz ||
			this.contextService.getContext().getInforStdTimeZone() ||
			"UTC";
	}

	save(): void {
		if (!this.timeZone) {
			this.showInvalidRangeError("A time zone must be selected.");
		}
		if (!this.dateRange.from && !this.dateRange.to) {
			this.modalDialog.close({
				button: DialogButtonType.Ok,
				value: null,
			});
			return;
		}
		this.setCanClose(false);
		this.adminService.validateDateRange([this.dateRange]).subscribe(
			(response) => {
				if (response && response.content && response.content[0]) {
					const dateRange = response.content && response.content[0];
					this.dateRange.sts = dateRange.sts;
					this.setCanClose(true);
					this.modalDialog.close({
						button: DialogButtonType.Ok,
						value: this.dateRange,
					});
				}
			},
			(response: IDateRangeResponse) => {
				if (response.hasError()) {
					this.showInvalidRangeError(response.getErrorMessages());
					return;
				} else {
					this.adminService.handleError(response);
				}
			},
		);
	}

	private showInvalidRangeError(errorMessage: string) {
		this.showError("Date range", errorMessage);
	}

	get timeZone() {
		return this.dateRange.tz;
	}

	set timeZone(value: string) {
		this.dateRange.tz = value;
	}

	get from() {
		return DateUtil.parseToString(this.dateRange.from);
	}

	set from(value: string) {
		this.dateRange.from = value ? this.dateToFromIds(value) : null;
	}

	get to() {
		return DateUtil.parseToString(this.dateRange.to);
	}

	set to(value: string) {
		this.dateRange.to = value ? this.dateToFromIds(value) : null;
	}

	private dateToFromIds(idsValue: string) {
		const date = DateUtil.parseLocaleDate(idsValue);
		return AdminUtil.toIsoDateTimeLocal(date);
	}
}
