import { Component, EventEmitter, Output } from "@angular/core";
import { ArrayUtil } from "lime";
import {
	CoreUtil,
	DynamicColorType,
	IDynamicContainer,
	IDynamicHeader,
} from "lime/core";
import { of } from "rxjs";
import { catchError } from "rxjs/operators";
import { DynamicUtil } from "../../../../util";
import { DynamicContainerListBase } from "../../dynamic-container/dynamic-container-list";
import { DynamicInformationHeaderDialog } from "./add-header-dialog";

@Component({
	selector: "lm-header-list-component",
	templateUrl: "../../dynamic-container/dynamic-container-list.html",
	styleUrls: ["../../dynamic-container/dynamic-container-list.scss"],
})
export class DynamicHeaderListComponent extends DynamicContainerListBase {
	@Output() headerAdded = new EventEmitter();
	colorTypes = DynamicColorType;

	ngOnInit() {
		this.updateEmptyProperty();
		this.initItems(
			"Add Header",
			"",
			"Header color bar",
			"Image",
			"Heading",
			"Subheading",
		);
		this.automationIdentifier = this.automationIdentifier + "-h";
	}

	addHeader() {
		if (!this.canAdd() || this.isDialogOpen) {
			return;
		}
		this.isDialogOpen = true;

		const dialog = this.dialogService
			.modal(DynamicInformationHeaderDialog, this.viewContainerRef)
			.title("Add Header")
			.id("lm-a-dp-info-addheader-dialog")
			.afterClose((header) => {
				this.isDialogOpen = false;
				if (header) {
					this.updateEmptyProperty();
				}
			});

		dialog
			.apply((component: DynamicInformationHeaderDialog) => {
				component.modalDialog = dialog;
				component.container = this.container;
				component.containerLznEdited = this.container.lzn;
				component.isEdit = false;
			})
			.open();
	}

	editItem(isPermissionTab: boolean, header: IDynamicHeader) {
		if (this.isDialogOpen) {
			return;
		}
		this.isDialogOpen = true;

		const expressions = DynamicUtil.toExpressions(header, this.accessTitles);
		const dialog = this.dialogService
			.modal(DynamicInformationHeaderDialog, this.viewContainerRef)
			.title(`${this.isEditable ? "Edit" : "View"} Header`)
			.id("lm-a-dp-info-editheader-dialog")
			.afterClose((updatedHeader) => {
				this.isDialogOpen = false;
				if (updatedHeader) {
					this.updateEmptyProperty();
				}
			});

		dialog
			.apply((component: DynamicInformationHeaderDialog) => {
				component.modalDialog = dialog;
				component.selectedColorNr = header.cl;
				component.isEdit = true;
				component.container = this.container;
				component.containerLznEdited = this.container.lzn;
				component.oldHeader = header;
				component.header = header;
				component.item = {
					eid: header.eid,
				};
				component.selectedExpressions = expressions;
				component.isPermissionTabOnInit = isPermissionTab;
				component.isEditable = this.isEditable;
			})
			.open();
	}

	deleteItems(
		headers: IDynamicHeader[],
		parentContainer?: IDynamicContainer,
	): void {
		const containerCopy = CoreUtil.copy(parentContainer || this.container);

		for (const header of headers) {
			const removeIndex = ArrayUtil.indexByProperty(
				containerCopy.hds,
				"eid",
				header.eid,
			);
			if (removeIndex > -1) {
				containerCopy.hds.splice(removeIndex, 1);
			}
		}
		this.pageService
			.updateContainer(containerCopy, containerCopy, headers)
			.pipe(
				// Ignore error since it's handled in service
				catchError(() => of()),
			)
			.subscribe(() => this.updateEmptyProperty());
	}

	getEntityCount(): number {
		return (
			(this.container.its && this.container.its.length) +
			(this.container.hds && this.container.hds.length)
		);
	}

	private updateEmptyProperty() {
		const containers = this.pageService.getPage().cts;
		const container = ArrayUtil.itemByProperty(
			containers,
			"eid",
			this.container.eid,
		);
		const hasHeader = container.hds && container.hds.length > 0;
		if (this.isEmpty === hasHeader) {
			this.headerAdded.emit();
		}
		this.isEmpty = !hasHeader;
	}
}
