import { DynamicPageAdminService } from "../../service";

@Component({
	templateUrl: "container-settings-dialog.html",
})
export class DynamicContainerSettingsDialog
	extends DynamicSettingsDialogBase
	implements OnInit
{
	containerTypes = DynamicContainerType;
	expandStrategies = DynamicLinksExpandType;
	size: IWidgetSize;
	isMainAreaContainer: boolean;
	isLinkList: boolean;

	constructor(
		private pageService: DynamicPageAdminService,
		messageService: SohoMessageService,
	) {
		super("ContainerSettingsDialogComponent", messageService);
		this.optionsItems = [
			{
				name: "t",
				label: "Title",
				labelId: "lm-a-dp-cs-at-t-lbl",
				valueId: "lm-a-dp-cs-at-t-inp",
				maxLength: Constants.dynPageDefaultMaxLength,
				defaultValue: "",
			},
		];
	}

	ngOnInit() {
		this.initModalDialog();

		const container = this.container;
		const sizeInit = {
			cols: container.cs ? container.cs : 1,
			rows: container.rs ? container.rs : 1,
		};

		this.setSize(sizeInit);
		this.size = sizeInit;
		this.isLinkList =
			container.ct === DynamicContainerType.Links && !container.st;
		if (this.isLinkList && CommonUtil.isUndefined(container.ex)) {
			this.container.ex = DynamicLinksExpandType.None;
		}
		this.onTitleChange(container.t);
	}

	setSize(size: IWidgetSize) {
		this.container.cs = size.cols;
		this.container.rs = size.rows;
	}

	onIconChanged(icon: string) {
		this.container.i = icon;
	}

	onColorChanged(color: number) {
		this.container.icl = color;
	}

	onColorTypeChanged(colorType: DynamicColorType) {
		this.container.clt = colorType;
	}

	save() {
		if (!this.isEditable) {
			return;
		}
		const containerCopy = CoreUtil.copy(this.container);
		const hasInvalidOldTranslations = this.hasInvalidTranslations(
			containerCopy.lzn,
		);
		if (this.containerLznEdited) {
			if (hasInvalidOldTranslations) {
				const invalidOldTranslations = this.getInvalidTranslations(
					containerCopy.lzn,
				);
				containerCopy.lzn = {
					...invalidOldTranslations,
					...this.containerLznEdited,
				};
			} else {
				containerCopy.lzn = this.containerLznEdited;
			}
		} else if (hasInvalidOldTranslations) {
			containerCopy.lzn = this.getInvalidTranslations(containerCopy.lzn);
		} else {
			containerCopy.lzn = null;
		}
		if (this.hasInvalidTranslations(containerCopy.lzn)) {
			this.showConfirmDiscardTranslations().subscribe(
				() => {
					this.deleteTranslations(containerCopy.lzn);
					this.submitSafe(
						this.pageService.updateContainer(containerCopy, this.container),
					).subscribe();
				},
				null,
				() => this.setCanClose(true),
			);
		} else {
			this.submitSafe(
				this.pageService.updateContainer(containerCopy, this.container),
			).subscribe();
		}
	}

	onLocalizationChange(translationData: IDynamicEntityLocalizationMap) {
		const updatedLzn = (this.containerLznEdited = translationData || {});

		// Add items to localizations object
		for (const langKey of Object.keys(updatedLzn)) {
			// Add items
			if (this.container.lzn && this.container.lzn[langKey]) {
				updatedLzn[langKey].its = this.container.lzn[langKey].its;
			}
			// Do not delete lzn with items
			if (updatedLzn[langKey].op === EntityOperation.Delete) {
				if (
					this.container.lzn[langKey].its &&
					Object.keys(this.container.lzn[langKey].its).length > 0
				) {
					updatedLzn[langKey] = {
						t: "",
						op: EntityOperation.Update,
						its: this.container.lzn[langKey].its,
						eid: this.container.lzn[langKey].eid,
					};
				}
			}
		}
	}

	onTitleChange(title: string) {
		const titleLznItemIndex = this.getTranslationItemIndex("t");
		if (titleLznItemIndex > -1) {
			this.optionsItems[titleLznItemIndex].defaultValue = title;
		}
		this.setIsTranslateable();
		this.optionsItems = [...this.optionsItems];
	}

	setIsTranslateable() {
		this.isTranslateable = this.container.t && this.container.t.length > 0;
	}

	hasInvalidTranslation(lang: IDynamicEntityLocalization): boolean {
		return (
			!this.isTranslateable &&
			lang &&
			lang.t &&
			lang.t.length &&
			lang.t.length > 0
		);
	}

	deleteTranslation(lang: IDynamicEntityLocalization): void {
		if (!(this.container.t && this.container.t.length)) {
			lang.t = "";
		}
	}
}

@Component({
	selector: "lm-icon-selector",
	template: `
		<div class="field">
			<label class="lm-margin-md-b" *ngIf="!showAllIcons">Icon</label>
			<button
				class="btn-icon lm-margin-sm-b"
				*ngFor="let icon of icons; let i = index"
				[name]="'lm-a-dp-iconselector-icon-' + i"
				[attr.data-lm-a-dp-is-icon]="i"
				[disabled]="isDisabled"
				(click)="setIcon(icon)"
				[style.background-color]="
					selectedIcon === icon ? selectedColorHex : null
				">
				<svg
					class="icon"
					aria-hidden="true"
					focusable="false"
					style="top: -1px; height: 19px;"
					[class.selected]="icon === selectedIcon">
					<use [attr.xlink:href]="icon" />
				</svg>
			</button>
			<div *ngIf="!showAllIcons">
				<button
					class="moreIconsButton hyperlink"
					id="lm-a-dp-is-more-btn"
					[disabled]="isDisabled"
					[style.cursor]="isDisabled ? 'default' : 'pointer'"
					(click)="openIconDialog()">
					More...
				</button>
			</div>
		</div>
		<ng-container *ngIf="!showAllIcons">
			<div class="field lm-margin-zero-b">
				<label class="lm-margin-md-b">Icon background color</label>
				<ng-container *ngIf="enableTheming">
					<ng-container *ngIf="hasParent">
						<input
							soho-radiobutton
							name="icon-color-type"
							id="lm-a-dp-is-typeparent-chk"
							type="radio"
							[value]="colorTypes.InheritParent"
							(change)="onColorTypeChange()"
							[(ngModel)]="selectedColorType"
							[attr.disabled]="isDisabled ? '' : null" />
						<label
							id="lm-a-dp-is-componentcolor-label"
							soho-label
							for="lm-a-dp-is-typeparent-chk"
							[forRadioButton]="true"
							>Use component icon color</label
						>
						<br />
					</ng-container>
					<input
						soho-radiobutton
						name="icon-color-type"
						id="lm-a-dp-is-typepage-chk"
						type="radio"
						[value]="colorTypes.InheritPage"
						(change)="onColorTypeChange()"
						[(ngModel)]="selectedColorType"
						[attr.disabled]="isDisabled ? '' : null" />
					<label
						id="lm-a-dp-is-pagecolor-label"
						soho-label
						for="lm-a-dp-is-typepage-chk"
						[forRadioButton]="true"
						>Use page color</label
					>
					<br />
					<input
						soho-radiobutton
						name="icon-color-type"
						id="lm-a-dp-is-typecustom-chk"
						type="radio"
						[value]="colorTypes.Custom"
						(change)="onColorTypeChange()"
						[(ngModel)]="selectedColorType"
						[attr.disabled]="isDisabled ? '' : null" />
					<label
						id="lm-a-dp-is-customcolor-label"
						soho-label
						for="lm-a-dp-is-typecustom-chk"
						[forRadioButton]="true"
						>Select custom color</label
					>
					<br />
				</ng-container>
			</div>
			<div class="field">
				<input
					id="lm-a-dp-is-color-inp"
					soho-colorpicker
					[(ngModel)]="selectedColorHex"
					[editable]="colorpickerOptions.editable"
					[showLabel]="colorpickerOptions.showLabel"
					[colors]="colorpickerOptions.colors"
					[disabled]="isColorpickerDisabled()"
					[clearable]="false"
					[attributes]="{ name: 'id', value: 'lm-a-dp-icon-selector-color' }"
					(change)="onColorChange($event)" />
			</div>
		</ng-container>
	`,
	styles: [
		`
			button.btn-icon:focus {
				box-shadow: none;
			}

			.moreIconsButton {
				font-size: 12px;
				font-color: #5c5c5c;
				padding: 0px 6px;
			}

			svg.selected,
			button.btn-icon:hover svg.selected {
				color: #fff;
			}
		`,
	],
})
export class IconSelectorComponent implements AfterViewInit {
	@ViewChild(SohoColorPickerComponent, { static: false })
	colorpicker: SohoColorPickerComponent;
	@Input("icon") selectedIcon: string;
	@Input("color") selectedColorNr: number;
	@Input("colorType") selectedColorType: DynamicColorType;
	@Input() enableTheming = true;
	@Input() hasParent = true;
	@Input() isDisabled = false;
	@Input() showAllIcons = false;
	@Input() isIconMandatory = false;
	@Output() iconChanged = new EventEmitter<string>();
	@Output() colorChanged = new EventEmitter<number>();
	@Output() colorTypeChanged = new EventEmitter<DynamicColorType>();

	basicIcons = [
		"#icon-agent",
		"#icon-user",
		"#icon-group-selection",
		"#lime-icon-shortcut",
		"#lime-icon-hands",
		"#icon-phone",
		"#lime-icon-checklist",
		"#icon-map-pin",
		"#icon-insert-image",
		"#icon-star-filled",
		"#icon-cloud",
		"#icon-key",
		"#icon-timer",
		"#icon-notification",
		"#icon-zoom-in",
		"#icon-zoom-out",
		"#icon-link",
	];

	extraIcons = [
		"#lime-icon-calc",
		"#lime-icon-truck",
		"#lime-icon-wrench",
		"#lime-icon-thumb",
		"#lime-icon-settings",
		"#icon-edit",
		"#lime-icon-factory",
		"#lime-icon-drawer",
		"#lime-icon-dollar",
		"#lime-icon-diagram",
		"#lime-icon-note",
		"#icon-server",
		"#icon-screen",
		"#icon-scale",
		"#icon-run-job",
		"#icon-reply",
		"#icon-reply-all",
		"#icon-quick-reference",
		"#icon-purchasing",
		"#icon-ledger",
		"#icon-genealogy",
		"#icon-new-case",
		"#icon-enterprise-planning",
		"#icon-mobile",
		"#icon-area",
		"#lime-icon-bag",
		"#icon-info",
		"#icon-mingle-share",
		"#icon-tools",
		"#icon-formula-constituents",
		"#icon-counter-clockwise-90",
		"#icon-headphones",
		"#icon-distribution",
		"#icon-line-chart",
		"#icon-script",
		"#icon-binoculars",
		"#icon-help",
		"#lime-icon-heartrate",
		"#icon-warehouse",
		"#icon-travel-plan",
		"#icon-thumbs-up",
		"#icon-special-item",
		"#icon-service",
		"#lime-icon-timebook",
		"#lime-icon-window",
		"#lime-icon-window-fields",
		"#lime-icon-window-open",
		"#icon-bookmark-filled",
		"#icon-project",
		"#icon-technology",
		"#icon-contacts",
		"#icon-heart-outlined",
		"#icon-heart-filled",
		"#icon-exclamation",
		"#icon-workflow",
		"#icon-cascade-objects",
		"#icon-decrease-row-line-height",
		"#icon-design-mode",
		"#icon-lasso",
		"#icon-rocket",
		"#icon-bubble",
		"#icon-articles",
		"#icon-connections",
		"#icon-employee-directory",
		"#icon-calendar",
		"#icon-cart",
		"#icon-checkbox",
		"#icon-document",
		"#icon-sec-menu-expand",
		"#icon-notes",
		"#icon-print",
		"#icon-url",
		"#icon-mail",
		"#icon-map",
		"#lime-icon-doc",
		"#lime-icon-doc-html",
		"#lime-icon-doc-pdf",
		"#lime-icon-doc-ppt",
		"#lime-icon-doc-txt",
		"#lime-icon-doc-xls",
	];

	allIcons = [...this.basicIcons, ...this.extraIcons];

	maxIconsToShow = this.basicIcons.length + 1;
	colorpickerOptions = UIUtil.getColorpickerOptionsExtended();
	selectedColorHex: string;
	icons: Array<string>;
	colorTypes = DynamicColorType;

	constructor(
		protected viewContainerRef: ViewContainerRef,
		protected dialogService: SohoModalDialogService,
	) {}

	ngAfterViewInit() {
		if (this.enableTheming && !this.selectedColorType) {
			this.selectedColorType = this.selectedColorNr
				? DynamicColorType.Custom
				: this.hasParent
				  ? DynamicColorType.InheritParent
				  : DynamicColorType.InheritPage;
			this.onColorTypeChange();
		}
		this.selectedColorNr
			? this.setColor(this.selectedColorNr)
			: this.setColor(0);
		this.icons = this.showAllIcons ? this.allIcons : this.basicIcons;
		if (
			this.selectedIcon &&
			!ArrayUtil.contains(this.basicIcons, this.selectedIcon)
		) {
			this.basicIcons.push(this.selectedIcon);
		}
		if (this.isIconMandatory && !this.selectedIcon) {
			this.setIcon(this.basicIcons[0]);
		}
	}

	setIcon(icon) {
		if (this.selectedIcon !== icon) {
			this.selectedIcon = icon;
		} else if (this.isIconMandatory) {
			return;
		} else {
			this.selectedIcon = null;
		}
		this.iconChanged.emit(this.selectedIcon);
	}

	openIconDialog() {
		const dialog = this.dialogService
			.modal(MoreIconsDialog, this.viewContainerRef)
			.title("More Icons")
			.id("lm-a-dp-moreicons-dialog")
			.afterClose((newIcon) => {
				if (newIcon) {
					if (!ArrayUtil.contains(this.basicIcons, newIcon)) {
						if (this.basicIcons.length === this.maxIconsToShow) {
							this.basicIcons.pop();
						}
						this.basicIcons.push(newIcon);
					}
					this.setIcon(newIcon);
				}
			});
		dialog
			.apply((component: MoreIconsDialog) => {
				component.iconsDialog = dialog;
				component.iconColor = this.selectedColorNr;
				component.selectedIcon = this.selectedIcon;
			})
			.open();
	}

	onColorChange(event: SohoColorPickerEvent) {
		const hexValue = this.colorpicker.getHexValue();
		this.selectedColorHex = hexValue;
		this.colorChanged.emit(UIUtil.hexCodeToNumberExtended(hexValue));
	}

	onColorTypeChange() {
		if (this.isColorpickerDisabled()) {
			this.setColor(0);
			this.colorChanged.emit(
				UIUtil.hexCodeToNumberExtended(this.selectedColorHex),
			);
			if (this.colorpicker) {
				setTimeout(() => {
					this.colorpicker.disabled = true;
				});
			}
		}
		this.colorTypeChanged.emit(this.selectedColorType);
	}

	isColorpickerDisabled(): boolean {
		const colorpickerDisabled =
			this.enableTheming && this.selectedColorType !== DynamicColorType.Custom;
		return this.isDisabled || colorpickerDisabled;
	}

	private setColor(colorNr: number) {
		this.selectedColorNr = colorNr;
		this.selectedColorHex = UIUtil.numberToHexCodeExtended(colorNr);
	}
}

@Component({
	template: `
		<div style="max-width: 390px">
			<lm-icon-selector
				[icon]="selectedIcon"
				[color]="iconColor"
				[showAllIcons]="true"
				[isDisabled]="false"
				(iconChanged)="onIconChanged($event)">
			</lm-icon-selector>
			<div class="modal-buttonset">
				<button
					name="lm-a-moreicons-cancel"
					type="button"
					class="btn-modal"
					(click)="cancel()">
					Cancel
				</button>
				<button
					name="lm-a-moreicons-save"
					type="button"
					class="btn-modal-primary"
					(click)="save()">
					OK
				</button>
			</div>
		</div>
	`,
	styles: [],
})
export class MoreIconsDialog {
	iconsDialog: SohoModalDialogRef<MoreIconsDialog>;
	selectedIcon: string;
	icon: string;
	iconColor: number;

	onIconChanged(selectedIcon: string) {
		this.icon = selectedIcon;
	}

	cancel() {
		this.iconsDialog.close();
	}

	save() {
		this.iconsDialog.close(this.icon);
	}
}
