import {
	Component,
	EventEmitter,
	NgZone,
	OnInit,
	Output,
	ViewChild,
	ViewContainerRef,
} from "@angular/core";
import {
	SohoDataGridComponent,
	SohoMessageService,
	SohoModalDialogService,
} from "ids-enterprise-ng";
import { ArrayUtil, IDialogResult } from "lime";
import {
	AdminPages,
	CommonDataService,
	EntityFilter,
	ErrorInfo,
	IAdminNavigationEvent,
	IAttributeInfo,
	IOperationResponse,
	IUniqueIdRequest,
	LanguageService,
} from "lime/core";
import { CustomFormatters } from "../admin";
import { AdminListComponent } from "../admin-list.component";
import {
	AdminContext,
	AdminMultiOperationDialog,
	AdminService,
	AdminUtil,
	IAdminTool,
	IExpInfo,
	IExpressionListRequest,
	IExpressionListResponse,
	IExpressionResponse,
	IMultiOperationOptions,
} from "../service";
import { EditPolicyComponent, PolicyEditorMode, PolicyUtil } from "./policy";

@Component({
	selector: "lm-admin-policies",
	templateUrl: "./policies.html",
})
export class AdminPoliciesComponent
	extends AdminListComponent<IExpInfo>
	implements OnInit
{
	@ViewChild("policiesDatagrid", { static: false })
	dataGrid: SohoDataGridComponent;

	@Output() onNavigationEvent = new EventEmitter<IAdminNavigationEvent>();
	adminTool: IAdminTool;
	isAdministrator: boolean;

	private attributes: IAttributeInfo[];
	private importedUnsubscriber: () => void;
	private isEditorOpen: boolean;

	constructor(
		messageService: SohoMessageService,
		languageService: LanguageService,
		adminService: AdminService,
		sohoModalDialogService: SohoModalDialogService,
		zone: NgZone,
		private readonly commonService: CommonDataService,
		private readonly adminContext: AdminContext,
		readonly viewRef: ViewContainerRef,
	) {
		super(
			"AdminPoliciesComponent",
			"policy",
			messageService,
			languageService,
			adminService,
			sohoModalDialogService,
			zone,
			{
				isFilter: true,
				isOwnerFilter: false,
				isOtherUserFilter: false,
				isRestrictionFilter: false,
				filters: [
					{
						name: "Invalid",
						propertyName: "includeInvalid",
						value: true,
						type: EntityFilter.Custom,
					},
				],
			},
		);

		this.importedUnsubscriber = adminService.onPoliciesImported().on(() => {
			this.refresh();
		});

		this.initGrid();
	}

	ngOnInit(): void {
		const tool = this.adminContext.get();
		if (tool) {
			this.currentUser = tool.userId;
			this.adminTool = tool;
			this.isAdministrator = tool.isAdministrator;
		}
		this.refresh();
	}

	ngOnDestroy(): void {
		this.importedUnsubscriber();
	}

	getDataGrid(): SohoDataGridComponent {
		return this.dataGrid;
	}

	listItems(reload: boolean): void {
		const request = this.createRequest(reload) as IExpressionListRequest;
		if (!request) {
			return;
		}

		const adminService = this.adminService;
		const observable = adminService.listExpressions(request);
		this.withBusy(observable).subscribe(
			(response: IExpressionListResponse) => {
				this.addItems(response.content, response.paging);
				this.updateCount(response.expCount, response.expCountAllowed);
			},
			(r) => {
				adminService.handleError(r);
			},
		);
	}

	exportSelected(): void {
		const keys = this.getSelectedItems().map((item) => item.expressionId);
		if (keys.length === 0) {
			return;
		}
		this.adminService.exportExpressions(keys);
	}

	exportAll(): void {
		this.adminService.exportExpressions();
	}

	importPolicies(): void {
		this.adminService.openPolicyImportDialog(this.viewRef).subscribe();
	}

	confirmDelete(): void {
		const deleteCount = this.selectionCount;
		const policyString = AdminUtil.pluralize("policy", deleteCount);
		this.showConfirm(
			`Delete ${policyString}`,
			`Are you sure that you want to delete the selected ${policyString}? The archive will not be checked for usages.`,
		).subscribe(() => {
			if (deleteCount === 1) {
				this.deleteSelected();
			} else {
				this.deleteMultiSelected();
			}
		});
	}

	showDeleteFailedInUse(message: string, title: string): void {
		this.showError(
			"Unable to delete",
			title +
				" cannot be deleted. " +
				message +
				" Use the 'Used by' action to find the related entities",
		).subscribe();
	}

	deleteSelected(): void {
		const item = this.getSelectedItem();
		if (item) {
			this.setBusy(true);
			const request: IUniqueIdRequest = { content: item.expressionId };
			try {
				this.adminService.deleteExpression(request).subscribe(
					() => {
						this.refresh();
					},
					(response: IOperationResponse) => {
						if (response.errorList && response.errorList.length > 0) {
							const errorInfo: ErrorInfo = response.errorList[0];
							this.showDeleteFailedInUse(errorInfo.message, item.title);
						} else {
							this.adminService.handleError(response);
						}
					},
				);
			} catch (ex) {
			} finally {
				this.setBusy(false);
			}
		}
	}

	deleteMultiSelected(): void {
		const items = this.getSelectedItems();
		if (items) {
			const operations = [];
			for (const item of items) {
				const request: IUniqueIdRequest = { content: item.expressionId };
				const operation = this.adminService.deleteExpression(request);
				operations.push(operation);
			}
			const operationDialog = this.sohoDialogService
				.modal(AdminMultiOperationDialog, this.viewRef)
				.title("Delete policies")
				.id("lm-a-sp-delete-dialog")
				.afterClose(() => {
					this.refresh();
				});

			const options: IMultiOperationOptions = {
				customSuccessfulMessage: (count) =>
					`Deleted ${count} ${AdminUtil.pluralize("policy", count)}.`,
				customFailedMessage: (
					count,
				) => `Failed to delete ${count} ${AdminUtil.pluralize("policy", count)}.
					Policies in use cannot be deleted.`,
				entityname: "policy",
				operationName: "delete",
				operations: operations,
			};

			operationDialog
				.apply((dialog) => {
					dialog.modalDialog = operationDialog;
					dialog.options = options;
				})
				.open();
		}
	}

	add(): void {
		if (this.isMaxQuota) {
			const title = "Add Policy";
			const message =
				"Unable to add policy since the maximum limit for allowed security policies has been reached.";
			this.showError(title, message);
		} else {
			this.openEditor(PolicyEditorMode.Add);
		}
	}

	edit(): void {
		this.openExistingPolicy(PolicyEditorMode.Edit);
	}

	copy(): void {
		this.openExistingPolicy(PolicyEditorMode.Copy);
	}

	view(): void {
		this.openExistingPolicy(PolicyEditorMode.View);
	}

	openExistingPolicy(mode: PolicyEditorMode): void {
		const request = this.createUniqueRequest();
		if (!request) {
			return;
		}

		const observable = this.adminService.getExpression(request);
		this.withBusy(observable).subscribe(
			(response: IExpressionResponse) => {
				this.openEditor(mode, response.content);
			},
			(r: IOperationResponse) => {
				this.adminService.handleError(r);
			},
		);
	}

	openEditor(mode: PolicyEditorMode, expInfo?: IExpInfo): void {
		if (this.isEditorOpen) {
			return;
		}
		this.isEditorOpen = true;

		if (expInfo && mode === PolicyEditorMode.Copy) {
			expInfo.title = expInfo.title + " - Copy";
		}

		const title = PolicyUtil.getEditorTitle(mode);
		const dialog = this.sohoDialogService
			.modal(EditPolicyComponent, this.viewRef)
			.title(title)
			.id("lm-a-sp-edit-dialog")
			.suppressEnterKey(true)
			.afterClose((r: IDialogResult) => {
				this.isEditorOpen = false;
				if (r && r.value) {
					if (mode === PolicyEditorMode.Edit) {
						this.updateItem(r.value as IExpInfo);
					} else {
						this.refresh();
					}
				}
			});

		dialog
			.apply((component) => {
				component.modalDialog = dialog;
				component.attributes = this.attributes || [];
				component.mode = mode;
				component.policyEdit = expInfo;
			})
			.open();
	}

	usedByPages(): void {
		this.raiseNavigationEvent(AdminPages.DynamicPages);
	}

	usedByAnnouncements(): void {
		this.raiseNavigationEvent(AdminPages.Announcements);
	}

	raiseNavigationEvent(adminPage: AdminPages) {
		const event = this.createNavigationEventTarget(adminPage);
		if (event) {
			this.onNavigationEvent.emit(event);
		}
	}

	protected getColumns(): SohoDataGridColumn[] {
		return [
			this.getSelectionColumn(),
			{
				width: 745,
				id: "adm-pol-col-nm",
				field: "title",
				name: "Name",
				resizable: true,
				sortable: false,
			},
			{
				width: 200,
				id: "adm-pol-col-cd",
				field: "changeDate",
				name: "Change date",
				resizable: true,
				sortable: false,
				formatter: CustomFormatters.date,
			},
			{
				width: 250,
				id: "adm-pol-col-cb",
				field: "changedByName",
				name: "Changed by",
				resizable: true,
				sortable: false,
				formatter: CustomFormatters.displayName,
			},
		];
	}

	protected getEmptyMessage(): string {
		return "No policies found";
	}

	private createNavigationEventTarget(
		adminPage: AdminPages,
	): IAdminNavigationEvent {
		const item = this.getSelectedItem();
		if (!item) {
			return null;
		}
		// Raise event that someone else can handle
		const event: IAdminNavigationEvent = {
			adminPage: adminPage,
			entityId: item.expressionId,
			entityTitle: item.title,
		};
		return event;
	}

	private updateItem(expInfo: IExpInfo): void {
		const items = this.items;
		const index = ArrayUtil.indexByProperty(
			items,
			"expressionId",
			expInfo.expressionId,
		);
		if (index >= 0) {
			items[index] = expInfo;
			this.items = [...items];
			this.updateGridData();
		}
	}

	private createUniqueRequest(): IUniqueIdRequest {
		const selected = this.getSelectedItem() as IExpInfo;
		if (selected && !this.isBusy) {
			return { content: selected.expressionId };
		}
		return null;
	}

	private initGrid(): void {
		const options = this.defaultOptions();
		options.expandableRow = false;
		this.datagridOptions = options;
	}
}
