import { ArrayUtil, Log } from "lime";
import {
	Constants,
	DynamicContainerType,
	DynamicPageAreaKey,
	IAttributeInfo,
	IDynamicContainer,
	IDynamicEntity,
	IDynamicEntityLayout,
	IStringMap,
	IValidationInfo,
	ValidatorBase,
} from "lime/core";
import { AdminConstants, IExpInfo } from "../../service";
import { IDynamicPageAdmin } from "./core";

export class DynamicEntityValidator extends ValidatorBase<IDynamicEntity> {
	constructor(validations: IValidationInfo<IDynamicEntity>[]) {
		super(validations);
	}

	onValidate(item: IDynamicEntity): void {
		super.onValidate(item);
	}
}

export class DynamicPageSettingValidator extends DynamicEntityValidator {
	constructor() {
		super([
			{
				max: Constants.pageTitleLength,
				name: "t",
			},
			{
				max: Constants.pageDescriptionLength,
				name: "d",
				optional: true,
			},
		]);
	}
}

export interface IDynamicAppliesTo {
	tooltip: string;
	cellText: string;
	icon: string;
	iconClass: string;
}

export class DynamicUtil {
	static allUsersText = "All users";
	static noPolicyKey = "no-security-policy";
	static missingPolicyText = "Missing policy";
	static repairPageText =
		"This page contains missing policies. The affected content will be hidden until the policy " +
		"restrictions have been updated or cleared. You can also repair the page by using the repair action " +
		"after importing the missing policies.";

	static expAccessText(items: IExpInfo[]): string {
		const count = items ? items.length : 0;
		return DynamicUtil.accessText(count > 0 ? items[0].title : null, count);
	}

	static entityAccessText(
		entity: IDynamicEntity,
		accessTitles: IStringMap,
	): string {
		return DynamicUtil.idsAccessText(entity.ais, accessTitles);
	}

	static getAppliesTo(
		ids: string[],
		accessTitles: IStringMap,
	): IDynamicAppliesTo {
		return {
			tooltip: DynamicUtil.idsAccessToolTip(ids, accessTitles),
			cellText: DynamicUtil.idsAccessText(ids, accessTitles),
			icon: DynamicUtil.idsAccessIcon(ids, accessTitles),
			iconClass: DynamicUtil.idsAccessIconClass(ids, accessTitles),
		};
	}

	static idsAccessText(ids: string[], accessTitles: IStringMap): string {
		const count = ids ? ids.length : 0;
		let text: string = null;
		if (count > 0) {
			text = accessTitles[ids[0]] || DynamicUtil.missingPolicyText;
		}
		return DynamicUtil.accessText(text, count);
	}

	static idsAccessIcon(ids: string[], accessTitles: IStringMap): string {
		if (ids && ids.length > 0) {
			return this.hasMissingAccess(ids, accessTitles) ? "alert" : "locked";
		}
		return "url";
	}

	static idsAccessIconClass(ids: string[], accessTitles: IStringMap): string {
		return this.hasMissingAccess(ids, accessTitles) ? "icon-alert" : "";
	}

	static hasMissingAccess(ids: string[], accessTitles: IStringMap): boolean {
		return ids && ids.some((id) => !accessTitles[id]);
	}

	static idsAccessToolTip(ids: string[], accessTitles: IStringMap): string {
		if (!ids) {
			return null;
		}

		let toolTip = "";
		for (const id of ids) {
			if (toolTip.length > 0) {
				toolTip += ", ";
			}
			toolTip += accessTitles[id] || DynamicUtil.missingPolicyText;
		}

		return toolTip;
	}

	static entityErrorText(
		accessIds: string[],
		accessTitles: IStringMap,
	): string {
		const getMultipleErrorText = (adjective: string) => {
			return `One or more security policies are ${adjective}. ${AdminConstants.policyMissingOrInvalidText}`;
		};
		const getSingleErrorText = (adjective: string) => {
			return `This security policy is ${adjective}. ${AdminConstants.policyMissingOrInvalidText}`;
		};
		accessIds = accessIds || [];
		const count = accessIds.length;
		for (const aid of accessIds) {
			if (!accessTitles[aid]) {
				return count === 1
					? getSingleErrorText("no longer available")
					: getMultipleErrorText("no longer available or invalid");
			}
		}
		return count === 1
			? getSingleErrorText("invalid")
			: getMultipleErrorText("invalid");
	}

	static accessText(text: string, count: number): string {
		if (!text) {
			return this.allUsersText;
		}
		if (count > 1) {
			text += ", and " + (count - 1) + " more";
		}
		return text;
	}

	static getOperator(expressions: IExpInfo[]): string {
		let operator: string;
		if (expressions && expressions.length > 0) {
			operator = expressions[0].operator;
		}
		return operator || "||";
	}

	static toIds(expressions: IExpInfo[]): string[] {
		if (!expressions || !expressions.length) {
			return null;
		}

		const items = [];
		for (const expression of expressions) {
			items.push(expression.expressionId);
		}
		return items;
	}

	static toExpressions(
		entity: IDynamicEntity,
		accessTitles: IStringMap,
	): IExpInfo[] {
		const ids = entity.ais;
		if (!ids || ids.length == 0) {
			return null;
		}

		const items = [];
		for (const id of ids) {
			const title = accessTitles[id] || DynamicUtil.missingPolicyText;
			items.push({ title: title, expressionId: id });
		}
		return items;
	}

	static hasAccess(entity: IDynamicEntity): boolean {
		const items = entity.ais;
		return items && items.length > 0;
	}

	static containsAccess(entities: IDynamicEntity[], accessId: string): boolean {
		if (entities) {
			for (const entity of entities) {
				const ids = entity.ais;
				if (ids) {
					for (const id of ids) {
						if (id === accessId) {
							return true;
						}
					}
				}
			}
		}
		return false;
	}

	static getNewEntityId(container: IDynamicContainer): string {
		let id = container.ni;
		if (!(id >= 0)) {
			id = 0;
		}
		container.ni = id + 1;
		return id + "";
	}

	static isValidAreaTarget(
		page: IDynamicPageAdmin,
		sourceLayout: IDynamicEntityLayout,
		targetKey: DynamicPageAreaKey,
	): boolean {
		const container = ArrayUtil.itemByProperty(
			page.cts,
			"eid",
			sourceLayout.id,
		);
		if (container) {
			const widgets = container.ws;
			if (widgets) {
				for (const widget of widgets) {
					const bannerTargetLevel = widget.bl || 0;
					if (targetKey == "banner") {
						if (!(bannerTargetLevel == 1 || bannerTargetLevel == 2)) {
							// Banner must be supported for banner area (1 or 2)
							return false;
						}
					} else if (targetKey == "main") {
						if (bannerTargetLevel == 1) {
							// Banner only are not allowed in main area
							return false;
						}
					}
				}
			}
		}
		return true;
	}

	static formatProperty(info: IAttributeInfo): string {
		const name = info.name;
		if (info.type === "d") {
			// TODO Constant class for date type "d"
			return `{${name} | df}`;
		}
		return `{${name}}`;
	}

	static getComponentTypeLabel(
		type: DynamicContainerType,
		subType?: number,
	): string {
		let label = "";
		switch (type) {
			case DynamicContainerType.Image:
				label = "Image";
				break;
			case DynamicContainerType.Links: {
				if (subType === 1) {
					label = "Shortcuts";
				} else {
					label = "Link list";
				}
				break;
			}
			case DynamicContainerType.Text:
				label = "Text";
				break;
			case DynamicContainerType.Items:
				label = "Information";
				break;
			case DynamicContainerType.Widget:
				label = "Widget";
				break;
			case DynamicContainerType.Web:
				label = "Web";
				break;
			default:
				Log.error(`Invalid container type ${type}`);
		}

		return label;
	}
}
