import { Component, OnInit } from "@angular/core";
import { SohoModalDialogRef } from "ids-enterprise-ng";
import { DialogButtonType } from "lime";
import {
	CoreUtil,
	IEntityAccessDialogOptions,
	IOperationResponse,
	ModalDialogBase,
} from "lime/core";
import { AdminService } from "./service";

@Component({
	templateUrl: "./entity-access-dialog.html",
})
export class EntityAccessDialogComponent
	extends ModalDialogBase
	implements OnInit
{
	modalDialog: SohoModalDialogRef<EntityAccessDialogComponent>;
	parameter: IEntityAccessDialogOptions;
	accessOptions: IEntityAccessDialogOptions;
	isWidget: boolean;

	constructor(private adminService: AdminService) {
		super("EntityAccessDialogComponent");
	}

	ngOnInit(): void {
		const options = this.parameter;
		const access = options.access;
		options.access = access ? CoreUtil.copy(access) : [];
		this.accessOptions = options;
		this.initModalDialog();
	}

	save(): void {
		const options = this.accessOptions;

		if (options.access) {
			this.setBusy(true);
			this.setCanClose(false);
			const self = this;
			if (this.isWidget) {
				this.adminService
					.updateWidgetAccess({
						id: options.entityId,
						accessList: options.access,
					})
					.subscribe(
						(response: IOperationResponse) => {
							self.closeWithResult(DialogButtonType.Ok, response);
						},
						(response: IOperationResponse) => {
							self.adminService.handleError(response);
							self.setBusy(false);
							self.setCanClose(true);
						},
					);
			} else {
				this.adminService
					.updatePageAccess({
						pageId: options.entityId,
						access: options.access,
					})
					.subscribe(
						(response) => {
							self.closeWithResult(DialogButtonType.Ok, response);
						},
						(response: IOperationResponse) => {
							self.adminService.handleError(response);
							self.setBusy(false);
							self.setCanClose(true);
						},
					);
			}
		}
	}
}
