import {
	Component,
	NgZone,
	OnInit,
	ViewChild,
	ViewContainerRef,
} from "@angular/core";
import {
	SohoDataGridComponent,
	SohoMessageService,
	SohoModalDialogService,
	SohoSearchFieldComponent,
} from "ids-enterprise-ng";
import {
	ArrayUtil,
	CommonUtil,
	DialogButtonType,
	HtmlUtil,
	IAutocompleteEntity,
	IDialogResult,
} from "lime";
import {
	CommonDataService,
	Constants,
	CoreUtil,
	DialogResponseCode,
	EntityCategory,
	IImportOptions,
	IIntegerResponse,
	IOperationResponse,
	IPage,
	IPageListResponse,
	IStringMap,
	IUser,
	IUserListResponse,
	LanguageService,
	PrincipalType,
	Templates,
} from "lime/core";
import { CustomFormatters } from "../admin";
import { AdminListComponent } from "../admin-list.component";
import { AdminService } from "../service";

type SearchCategory = "user" | "pageTitle";

@Component({
	selector: "lm-admin-private-pages",
	templateUrl: "./private-pages.html",
})
export class AdminPrivatePagesComponent
	extends AdminListComponent<IPage>
	implements OnInit
{
	@ViewChild(SohoDataGridComponent, { static: false })
	privatePagesDataGrid: SohoDataGridComponent;
	@ViewChild(SohoSearchFieldComponent, { static: true })
	searchfield: SohoSearchFieldComponent;
	searchQuery: string;
	selectedUser: string;
	selectedUserEmail: string;
	selectedUserDisplayName: string;
	autocompleteSource: (
		value: string,
		done: (value: string, items: IUser[]) => void,
	) => void;
	autocompleteTemplate: string;

	selectedCategory: SearchCategory = "user";
	searchfieldOptions: SohoSearchFieldOptions;

	get isUserCategorySelected(): boolean {
		return this.selectedCategory === "user";
	}

	get isPageTitleCategorySelected(): boolean {
		return this.selectedCategory === "pageTitle";
	}

	get placeholder(): string {
		return this.isUserCategorySelected
			? "Search for a user"
			: "Search for a private page";
	}

	get showToolbar(): boolean {
		return this.showGrid;
	}

	get flexToolbarTitle(): string {
		if (this.isUserCategorySelected && this.selectedUser) {
			return `${this.selectedUserDisplayName} - ${this.selectedUserEmail}`;
		}
	}

	get showGrid(): boolean {
		if (this.isUserCategorySelected) {
			return !!this.selectedUser;
		}

		if (this.isPageTitleCategorySelected) {
			return !!this.query;
		}

		return false;
	}

	constructor(
		public adminService: AdminService,
		messageService: SohoMessageService,
		languageService: LanguageService,
		sohoDialogService: SohoModalDialogService,
		ngZone: NgZone,
		private commonDataService: CommonDataService,
		private readonly viewRef: ViewContainerRef,
	) {
		super(
			"AdminPrivatePagesComponent",
			"private page",
			messageService,
			languageService,
			adminService,
			sohoDialogService,
			ngZone,
		);

		this.initAutocomplete();
		this.initSearchFieldOptions();
		this.updateGridOptions();
	}

	ngOnInit(): void {
		if (this.selectedUser) {
			this.refresh();
		}
	}

	/**
	 * Lists private pages from cache or server.
	 *
	 * @param reload Boolean - True: load from server. False: load from cache.
	 */
	listItems(reload: boolean): void {
		if (this.isBusy) {
			return;
		}

		this.setBusy(true);
		if (reload) {
			this.items = [];
			this.updateGridData();
		}

		const content = this.isUserCategorySelected
			? this.selectedUser
			: this.searchQuery;
		const adminService = this.adminService;
		adminService
			.listPrivatePages(content, reload, this.isPageTitleCategorySelected)
			.subscribe(
				(r: IPageListResponse) => {
					this.onItems(r.content);
					this.updateGridData();
					this.setBusy(false);
				},
				(r: IOperationResponse) => {
					adminService.handleError(r);
					this.setBusy(false);
				},
			);
	}

	/**
	 * Import private pages.
	 */
	importPages(): void {
		const dialogTitle = "Import Private Pages";
		const adminService = this.adminService;
		const options: IImportOptions = {
			title: dialogTitle,
			operation: EntityCategory.privatePage.toString(),
		};
		const map: IStringMap = {};
		map.userId = this.selectedUser;
		options.formFields = map;

		adminService
			.openImportFilesDialog(options, this.viewRef)
			.subscribe((r: IDialogResult) => {
				const value = r.value;
				if (
					r.button === DialogButtonType.Yes &&
					value.responseCode === DialogResponseCode.Success
				) {
					this.adminService
						.showUploadCompleteDialog(dialogTitle, value.message)
						.subscribe((result: IDialogResult) => {
							if (result.button === DialogButtonType.Ok) {
								this.refresh();
							}
						});
				} else if (
					r.button === DialogButtonType.Yes &&
					value.responseCode === DialogResponseCode.Fail
				) {
					adminService.showUploadCompleteDialog(
						dialogTitle,
						value.message,
						true,
					);
				}
			});
	}

	/**
	 * Exports selected private pages.
	 */
	exportPages(): void {
		if (this.selectionCount === this.items.length) {
			this.exportAll();
		} else {
			const pagesToExport = this.getSelectedItems();
			this.adminService.exportPrivatePages(this.selectedUser, pagesToExport);
		}
	}

	/**
	 * Exports all private pages.
	 */
	exportAll(): void {
		this.adminService.exportPrivatePages(this.selectedUser);
	}

	deletePages(): void {
		const pagesToDelete = this.getSelectedItems();
		const options = this.adminService.getDeletePageOptions(
			pagesToDelete,
			true,
			this.isPageTitleCategorySelected,
		);

		this.showConfirm(options.title, options.message).subscribe(() => {
			this.deletePrivatePage(pagesToDelete);
		});
	}

	onSelected(event: Event): void {
		if (event[2]) {
			// Autocomplete item selected
			if (this.isUserCategorySelected) {
				this.onUserSelect(event);
			}
		} else {
			// Category selected
			this.onCategorySelected();
		}
	}

	private onCategorySelected(): void {
		const categories = this.searchfield.getCategoryData(true) || [];
		const category =
			categories[0].id === "autocomplete-private-pages-user"
				? "user"
				: "pageTitle";
		if (category !== this.selectedCategory) {
			this.selectedCategory = category;
			this.clearSearch();
			this.clearSelection();
			this.updateGridOptions();
		}
	}

	onSearch(): void {
		if (this.isPageTitleCategorySelected) {
			this.query = this.searchQuery;
			this.search();
		}
	}

	onUserSelect(event: Event): void {
		if (event[2]) {
			const object = event[2] as IAutocompleteEntity;
			if (
				CommonUtil.isUndefined(object) ||
				CommonUtil.isUndefined(object.value)
			) {
				return;
			}

			this.selectedUser = object.value as string;
			this.selectedUserEmail = object.info;
			this.selectedUserDisplayName = object.label;
			this.refresh();
		}
	}

	clearSearch() {
		this.searchQuery = null;
		this.selectedUser = null;
		this.selectedUserEmail = null;
		this.selectedUserDisplayName = null;
		this.clearSelection();
		if (this.isPageTitleCategorySelected) {
			super.clearSearch(false);
		}
	}

	protected getDataGrid(): SohoDataGridComponent {
		return this.privatePagesDataGrid;
	}

	private onItems(content: IPage[]): void {
		this.items = content;
		this.items.forEach((item) => {
			if (this.isUserCategorySelected) {
				item.data.title = HtmlUtil.escapeStringForHtml(item.data.title);
			} else {
				item.title = HtmlUtil.escapeStringForHtml(item.title);
			}
		});
	}

	/**
	 * Deletes provided private page IDs.
	 *
	 * @param pages Pages to be deleted.
	 */
	private deletePrivatePage(pages: IPage[]): void {
		const content = pages.map((page) => {
			return this.isUserCategorySelected ? page.data.id : page.title;
		});

		this.setBusy(true);
		this.adminService
			.deletePrivatePages(content, this.isPageTitleCategorySelected)
			.subscribe(
				(r: IIntegerResponse) => {
					this.setBusy(false);
					if (r.content > 0) {
						this.refresh();

						if (this.isPageTitleCategorySelected) {
							const options =
								this.adminService.getPageDeletedForUsersConfirmationOptions(
									content[0],
									r.content,
								);
							this.showMessage(options.title, options.message);
						}
					}
				},
				(e: IOperationResponse) => {
					this.adminService.handleError(e);
					this.setBusy(false);
				},
			);
	}

	private initAutocomplete(): void {
		this.autocompleteSource = (
			value: string,
			done: (value: string, items: IUser[]) => void,
		) => {
			this.onAutoComplete(value, done);
		};
		this.autocompleteTemplate = Templates.autocompleteEntity;
	}

	private onAutoComplete(
		value: string,
		done: (value: string, items: IUser[]) => void,
	): void {
		if (this.isPageTitleCategorySelected) {
			return;
		}
		const query = value.trim();
		if (!query) {
			done(value, []);
			return;
		}

		this.commonDataService.searchUsers(query).subscribe(
			(response: IUserListResponse) => {
				done(
					query,
					ArrayUtil.sortByProperty(
						CoreUtil.getEntityArray(PrincipalType.User, response.content),
						"label",
					),
				);
			},
			(r: IOperationResponse) => {
				this.commonDataService.handleError(r);
			},
		);
	}

	private initSearchFieldOptions(): void {
		this.searchfieldOptions = {
			filterMode: "contains",
			attributes: [{ name: "name", value: "lm-a-private-pages-search" }],
			clearable: true,
			showCategoryText: true,
			showAllResults: false,
			categories: [
				{ id: "autocomplete-private-pages-user", name: "User", checked: true },
				{
					id: "autocomplete-private-pages-pageTitle",
					name: "Page Title",
					checked: false,
				},
			],
		};
	}

	private updateGridOptions(): void {
		const options = this.isUserCategorySelected
			? this.defaultGridOptions
			: this.pageCountGridOptions;
		this.datagridOptions = {
			...options,
			emptyMessage: {
				title: "No private pages found",
				icon: Constants.adminEmptyDatagridIcon,
			},
		};
	}

	private get defaultGridOptions(): SohoDataGridOptions {
		const rowTemplate =
			'<div class="datagrid-cell-layout"><span class="datagrid-textarea lm-white-space-normal">{{data.description}}</span></div>';
		return {
			selectable: "multiple" as SohoDataGridSelectable,
			rowTemplate: rowTemplate,
			filterable: true,
			disableRowDeactivation: true,
			clickToSelect: false,
			columns: [
				this.getSelectionColumn(),
				{
					width: 595,
					id: "adm-pp-col-t",
					field: "data.title",
					name: "Title",
					resizable: true,
					sortable: true,
					filterType: "text",
					formatter: Formatters.Expander,
				},
				{
					width: 200,
					id: "adm-pp-col-on",
					field: "data.ownerName",
					name: "Owner",
					resizable: true,
					sortable: true,
					filterType: "text",
					formatter: CustomFormatters.displayName,
				},
				{
					width: 200,
					id: "adm-pp-col-cd",
					field: "data.changeDate",
					name: "Change date",
					resizable: true,
					sortable: true,
					filterType: "text",
					formatter: CustomFormatters.date,
				},
				{
					width: 200,
					id: "adm-pp-col-cbn",
					field: "data.changedByName",
					name: "Changed by",
					resizable: true,
					sortable: true,
					filterType: "text",
					formatter: CustomFormatters.displayName,
				},
			],
		};
	}

	private get pageCountGridOptions(): SohoDataGridOptions {
		return {
			selectable: "single",
			stretchColumn: "adm-pp-col-t",
			columns: [
				this.getSelectionColumn(),
				{
					id: "adm-pp-col-t",
					field: "title",
					name: "Title",
					sortable: false,
				},
				{
					width: 250,
					id: "adm-pp-col-count",
					field: "popularity",
					name: "Number of pages",
					sortable: false,
				},
			],
		};
	}
}
