import { Component, OnInit } from "@angular/core";
import {
	ErrorInfo,
	IOperationResponse,
	IStringMap,
	MessageInfo,
	ModalDialogBase,
} from "lime/core";
import {
	AdminConstants,
	AdminService,
	IAdminOperationResponse,
} from "../../service";
import { DynamicPageAdminService } from "./service";

@Component({
	templateUrl: "./dynamic-page-import-dialog.html",
})
export class DynamicPageImportDialog extends ModalDialogBase implements OnInit {
	pageId: string;
	pageIdMap: IStringMap = {};
	title: string;
	operation: string;
	statusMessageList: MessageInfo[];
	errorMessageList: ErrorInfo[];
	isImporting = false;
	isCancelled = false;

	constructor(
		public dynamicPageAdminService: DynamicPageAdminService,
		public adminService: AdminService,
	) {
		super("DynamicPageImportDialog");
		this.clearMessages();
	}

	ngOnInit(): void {
		if (this.pageId != null) {
			this.pageIdMap[AdminConstants.entityIdKey] = this.pageId;
		}
		this.initModalDialog();
		this.importData();
	}

	cancel(): void {
		if (this.isCancelled) {
			return;
		}
		this.isCancelled = true;
		this.dynamicPageAdminService.cancelOperation().subscribe(
			(r: IAdminOperationResponse) => {
				// Nothing to process here since cancel status won't be returned from server
			},
			(r: IOperationResponse) => {
				this.isImporting = false;
				this.adminService.showUploadCompleteDialog(
					"Error",
					r.toErrorLog(),
					true,
				);
			},
		);
	}

	close(): void {
		this.setCanClose(true);
		this.modalDialog.close(this.errorMessageList.length === 0);
	}

	private clearMessages(): void {
		this.statusMessageList = [];
		this.errorMessageList = [];
	}

	private checkStatus(callback?: () => void): void {
		const self = this;
		self.dynamicPageAdminService.getOperationStatus().subscribe(
			(r: IAdminOperationResponse) => {
				const content = r.content;

				if (content && content.messageList) {
					self.statusMessageList = content.messageList;
				}

				if (content && content.isRunning) {
					this.isCancelled = false;
					setTimeout(
						() => self.checkStatus(callback),
						AdminConstants.checkStatusInterval,
					);
				} else {
					self.isImporting = false;
					if (callback) {
						callback();
					}
				}
			},
			(r: IOperationResponse) => {
				const content = r.content;
				if (content && content.messageList) {
					self.statusMessageList = content.messageList;
				}
				if (r.errorList) {
					self.errorMessageList = r.errorList;
				}

				// Keep polling if operation is still active, errors may occur during e.g. import
				if (content.isRunning) {
					setTimeout(
						() => self.checkStatus(callback),
						AdminConstants.checkStatusInterval,
					);
				} else {
					self.isImporting = false;
					if (callback) {
						callback();
					}
				}
			},
		);
	}

	private importData(): void {
		const self = this;
		self.isImporting = true;

		this.submitSafe(
			self.dynamicPageAdminService.startImportOperation(self.pageIdMap),
			true,
			true,
		).subscribe(
			(r: IAdminOperationResponse) => {
				const content = r.content;
				if (content.isRunning) {
					if (content.messageList) {
						self.statusMessageList = content.messageList;
					}
					self.checkStatus();
				} else {
					self.isImporting = false;
				}
			},
			(r: IOperationResponse) => {
				self.isImporting = false;
				self.adminService.showUploadCompleteDialog(
					"Import Error",
					r.toErrorLog(),
					true,
				);
			},
		);
	}
}
