import {
	ICatalogRequest,
	ICatalogResponse,
	IDynamicContainer,
	IDynamicEntity,
	IDynamicEntityHandle,
	IDynamicPageLayout,
	IDynamicPageSetting,
	IOperationResponse,
} from "lime/core";

export interface IDynamicPageRequestAdmin {
	page?: IDynamicPageAdmin;
	container?: IDynamicContainer;
	setting?: IDynamicPageSetting;
	createAccessIds?: string[];
	deleteAccessIds?: string[];
	contentArea?: string;
	contentIndex?: number;
}

export interface IDynamicPageResponseAdmin extends IOperationResponse {
	page?: IDynamicPageAdmin;
	container?: IDynamicContainer;
	setting?: IDynamicPageSetting;
	accesses?: IDynamicAccess[];
	deletedAccessIds?: string[];
}

export interface IDynamicPublishRequest extends IOperationResponse {
	pid: string;
	accs: IDynamicAccess[];
}

export interface IDynamicPageListRequest extends ICatalogRequest {
	expressionId?: string;
}

export interface IDynamicPageListResponse extends ICatalogResponse {
	content: IDynamicPageInfo[];
	count: number;
	maxCountAllowed: number;
}

export interface IDynamicPageInfoResponseAdmin extends IOperationResponse {
	content: IDynamicPageInfo;
}

export interface IDynamicContainerResponseAdmin extends IOperationResponse {
	container: IDynamicContainer;
	access: IDynamicAccess;
}

export interface IDynamicSettingResponseAdmin extends IOperationResponse {
	setting: IDynamicPageSetting;
}

export interface IDynamicAccessResponseAdmin extends IOperationResponse {
	access: IDynamicAccess;
}

export enum DynamicPageState {
	Draft = 1,
	Published = 2,
	PublishedEdited = 3,
}

export interface IDynamicPageInfo {
	pageId: string;
	title: string;
	description: string;
	changedBy: string;
	changedByName: string;
	changeDate: string;
	state?: DynamicPageState;
	lock?: number;
	lockedByUser?: boolean;

	/**
	 * Gets or sets the page access for restricted (non public) pages.
	 * This property is not used in lists.
	 */
	accesses?: IDynamicAccess[];
}

export interface IDynamicAdminEntity extends IDynamicEntity {
	/**
	 * Entity type
	 */
	et?: number; // TODO: Add more specific type/enum

	/**
	 * Changed by
	 */
	cb?: string;

	/**
	 * Change date
	 */
	cd?: string;
}

export interface IDynamicPage extends IDynamicAdminEntity {
	/**
	 * Containers
	 */
	cts?: Array<IDynamicAdminEntity>;

	/**
	 * Settings
	 */
	sets?: Array<IDynamicAdminEntity>;
}

export interface IDynamicPageAdmin extends IDynamicAdminEntity {
	/**
	 * Layout
	 */
	ly?: IDynamicPageLayout;

	/**
	 * Containers
	 */
	cts?: IDynamicContainer[];

	/**
	 * Accesss
	 */
	accs?: IDynamicAccess[];

	/**
	 * Settings
	 */
	sets?: IDynamicPageSetting[];

	/**
	 * Settings order
	 */
	seto?: IDynamicEntityHandle[];

	/**
	 * Languages that have been translated on the page itself or any of its children.
	 */
	lngs?: string[];

	/**
	 * Set by the client to handle the page as a read only page for the support user role.	 *
	 */
	isReadOnly?: boolean;
}

export interface IDynamicAccess {
	id?: string;

	/**
	 * Expression ID
	 */
	exid?: string;

	/**
	 * Access scope
	 */
	as?: number;

	/**
	 * Title
	 */
	t?: string;

	/**
	 * Error code
	 */
	ec?: number;
}
