import { Component, ViewChild, ViewContainerRef } from "@angular/core";
import {
	SohoColorPickerComponent,
	SohoMessageService,
	SohoModalDialogService,
} from "ids-enterprise-ng";
import { CommonUtil, StringUtil } from "lime";
import {
	Constants,
	CoreUtil,
	DynamicColorType,
	DynamicItemSettingsDialog,
	IAttributeInfo,
	IDynamicContainer,
	IDynamicEntityLocalization,
	IDynamicHeader,
	UIUtil,
} from "lime/core";
import { IExpInfo } from "../../../../../../service";
import { DynamicPageAdminService } from "../../../../service";
import { DynamicUtil } from "../../../../util";
import { UserPropertiesListDialog } from "../../../user-properties-dialog";

@Component({
	templateUrl: "./add-header-dialog.html",
	styleUrls: ["./add-header-dialog.scss"],
})
export class DynamicInformationHeaderDialog extends DynamicItemSettingsDialog {
	@ViewChild("dialogViewContRef", { read: ViewContainerRef, static: false })
	dialogViewContRef: ViewContainerRef;
	@ViewChild(SohoColorPickerComponent, { static: false })
	colorpicker: SohoColorPickerComponent;

	listLabel = "Choose which set of users this header should be visible for.";
	propertyRegex = /^{[^{}]*?}$/;
	selectedExpressions: IExpInfo[];
	expressions: IExpInfo[];
	isEdit: boolean;
	container: IDynamicContainer;
	oldHeader: IDynamicHeader;
	header: IDynamicHeader;
	colorTypes = DynamicColorType;
	colorpickerOptions = UIUtil.getColorpickerOptionsExtended();
	selectedColorNr: number;
	selectedColorHex: string;
	imgMaxLength = Constants.dynPageUrlMaxLength;

	headingStrategies = HeadingStrategy;
	h1Strategy: HeadingStrategy;
	h2Strategy: HeadingStrategy;

	propertyField = PropertyField;
	imgText: string;
	h1Text: string;
	h1Property: string;
	h2Text: string;
	h2Property: string;
	inputMaxLength = Constants.dynPageDefaultMaxLength;

	constructor(
		public dynamicPageService: DynamicPageAdminService,
		private sohoModalDialogService: SohoModalDialogService,
		sohoMessageService: SohoMessageService,
	) {
		super("DynamicInformationHeaderDialog", sohoMessageService);
	}

	ngOnInit() {
		this.initLocalizations();
		if (this.isEdit) {
			this.header = {
				...this.header,
			};
		} else {
			this.header = {
				clt: this.colorTypes.None,
				eid: DynamicUtil.getNewEntityId(this.container),
				im: {
					u: null,
				},
				...this.header,
			};
		}

		// Need an item for localizations.
		this.item = {
			eid: this.header.eid,
		};

		this.setInitialValues();
		this.selectedColorNr
			? this.setColorToHex(this.selectedColorNr)
			: this.setColorToHex(0);
		this.initModalDialog();
	}

	ngAfterViewInit() {
		// TODO remove when IDS issue #257 is resolved
		if (this.colorpicker) {
			setTimeout(() => {
				this.colorpicker.disabled = this.disabledColorPicker();
			}, 100);
		}
	}

	disabledColorPicker(): boolean {
		return this.header.clt !== this.colorTypes.Custom;
	}

	save() {
		if (!this.isEditable) {
			return;
		}

		if (!this.header.eid) {
			this.header.eid = DynamicUtil.getNewEntityId(this.container);
		}
		const headerCopy = this.getHeaderForSave();
		if (this.expressions) {
			headerCopy.as = 1;
			headerCopy.ais = DynamicUtil.toIds(this.expressions);
			headerCopy.op = DynamicUtil.getOperator(this.expressions);
		} else if (this.selectedExpressions) {
			headerCopy.as = null;
			headerCopy.ais = null;
		}

		const updatedContainer = CoreUtil.copy(this.container);
		const hasInvalidOldTranslations = this.hasInvalidTranslations(
			updatedContainer.lzn,
		);
		if (this.itemLznEdited) {
			const newTranslations = this.getContainerLocalizations(
				this.itemLznEdited,
				headerCopy.eid,
			);
			if (hasInvalidOldTranslations) {
				const invalidOldTranslations = this.getInvalidTranslations(
					updatedContainer.lzn,
				);
				updatedContainer.lzn = {
					...invalidOldTranslations,
					...newTranslations,
				};
			} else {
				updatedContainer.lzn = newTranslations;
			}
		} else if (hasInvalidOldTranslations) {
			updatedContainer.lzn = this.getInvalidTranslations(updatedContainer.lzn);
		} else {
			updatedContainer.lzn = null;
		}

		if (this.hasInvalidTranslations(updatedContainer.lzn)) {
			this.showConfirmDiscardTranslations().subscribe(
				() => {
					this.deleteTranslations(updatedContainer.lzn);
					this.performSave(updatedContainer, headerCopy);
				},
				null,
				() => this.setCanClose(true),
			);
		} else {
			this.performSave(updatedContainer, headerCopy);
		}
	}

	performSave(updatedContainer: IDynamicContainer, headerCopy: IDynamicHeader) {
		if (this.isEdit) {
			this.submitSafe(
				this.dynamicPageService.editContainerEntityWithLocalization(
					updatedContainer,
					headerCopy,
					this.oldHeader,
					this.container,
					true,
				),
				false,
				true,
			).subscribe(() => this.modalDialog.close(headerCopy));
		} else {
			this.submitSafe(
				this.dynamicPageService.addContainerEntity(
					updatedContainer,
					headerCopy,
					true,
					this.container,
				),
				false,
				true,
			).subscribe(() => this.modalDialog.close(headerCopy));
		}
	}

	openUserPropertyDialog(field: PropertyField, element?: HTMLInputElement) {
		const dialog = this.sohoModalDialogService
			.modal(UserPropertiesListDialog, this.dialogViewContRef)
			.title("Select User Property")
			.id("lm-a-dp-info-h-selectprop-dialog")
			.afterClose((selected?: IAttributeInfo) => {
				if (selected) {
					this.applyUserProperty(selected, field, element);
				}
			});

		dialog
			.apply((comp) => {
				comp.modalDialog = dialog;
			})
			.open();
	}

	onTabChange(): void {
		if (!this.optionsItems) {
			this.optionsItems = [];
		}
		this.updateH1OptionsItem();
		this.updateH2OptionsItem();
		this.optionsItems = [...this.optionsItems];
		this.isTranslateable = this.hasH1() || this.hasH2();
	}

	updateH1OptionsItem(): void {
		const h1LznItemIndex = this.getTranslationItemIndex("h1");
		const hasH1LznItem = h1LznItemIndex > -1;
		if (this.hasH1()) {
			if (!hasH1LznItem) {
				// Heading should be first in the array.
				this.optionsItems.unshift({
					name: "h1",
					label: "Heading",
					labelId: "lm-a-dp-aeh-at-h1-lbl",
					valueId: "lm-a-dp-aeh-at-h1-inp",
					maxLength: this.inputMaxLength,
					defaultValue: this.h1Text,
					isRequired: false,
				});
			} else {
				this.optionsItems[h1LznItemIndex].defaultValue = this.h1Text;
			}
		} else if (hasH1LznItem) {
			this.removeTranslationItem("h1");
		}
	}

	updateH2OptionsItem(): void {
		const h2LznItemIndex = this.getTranslationItemIndex("h2");
		const hasH2LznItem = h2LznItemIndex > -1;
		if (this.hasH2()) {
			if (!hasH2LznItem) {
				// Subheading should be last in the array.
				this.optionsItems.push({
					name: "h2",
					label: "Subheading",
					labelId: "lm-a-dp-aeh-at-h2-lbl",
					valueId: "lm-a-dp-aeh-at-h2-inp",
					maxLength: this.inputMaxLength,
					defaultValue: this.h2Text,
					isRequired: false,
				});
			} else {
				this.optionsItems[h2LznItemIndex].defaultValue = this.h2Text;
			}
		} else if (hasH2LznItem) {
			this.removeTranslationItem("h2");
		}
	}

	hasH1(): boolean {
		return !!this.h1Text && this.h1Strategy === HeadingStrategy.Text;
	}

	hasH2(): boolean {
		return !!this.h2Text && this.h2Strategy === HeadingStrategy.Text;
	}

	getEmptyTranslateablePropertyNames(): string[] {
		const properties = [];
		if (!this.hasH1()) {
			properties.push("h1");
		}
		if (!this.hasH2()) {
			properties.push("h2");
		}
		return properties;
	}

	hasInvalidTranslation(lang: IDynamicEntityLocalization): boolean {
		const hasTranslation = lang.its && lang.its[this.item.eid];
		if (hasTranslation) {
			const hasH1Translation =
				lang.its[this.item.eid].h1 && lang.its[this.item.eid].h1.length;
			if (!this.hasH1() && hasH1Translation) {
				return true;
			}
			const hasH2Translation =
				lang.its[this.item.eid].h2 && lang.its[this.item.eid].h2.length;
			if (!this.hasH2() && hasH2Translation) {
				return true;
			}
		}
		return false;
	}

	private setColorToHex(colorNr: number) {
		this.selectedColorHex = UIUtil.numberToHexCodeExtended(colorNr);
	}

	private setColorToNumber() {
		this.selectedColorHex = this.colorpicker.getHexValue();
		this.selectedColorNr = UIUtil.hexCodeToNumberExtended(
			this.selectedColorHex,
		);
	}

	private applyUserProperty(
		info: IAttributeInfo,
		field: PropertyField,
		element?: HTMLInputElement,
	) {
		const propertyName = DynamicUtil.formatProperty(info);
		switch (field) {
			case PropertyField.Image:
				if (element) {
					this.imgText = this.applyUserPropertyAtCaret(
						propertyName,
						this.imgText,
						element,
					);
				} else {
					this.logDebug(
						"applyUserProperty: Input component for html field is undefined.",
					);
				}
				break;
			case PropertyField.h1:
				if (element) {
					this.h1Text = this.applyUserPropertyAtCaret(
						propertyName,
						this.h1Text,
						element,
					);
				} else {
					this.h1Property = propertyName;
				}
				break;
			case PropertyField.h2:
				if (element) {
					this.h2Text = this.applyUserPropertyAtCaret(
						propertyName,
						this.h2Text,
						element,
					);
				} else {
					this.h2Property = propertyName;
				}
				break;
			default:
				this.logDebug(
					"applyUserProperty: Could not determine which field to update.",
				);
		}
	}

	private applyUserPropertyAtCaret(
		propertyName: string,
		item: string,
		element: HTMLInputElement,
	): string {
		if (!item) {
			return propertyName;
		}
		const startIndex = element.selectionStart;
		const endIndex = element.selectionEnd;
		if (
			CommonUtil.isUndefined(startIndex) &&
			CommonUtil.isUndefined(endIndex)
		) {
			return item.slice(0, startIndex) + propertyName + item.slice(endIndex);
		}
		return item + propertyName;
	}

	private getHeaderForSave(): IDynamicHeader {
		const headerCopy = CoreUtil.copy(this.header);

		if (this.imgText) {
			headerCopy.im = { u: this.imgText };
		} else {
			headerCopy.im = null;
		}
		headerCopy.h1 =
			this.h1Strategy === HeadingStrategy.Text
				? this.h1Text
				: this.h1Strategy === HeadingStrategy.Property
				  ? this.h1Property
				  : undefined;
		headerCopy.h2 =
			this.h2Strategy === HeadingStrategy.Text
				? this.h2Text
				: this.h2Strategy === HeadingStrategy.Property
				  ? this.h2Property
				  : undefined;
		if (headerCopy.clt === this.colorTypes.Custom) {
			this.setColorToNumber();
			headerCopy.cl = this.selectedColorNr;
		}
		return headerCopy;
	}

	private setInitialValues() {
		if (this.header.im) {
			this.imgText = this.header.im.u;
		}
		// H1
		const h1 = this.header.h1;
		if (StringUtil.isNullOrWhitespace(h1)) {
			this.h1Strategy = HeadingStrategy.None;
		} else if (h1.match(this.propertyRegex)) {
			this.h1Property = h1;
			this.h1Strategy = HeadingStrategy.Property;
		} else {
			this.h1Text = h1;
			this.h1Strategy = HeadingStrategy.Text;
		}

		// H2
		const h2 = this.header.h2;
		if (StringUtil.isNullOrWhitespace(h2)) {
			this.h2Strategy = HeadingStrategy.None;
		} else if (h2.match(this.propertyRegex)) {
			this.h2Property = h2;
			this.h2Strategy = HeadingStrategy.Property;
		} else {
			this.h2Text = h2;
			this.h2Strategy = HeadingStrategy.Text;
		}
	}

	private formatProperty(property: string): string {
		return `{${property}}`;
	}
}

export enum HeadingStrategy {
	None = 1,
	Text,
	Property,
}

export enum PropertyField {
	Image = 1,
	h1,
	h2,
}
