import { Component, NgZone, OnInit, ViewChild } from "@angular/core";
import {
	SohoDataGridComponent,
	SohoMessageService,
	SohoModalDialogRef,
	SohoModalDialogService,
} from "ids-enterprise-ng";
import { ArrayUtil, DialogService } from "lime";
import { ArchiveType, EntityFilter, LanguageService } from "lime/core";
import { CustomFormatters } from "../../admin";
import { AdminListComponent } from "../../admin-list.component";
import { AdminContext, AdminService } from "../../service";
import {
	DynamicPageState,
	IDynamicPageInfo,
	IDynamicPageListRequest,
	IDynamicPageListResponse,
} from "../dyn/core";
import { DynamicPageAdminService } from "../dyn/service";

@Component({
	templateUrl: "./selector.html",
})
export class ArchiveSelectorDialog
	extends AdminListComponent<IDynamicPageInfo>
	implements OnInit
{
	@ViewChild("entityDatagrid", { static: false })
	dataGrid: SohoDataGridComponent;

	archiveType: ArchiveType;
	dialog: SohoModalDialogRef<ArchiveSelectorDialog>;
	title: string;

	constructor(
		messageService: SohoMessageService,
		languageService: LanguageService,
		adminService: AdminService,
		sohoModalDialogService: SohoModalDialogService,
		zone: NgZone,
		public dynamicPageService: DynamicPageAdminService,
		private readonly adminContext: AdminContext,
		private readonly dialogService: DialogService,
	) {
		super(
			"ArchiveSelectorDialog",
			"page",
			messageService,
			languageService,
			adminService,
			sohoModalDialogService,
			zone,
			{
				isFilter: true,
				isOwnerFilter: false,
				isOtherUserFilter: false,
				isRestrictionFilter: false,
				filters: [
					{
						name: "Checked out",
						propertyName: "lock",
						value: 1,
						type: EntityFilter.Custom,
					},
					{
						name: "Draft",
						propertyName: "state",
						value: DynamicPageState.Draft,
						type: EntityFilter.Custom,
					},
					{
						name: "Published",
						propertyName: "state",
						value: DynamicPageState.Published,
						type: EntityFilter.Custom,
					},
					{
						name: "Published (Edited)",
						propertyName: "state",
						value: DynamicPageState.PublishedEdited,
						type: EntityFilter.Custom,
					},
				],
			},
		);
	}

	getDataGrid(): SohoDataGridComponent {
		return this.dataGrid;
	}

	ngOnInit(): void {
		const tool = this.adminContext.get();
		if (tool) {
			this.currentUser = tool.userId;
		}
		this.initGrid();
		this.refresh();
	}

	closeWithSelected(selected: any): void {
		this.dialog.close(selected);
	}

	listItems(reload: boolean): void {
		// Add more archive types if implemented
		switch (this.archiveType) {
			case ArchiveType.DynamicPage:
				this.listDynamicPages(reload);
				break;
			default:
				this.logDebug(`listItems: Unknown archive type: ${this.archiveType}`);
				break;
		}
	}

	listDynamicPages(reload: boolean): void {
		const request = this.createRequest(reload) as IDynamicPageListRequest;
		if (!request) {
			return;
		}

		const observable = this.dynamicPageService.listPages(request);
		this.withBusy(observable).subscribe(
			(response: IDynamicPageListResponse) => {
				this.addItems(response.content, response.paging);
			},
			(r: IDynamicPageListResponse) => {
				this.onError(r);
			},
		);
	}

	getTitle(): string {
		// Add more titles if other archive types are implemented
		switch (this.archiveType) {
			case ArchiveType.DynamicPage:
				return this.getTitleDynamicPage();
			default:
				this.logDebug(`getTitle: Unknown archive type: ${this.archiveType}`);
				return "";
		}
	}

	checkOutPage(page: IDynamicPageInfo) {
		this.logDebug(`Checking out page ${page.pageId}`);
		const title = "Check out";
		const observable = this.dynamicPageService.checkOutPage(page.pageId);
		this.withBusy(observable).subscribe(
			(response) => {
				this.updateSelected(response.content);
				this.showToast(title, `'${page.title}' was checked out.`);
			},
			() => {
				this.showError(title, "Unable to check out page.");
			},
		);
	}

	protected getColumns(): SohoDataGridColumn[] {
		return [
			this.getSelectionColumn(),
			{
				width: 205,
				id: "lm-a-arc-sel-col-t",
				field: "title",
				name: "Title",
				sortable: false,
				resizable: true,
			},
			{
				width: 304,
				id: "lm-a-arc-sel-col-d",
				field: "description",
				name: "Description",
				sortable: false,
				resizable: true,
			},
			{
				width: 200,
				id: "lm-a-arc-sel-col-cd",
				field: "changeDate",
				name: "Change date",
				sortable: false,
				resizable: true,
				formatter: CustomFormatters.date,
			},
			{
				width: 173,
				id: "lm-a-arc-sel-col-cbn",
				field: "changedByName",
				name: "Changed by",
				sortable: false,
				resizable: true,
				formatter: CustomFormatters.displayName,
			},
			{
				width: 173,
				id: "lm-a-arc-sel-col-lbn",
				field: "",
				name: "Checked out by",
				sortable: false,
				resizable: true,
				formatter: (row, cell, value, col) => {
					const item = this.items[row];
					return item && item.lock === 1
						? CustomFormatters.displayName(null, null, item.changedByName, null)
						: "";
				},
			},
			{
				width: 140,
				id: "lm-a-arc-sel-col-s",
				field: "state",
				name: "Status",
				sortable: false,
				resizable: true,
				formatter: CustomFormatters.dynamicPageStatus,
			},
		];
	}

	protected getEmptyMessage(): string {
		return "No dynamic pages found";
	}

	private initGrid(): void {
		// Add more archive types if implemented
		switch (this.archiveType) {
			case ArchiveType.DynamicPage:
				this.initDynamicPagesGrid();
				break;
			default:
				this.logDebug(`initGrid: Unknown archive type: ${this.archiveType}`);
				break;
		}
	}

	private getTitleDynamicPage(): string {
		const selected = this.selected;
		if (selected && selected.lock === 1 && !selected.lockedByUser) {
			return "This page has been checked out by another user";
		} else if (selected && selected.lock !== 1) {
			return "You need to check out the page before you can restore the archive";
		} else if (selected && selected.lockedByUser) {
			return "Press OK to restore the archive on this page";
		}
		return "";
	}

	private showToast(title: string, message: string): void {
		this.dialogService.showToast({
			title: title,
			message: message,
		});
	}

	private updateSelected(info: IDynamicPageInfo): void {
		const index = ArrayUtil.indexByProperty(this.items, "pageId", info.pageId);
		if (index < 0) {
			return;
		}

		this.items[index] = info;
		this.dataGrid.updateRow(index, info);

		// Update selection in base class manually for now
		this.selectItem(info);
	}

	private initDynamicPagesGrid(): void {
		const options = this.defaultOptions();
		options.selectable = "single" as SohoDataGridSelectable;
		options.rowHeight = "medium" as SohoDataGridRowHeight;
		options.expandableRow = false;
		this.datagridOptions = options;
	}
}
