import { Injectable } from "@angular/core";
import { AdminPages, CoreBase } from "lime/core";
import { map } from "rxjs/operators";
import { AdminContext, IAdminTool } from "./service";

/**
 * This service is used to find out whether an Admin page is accessible to the user.
 * For instance determine if it should be possible to navigate to the page, and whether it is editable.
 */
@Injectable({
	providedIn: "root",
})
export class AdminAccessService extends CoreBase {
	private pages = new Map<AdminPages, IAccessPage>([
		[AdminPages.Home, new UnrestrictedPage()],
		[AdminPages.Settings, new AdminOnlyPage()],
		[AdminPages.Features, new AdminOnlyPage()],
		[AdminPages.Properties, new AdminOnlyPage()],
		[AdminPages.PrivatePages, new AdminOnlyPage()],
		[AdminPages.PublishedPages, new UnrestrictedPage()],
		[AdminPages.StandardPages, new AdminOnlyPage()],
		[AdminPages.DynamicPages, new UnrestrictedPage()],
		[AdminPages.Archive, new UnrestrictedPage()],
		[AdminPages.PublishedWidgets, new UnrestrictedPage()],
		[AdminPages.StandardWidgets, new AdminOnlyPage()],
		[AdminPages.TenantWidgets, new AdminOnlyPage()],
		[AdminPages.EarlyAccessWidgets, new AdminOnlyPage()],
		[AdminPages.FeaturedPages, new UnrestrictedPage()],
		[AdminPages.FeaturedWidgets, new UnrestrictedPage()],
		[AdminPages.FeaturedBannerWidgets, new UnrestrictedPage()],
		[AdminPages.Tags, new UnrestrictedPage()],
		[AdminPages.Announcements, new UnrestrictedPage()],
		[AdminPages.SecurityPolicies, new ReadOnlyPage()],
		[AdminPages.Import, new AdminOnlyPage()],
		[AdminPages.Export, new AdminOnlyPage()],
		[AdminPages.BulkDelete, new AdminOnlyPage()],
	]);

	constructor(private context: AdminContext) {
		super("AdminAccessService");
	}

	/**
	 * Evaluate whether a page is readable by the user.
	 */
	readable(page: AdminPages) {
		return this.context.tool$.pipe(
			map((tool) => this.pages.get(page).isReadable(tool)),
		);
	}

	/**
	 * Evaluate whether a page is editable by the user.
	 */
	editable(page: AdminPages) {
		return this.context.tool$.pipe(
			map((tool) => this.pages.get(page).isEditable(tool)),
		);
	}
}

interface IAccessPage {
	isReadable(tool: IAdminTool): boolean;
	isEditable(tool: IAdminTool): boolean;
}

/**
 * A page that is only accessible to Administrators.
 */
class AdminOnlyPage implements IAccessPage {
	isReadable(tool: IAdminTool) {
		return tool.isAdministrator;
	}
	isEditable(tool: IAdminTool) {
		return tool.isAdministrator;
	}
}

/**
 * A page that is accessible to both Administrators, Support users and ContentAdministrators
 */
class UnrestrictedPage implements IAccessPage {
	isReadable(tool: IAdminTool) {
		return (
			tool.isPageAdministrator || tool.isAdministrator || tool.isSupportUser
		);
	}
	isEditable(tool: IAdminTool) {
		return tool.isPageAdministrator || tool.isAdministrator;
	}
}

/**
 * A page that is accessible to Administrators, and read-only for ContentAdministrators or Support users
 */
class ReadOnlyPage implements IAccessPage {
	isReadable(tool: IAdminTool) {
		return (
			tool.isPageAdministrator || tool.isAdministrator || tool.isSupportUser
		);
	}
	isEditable(tool: IAdminTool) {
		return tool.isAdministrator;
	}
}
