import { Component, Input } from "@angular/core";
import { CoreBase } from "lime/core";
import { Memo, MemoFrequency, MemoMainType } from "./core";

@Component({
	selector: "lm-admin-memo-date",
	styleUrls: ["./date.scss"],
	templateUrl: "./date.html",
})
export class MemoDateComponent extends CoreBase {
	@Input() memo: Memo;

	recurrenceOptions: IRecurrenceOptions = [
		{
			id: "lm-a-mm-dr-rec-no",
			label: "No recurrence",
			value: MemoFrequency.None,
		},
		{
			id: "lm-a-mm-dr-rec-weekly",
			label: "Weekly",
			value: MemoFrequency.Weekly,
		},
		{
			id: "lm-a-mm-dr-rec-monthly",
			label: "Monthly",
			value: MemoFrequency.Monthly,
		},
		{
			id: "lm-a-mm-dr-rec-yearly",
			label: "Yearly",
			value: MemoFrequency.Yearly,
		},
	];

	constructor() {
		super("MemoDateComponent");
	}

	recurrenceChanged(value: MemoFrequency) {
		if (value === MemoFrequency.None) {
			this.memo.mainType = MemoMainType.Default;
		} else {
			this.memo.mainType = MemoMainType.Recurring;
		}
	}

	get recurrence(): MemoFrequency {
		return this.memo.iteration.frequency;
	}

	set recurrence(frequency: MemoFrequency) {
		this.memo.iteration.frequency = frequency;
	}

	get showRecurrencePatterns(): boolean {
		return this.recurrence !== MemoFrequency.None;
	}

	get showWeekRecurrence(): boolean {
		return this.recurrence === MemoFrequency.Weekly;
	}

	get showMonthRecurrence(): boolean {
		return this.recurrence === MemoFrequency.Monthly;
	}

	get showYearRecurrence(): boolean {
		return this.recurrence === MemoFrequency.Yearly;
	}
}

interface IRecurrenceOption {
	readonly id: string;
	readonly label: string;
	readonly value: MemoFrequency;
}

type IRecurrenceOptions = ReadonlyArray<IRecurrenceOption>;
