import {
	Component,
	Directive,
	OnInit,
	ViewChild,
	ViewContainerRef,
} from "@angular/core";
import { SohoMessageService, SohoModalDialogService } from "ids-enterprise-ng";
import { ArrayUtil, CommonUtil, DialogButtonType, IDialogResult } from "lime";
import {
	CoreBase,
	DialogResponseCode,
	IFileInfoResponse,
	IImportOptions,
	IOperationResponse,
	ISetting,
	IStringToAnyMap,
	MessageInfo,
	SettingsNames,
} from "lime/core";
import { Subscription } from "rxjs";
import { DateUtil } from "./core";
import {
	AdminConstants,
	AdminContext,
	AdminOperations,
	AdminService,
	IAdminContext,
	IAdminOperationInfo,
	IAdminOperationResponse,
} from "./service";
import { AdminSettingsService } from "./settings/admin-settings.service";

/**
 * Abstract base class for bulk import and export used for inheritance.
 */
@Directive()
export abstract class AdminOperationBase extends CoreBase {
	includeOptions: IStringToAnyMap = {};
	statusMessageList: MessageInfo[];
	isStandardPagesEnabled: boolean;
	isImportEnabled = false;
	isAllSelected = true;
	isCancelled = false;

	private subscriptions = new Subscription();

	constructor(
		public logPrefix: string,
		protected adminContext: AdminContext,
		public adminService: AdminService,
		messageService: SohoMessageService,
		protected sohoModalDialogService: SohoModalDialogService,
		private settingsService: AdminSettingsService,
	) {
		super(logPrefix, messageService);
		this.initDefaults(adminContext);

		this.subscriptions.add(
			this.settingsService.features$.subscribe((features) => {
				this.updateSettingControlledValues(features);
			}),
		);
	}

	ngOnDestroy() {
		this.subscriptions.unsubscribe();
	}

	clearMessages(): void {
		this.statusMessageList = [];
	}

	updateSettingControlledValues(settings: ISetting[]) {
		const setting = ArrayUtil.itemByProperty<ISetting>(
			settings,
			"settingName",
			SettingsNames.featureStandardPages,
		);
		if (setting) {
			this.isStandardPagesEnabled = setting.value === "true";
		}
	}

	handleChange(value: boolean, name: string) {
		if (value) {
			return;
		}

		if (name === AdminConstants.parameterIncludeSettings) {
			this.includeOptions[AdminConstants.parameterIncludeSettingsRules] = false;
		} else if (name === AdminConstants.parameterIncludePublishedWidgets) {
			this.includeOptions[
				AdminConstants.parameterIncludePublishedWidgetAccess
			] = false;
		} else if (name === AdminConstants.parameterIncludePublishedPages) {
			this.includeOptions[AdminConstants.parameterIncludePublishedPageAccess] =
				false;
			this.includeOptions[
				AdminConstants.parameterIncludePublishedPageConnections
			] = false;
		}
	}

	onSelectDeselectAll(value: boolean) {
		const options = this.includeOptions;
		const keys = Object.keys(options);
		for (const key of keys) {
			if (CommonUtil.isBoolean(options[key])) {
				options[key] = value;
			}
		}
	}

	/**
	 * Starts polling the server for the current operation's status.
	 * @param callback Method to be called when the operation has finished
	 */
	checkStatus(callback?: () => void): void {
		const self = this;
		self.adminService.getOperationStatus().subscribe(
			(r: IAdminOperationResponse) => {
				const content = r.content;
				self.updateMessages(content);

				// Keep polling if operation is still active
				if (content && content.isRunning) {
					this.isCancelled = false;
					setTimeout(
						() => self.checkStatus(callback),
						AdminConstants.checkStatusInterval,
					);
				} else {
					self.setBusy(false);
					if (callback) {
						callback();
					}
				}
			},
			(r: IAdminOperationResponse) => {
				const content = r.content;
				self.updateMessages(content);

				// Keep polling if operation is still active, errors may occur during e.g. import
				if (content && content.isRunning) {
					setTimeout(
						() => self.checkStatus(callback),
						AdminConstants.checkStatusInterval,
					);
				} else {
					self.setBusy(false);
					if (callback) {
						callback();
					}
					// Errors will persist in responses, show errors only after operation is complete
					if (r.hasError()) {
						self.adminService.showUploadCompleteDialog(
							"Error",
							r.toErrorLog(),
							true,
						);
					}
				}
			},
		);
	}

	/**
	 * Cancels the current operation running on the server.
	 */
	cancel(): void {
		const self = this;
		this.isCancelled = true;
		self.adminService.cancelOperation().subscribe(
			(r: IAdminOperationResponse) => {
				self.updateMessages(r.content);
			},
			(r: IOperationResponse) => {
				this.isCancelled = false;
				self.setBusy(false);
				self.adminService.showUploadCompleteDialog(
					"Error",
					r.toErrorLog(),
					true,
				);
			},
		);
	}

	/**
	 * Exclude standard pages access from data if feature is OFF
	 */
	verifyOptions(): void {
		if (!this.isStandardPagesEnabled) {
			this.includeOptions.includestandardpageaccess = false;
		}
	}

	/**
	 *  Verify if any data is included for the import/export
	 */
	hasIncludes(): boolean {
		const includes = this.includeOptions;
		for (const entity in includes) {
			if (includes.hasOwnProperty(entity) && includes[entity] === true) {
				return true;
			}
		}

		return false;
	}

	/**
	 * Abstract set busy method to be overridden by sub-classes.
	 * @param isBusy
	 */
	protected abstract setBusy(isBusy: boolean): void;

	private updateMessages(content: IAdminOperationInfo): void {
		if (content && content.messageList) {
			this.statusMessageList = content.messageList;
		}
	}

	/**
	 * Sets initial values for what content to include in either a bulk import or export.
	 */
	private initDefaults(adminContext: IAdminContext): void {
		this.clearMessages();

		const includeOptions = this.includeOptions;
		const adminConstants = AdminConstants;
		includeOptions[adminConstants.parameterIncludeSettings] = true;
		includeOptions[adminConstants.parameterIncludeSettingsRules] = true;
		includeOptions[adminConstants.parameterIncludeUserSettings] = true;
		includeOptions[adminConstants.parameterIncludeProperties] = true;
		includeOptions[adminConstants.parameterIncludePublishedWidgets] = true;
		includeOptions[adminConstants.parameterIncludePublishedWidgetAccess] = true;
		includeOptions[adminConstants.parameterIncludeStandardWidgetAccess] = true;
		includeOptions[adminConstants.parameterIncludePublishedPages] = true;
		includeOptions[adminConstants.parameterIncludePublishedPageConnections] =
			true;
		includeOptions[adminConstants.parameterIncludePublishedPageAccess] = true;
		includeOptions[adminConstants.parameterIncludePrivatePages] = true;
		includeOptions[adminConstants.parameterIncludeStandardPageAccess] = true;
		includeOptions[adminConstants.parameterIncludeMemos] = true;
		includeOptions[adminConstants.parameterIncludePolicies] = true;

		if (adminContext) {
			const adminTool = adminContext.get();
			if (adminTool) {
				const settings = adminTool.settings;
				if (settings) {
					this.updateSettingControlledValues(settings);
				}
			}
		}
	}
}

/**
 * UI controller for the bulk export operation.
 */
@Component({
	selector: "lm-admin-export",
	templateUrl: "./export.html",
})
export class AdminExportComponent extends AdminOperationBase implements OnInit {
	@ViewChild("lmAdminExport", { read: ViewContainerRef, static: false })
	content: ViewContainerRef;

	isBusy = false;
	fileExists: boolean;
	fileMessage: string;

	constructor(
		protected adminContext: AdminContext,
		public adminService: AdminService,
		messageService: SohoMessageService,
		protected sohoModalDialogService: SohoModalDialogService,
		settingsService: AdminSettingsService,
	) {
		super(
			"AdminExportComponent",
			adminContext,
			adminService,
			messageService,
			sohoModalDialogService,
			settingsService,
		);
	}

	ngOnInit(): void {
		this.updateFileInfo();
	}

	onClickExport(): void {
		this.verifyOptions();
		const hasIncludes = this.hasIncludes();

		if (hasIncludes) {
			this.clearMessages();
			this.exportData();
		} else {
			this.showMessage("No data included", "Please select data to export.");
		}
	}

	/**
	 * Starts an export operation on the server with the content selected in the UI.
	 */
	exportData(): void {
		this.setBusy(true);
		this.isCancelled = false;
		this.adminService.startExportOperation(this.includeOptions).subscribe(
			(r: IAdminOperationResponse) => {
				if (r.content.isRunning) {
					this.checkStatus(() => this.updateFileInfo());
				} else {
					this.setBusy(false);
				}
			},
			(r: IOperationResponse) => {
				this.setBusy(false);
				this.adminService.showUploadCompleteDialog(
					"Export Error",
					r.toErrorLog(),
					true,
				);
			},
		);
	}

	download(): void {
		this.adminService.downloadExportFile();
	}

	confirmDelete(): void {
		this.showConfirm(
			"Confirm delete",
			"Are you sure that you want to delete the exported file?",
		).subscribe(() => {
			this.delete();
		});
	}

	setBusy(isBusy: boolean): void {
		this.isBusy = isBusy;
	}

	private updateFileInfo(): void {
		this.setBusy(true);
		this.adminService.getExportFileInfo().subscribe(
			(response: IFileInfoResponse) => {
				this.onFileInfo(response);
				this.setBusy(false);
			},
			() => {
				this.setBusy(false);
			},
		);
	}

	private delete(): void {
		this.setBusy(true);
		this.adminService.deleteExportFile().subscribe(
			() => {
				this.fileExists = false;
				this.fileMessage = null;
				this.setBusy(false);
			},
			() => {
				this.setBusy(false);
				this.showError("Unable to delete", "The file could not be deleted.");
			},
		);
	}

	private onFileInfo(response: IFileInfoResponse): void {
		this.fileExists = response.exists;
		if (response.exists) {
			this.fileMessage =
				"An export file created " +
				DateUtil.dateToString(response.changeDate) +
				" is available for download.";
		} else {
			this.fileMessage = "";
		}
	}
}

/**
 * UI controller for the bulk import operation.
 */
@Component({
	selector: "lm-admin-import",
	templateUrl: "./import.html",
})
export class AdminImportComponent extends AdminOperationBase {
	@ViewChild("lmAdminImport", { read: ViewContainerRef, static: false })
	content: ViewContainerRef;

	isBusy = false;

	constructor(
		protected adminContext: AdminContext,
		public adminService: AdminService,
		messageService: SohoMessageService,
		protected sohoModalDialogService: SohoModalDialogService,
		settingsService: AdminSettingsService,
	) {
		super(
			"AdminImportComponent",
			adminContext,
			adminService,
			messageService,
			sohoModalDialogService,
			settingsService,
		);
	}

	/**
	 * Opens a a file upload dialog.
	 * Used for uploading an import file to the server.
	 */
	upload(): void {
		this.clearMessages();

		const dialogTitle = "Upload Homepages Data";
		const adminService = this.adminService;
		const options: IImportOptions = {
			title: dialogTitle,
			operation: AdminOperations.importData,
			buttonText: "Upload",
		};

		adminService
			.openImportFilesDialog(options, this.content)
			.subscribe((r: IDialogResult) => {
				const value = r.value;
				if (
					r.button === DialogButtonType.Yes &&
					value.responseCode === DialogResponseCode.Success
				) {
					const message = value.message
						? value.message
						: "The file was successfully uploaded to the server.";
					adminService.showUploadCompleteDialog(dialogTitle, message);
					this.isImportEnabled = true;
				} else if (
					r.button === DialogButtonType.Yes &&
					value.responseCode === DialogResponseCode.Fail
				) {
					adminService.showUploadCompleteDialog(
						dialogTitle,
						value.message,
						true,
					);
				}
			});
	}

	onClickImport(): void {
		this.verifyOptions();
		const hasIncludes = this.hasIncludes();

		if (hasIncludes) {
			this.showConfirmImport();
			this.clearMessages();
			this.isImportEnabled = false;
		} else {
			this.showMessage("No data included", "Please select data to import.");
		}
	}

	showConfirmImport(): void {
		this.showConfirm(
			"Import Homepages Data",
			"Are you sure you want to start an import operation?",
		).subscribe(() => {
			this.importData();
		});
	}

	setBusy(isBusy: boolean): void {
		this.isBusy = isBusy;
	}

	isMaxLimitMessage(message: string): boolean {
		return message.indexOf("The maximum number of") !== -1;
	}

	/**
	 * Starts an import operation on the server with the content selected in the UI.
	 */
	private importData(): void {
		const self = this;
		const includeOptions = self.includeOptions;
		self.setBusy(true);
		self.isCancelled = true;
		self.adminService.startImportOperation(includeOptions).subscribe(
			(r: IAdminOperationResponse) => {
				if (r.content.isRunning) {
					const callback = () => {
						self.onImported(includeOptions);
					};
					self.checkStatus(callback);
				} else {
					self.setBusy(false);
				}
			},
			(r: IOperationResponse) => {
				self.setBusy(false);
				self.adminService.showUploadCompleteDialog(
					"Import Error",
					r.toErrorLog(),
					true,
				);
			},
		);
	}

	/**
	 * Called after successful import operation, in order to invalidate affected caches on client.
	 * @param options Content that was imported.
	 */
	private onImported(options: IStringToAnyMap): void {
		this.adminService.invalidateCaches(options);
	}
}
