import {
	Component,
	ContentChild,
	ContentChildren,
	EventEmitter,
	Input,
	Output,
	QueryList,
	TemplateRef,
} from "@angular/core";
import { NumUtil } from "lime";
import { DynamicPageAreaKey } from "lime/core";
import { DynamicPageAdminService, IContainerAddedInfo } from "../service";

@Component({
	selector: "lm-dynamic-accordion",
	template: `
		<div
			class="header-wrapper"
			[attr.name]="automationIdentifier + '-header'"
			[attr.data-lm-a-dp-accheader]="entity"
			[class.lm-hdr-bg]="!lightTheme"
			[class.lm-item-bg]="lightTheme"
			(click)="toggleExpanded()">
			<ng-content
				style="display: none;"
				select="lm-dynamic-accordion-header"></ng-content>
			<button
				[name]="automationIdentifier + '-header-button'"
				soho-button="icon"
				[icon]="caretIcon"></button>
		</div>
		<div
			class="pane-wrapper lm-bg"
			[attr.name]="automationIdentifier + '-panel'"
			lm-expandable
			[isExpanded]="expanded"
			(afterCollapsed)="setCollapsed(true)"
			(onExpand)="setCollapsed(false)">
			<ng-template
				[ngTemplateOutlet]="paneTemplate"
				*ngIf="!paneIsCollapsed || hasBeenExpanded"></ng-template>
		</div>
	`,
	host: { class: "lm-brd" },
	styles: [
		`
			:host {
				display: flex;
				flex-direction: column;
				height: auto;
				border: 1px solid;
			}

			.header-wrapper {
				display: flex;
				flex-direction: row;
				align-items: center;
				justify-content: space-between;
				padding: 5px;
				cursor: pointer;
			}

			.pane-wrapper {
				height: 0;
				overflow: hidden;
			}
		`,
	],
})
export class DynamicAccordion {
	@ContentChild(TemplateRef, { static: false })
	paneTemplate: TemplateRef<DynamicAccordionPane>;
	@Input() lightTheme = false;
	@Input() entity: string;
	@Input() automationIdentifier: string;

	expanded: boolean;
	caretIcon: "caret-up" | "caret-down";
	paneIsCollapsed = true;
	hasBeenExpanded: boolean;

	constructor() {
		this.expanded = false;
		this.setCaretIcon();
	}

	toggleExpanded() {
		this.expanded = !this.expanded;
		this.setCaretIcon();
	}

	setCaretIcon() {
		if (this.expanded) {
			this.caretIcon = "caret-up";
		} else {
			this.caretIcon = "caret-down";
		}
	}

	collapse() {
		this.expanded = false;
		this.setCaretIcon();
	}

	expand() {
		this.hasBeenExpanded = true;
		this.expanded = true;
		this.setCaretIcon();
	}

	setCollapsed(isCollapsed: boolean) {
		this.paneIsCollapsed = isCollapsed;
	}
}

@Component({
	selector: "lm-dynamic-accordion-header",
	template: ` <ng-content></ng-content> `,
	styles: [
		`
			:host-context(.container-accordion) {
				padding: 0;
			}

			:host {
				flex: 1;
				display: flex;
				flex-direction: row;
				align-items: center;
				padding: 0 10px;
			}
		`,
	],
})
export class DynamicAccordionHeader {}

@Component({
	selector: "lm-dynamic-accordion-pane",
	template: `
		<ng-content></ng-content>
		<div
			class="add-button-container"
			*ngIf="addButtonText"
			[class.empty]="isEmpty">
			<div class="lm-text-align-c" *ngIf="addText && isEmpty">
				<p>{{ addText }}</p>
			</div>
			<button
				[id]="'lm-a-dp-add-button-' + entity"
				soho-button="primary"
				[disabled]="!isEnabled"
				[attr.data-lm-a-dp-accpane-btn]="entity"
				icon="add"
				(click)="addButtonClicked.emit()">
				{{ addButtonText }}
			</button>
		</div>
	`,
	host: { class: "lm-brd" },
	styles: [
		`
			:host {
				display: flex;
				flex-direction: column;
				border-top: 1px solid;
				padding: 15px;
			}

			:host ::ng-deep .add-button-container {
				display: flex;
				flex-direction: row;
				justify-content: center;
				align-items: center;
				margin-top: 10px;
			}

			:host ::ng-deep .add-button-container:not(.empty) button {
				flex: 1;
			}

			:host ::ng-deep .add-button-container.empty {
				height: 200px;
				margin-top: 0;
				flex-direction: column;
			}

			:host ::ng-deep .add-button-container.empty button {
				margin-top: 20px;
			}
		`,
	],
})
export class DynamicAccordionPane {
	@ContentChildren(DynamicAccordion) containers: QueryList<DynamicAccordion>;

	@Input() addButtonText: string;
	@Input() entity: string;
	@Input() addText: string;
	@Input() isEmpty: boolean;
	@Input() isEnabled = true;
	@Input() area: DynamicPageAreaKey;
	@Output() addButtonClicked = new EventEmitter();

	constructor(private readonly pageService: DynamicPageAdminService) {}

	ngOnInit(): void {
		if (this.area) {
			this.pageService.containerAdded.subscribe((info: IContainerAddedInfo) => {
				if (info && info.area && info.area === this.area) {
					this.expandContainer(info.index);
				}
			});
		}
	}

	private expandContainer(index?: number): void {
		// Next digest cycle to await containers re-render after add
		setTimeout(() => {
			const containers = this.containers;
			if (containers.length) {
				NumUtil.isNumber(index)
					? containers.toArray()[index].expand()
					: containers.last.expand();
			}
		}, 0);
	}
}
