import {
	Component,
	NgZone,
	OnInit,
	ViewChild,
	ViewContainerRef,
} from "@angular/core";
import {
	SohoDataGridComponent,
	SohoMessageService,
	SohoModalDialogRef,
	SohoModalDialogService,
} from "ids-enterprise-ng";
import {
	DialogButtonType,
	DialogService,
	IDialogResult,
	StringUtil,
} from "lime";
import {
	CoreUtil,
	DataService,
	DialogResponseCode,
	EntityCategory,
	EntityFilter,
	HttpUtil,
	IEntityAccess,
	IImportOptions,
	IIntegerResponse,
	IOperationResponse,
	IWidgetCatalogRequest,
	IWidgetCatalogResponse,
	IWidgetHandle,
	IWidgetInfo,
	IWidgetInfoResponse,
	LanguageService,
	WidgetService,
} from "lime/core";
import { take } from "rxjs/operators";
import { CustomFormatters, GridUtil, WidgetUtilAdmin } from "../admin";
import { AdminListComponent } from "../admin-list.component";
import {
	AdminContext,
	AdminService,
	AdminUtil,
	IChangeOwnerDialogOptions,
} from "../service";

@Component({
	selector: "lm-admin-published-widgets",
	templateUrl: "./published-widgets.html",
})
export class AdminPublishedWidgetsComponent
	extends AdminListComponent<IWidgetInfo>
	implements OnInit
{
	@ViewChild("publishedWidgetsDatagrid", { static: false })
	dataGrid: SohoDataGridComponent;

	accessCopy: IEntityAccess[];
	noOfSelected: number;
	widgetsGridOptions: any;
	isSearchActive: boolean;

	private accessCopyWidgetId: string;

	constructor(
		messageService: SohoMessageService,
		languageService: LanguageService,
		adminService: AdminService,
		zone: NgZone,
		private adminContext: AdminContext,
		private dialogService: DialogService,
		sohoModalDialogService: SohoModalDialogService,
		private widgetService: WidgetService,
		private dataService: DataService,
		readonly viewRef: ViewContainerRef,
	) {
		super(
			"AdminPublishedWidgetsComponent",
			"widget",
			messageService,
			languageService,
			adminService,
			sohoModalDialogService,
			zone,
			{
				isFilter: true,
				filters: [
					{
						name: "Mobile",
						propertyName: "includeMobileOnly",
						value: true,
						type: EntityFilter.Custom,
					},
				],
			},
		);
		this.datagridOptions = this.defaultOptions();
	}

	ngOnInit(): void {
		if (this.initializing) {
			this.adminContext.tool$.pipe(take(1)).subscribe((tool) => {
				this.maxCount = tool.maxCountWidget || 0;
				this.currentUser = tool.userId;
				this.isReadOnly = AdminUtil.isReadOnlyUser(tool);
			});
		}

		this.refresh();
	}

	getDataGrid(): SohoDataGridComponent {
		return this.dataGrid;
	}

	listItems(reload: boolean): void {
		if (this.isBusy) {
			return;
		}

		const self = this;
		const adminService = self.adminService;
		this.setBusy(true);

		if (reload) {
			this.hasMore = true;
			this.paging = null;
			this.items = [];
			this.clearSelection();
		}

		const orderBy = this.orderBy;
		const query = this.getQuery();
		const request: IWidgetCatalogRequest = {
			paging: this.paging,
			pageSize: this.pageSize,
			sortOrder: orderBy.order,
			sortBy: orderBy.entity,
			query: query,
		};

		// Set common active request filters
		this.setRequestFilters(request);

		if (CoreUtil.isGuid(query)) {
			request.entityId = query;
			request.query = null;
		}

		adminService.listPublishedWidgets(request).subscribe(
			(response: IWidgetCatalogResponse) => {
				const newItems = response.content;
				self.addItems(newItems, response.paging);
				self.updateCount(response.count, this.maxCount);
				self.setBusy(false);
			},
			(r: IOperationResponse) => {
				self.setBusy(false);
				self.onError(r);
			},
		);
	}

	importWidgets(): void {
		const dialogTitle = "Import Published Widgets";
		const adminService = this.adminService;
		const options: IImportOptions = {
			title: dialogTitle,
			operation: EntityCategory.publishedWidget.toString(),
			showStrategySelector: true,
		};

		const self = this;
		adminService
			.openImportFilesDialog(options, this.viewRef)
			.subscribe((r: IDialogResult) => {
				const value = r.value;
				if (
					r.button === DialogButtonType.Yes &&
					value.responseCode === DialogResponseCode.Success
				) {
					this.adminService
						.showUploadCompleteDialog(dialogTitle, value.message)
						.subscribe((result: IDialogResult) => {
							if (result.button === DialogButtonType.Ok) {
								self.refresh();
							}
						});
				} else if (
					r.button === DialogButtonType.Yes &&
					value.responseCode === DialogResponseCode.Fail
				) {
					adminService.showUploadCompleteDialog(
						dialogTitle,
						value.message,
						true,
					);
				}
			});
	}

	/**
	 * Export selected published widgets.
	 */
	exportWidgets(): void {
		const items = this.getSelectedItems();
		this.adminService.exportPublishedWidgets(items);
		this.clearSelection();
	}

	/**
	 * Export all published widgets.
	 */
	exportAll(): void {
		this.adminService.exportPublishedWidgets();
	}

	onClickDelete(): void {
		const items = this.getSelectedItems();
		if (items && items.length === 0) {
			this.logWarning("No selection to delete");
			return;
		}

		const isMultiple = items.length > 1;

		const widgetList = items.map((widget) => {
			return this.createWidgetHandle(widget);
		});

		const firstWidget = items[0];
		const title = isMultiple ? "Delete Widgets" : "Delete Widget";
		const message = isMultiple
			? "Are you sure that you want to remove the selected widgets? They will be removed for all users."
			: `Are you sure that you want to remove the widget '${firstWidget.title}'? It will be removed for all users.`;

		this.showConfirm(title, message).subscribe(() => {
			this.deleteWidgets(widgetList);
		});
	}

	/**
	 * Opens the widget permissions dialog.
	 */
	editAccess(): void {
		const self = this;
		const widget = self.getSelectedItem();
		this.adminService.openWidgetAccessDialog(
			widget,
			(resp: IWidgetInfoResponse) => {
				if (resp && resp.content) {
					self.refresh();
				}
			},
			this.viewRef,
		);
	}

	takeOwnership(): void {
		const widget = this.getSelectedItem();
		const self = this;
		this.setBusy(true);
		this.widgetService.updatePublishedOwner(widget.widgetId, null).subscribe(
			() => {
				this.setBusy(false);
				this.refresh();
			},
			(e) => {
				self.onError(e);
			},
		);
	}

	changeOwnership(): void {
		const widget = this.getSelectedItem();
		const dialogOptions: IChangeOwnerDialogOptions = {
			title: widget.title,
			currentOwnerId: widget.owner,
			itemId: widget.widgetId,
			isWidget: true,
			callback: () => this.refresh(),
		};

		this.adminService.openChangeOwnerDialog(dialogOptions, this.viewRef);
	}

	onExpandRow(event: any): void {
		const container = $(event.detail)
			.find(".datagrid-row-detail-padding")
			.empty();
		const description = this.escape(event.item.description);
		const item: IWidgetInfo = event.item;
		let template = `<div class="datagrid-cell-layout">
				<span class="datagrid-textarea lm-white-space-normal">${description}</span>
			`;

		if (item.tags) {
			template += `<div class="lm-margin-lg-t"><span>`;
			const tagsArray = item.tags.split("#");
			tagsArray.shift();

			for (const tag of tagsArray) {
				template += `<a class="tag lm-margin-sm-r">${tag}</a>`;
			}

			template += `</span></div>`;
		}

		if (item.widgetErrorInfo) {
			template += this.getErrorMessageTemplate(
				GridUtil.formatError(item.widgetErrorInfo.message),
			);
		}

		if (item.isDeprecated) {
			const message = item.deprecatedInfo
				? item.deprecatedInfo
				: "This widget has been deprecated and will soon be removed.";
			template += this.getErrorMessageTemplate(
				GridUtil.formatAlert(this.escape(message)),
			);
		}

		if (item.helpUrl && !this.hasReplacementTemplate(item.helpUrl)) {
			template += this.getLinkTemplate(item.helpUrl);
		}

		template += `</div>`;
		$(container).append($(template));
	}

	/**
	 * Copy access rights of a widget.
	 */
	copyAccess(): void {
		const widget = this.getSelectedItem();
		const self = this;
		const widgetId = widget.widgetId;
		const adminService = self.adminService;

		this.setBusy(true);
		adminService.getWidgetAccess({ id: widgetId, accessList: [] }).subscribe(
			(r: IOperationResponse) => {
				self.accessCopy = WidgetUtilAdmin.getAccessCopy(r.content.accessList);
				self.accessCopyWidgetId = widgetId;
				self.setBusy(false);
			},
			(r: IOperationResponse) => {
				self.adminService.handleError(r);
				self.setBusy(false);
			},
		);
	}
	/**
	 * Apply copied acces rights to selected widget(s).
	 */
	applyAccessCopy(): void {
		const items = this.getSelectedItems();
		this.adminService.applyWidgetAccess(items, this.accessCopy, () => {
			this.refresh();
		});
	}

	/**
	 * Clear Or Replace With Access Copy
	 *
	 * If indicated with "isReplace", replaces access rights.
	 * Otherwise clear access rights of selected widgets.
	 *
	 * @params isReplace Boolean, true: replace, false: clear.
	 */
	clearOrReplaceWithAccessCopy(isReplace?: boolean): void {
		const items = this.getSelectedItems();
		this.adminService.clearOrReplaceWidgetAccess(
			items,
			isReplace,
			() => {
				this.refresh();
			},
			this.accessCopy,
		);
	}

	/**
	 * Shows a dialog with details of the widget.
	 */
	showDetails(): void {
		const widget = this.getSelectedItem();
		const dialog = this.sohoDialogService
			.modal(AdminPublishedWidgetAboutComponent, this.viewRef)
			.title("Details")
			.id("lm-a-pw-details-dialog");

		dialog
			.apply((component) => {
				component.dialog = dialog;
				component.parameter = {
					widget: widget,
					widgetUrl: this.getWidgetUrl(widget),
				};
			})
			.open();
	}

	protected getColumns(): SohoDataGridColumn[] {
		return [
			this.getSelectionColumn(),
			{
				width: 375,
				id: "adm-pw-col-t",
				field: "title",
				name: "Title",
				resizable: true,
				sortable: false,
				formatter: Formatters.Expander,
			},
			{
				width: 150,
				id: "adm-pw-col-on",
				field: "ownerName",
				name: "Owner",
				resizable: true,
				sortable: false,
				formatter: CustomFormatters.displayName,
			},
			{
				width: 250,
				id: "adm-pw-col-swi",
				field: "standardWidgetId",
				name: "Based on",
				sortable: false,
				formatter: (row, cell, value, col) => {
					const widgetInfo: IWidgetInfo = this.items[row];
					const error = widgetInfo.widgetErrorInfo;
					if (error) {
						return GridUtil.formatError(value);
					}
					if (widgetInfo.isDeprecated) {
						return GridUtil.formatAlert(value);
					}
					return value;
				},
			},
			{
				width: 160,
				id: "adm-pw-col-cd",
				field: "changeDate",
				name: "Change date",
				resizable: true,
				sortable: false,
				formatter: CustomFormatters.date,
			},
			{
				width: 150,
				id: "adm-pw-col-cbn",
				field: "changedByName",
				name: "Changed by",
				resizable: true,
				sortable: false,
				formatter: CustomFormatters.displayName,
			},
			{
				width: 110,
				id: "adm-pw-col-hr",
				field: "hasRestrictions",
				name: "Permissions",
				sortable: false,
				formatter: CustomFormatters.restricted,
			},
		];
	}

	protected getEmptyMessage(): string {
		return "No published widgets found";
	}

	private createWidgetHandle(widget: IWidgetInfo): IWidgetHandle {
		const handle: IWidgetHandle = { id: widget.widgetId };
		if (!StringUtil.isNullOrWhitespace(widget.standardWidgetId)) {
			handle.pid = widget.standardWidgetId;
			handle.byRef = true;
		}
		return handle;
	}

	/**
	 * Deletes selected widgets.
	 */
	private deleteWidgets(widgetArray: IWidgetHandle[]): void {
		this.setBusy(true);

		this.adminService.deletePublishedWidget(widgetArray).subscribe(
			(r: IIntegerResponse) => {
				this.setBusy(false);
				if (r.content > 0) {
					this.refresh();
				}
			},
			(r: IOperationResponse) => {
				this.setBusy(false);
				this.adminService.handleError(r, r.getErrorMessages());
			},
		);
	}

	private updateOwner(existing: IWidgetInfo, updated: IWidgetInfo): void {
		// Note! The widget info does only contain owner and changeby information
		existing.owner = updated.owner;
		existing.ownerName = updated.ownerName;
		existing.changedByName = updated.changedByName;
		existing.changeDate = updated.changeDate;

		this.clearSelection();
	}

	/**
	 * Returns the URL to a widget's context app.
	 * @param widget
	 */
	private getWidgetUrl(widget: IWidgetInfo): string {
		return (
			window.location.protocol +
			"//" +
			window.location.host +
			(HttpUtil.isLocalhost ? "" : "/lime") +
			"/?widgetid=" +
			widget.widgetId
		);
	}
}

@Component({
	templateUrl: "./published-widget-about.html",
})
export class AdminPublishedWidgetAboutComponent implements OnInit {
	dialog: SohoModalDialogRef<AdminPublishedWidgetAboutComponent>;
	parameter: any;
	widget = {
		title: "",
		widgetId: "",
		owner: "",
	};

	ngOnInit(): void {
		const widget = this.parameter.widget;
		if (widget) {
			this.widget.title = widget.title;
			this.widget.widgetId = widget.widgetId;
			this.widget.owner = widget.owner;
		}
	}

	close(): void {
		this.dialog.close();
	}
}
