import {
	Component,
	EventEmitter,
	Input,
	NgZone,
	Output,
	ViewChild,
} from "@angular/core";
import { ArrayUtil } from "lime";
import { Constants } from "lime/core";
import { DynamicItemType } from "../../../../../../core/base/core";
import { DynamicContainerListBase } from "../dynamic-container/dynamic-container-list";
import { DynamicContentListComponent } from "./content/content";
import { DynamicHeaderListComponent } from "./header/header";

@Component({
	selector: "lm-dynamic-information-list",
	template: `
		<p>
			<svg soho-icon class="dyn-experimental" icon="formula-constituents"></svg>
			<small class="text-descriptive">{{ experimentalTooltip }}</small>
		</p>

		<div class="header-container" *ngIf="!isEmpty">
			<h2>Header</h2>
			<label *ngIf="!hasHeader && hasContent" soho-label
				>No header has been configured.</label
			>
			<label *ngIf="hasHeader" soho-label
				>Only one header will be displayed.</label
			>
		</div>
		<lm-header-list-component
			(headerAdded)="updateEmptyProperty()"
			[area]="area"
			[itemContainerEmpty]="isEmpty"
			[container]="container"
			[isHeader]="true"
			[accessTitles]="accessTitles"
			[accessErrors]="accessErrors"
			[query]="query"
			[filter]="filter"
			[isEditable]="isEditable">
		</lm-header-list-component>

		<div class="content-container" *ngIf="!isEmpty">
			<h2>Content</h2>
			<label *ngIf="!hasContent" soho-label>No content has been added.</label>
		</div>

		<lm-content-list-component
			(contentAdded)="updateEmptyProperty()"
			[area]="area"
			[itemContainerEmpty]="isEmpty"
			[container]="container"
			[isContent]="true"
			[accessTitles]="accessTitles"
			[accessErrors]="accessErrors"
			[query]="query"
			[filter]="filter"
			[isEditable]="isEditable">
		</lm-content-list-component>

		<div class="add-button-container empty" *ngIf="isEmpty">
			<p>
				This component is empty. Start configuring by clicking Add Header or Add
				Content.
			</p>
			<div class="add-buttons">
				<button
					soho-button="primary"
					[name]="automationIdentifier + '-addempty-btn'"
					[attr.data-lm-a-dp-addempty-btn]="container.eid"
					icon="add"
					(click)="addHeader()"
					[disabled]="!isEditable">
					Add Header
				</button>
				<lm-dyn-info-menu-btn
					[menuId]="menuId"
					[entity]="container.eid"
					[isPrimary]="true"
					[isEditable]="isEditable"
					(selected)="addContent($event)"></lm-dyn-info-menu-btn>
			</div>
		</div>
	`,
	styles: [
		`
			.header-container {
				padding: 10px 0 10px 0px;
			}

			.content-container {
				padding: 25px 0 10px 0px;
			}

			h2 {
				padding: 5px 0px;
			}

			.add-button-container.empty {
				height: 100px;
			}

			.dyn-experimental {
				height: 14px;
			}
		`,
	],
})
export class DynamicInformationList extends DynamicContainerListBase {
	@ViewChild(DynamicHeaderListComponent, { static: false })
	headerList: DynamicHeaderListComponent;
	@ViewChild(DynamicContentListComponent, { static: false })
	contentList: DynamicContentListComponent;

	hasHeader: boolean;
	hasContent: boolean;
	menuId: string;
	experimentalTooltip = Constants.dynPageExperimentalFeatureMsg;

	ngOnInit() {
		this.menuId = "lm-a-d-in-emp" + this.container.eid;
		this.updateEmptyProperty();
	}

	updateEmptyProperty() {
		const containers = this.pageService.getPage().cts;
		const container = ArrayUtil.itemByProperty(
			containers,
			"eid",
			this.container.eid,
		);
		this.hasHeader = container.hds && container.hds.length > 0;
		this.hasContent = container.its && container.its.length > 0;
		this.isEmpty = !this.hasHeader && !this.hasContent;
	}

	addLineBreak() {
		this.contentList.addLineBreak();
	}

	addHeader() {
		this.headerList.addHeader();
		this.hasHeader = !this.headerList.isEmpty;
	}

	addContent(itemType: DynamicItemType) {
		this.contentList.addContent(itemType);
		this.hasContent = !this.contentList.isEmpty;
	}

	getEntityCount(): number {
		return (
			(this.container.its && this.container.its.length) +
			(this.container.hds && this.container.hds.length)
		);
	}
}

@Component({
	selector: "lm-dyn-info-menu-btn",
	template: `
		<button
			soho-menu-button
			name="lm-a-dp-info-addcontent-button"
			[attr.data-lm-a-dp-icm-btn]="entity"
			[class.btn-primary]="isPrimary"
			icon="add"
			[menu]="menuId"
			[disabled]="!isEditable"
			(selected)="onSelected($event.args[0].id)">
			<span> Add Content </span>
		</button>
		<ul soho-popupmenu [id]="menuId" name="lm-a-dp-info-addcontent-menu">
			<li soho-popupmenu-item>
				<a
					soho-popupmenu-label
					name="lm-a-dp-info-addlink"
					id="{{ dynamicItemType.Link }}"
					>Link</a
				>
			</li>
			<li soho-popupmenu-item>
				<a
					soho-popupmenu-label
					name="lm-a-dp-info-addtext"
					id="{{ dynamicItemType.Text }}"
					>Text</a
				>
			</li>
			<li soho-popupmenu-item>
				<a
					soho-popupmenu-label
					name="lm-a-dp-info-addpropery"
					id="{{ dynamicItemType.Attribute }}"
					>User Property</a
				>
			</li>
		</ul>
	`,
})
export class DynamicInformationMenuButton {
	@Input() menuId: string;
	@Input() isPrimary: boolean;
	@Input() entity: string;
	@Input() isEditable = true;
	@Output() selected = new EventEmitter<DynamicItemType>();
	dynamicItemType = DynamicItemType;

	constructor(private zone: NgZone) {}

	onSelected(id: string) {
		this.selected.emit(parseInt(id));
	}
}
