import { Component, EventEmitter, Input, OnInit, Output } from "@angular/core";
import { SohoMessageService } from "ids-enterprise-ng";
import { ArrayUtil, StringUtil } from "lime";
import {
	Constants,
	CoreUtil,
	DynamicColorType,
	DynamicItemSettingsDialog,
	DynamicLinkSize,
	IDynamicContainer,
	IDynamicEntityLocalization,
	IDynamicEntityLocalizationMap,
	IDynamicItem,
} from "lime/core";
import { of } from "rxjs";
import { catchError } from "rxjs/operators";
import { IExpInfo } from "../../../../service";
import { DynamicPageAdminService } from "../../service";
import { DynamicUtil } from "../../util";
import { DynamicContainerListBase } from "./dynamic-container/dynamic-container-list";

interface IDynamicLinkListDialogReturnValue {
	link: IDynamicItem;
	localizations: IDynamicEntityLocalizationMap;
}

@Component({
	selector: "lm-add-link",
	templateUrl: "./add-link.html",
})
export class DynamicLinkListBasic {
	@Input() isShortcut = false;
	@Input() isContentLink = false;
	@Input() link: IDynamicItem;
	@Output() titleChanged = new EventEmitter<any>();
	linkSizes = DynamicLinkSize;
	colorTypes = DynamicColorType;
	urlMaxLength = Constants.dynPageUrlMaxLength;
	titleMaxLength = Constants.dynPageDefaultMaxLength;

	isLinkHeading(): boolean {
		return this.link.sz === this.linkSizes.Heading;
	}

	onIconChanged(icon: string) {
		this.link.i = icon;
	}

	onColorChanged(color: number) {
		this.link.cl = color;
	}

	onColorTypeChanged(colorType: DynamicColorType) {
		this.link.clt = colorType;
	}

	onTitleChanged(title: string) {
		this.titleChanged.emit(title);
	}
}

@Component({
	selector: "lm-add-link-dialog",
	templateUrl: "./add-link-dialog.html",
})
export class DynamicLinkListDialog extends DynamicItemSettingsDialog {
	isEdit: boolean;
	oldLink: IDynamicItem;
	linkSizes = DynamicLinkSize;
	selectedExpressions: IExpInfo[];
	expressions: IExpInfo[];
	listLabel = "Choose which set of users this link should be visible for.";
	isShortcut: boolean;
	isSaveDisabled: boolean;

	constructor(
		public dynamicPageService: DynamicPageAdminService,
		sohoMessageService: SohoMessageService,
	) {
		super("DynamicLinkListDialog", sohoMessageService);
	}

	ngOnInit(): void {
		this.initLocalizations();

		this.item = {
			sz: this.linkSizes.Heading,
			cl: 0,
			...this.item,
		};

		this.optionsItems = [
			{
				name: "t",
				label: "Title",
				labelId: "lm-a-dp-ael-at-t-lbl",
				valueId: "lm-a-dp-ael-at-t-inp",
				maxLength: Constants.dynPageDefaultMaxLength,
				defaultValue: this.item.t,
			},
		];

		this.initModalDialog();
		this.onInputChanged();
	}

	onInputChanged(): void {
		this.isSaveDisabled =
			StringUtil.isNullOrWhitespace(this.item.t) ||
			(this.isShortcut && StringUtil.isNullOrWhitespace(this.item.u));
		const titleLznItemIndex = this.getTranslationItemIndex("t");
		if (titleLznItemIndex > -1) {
			this.optionsItems[titleLznItemIndex].defaultValue = this.item.t;
		}
	}

	cancel() {
		this.modalDialog.close();
	}

	save() {
		if (!this.isEditable) {
			return;
		}

		if (!this.item.eid) {
			this.item.eid = this.getNewLinkId();
		}
		const link = CoreUtil.copy(this.item);
		if (link.sz !== this.linkSizes.Heading && !this.isShortcut) {
			link.cl = null;
			link.i = null;
		}
		if (this.expressions) {
			link.as = 1;
			link.ais = DynamicUtil.toIds(this.expressions);
			link.op = DynamicUtil.getOperator(this.expressions);
		} else if (this.selectedExpressions) {
			link.as = null;
			link.ais = null;
		}

		const updatedContainer = CoreUtil.copy(this.container);
		updatedContainer.lzn = null;
		if (this.itemLznEdited) {
			updatedContainer.lzn = this.getContainerLocalizations(
				this.itemLznEdited,
				link.eid,
			);
		}

		if (this.isEdit) {
			this.submitSafe(
				this.dynamicPageService.editContainerEntityWithLocalization(
					updatedContainer,
					link,
					this.oldLink,
					this.container,
				),
				false,
				true,
			).subscribe(() => this.modalDialog.close(link));
		} else {
			this.submitSafe(
				this.dynamicPageService.addContainerEntity(
					updatedContainer,
					link,
					false,
					this.container,
				),
				false,
				true,
			).subscribe(() => this.modalDialog.close(link));
		}
	}

	getNewLinkId(): string {
		return DynamicUtil.getNewEntityId(this.container);
	}

	hasInvalidTranslation(lang: IDynamicEntityLocalization): boolean {
		// Has no optional translations
		return false;
	}

	getEmptyTranslateablePropertyNames(): string[] {
		// Has no optional translations
		return [];
	}
}

@Component({
	selector: "lm-dynamic-link-list",
	templateUrl: "./dynamic-container/dynamic-container-list.html",
	styleUrls: ["./dynamic-container/dynamic-container-list.scss"],
})
export class DynamicLinkList
	extends DynamicContainerListBase
	implements OnInit
{
	@Input() isShortcut: boolean;
	linkSizes = DynamicLinkSize;

	ngOnInit() {
		const buttonText = this.isShortcut ? "Add Shortcut" : "Add Link";
		const buttonInfoText =
			"This component is empty. Start adding content by clicking " +
			buttonText +
			".";
		this.updateEmptyProperty();
		const urlTitle = this.isShortcut ? "Shortcut URL" : "Link URL";
		this.initItems(
			buttonText,
			buttonInfoText,
			"Title",
			urlTitle,
			"Icon background color",
		);
	}

	addItem() {
		if (!this.canAdd() || this.isDialogOpen) {
			return;
		}
		this.isDialogOpen = true;

		const dialog = this.dialogService
			.modal(DynamicLinkListDialog, this.viewContainerRef)
			.title(this.addItemText)
			.id("lm-a-dp-linklist-add-dialog")
			.afterClose((link) => {
				this.isDialogOpen = false;
				if (link) {
					this.updateEmptyProperty();
				}
			});

		dialog
			.apply((component: DynamicLinkListDialog) => {
				component.modalDialog = dialog;
				component.container = this.container;
				component.containerLznEdited = component.container.lzn;
				component.isShortcut = this.isShortcut;
				component.isEdit = false;
			})
			.open();
	}

	editItem(isPermissionTab: boolean, link: IDynamicItem): void {
		if (this.isDialogOpen) {
			return;
		}
		this.isDialogOpen = true;
		const expressions = DynamicUtil.toExpressions(link, this.accessTitles);
		const action = this.isEditable ? "Edit" : "View";
		const dialog = this.dialogService
			.modal(DynamicLinkListDialog, this.viewContainerRef)
			.title(this.isShortcut ? `${action} Shortcut` : `${action} Link`)
			.id("lm-a-dp-linklist-edit-dialog")
			.afterClose((updatedLink: IDynamicLinkListDialogReturnValue) => {
				this.isDialogOpen = false;
				if (updatedLink) {
					this.updateEmptyProperty();
				}
			});

		dialog
			.apply((component: DynamicLinkListDialog) => {
				component.modalDialog = dialog;
				component.container = this.container;
				component.oldLink = link;
				component.item = link;
				component.isShortcut = this.isShortcut;
				component.selectedExpressions = expressions;
				component.isEdit = true;
				component.containerLznEdited = component.container.lzn;
				component.isPermissionTabOnInit = isPermissionTab;
				component.isEditable = this.isEditable;
			})
			.open();
	}

	deleteItems(
		links: IDynamicItem[],
		parentContainer?: IDynamicContainer,
	): void {
		const containerCopy = CoreUtil.copy(parentContainer || this.container);

		for (const link of links) {
			const removeIndex = ArrayUtil.indexByProperty(
				containerCopy.its,
				"eid",
				link.eid,
			);
			if (removeIndex > -1) {
				containerCopy.its.splice(removeIndex, 1);
			}
		}
		this.pageService
			.updateContainer(containerCopy, containerCopy, links)
			.pipe(
				// Ignore error since it's handled in service
				catchError(() => of()),
			)
			.subscribe(() => this.updateEmptyProperty());
	}

	getEntityCount(): number {
		return this.container.its && this.container.its.length;
	}

	onCopy() {
		this.copySelected(this.container.its);
	}

	onCut() {
		this.cutSelected(this.container.its);
	}

	onDeleteSelected() {
		this.deleteSelectedItems(this.container.its);
	}

	private updateEmptyProperty() {
		const containers = this.pageService.getPage().cts;
		const container = ArrayUtil.itemByProperty(
			containers,
			"eid",
			this.container.eid,
		);
		const hasLinks = container.its && container.its.length > 0;
		this.isEmpty = !hasLinks;
		this.clearSelectionCount();
	}
}
