import {
	Component,
	OnDestroy,
	OnInit,
	QueryList,
	ViewChildren,
} from "@angular/core";
import { SohoMessageService } from "ids-enterprise-ng";
import { CommonUtil } from "lime";
import {
	AdminPages,
	ContainerService,
	CoreBase,
	EntityType,
	IAdminContainerComponent,
	IAdminNavigationEvent,
	IOperationResponse,
} from "lime/core";
import { AsyncSubject, Observable } from "rxjs";
import { map } from "rxjs/operators";
import { AdminRoutingService } from "./admin-routing.service";
import { DynamicPageAdminService } from "./pages/dyn/service";
import {
	AdminConstants,
	AdminContext,
	AdminService,
	ExpressionFilterTarget,
	IExpInfoFilter,
} from "./service";
import { AdminSettingsService } from "./settings/admin-settings.service";
import { AdminSettingsComponent } from "./settings/settings";

@Component({
	selector: "lm-admin-container",
	templateUrl: "./admin-container.html",
	styleUrls: ["./admin-container.scss"],
})
export class AdminContainerComponent
	extends CoreBase
	implements OnDestroy, OnInit, IAdminContainerComponent
{
	@ViewChildren(AdminSettingsComponent)
	settingsComponents: QueryList<AdminSettingsComponent>;
	tenant$: Observable<string> = this.adminContext.tool$.pipe(
		map((tool) => tool.tenantId),
	);
	showPage$: Observable<AdminPages> = this.routingService.currentPage$;
	openedPages$ = this.routingService.openedPages$;
	canNavigateTo$ = this.routingService.canNavigateTo$;
	isDynamicEditorOpen$: Observable<boolean> =
		this.dynamicPageAdminService.editorToggled;
	applicationMenuTriggers;
	constants = AdminConstants;
	featureType = {
		page: EntityType.Page,
		widget: EntityType.Widget,
		banner: EntityType.HeroWidget,
	};
	isBusy: boolean;
	/**
	 * Special filter for showing pages that uses a global expression.
	 */
	expressionFilter: IExpInfoFilter;
	AdminPages = AdminPages;

	private cacheUnsubscriber: () => void;

	constructor(
		messageService: SohoMessageService,
		private adminContext: AdminContext,
		private adminService: AdminService,
		private containerService: ContainerService,
		private routingService: AdminRoutingService,
		private dynamicPageAdminService: DynamicPageAdminService,
		private settingsService: AdminSettingsService,
	) {
		super("AdminContainerComponent", messageService);

		this.cacheUnsubscriber = adminService.onCachesInvalidated().on(() => {
			const currentPage = adminService.getLastVisitedTab();
			this.reinitialize(currentPage);
		});
	}

	ngOnInit(): void {
		CommonUtil.detectBrowser();
		const adminService = this.adminService;
		this.applicationMenuTriggers = ["#lm-admin-appmenu-trigger"];
		this.setBusy(true);
		this.adminContext.initialize(true).subscribe(
			() => {
				this.setBusy(false);
			},
			(r: IOperationResponse) => {
				this.setBusy(false);
				adminService.handleError(r);
			},
		);
	}

	ngOnDestroy(): void {
		this.cacheUnsubscriber();
		$("#lm-admin-appmenu-trigger").off("click");
	}

	close(): void {
		this.handleChangedSettings().subscribe(() => {
			this.containerService.closeAdmin();
		});
	}

	hide(): void {
		this.containerService.hideAdmin(this.adminService.getLastVisitedTab());
	}

	onMenuToggled(isOpen: boolean) {
		if (isOpen) {
			try {
				const transition = $("#application-menu").css("transition-duration");
				const timeout =
					parseFloat(transition.split(",")[0].slice(0, -1)) * 1000;
				this.adminService.raiseAppMenuExpanded(timeout);
			} catch (e) {
				this.logDebug(
					this.logPrefix +
						" App Menu implementation has changed. Setting default timeout.",
				);
				this.adminService.raiseAppMenuExpanded(300);
			}
		} else {
			this.adminService.raiseAppMenuCollapsed();
		}
	}

	/**
	 * Check to see if a setting or rule has been changed before changing tab.
	 * If changes exist, a dialog will ask the user if changes should be saved.
	 * @param page	Page to change to.
	 * @param event	Click event.
	 */
	changeTab(page: AdminPages, event?: MouseEvent): void {
		this.handleChangedSettings(page).subscribe(() => {
			this.routingService.navigateTo(page);
		});
	}

	/**
	 * Handles switch of UI. Not used for settings and rule switching.
	 * @param navigationEvent IAdminNavigationEvent
	 * @param event	Click event.
	 */
	onNavigationEvent(navigationEvent: IAdminNavigationEvent): void {
		const page = navigationEvent.adminPage;

		if (page === AdminPages.DynamicPages) {
			const openedEditorPage = this.dynamicPageAdminService.getPageClone();
			if (openedEditorPage !== null) {
				const title = "Confirm navigation";

				const message = `Are you sure that you want to navigate to the Dynamic pages list? This will close the editor for page "${openedEditorPage.t}".`;
				this.showConfirm(title, message).subscribe(() => {
					this.dynamicPageAdminService.closeEditor();
					this.navigateToAdminPage(navigationEvent);
				});
				return;
			}
		}

		this.navigateToAdminPage(navigationEvent);
	}

	private reinitialize(page: AdminPages) {
		this.setBusy(true);
		this.adminContext.initialize().subscribe(
			() => {
				this.routingService.navigateTo(page);
				this.setBusy(false);
			},
			(r: IOperationResponse) => {
				this.setBusy(false);
				this.adminService.handleError(r);
			},
		);
	}

	private setBusy(isBusy: boolean) {
		this.isBusy = isBusy;
	}

	private navigateToAdminPage(navigationEvent: IAdminNavigationEvent): void {
		const page = navigationEvent.adminPage;
		this.routingService.navigateTo(page);
		this.expressionFilter = null;
		if (navigationEvent.entityId) {
			const expFilter = this.createExpressionFilter(navigationEvent);
			this.expressionFilter = expFilter;
		}
	}

	private createExpressionFilter(
		navigationEvent: IAdminNavigationEvent,
	): IExpInfoFilter {
		let target = ExpressionFilterTarget.All;
		if (navigationEvent.adminPage === AdminPages.DynamicPages) {
			target = ExpressionFilterTarget.DynamicPages;
		} else if (navigationEvent.adminPage === AdminPages.Announcements) {
			target = ExpressionFilterTarget.Announcements;
		}
		const expFilter: IExpInfoFilter = {
			expressionId: navigationEvent.entityId,
			title: navigationEvent.entityTitle,
			filterTarget: target,
		};
		return expFilter;
	}

	private handleChangedSettings(nextPage?: AdminPages): Observable<void> {
		const subject = new AsyncSubject<void>();
		if (this.hasChangedSettings(nextPage)) {
			const isFeaturesTab =
				this.adminService.getLastVisitedTab() === AdminPages.Features;
			const tabName = isFeaturesTab ? "features" : "settings";
			const settingsComponent = this.getChangedSettingComponent();
			let isDiscard = true;
			this.showConfirm(
				"Unsaved Changes",
				`There are unsaved changes. Do you want to save the changes before` +
					` leaving ${tabName}? If you click no, all changes will be discarded.`,
			).subscribe(
				() => {
					settingsComponent.save().subscribe(
						() => this.asyncComplete(subject, nextPage),
						() => subject.complete(),
					);
					isDiscard = false;
				},
				null,
				() => {
					if (isDiscard) {
						settingsComponent.performDiscard();
						this.asyncComplete(subject, nextPage);
					}
				},
			);
		} else {
			this.asyncComplete(subject, nextPage);
		}
		return subject.asObservable();
	}

	private hasChangedSettings(next: AdminPages): boolean {
		const lastTab = this.adminService.getLastVisitedTab();
		const isSettingsChanged =
			this.settingsService.isSettingsChanged ||
			this.settingsService.isRulesChanged;
		const isSaveSettings =
			isSettingsChanged &&
			next !== AdminPages.Settings &&
			lastTab === AdminPages.Settings;
		const isSaveFeatures =
			this.settingsService.isSettingsChanged &&
			next !== AdminPages.Features &&
			lastTab === AdminPages.Features;
		return isSaveSettings || isSaveFeatures;
	}

	private getChangedSettingComponent(): AdminSettingsComponent {
		const isFeaturesTab =
			this.adminService.getLastVisitedTab() === AdminPages.Features;
		return this.settingsComponents.find(
			(component) => component.isFeatureMode === isFeaturesTab,
		);
	}
}
