import { Component, Input, OnInit, ViewChild } from "@angular/core";
import { SohoMessageService } from "ids-enterprise-ng";
import {
	DialogButtonType,
	ITranslationItem,
	ITranslationOptions,
	StringUtil,
} from "lime";
import {
	EntityCategory,
	ILocalizationParameter,
	IStringMap,
	ModalDialogBase,
	OperationResponse,
} from "lime/core";
import { DynamicUtil } from "../pages/dyn/util";
import { IExpInfo } from "../service";
import { MemoBasicComponent } from "./basic";
import { IMemoRequest, Memo, MemoConstants } from "./core";
import { MemoAdminService } from "./service";

@Component({
	templateUrl: "./dialog.html",
})
export class MemoDialogComponent extends ModalDialogBase implements OnInit {
	@Input()
	memo: Memo;

	@Input()
	accessTitles: IStringMap;

	@ViewChild(MemoBasicComponent, { static: true })
	basicComponent: MemoBasicComponent;

	provider: () => ILocalizationParameter;
	isEdit: boolean;
	entityCategory = EntityCategory.memo;
	selectedExpressions: IExpInfo[];
	expressions: IExpInfo[];
	permissionLabel =
		"Choose which set of users this announcement should be visible for.";

	private localizationParameter: ILocalizationParameter;

	constructor(
		private readonly memoService: MemoAdminService,
		readonly messageService: SohoMessageService,
	) {
		super("MemoDialogComponent", messageService);
		this.provider = () => {
			return this.getLocalizationParameter();
		};
	}

	ngOnInit(): void {
		this.initModalDialog();
		this.initExpressions();
		this.initTranslations();
	}

	save(): void {
		if (!this.canSave()) {
			return;
		}

		this.setCanClose(false);
		this.setBusy(true);

		const request = this.createRequest();

		const observable = this.isEdit
			? this.memoService.update(request)
			: this.memoService.create(request);
		observable.subscribe(
			(r) => {
				this.closeWithResult(DialogButtonType.Ok, r);
			},
			(r: OperationResponse) => {
				// TODO Verify error handling, display of message etc
				this.showError(
					`Failed to ${this.isEdit ? "update" : "create"} announcement`,
					r.getErrorMessages(),
				);
				this.canClose = true;
				this.setBusy(false);
			},
		);
	}

	canSave(): boolean {
		if (this.isBusy) {
			return false;
		}
		const basic = this.basicComponent;
		if (basic) {
			return this.memo.validateMandatory(basic.showActionButton);
		}
		return true;
	}

	private getLocalizationParameter(): ILocalizationParameter {
		this.updateTranslationOptions();
		return this.localizationParameter;
	}

	private initTranslations(): void {
		this.localizationParameter = {
			translationOptions: this.createTranslationOptions(),
			localizationMap: this.memo.localization || {},
			enablePortation: false,
		};
	}

	private updateTranslationOptions(): void {
		this.localizationParameter.translationOptions =
			this.createTranslationOptions();
	}

	private createTranslationOptions(): ITranslationOptions {
		const items: ITranslationItem[] = [
			{
				name: MemoConstants.LocalizationKeyTitle,
				label: "Title",
				labelId: "lm-a-mm-tr-t-lbl",
				valueId: "lm-a-mm-tr-t",
				maxLength: MemoConstants.MaxLengthTitle,
				defaultValue: this.memo.title,
				isRequired: true,
			},
			{
				name: MemoConstants.LocalizationKeyText,
				label: "Content",
				labelId: "lm-a-mm-tr-tx-lbl",
				valueId: "lm-a-mm-tr-tx",
				maxLength: MemoConstants.MaxLengthText,
				isMarkdown: true,
				defaultValue: this.memo.text,
				isRequired: !StringUtil.isNullOrWhitespace(this.memo.text),
			},
		];

		if (this.basicComponent.showActionButton) {
			items.push({
				name: MemoConstants.LocalizationKeyActionText,
				label: "Button title",
				labelId: "lm-a-mm-tr-at-lbl",
				valueId: "lm-a-mm-tr-at",
				maxLength: MemoConstants.MaxLengthActionText,
				defaultValue: this.memo.actionText,
				isRequired: true,
			});
		}

		return { items: items };
	}

	private initExpressions(): void {
		if (this.memo.hasAccess) {
			this.selectedExpressions = this.memo.accessIds.map((id) => {
				return {
					expressionId: id,
					title: this.accessTitles[id] || DynamicUtil.missingPolicyText,
				};
			});
		}
	}

	private createRequest(): IMemoRequest {
		const memo = this.memo;
		const basic = this.basicComponent;
		const hadAccess = memo.hasAccess;
		const expressions = this.expressions;
		const hasAccess = expressions && expressions.length > 0;

		memo.normalize();

		if (!basic.showActionButton) {
			memo.actionText = undefined;
			memo.actionUrl = undefined;
		}

		if (hasAccess) {
			memo.accessIds = expressions.map((exp) => exp.expressionId);
		} else if (hadAccess) {
			// An empty array tells the server to delete existing access
			memo.accessIds = [];
		} else {
			memo.accessIds = null;
		}

		memo.localization = this.localizationParameter.localizationMap;

		return { content: memo };
	}
}
