import {
	Component,
	NgZone,
	OnInit,
	ViewChild,
	ViewContainerRef,
} from "@angular/core";
import {
	SohoDataGridComponent,
	SohoMessageService,
	SohoModalDialogRef,
	SohoModalDialogService,
} from "ids-enterprise-ng";
import { DialogButtonType, IDialogResult } from "lime";
import {
	EntityFilter,
	IOperationResponse,
	ITagInfo,
	ITagListRequest,
	ITagListResponse,
	LanguageService,
} from "lime/core";
import { take } from "rxjs/operators";
import { CustomFormatters } from "../admin";
import { AdminListComponent } from "../admin-list.component";
import { AdminContext, AdminService, AdminUtil } from "../service";

@Component({
	selector: "lm-admin-tags",
	templateUrl: "./tags.html",
})
export class AdminTagsComponent
	extends AdminListComponent<ITagInfo>
	implements OnInit
{
	@ViewChild("tagsDatagrid", { static: false })
	dataGrid: SohoDataGridComponent;

	widgetsGridOptions: any;
	includeAll = false;
	filterTooltipFunc: Function;

	private accessCopyWidgetId: string;

	constructor(
		messageService: SohoMessageService,
		languageService: LanguageService,
		zone: NgZone,
		public adminService: AdminService,
		public sohoModalDialogService: SohoModalDialogService,
		readonly viewRef: ViewContainerRef,
		protected readonly adminContext: AdminContext,
	) {
		super(
			"AdminTagsComponent",
			"tag",
			messageService,
			languageService,
			adminService,
			sohoModalDialogService,
			zone,
			{
				sortUsedBy: false,
				isFilter: true,
				isUserFilter: false,
				isRestrictionFilter: false,
				filters: [
					{ name: "Pages", type: EntityFilter.PageTags },
					{ name: "Widgets", type: EntityFilter.WidgetTags },
				],
			},
		);

		this.initGrid();
	}

	ngOnInit(): void {
		if (this.initializing) {
			this.adminContext.tool$.pipe(take(1)).subscribe((tool) => {
				this.isReadOnly = AdminUtil.isReadOnlyUser(tool);
			});

			this.refresh();
		}
	}

	getDataGrid(): SohoDataGridComponent {
		return this.dataGrid;
	}

	setFilterTooltip(): void {
		function filterActive() {
			return "Filter active";
		}

		function filterInactive() {
			return false;
		}

		if (this.filter.type > 0) {
			this.filterTooltipFunc = filterActive;
		} else {
			this.filterTooltipFunc = filterInactive;
		}
	}

	listItems(reload: boolean): void {
		if (this.isBusy) {
			return;
		}

		const self = this;
		const adminService = self.adminService;
		this.setBusy(true);

		if (reload) {
			this.hasMore = true;
			this.paging = null;
			this.items = [];
			this.clearSelection();
		}

		const types = EntityFilter;
		const filter = this.filter;
		const filterType = filter ? filter.type : 0;
		const tagType =
			filterType === types.PageTags
				? 1
				: filterType === types.WidgetTags
				  ? 2
				  : 0;
		const orderBy = this.orderBy;
		const request: ITagListRequest = {
			paging: this.paging,
			pageSize: this.pageSize,
			sortOrder: orderBy.order,
			sortBy: orderBy.entity,
			query: this.query,
			tagType: tagType,
		};

		// Set common active request filters
		this.setRequestFilters(request);

		adminService.listTags(request).subscribe(
			(response: ITagListResponse) => {
				self.addItems(response.content, response.paging);
				self.setBusy(false);
			},
			(r: IOperationResponse) => {
				self.setBusy(false);
				self.onError(r);
			},
		);
	}

	add(): void {
		const self = this;
		const dialog = this.sohoModalDialogService
			.modal(AddTagsComponent, this.viewRef)
			.title("Add Tags")
			.id("lm-admin-tags-mdl")
			.afterClose((r: IDialogResult) => {
				if (r && r.button === DialogButtonType.Ok) {
					self.refresh();
				}
			});

		dialog
			.apply((component) => {
				component.modalDialog = dialog;
			})
			.open();
	}

	/**
	 * Deletes the selected tags if the user confirms the action.
	 */
	onClickDelete(): void {
		if (!this.hasSelection()) {
			return;
		}

		const dialog = this.sohoModalDialogService

			.message(
				"<p>Are you sure that you want to delete the selected tags? The tags will only be deleted from the suggestion list. They will not be deleted from the widgets/pages that already use the tags.</p>",
			)
			.buttons([
				{
					text: "No",
					id: "lm-a-tags-delete-message-no",
					click: () => {
						dialog.close(DialogButtonType.No);
					},
				},
				{
					text: "Yes",
					id: "lm-a-tags-delete-message-yes",
					click: () => {
						dialog.close(DialogButtonType.Yes);
					},
					isDefault: true,
				},
			])
			.title("Confirmation")
			.id("lm-admin-tags-mdl")
			.open()
			.afterClose((result) => {
				if (result === DialogButtonType.Yes) {
					this.deleteTags();
				}
			});
	}

	protected getColumns(): SohoDataGridColumn[] {
		const self = this;
		return [
			this.getSelectionColumn(),
			{
				width: "100%",
				id: "adm-tg-col-tg",
				field: "tag",
				name: "Tag",
				sortable: false,
			},
			{
				width: 200,
				id: "adm-tg-col-tgt",
				field: "tagType",
				name: "Content Type",
				sortable: false,
				formatter: (row, cell, value, col) => {
					const type = self.items[row].tagType;
					return type === 1 ? "Page" : type === 2 ? "Widget" : "";
				},
			},
			{
				width: 250,
				id: "adm-tg-col-cd",
				field: "changeDate",
				name: "Change date",
				sortable: false,
				formatter: CustomFormatters.date,
			},
		];
	}

	protected getEmptyMessage(): string {
		return "No tags found";
	}

	private deleteTags(): void {
		const self = this;
		const items = self.getSelectedItems();
		self.setBusy(true);
		self.adminService.deleteTags({ content: items }).subscribe(
			(r: ITagListResponse) => {
				self.setBusy(false);
				self.refresh();
			},
			(r: IOperationResponse) => {
				self.setBusy(false);
				self.onError(r);
			},
		);
	}

	private initGrid(): void {
		const options = this.defaultOptions();
		options.expandableRow = false;
		this.datagridOptions = options;
	}
}

@Component({
	selector: "lm-admin-add-tags-component",
	templateUrl: "./add-tags.html",
})
export class AddTagsComponent implements OnInit {
	modalDialog: SohoModalDialogRef<AddTagsComponent>;
	tags = [];
	selectedType = 0;
	enableType = true;
	isBusy = false;

	private canClose = true;

	constructor(private adminService: AdminService) {}

	ngOnInit() {
		this.modalDialog.beforeClose(() => {
			return this.canClose;
		});
	}

	hasTags(): boolean {
		return this.tags.length > 0;
	}

	onCancel(): void {
		this.modalDialog.close({ button: DialogButtonType.Cancel });
	}

	onOk(): void {
		const tags = this.tags;
		if (tags.length === 0) {
			return;
		}

		const map = (t) => {
			return tags.map((tag, i) => {
				return { tag: tag, tagType: t };
			});
		};

		const type = this.selectedType;
		let items;
		if (type === 0) {
			const pages = map(1);
			const widgets = map(2);
			items = pages.concat(widgets);
		} else {
			items = map(type);
		}

		this.addTags(items);
	}

	private addTags(tags: ITagInfo[]): void {
		// FUTURE The server validation has a limit of 20 which the client should enforce as well

		if (!tags || tags.length === 0) {
			return;
		}

		this.setBusy(true);
		this.canClose = false;
		const self = this;
		this.adminService.updateTags({ content: tags }).subscribe(
			(r: IOperationResponse) => {
				self.setBusy(false);
				self.canClose = true;
				this.modalDialog.close({
					button: DialogButtonType.Ok,
				});
			},
			(r: IOperationResponse) => {
				self.setBusy(false);
				self.adminService.handleError(r);
			},
		);
	}

	private setBusy(isBusy: boolean): void {
		if (this.isBusy !== isBusy) {
			this.isBusy = isBusy;
		}
	}
}
