import { Injectable } from "@angular/core";
import { SohoMessageService } from "ids-enterprise-ng";
import { CoreBase, DynamicContainerType, LanguageService } from "lime/core";
import { Observable } from "rxjs";
import { map } from "rxjs/operators";
import { IDynamicAccess } from "./core";
import { DynamicPageAdminService } from "./service";
import { DynamicUtil } from "./util";

export interface IComponentsFilter {
	hasContent: boolean;
	hasLink?: boolean;
	hasShortcut?: boolean;
	hasImage?: boolean;
	hasItems?: boolean;
	hasWidget?: boolean;
	hasWeb?: boolean;
	hasText?: boolean;
}

export interface IDynamicFilterService {
	accessFilters$: Observable<IDynamicAccess[]>;
	componentFilters$: Observable<IComponentsFilter>;
}

@Injectable({
	providedIn: "root",
})
export class DynamicFilterService
	extends CoreBase
	implements IDynamicFilterService
{
	accessFilters$: Observable<IDynamicAccess[]> =
		this.pageService.editedPage.pipe(
			map((page) =>
				page
					? page.accs.filter((access) => {
							if (!page.cts) {
								return false;
							}
							const accessId = access.exid;
							if (DynamicUtil.containsAccess(page.cts, accessId)) {
								return true;
							}

							for (const ct of page.cts) {
								if (DynamicUtil.containsAccess(ct.its, accessId)) {
									return true;
								}
								if (DynamicUtil.containsAccess(ct.ims, accessId)) {
									return true;
								}
								if (DynamicUtil.containsAccess(ct.ws, accessId)) {
									return true;
								}
								if (DynamicUtil.containsAccess(ct.hds, accessId)) {
									return true;
								}
								if (DynamicUtil.containsAccess(ct.wbs, accessId)) {
									return true;
								}
								if (DynamicUtil.containsAccess(ct.txts, accessId)) {
									return true;
								}
							}
					  })
					: null,
			),
		);

	componentFilters$: Observable<IComponentsFilter> =
		this.pageService.editedPage.pipe(
			map((page) => {
				if (page) {
					const componentFilter: IComponentsFilter = { hasContent: false };
					const containers = page.cts || [];
					for (const container of containers) {
						switch (container.ct) {
							case DynamicContainerType.Links:
								if (container.st === 1) {
									componentFilter.hasShortcut = true;
								} else {
									componentFilter.hasLink = true;
								}
								break;
							case DynamicContainerType.Image:
								componentFilter.hasImage = true;
								break;
							case DynamicContainerType.Items:
								componentFilter.hasItems = true;
								break;
							case DynamicContainerType.Widget:
								componentFilter.hasWidget = true;
								break;
							case DynamicContainerType.Web:
								componentFilter.hasWeb = true;
								break;
							case DynamicContainerType.Text:
								componentFilter.hasText = true;
								break;
							default:
								this.logDebug(
									`componentFilters: Unknown container type: ${container.ct}`,
								);
								break;
						}
					}
					componentFilter.hasContent =
						componentFilter.hasLink ||
						componentFilter.hasShortcut ||
						componentFilter.hasImage ||
						componentFilter.hasItems ||
						componentFilter.hasWidget ||
						componentFilter.hasWeb ||
						componentFilter.hasText;

					return componentFilter;
				}
			}),
		);

	constructor(
		languageService: LanguageService,
		messageService: SohoMessageService,
		private pageService: DynamicPageAdminService,
	) {
		super("DynamicFilterService", messageService, languageService);
	}
}
