import {
	Component,
	ElementRef,
	OnInit,
	Pipe,
	PipeTransform,
	ViewChild,
	ViewContainerRef,
} from "@angular/core";
import {
	SohoInputValidateDirective,
	SohoMessageService,
	SohoModalDialogService,
} from "ids-enterprise-ng";
import { ITranslationItem, StringUtil } from "lime";
import {
	Constants,
	CoreUtil,
	DynamicItemSettingsDialog,
	DynamicItemType,
	IAttributeInfo,
	IDynamicContainer,
	IDynamicEntityLocalization,
	IDynamicItem,
} from "lime/core";
import { IExpInfo } from "../../../../../../service";
import { DynamicPageAdminService } from "../../../../service";
import { DynamicUtil } from "../../../../util";
import { UserPropertiesListDialog } from "../../../user-properties-dialog";

@Component({
	templateUrl: "./add-content-dialog.html",
	styleUrls: ["./add-content-dialog.scss"],
})
export class DynamicInformationContentDialog
	extends DynamicItemSettingsDialog
	implements OnInit
{
	@ViewChild("dialogViewContRef", { read: ViewContainerRef, static: false })
	dialogViewContRef: ViewContainerRef;
	@ViewChild("textItemTextArea", { static: false })
	textItemTextArea: ElementRef<HTMLInputElement>;
	@ViewChild(SohoInputValidateDirective, { static: false })
	textValidationDirective: SohoInputValidateDirective;

	isCustomLabel = true;
	isEdit: boolean;
	isSaveDisabled = true;
	selectedExpressions: IExpInfo[];
	expressions: IExpInfo[];
	oldContent: IDynamicItem;
	listLabel = "Choose which set of users this content should be visible for.";
	contentTypes = DynamicItemType;
	textMaxLength = Constants.dynPageTextMaxLength;
	defaultMaxLength = Constants.dynPageDefaultMaxLength;
	attributeLabel: string;

	constructor(
		private dynamicPageService: DynamicPageAdminService,
		private sohoModalDialogService: SohoModalDialogService,
		private trimCurlyBracesPipe: TrimCurlyBracesPipe,
		sohoMessageService: SohoMessageService,
	) {
		super("DynamicInformationContentDialog", sohoMessageService);
	}

	ngOnInit() {
		this.initModalDialog();
		this.setLabel();
		this.updateProperty(this.item.t, "t", true);
		this.initLocalizations();
	}

	updateProperty(
		stringToValidate: string,
		propertyName: string,
		validate?: boolean,
	): void {
		this.item = { ...this.item, [propertyName]: stringToValidate };
		if (validate) {
			this.isSaveDisabled = StringUtil.isNullOrWhitespace(stringToValidate);
		}
	}

	setLabel() {
		const item = this.item;
		const t = item.t ? this.trimCurlyBracesPipe.transform(item.t) : "";
		this.isCustomLabel = t !== item.l;
		if (this.isCustomLabel) {
			this.attributeLabel = item.l;
		}
	}

	save() {
		if (!this.isEditable) {
			return;
		}

		const contentCopy = this.getItemData();
		if (!this.item.eid) {
			this.item.eid = DynamicUtil.getNewEntityId(this.container);
			contentCopy.eid = this.item.eid;
		}
		if (this.expressions) {
			contentCopy.as = 1;
			contentCopy.ais = DynamicUtil.toIds(this.expressions);
			contentCopy.op = DynamicUtil.getOperator(this.expressions);
		} else if (this.selectedExpressions) {
			contentCopy.as = null;
			contentCopy.ais = null;
		}

		const updatedContainer = CoreUtil.copy(this.container);
		const hasInvalidOldTranslations = this.hasInvalidTranslations(
			updatedContainer.lzn,
		);
		if (this.itemLznEdited) {
			const newTranslations = this.getContainerLocalizations(
				this.itemLznEdited,
				contentCopy.eid,
			);
			if (hasInvalidOldTranslations) {
				const invalidOldTranslations = this.getInvalidTranslations(
					updatedContainer.lzn,
				);
				updatedContainer.lzn = {
					...invalidOldTranslations,
					...newTranslations,
				};
			} else {
				updatedContainer.lzn = newTranslations;
			}
		} else if (hasInvalidOldTranslations) {
			updatedContainer.lzn = this.getInvalidTranslations(updatedContainer.lzn);
		} else {
			updatedContainer.lzn = null;
		}
		if (this.hasInvalidTranslations(updatedContainer.lzn)) {
			this.showConfirmDiscardTranslations().subscribe(
				() => {
					this.deleteTranslations(updatedContainer.lzn);
					this.performSave(updatedContainer, contentCopy);
				},
				null,
				() => this.setCanClose(true),
			);
		} else {
			this.performSave(updatedContainer, contentCopy);
		}
	}

	performSave(updatedContainer: IDynamicContainer, contentCopy: IDynamicItem) {
		if (this.isEdit) {
			this.submitSafe(
				this.dynamicPageService.editContainerEntityWithLocalization(
					updatedContainer,
					contentCopy,
					this.oldContent,
					this.container,
				),
				false,
				true,
			).subscribe(() => this.modalDialog.close(contentCopy));
		} else {
			this.submitSafe(
				this.dynamicPageService.addContainerEntity(
					updatedContainer,
					contentCopy,
					false,
					this.container,
				),
				false,
				true,
			).subscribe(() => this.modalDialog.close(contentCopy));
		}
	}

	hasInvalidTranslation(lang: IDynamicEntityLocalization): boolean {
		const item = this.item;
		const label = this.item.l;
		const hasLabel = label && label.length && label.length > 0;
		const hasTranslation = lang.its && lang.its[item.eid];
		const labelTranslation = hasTranslation && lang.its[item.eid].l;
		const hasLabelTranslation =
			labelTranslation &&
			labelTranslation.length &&
			labelTranslation.length > 0;
		return !hasLabel && hasLabelTranslation;
	}

	getEmptyTranslateablePropertyNames(): string[] {
		const hasLabel = this.item.l && this.item.l.length;
		return !hasLabel ? ["l"] : [];
	}

	openUserPropertyDialog() {
		const dialog = this.sohoModalDialogService
			.modal(UserPropertiesListDialog, this.dialogViewContRef)
			.title("Select User Property")
			.id("lm-a-dp-info-c-selectprop-dialog")
			.afterClose((selected?: IAttributeInfo) => {
				if (selected) {
					this.applyUserProperty(selected);
					this.updateProperty(this.item.t, "t", true);
					if (this.textValidationDirective) {
						setTimeout(() => this.textValidationDirective.validate({}));
					}
				}
			});

		dialog
			.apply((comp) => {
				comp.modalDialog = dialog;
			})
			.open();
	}

	updateOptionsItems() {
		if (!this.optionsItems) {
			this.optionsItems = [];
		}
		const item = this.item;
		switch (item.it) {
			case DynamicItemType.Link:
				this.updateLinkOptionsItem();
				break;
			case DynamicItemType.Attribute:
				this.updateAttributeOptionsItem();
				break;
			case DynamicItemType.Text:
				this.updateTextOptionsItem();
				break;
			default:
				this.logDebug("ngOnInit: Could not determine item type for content");
		}
		this.setIsTranslateable();
		this.optionsItems = [...this.optionsItems];
	}

	setIsTranslateable() {
		const item = this.item;
		const label = item.l;
		const hasLabel = label && label.length > 0;
		const isAttribute = item.it === DynamicItemType.Attribute;
		this.isTranslateable = !(isAttribute && this.isCustomLabel) || hasLabel;
	}

	private updateLinkOptionsItem() {
		const titleLznItemIndex = this.getTranslationItemIndex("t");
		const hasTitleLznItem = titleLznItemIndex > -1;
		if (hasTitleLznItem) {
			this.optionsItems[titleLznItemIndex].defaultValue = this.item.t;
		} else {
			this.setLinkOptionsItem();
		}
	}

	private setLinkOptionsItem() {
		this.setOptionsItems([
			{
				name: "t",
				label: "Title",
				labelId: "lm-a-dp-aec-at-t-lbl",
				valueId: "lm-a-dp-aec-at-t-inp",
				maxLength: Constants.dynPageDefaultMaxLength,
				defaultValue: this.item.t,
			},
		]);
	}

	private updateAttributeOptionsItem() {
		const labelLznItemIndex = this.getTranslationItemIndex("l");
		const hasLabelLznItem = labelLznItemIndex > -1;
		if (this.hasLabel()) {
			if (hasLabelLznItem) {
				this.optionsItems[labelLznItemIndex].defaultValue = this.item.l;
			} else {
				this.setAttributeOptionsItem();
			}
		} else {
			this.removeTranslationItem("l");
		}
	}

	private setAttributeOptionsItem() {
		const item = this.item;
		const label = item.l
			? item.l
			: item.t && !this.isCustomLabel
			  ? this.trimCurlyBracesPipe.transform(item.t)
			  : "";
		this.setOptionsItems([
			{
				name: "l",
				label: "Label",
				labelId: "lm-a-dp-aec-at-l-lbl",
				valueId: "lm-a-dp-aec-at-t-inp",
				maxLength: Constants.dynPageDefaultMaxLength,
				defaultValue: label,
			},
		]);
	}

	private updateTextOptionsItem() {
		const labelLznItemIndex = this.getTranslationItemIndex("l");
		const textLznItemIndex = this.getTranslationItemIndex("t");
		const hasLabelLznItem = labelLznItemIndex > -1;
		const hasTextLznItem = textLznItemIndex > -1;
		const optionsItems = this.optionsItems;
		const item = this.item;
		if (this.hasLabel()) {
			if (hasLabelLznItem && hasTextLznItem) {
				optionsItems[textLznItemIndex].defaultValue = item.t;
				optionsItems[labelLznItemIndex].defaultValue = item.l;
			} else if (hasTextLznItem) {
				optionsItems[textLznItemIndex].defaultValue = item.t;
				this.addLabelOptionsItem();
			} else if (hasLabelLznItem) {
				optionsItems[labelLznItemIndex].defaultValue = item.l;
				this.addTextOptionsItem();
			} else {
				this.addLabelOptionsItem();
				this.addTextOptionsItem();
			}
		} else {
			if (hasTextLznItem) {
				optionsItems[textLznItemIndex].defaultValue = item.t;
			} else {
				this.addTextOptionsItem();
			}
			this.removeTranslationItem("l");
		}
	}

	private addLabelOptionsItem() {
		this.optionsItems.unshift({
			name: "l",
			label: "Label",
			labelId: "lm-a-dp-aec-at-l-lbl",
			valueId: "lm-a-dp-aec-at-t-inp",
			maxLength: Constants.dynPageDefaultMaxLength,
			defaultValue: this.item.l,
			isRequired: false,
		});
	}

	private addTextOptionsItem() {
		this.optionsItems.push({
			name: "t",
			label: "Text",
			labelId: "lm-a-dp-aec-at-t-lbl",
			valueId: "lm-a-dp-aec-at-t-inp",
			maxLength: Constants.dynPageTextMaxLength,
			defaultValue: this.item.t,
			isTextArea: true,
			isRequired: false,
		});
	}

	private applyUserProperty(info: IAttributeInfo) {
		const formattedProperty = DynamicUtil.formatProperty(info);
		switch (this.item.it) {
			case DynamicItemType.Link:
				this.logDebug("applyUserProperty: Not yet implemented on links");
				break;
			case DynamicItemType.Attribute:
				this.item.t = formattedProperty;
				break;
			case DynamicItemType.Text:
				this.item.t = this.item.t
					? this.applyUserPropertyAtCaret(this.item, formattedProperty)
					: formattedProperty;
				break;
			default:
				this.logDebug(
					"applyUserProperty: Could not determine item type for content",
				);
		}
	}

	private applyUserPropertyAtCaret(
		item: IDynamicItem,
		propertyName: string,
	): string {
		const startIndex = this.textItemTextArea.nativeElement.selectionStart;
		const endIndex = this.textItemTextArea.nativeElement.selectionEnd;
		if (startIndex !== undefined && endIndex !== undefined) {
			return (
				item.t.slice(0, startIndex) + propertyName + item.t.slice(endIndex)
			);
		}
		return item.t + propertyName;
	}

	private getItemData(): IDynamicItem {
		switch (this.item.it) {
			case DynamicItemType.Link:
				return this.item;
			case DynamicItemType.Attribute:
				if (this.attributeLabel) {
					this.item.l = this.attributeLabel.trim();
				}
				if (!this.isCustomLabel) {
					this.item.l = this.trimCurlyBracesPipe.transform(this.item.t);
				}
				return this.item;
			case DynamicItemType.Text:
				const item = this.item;
				item.t = item.t.trim();
				if (item.l) {
					item.l = item.l.trim();
				}
				return item;
			default:
				this.logDebug("getItemData: Could not determine item type for content");
		}
	}

	private setOptionsItems(items: ITranslationItem[]) {
		this.optionsItems = items;
	}

	private hasLabel() {
		const item = this.item;
		const label = item.l;
		const hasLabel = label && label.length > 0;
		const isAttribute = item.it === DynamicItemType.Attribute;
		return (isAttribute && !this.isCustomLabel) || hasLabel;
	}
}

@Pipe({ name: "lmTrimCurlyBraces" })
export class TrimCurlyBracesPipe implements PipeTransform {
	transform(value: string): string {
		// Todo: Improve regex
		value = value.replace(/[{}]/g, "");

		const index = value.indexOf("|");
		if (index > 0) {
			value = value.substring(0, index);
		}
		return value;
	}
}
