import { Component, NgZone, OnInit, ViewContainerRef } from "@angular/core";
import { SohoMessageService, SohoModalDialogService } from "ids-enterprise-ng";
import {
	ICatalogRequest,
	IOperationResponse,
	IWidgetEarlyAccessRequest,
	LanguageService,
	WidgetService,
} from "lime/core";
import { MessageBannerLevel } from "../common/message-banner";
import {
	AdminContext,
	AdminService,
	IAdminAction,
	IAdminTool,
} from "../service";
import { StandardWidgetsBaseComponent } from "./standard-widgets";

@Component({
	selector: "lm-admin-early-access-widgets",
	templateUrl: "./standard-widgets.html",
})
export class EarlyAccessWidgetsComponent
	extends StandardWidgetsBaseComponent
	implements OnInit
{
	// Override IDs to avoid conflicts with other instances of the base component
	idSort = "lm-a-eaw-sort";
	idFilter = "lm-a-eaw-filter";
	idPermissions = "lm-a-eaw-perm";
	idSearch = "lm-a-eaw-search";

	constructor(
		messageService: SohoMessageService,
		languageService: LanguageService,
		adminService: AdminService,
		sohoModalDialogService: SohoModalDialogService,
		zone: NgZone,
		adminContext: AdminContext,
		widgetService: WidgetService,
		viewRef: ViewContainerRef,
	) {
		super(
			"EarlyAccessWidgetsComponent",
			messageService,
			languageService,
			adminService,
			sohoModalDialogService,
			zone,
			adminContext,
			widgetService,
			viewRef,
			{
				isFilter: false,
				isUserFilter: false,
			},
		);

		this.enablePortation = false;
		this.enableShow = false;

		this.messageBanner = {
			title:
				"Get early access to upcoming Infor Homepages widgets before they are publicly released",

			message:
				"IMPORTANT NOTICE: Early access widgets are beta software that may not be fully tested so you might experience technical difficulties. Early access widgets are not intended as a substitute for your primary widgets and Homepages content. Early access content may be different from publicly released content. Infor is not responsible for any technical difficulties or data loss that occurs through the use of early access widgets.",
			level: MessageBannerLevel.Info,
		};
	}

	setRequestFilters(request: ICatalogRequest): void {
		request.includeEarlyAccessOnly = true;
	}

	protected getEmptyMessage(): string {
		return "No early access widgets found";
	}

	protected validateAngularJS(tool: IAdminTool) {
		// Don't show this message for early access
	}

	protected getActions(): IAdminAction[] {
		const actions = super.getActions();
		actions.unshift({
			text: () => "Disable",
			icon: "collapse-all",
			click: () => this.onUpdate(false),
			enabled: () => {
				return this.canToggle(false);
			},
		});
		actions.unshift({
			text: () => "Enable",
			icon: "expand-all",
			click: () => this.onUpdate(true),
			enabled: () => {
				return this.canToggle(true);
			},
		});
		return actions;
	}

	protected getColumns(): SohoDataGridColumn[] {
		const self = this;
		const columns = super.getColumns();

		(columns[1].width as number) -= 100;
		const column = {
			width: 100,
			id: "adm-eaw-col-ebl",
			field: "isEnabled",
			name: "Enabled",
			sortable: false,
			formatter: (row, cell, value) => {
				return self.items[row].isEnabled ? "Yes" : "No";
			},
		};
		columns.splice(2, 0, column);

		return columns;
	}

	private canToggle(enable: boolean): boolean {
		const items = this.getSelectedItems();
		if (items.length === 0) {
			return false;
		}
		for (const item of items) {
			if (enable && item.isEnabled) {
				return false;
			}
			if (!enable && !item.isEnabled) {
				return false;
			}
		}
		return true;
	}

	private onUpdate(enable: boolean): void {
		if (this.isBusy) {
			return;
		}

		const request = {
			enable: enable,
			content: this.getSelectedIds(),
		} as IWidgetEarlyAccessRequest;

		this.setBusy(true);
		this.widgetService.updadateEarlyAccess(request).subscribe(
			(r: IOperationResponse) => {
				this.setBusy(false);
				this.refresh();
			},
			(r: IOperationResponse) => {
				this.setBusy(false);
				this.adminService.handleError(r, r.getErrorMessages());
			},
		);
	}

	private getSelectedIds(): string[] {
		return this.getSelectedItems().map((item) => item.widgetId);
	}
}
