import { Pipe, PipeTransform } from "@angular/core";
import { ArrayUtil, CommonUtil, HtmlUtil } from "lime";
import {
	ArchiveType,
	IEntityAccess,
	IPage,
	ISettingItem,
	ISettingRuleConnection,
	SettingItemType,
	SettingsNames,
} from "lime/core";
import { DynamicPageState } from "./pages/dyn/core";
import type { IPageSelectorOptions } from "./service";

@Pipe({ name: "lmAccessState" })
export class AccessStatePipe implements PipeTransform {
	static map = {
		0: "-",
		1: "Disabled",
		2: "Restricted",
		3: "&nbsp;",
	};

	transform(value: string) {
		return AccessStatePipe.map[value];
	}
}

/**
 * Defines formatter functions for the Soho XI Data grid
 */
export class CustomFormatters {
	/**
	 * Converts an AccessState value to a description.
	 */
	static accessState(row, cell, value, col): string {
		return AccessStatePipe.map[value] as string;
	}

	static date(row, cell, value: string, col): string {
		return CommonUtil.getLocaleDateString(value);
	}

	static restricted(row, cell, value, col): string {
		return value ? "Restricted" : "&nbsp;";
	}

	static pageOrWidgetType(row, cell, value, col): string {
		return value ? "Standard" : "Published";
	}

	/**
	 * Gets an escaped string that is safe to insert into HTML.
	 */
	static text(row, cell, value: string, col): string {
		return HtmlUtil.escapeStringForHtml(value);
	}

	static dynamicPageStatus(row, cell, value: DynamicPageState, col): string {
		switch (value) {
			case DynamicPageState.Draft:
				return "Draft";
			case DynamicPageState.Published:
				return "Published";
			case DynamicPageState.PublishedEdited:
				return "Published (Edited)";
			default:
				return "Unknown";
		}
	}

	static archiveType(row, cell, value: ArchiveType, col): string {
		return value === ArchiveType.DynamicPage ? "Dynamic" : "Unknown";
	}

	static propertyDataType(row, cell, value: string, col): string {
		switch (value) {
			case "op":
				return "Operation";
			case "fnc":
				return "Function";
			case "b":
				return "Boolean";
			case "s":
				return "String";
			case "n":
				return "Number";
			case "d":
				return "Date";
			default:
				return "Unknown";
		}
	}

	static displayName(row, cell, value: string, col): string {
		return value ? CustomFormatters.text(row, cell, value, col) : "Unknown";
	}

	static dynamicDisabledExpander(
		row: number,
		cell: any,
		value: string,
		col: SohoDataGridColumn,
		item: IPage,
		api: SohoDataGridStatic,
	): string {
		if (item.err) {
			value = `
				<svg class="icon datagrid-alert-icon icon-alert lm-admin-page-warn-icon"
					focusable="false"
					aria-hidden="true"
					role="presentation">
					<use xlink:href="#icon-alert"></use>
				</svg>
				<span class="lm-margin-sm-l lm-text-alert">${value}</span>
			`;
		}
		return Formatters.Expander(row, cell, value, col, item, api) as string;
	}
}

/**
 * Utility class for the setting tab.
 */
export class SettingUtil {
	static getPageDisplayValue(value: string): string {
		if (value) {
			if (value.indexOf("{") >= 0) {
				// New JSON format, if empty the value will be {"pages":[]}
				return value === '{"pages":[]}' ? "<not set>" : "Edit...";
			} else {
				return "Edit...";
			}
		} else {
			return "<not set>";
		}
	}

	static getDisplayValue(item: ISettingItem, itemValue: string): string {
		const types = SettingItemType;
		const itemType = item.type;
		let displayValue: string;
		if (
			item.type === types.typeDefaultPages ||
			item.type === types.typeMandatoryPages
		) {
			displayValue = SettingUtil.getPageDisplayValue(itemValue);
		} else if (itemType === types.typeSelector) {
			const valueObject = ArrayUtil.itemByProperty(
				item.setting.values,
				"value",
				itemValue,
			);
			if (valueObject) {
				displayValue = valueObject.label;
			} else {
				displayValue = itemValue;
			}
		} else {
			displayValue = `${itemValue}`;
		}
		return displayValue;
	}

	static mergePages(items: any[], newItems: any[]): any[] {
		if (!items) {
			return newItems;
		}
		for (const item of newItems) {
			if (
				ArrayUtil.indexByPredicate(items, (i) => i.data.id === item.data.id) < 0
			) {
				items.push(item);
			}
		}
		return items;
	}

	static pageSelectorOptions(
		item: ISettingItem,
		selectedPages: any[],
	): IPageSelectorOptions {
		const isMultiSelect = item.settingName === SettingsNames.mandatoryPages;
		return {
			title: item.setting.label,
			isMultiSelect: isMultiSelect,
			noShowIds: selectedPages.map((page) => page.data.id),
		};
	}

	// TODO This a temporary function until final client implementation for mandatory and default pages are in place
	static getPageSelectorValue(items: any): any {
		if (!items || items.length === 0) {
			return "";
		}

		// TODO Mandatory and Default pages will require different additional properties in addition to the id property
		const pages = items.map((page: any) => {
			return {
				id: page.data.id,
			};
		});

		const value = { pages: pages };
		return JSON.stringify(value);
	}

	static isSameConnection(
		item1: ISettingRuleConnection,
		item2: ISettingRuleConnection,
	): boolean {
		return !!(
			item1 &&
			item2 &&
			item1.isUser === item2.isUser &&
			item1.name === item2.name
		);
	}

	static hasConnection(
		items: ISettingRuleConnection[],
		item: ISettingRuleConnection,
	): boolean {
		return !!ArrayUtil.find(items, (foundItem: ISettingRuleConnection) => {
			return SettingUtil.isSameConnection(item, foundItem);
		});
	}
}

export class WidgetUtilAdmin {
	static getAccessCopy(accessList: IEntityAccess[]): IEntityAccess[] {
		if (!accessList) {
			return accessList;
		}
		const access = [];
		for (const accessEntity of accessList) {
			access.push(accessEntity);
		}
		return access;
	}
}

export class GridUtil {
	static formatError(message: string): string {
		const icon = $.createIcon({
			icon: "error",
			classes: ["icon", "datagrid-alert-icon", "icon-error"],
		});
		return `<div>${icon}<span class="lm-margin-sm-l text-alert">${message}</span></div>`;
	}

	static formatAlert(message: string, yellow?: boolean): string {
		const icon = $.createIcon({
			icon: "alert",
			classes: ["icon", "datagrid-alert-icon", "icon-alert"],
		});

		const yellowClass = yellow ? " lm-text-alert" : "";
		return `<div>${icon}<span class="lm-margin-sm-l${yellowClass}">${message}</span></div>`;
	}
}
