import {
	Component,
	EventEmitter,
	Input,
	NgZone,
	OnInit,
	Output,
	ViewChild,
	ViewContainerRef,
} from "@angular/core";
import {
	SohoDataGridComponent,
	SohoMessageService,
	SohoModalDialogService,
} from "ids-enterprise-ng";
import { ArrayUtil, CommonUtil } from "lime";
import {
	AccessUtil,
	AdminPages,
	Constants,
	EntityListType,
	EntityType,
	IEntityListItem,
	IFeaturedItem,
	IFeaturedListResponse,
	IFeaturedRequest,
	IOperationResponse,
	ISetting,
	IWidgetInfo,
	LanguageService,
} from "lime/core";
import { Observable, Subscription } from "rxjs";
import { CustomFormatters } from "../admin";
import { AdminListComponent } from "../admin-list.component";
import { AdminContext, AdminService, AdminUtil } from "../service";
import { AdminSettingsService } from "../settings/admin-settings.service";

@Component({
	selector: "lm-admin-featured",
	templateUrl: "./featured.html",
})
export class AdminFeaturedComponent
	extends AdminListComponent<IFeaturedItem>
	implements OnInit
{
	@ViewChild(SohoDataGridComponent, { static: false })
	featuredDatagrid: SohoDataGridComponent;
	@Input() entityType: number;
	@Output() onGoToFeatures = new EventEmitter<AdminPages>();

	featureBannerOn: boolean;
	private isAdministrator: boolean;
	private subscriptions = new Subscription();

	constructor(
		messageService: SohoMessageService,
		languageService: LanguageService,
		adminService: AdminService,
		sohoModalDialogService: SohoModalDialogService,
		ngZone: NgZone,
		private adminContext: AdminContext,
		private readonly viewRef: ViewContainerRef,
		private readonly settingsService: AdminSettingsService,
	) {
		super(
			"FeaturedPagesComponent",
			"featured",
			messageService,
			languageService,
			adminService,
			sohoModalDialogService,
			ngZone,
		);

		this.subscriptions.add(
			this.settingsService.features$.subscribe((features) => {
				const setting = ArrayUtil.itemByProperty<ISetting>(
					features,
					"settingName",
					"BannerWidget",
				);
				if (setting) {
					this.featureBannerOn = setting.value === "true";
				}
			}),
		);
	}

	ngOnInit(): void {
		this.listItems();

		const tool = this.adminContext.get();
		if (tool) {
			this.isAdministrator = tool.isAdministrator;
			this.featureBannerOn = tool.featureBanner;
			this.isReadOnly = AdminUtil.isReadOnlyUser(tool);
		}
		this.initGrid();
	}

	ngOnDestroy(): void {
		this.subscriptions.unsubscribe();
	}

	listItems(): void {
		const request = this.request();
		const observable = this.adminService.listFeatured(request);
		this.execute(observable);
	}

	canEdit(): boolean {
		if (this.selectionCount !== 1) {
			return false;
		}

		// Dynamic pages are not allowed to be edited
		if (this.selected.isDynamic) {
			return false;
		}

		if (this.isAdministrator) {
			return true;
		}

		// Content admins may only edit published content
		return !this.selected.isStandard;
	}

	onClickRemoveAsFeatured(): void {
		const featuredItems = this.getSelectedItems();
		let featuredToUnset = featuredItems.length;

		for (const featuredItem of featuredItems) {
			const entityItem: IEntityListItem = {
				listType: EntityListType.Featured,
				entityType: this.entityType as number,
				entity: featuredItem.id,
			};
			this.adminService.removeFeaturedItem(entityItem).subscribe(
				() => {
					// nop
				},
				(r: IOperationResponse) => {
					this.adminService.handleError(r);
				},
				() => {
					featuredToUnset--;
					if (!featuredToUnset) {
						this.setBusy(false);
						this.refresh();
					}
				},
			);
		}
	}

	onExpandRow(event: any): void {
		const container = $(event.detail)
			.find(".datagrid-row-detail-padding")
			.empty();
		if (event.item) {
			const item = event.item;
			let template = `<div class="datagrid-cell-layout">
					<p><span class="datagrid-textarea lm-white-space-normal">${this.escape(
						item.description,
					)}</span></p>
					<p>
						<span class="label">Change date: ${CommonUtil.getLocaleDateString(
							item.changeDate,
						)}</span>
						<span class="label">Changed by: ${this.escape(item.changedByName)}</span>
					`;

			if (!item.isStandard) {
				template += `<span class="label">Owner: ${this.escape(
					item.ownerName,
				)}</span></p>`;
			}

			template += `</div>`;
			$(container).append($(template));
		}
	}

	editAccess(): void {
		const item = this.getSelectedItems()[0];
		if (this.entityType === EntityType.Page) {
			this.openPageAccess(item);
		} else {
			this.openWidgetAccess(item);
		}
	}

	/**
	 * Go to the Featured page.
	 */
	goToFeaturesPage(event: Event): void {
		event.preventDefault(); // Prevent reload
		this.onGoToFeatures.emit(AdminPages.Features);
	}

	onRowReordered(event: SohoDataGridRowReorderedEvent) {
		const start = event.startIndex;
		const end = event.endIndex;

		if (start === end) {
			return;
		}

		const request = this.request(this.items);
		const observable = this.adminService.reorderFeatured(request);
		this.execute(observable);
	}

	protected getDataGrid(): SohoDataGridComponent {
		return this.featuredDatagrid;
	}

	protected getColumns(): SohoDataGridColumn[] {
		return [
			{
				width: 62,
				id: "rowReorder",
				field: "id",
				align: "center",
				sortable: false,
				formatter: Formatters.RowReorder,
			},
			this.getSelectionColumn(),
			{
				width: 383,
				id: "adm-fp-col-t",
				field: "title",
				name: "Title",
				resizable: true,
				sortable: false,
				formatter: Formatters.Expander,
			},
			{
				width: 150,
				id: "adm-fp-col-typ",
				field: "isStandard",
				name: "Type",
				resizable: true,
				sortable: false,
				formatter: CustomFormatters.pageOrWidgetType,
			},
			{
				width: 200,
				id: "adm-fp-col-sd",
				field: "setDate",
				name: "Set date",
				resizable: true,
				sortable: false,
				formatter: CustomFormatters.date,
			},
			{
				width: 200,
				id: "adm-fp-col-sbn",
				field: "setByName",
				name: "Set by",
				resizable: true,
				sortable: false,
				formatter: CustomFormatters.displayName,
			},
			{
				width: 200,
				id: "adm-fp-col-hr",
				field: "hasRestrictions",
				name: "Permissions",
				sortable: false,
				formatter: CustomFormatters.restricted,
			},
		];
	}

	private execute(observable: Observable<IFeaturedListResponse>): void {
		this.setBusy(true);
		observable.subscribe(
			(response: IFeaturedListResponse) => {
				if (!response.hasError()) {
					const featuredItems = response.content;
					this.items = featuredItems;
					this.updateGridData();
				}
				this.setBusy(false);
			},
			(r: IOperationResponse) => {
				this.setBusy(false);
				this.adminService.handleError(r);
			},
		);
	}

	private request(items?: IFeaturedItem[]): IFeaturedRequest {
		const request: IFeaturedRequest = { entityType: this.entityType };
		if (items) {
			request.items = items.map((item) => {
				return { id: item.id, title: item.title };
			});
		}
		return request;
	}

	private openPageAccess(item: IFeaturedItem): void {
		const fakePage = { data: { id: item.id, title: item.title } };
		const options = item.isStandard
			? AccessUtil.standardPages(this.languageService, fakePage)
			: AccessUtil.publishedPages(this.languageService, fakePage);
		options.callback = () => this.listItems();
		this.adminService.openPageAccessDialog(options, this.viewRef);
	}

	private openWidgetAccess(item: IFeaturedItem): void {
		const fakeWidget: IWidgetInfo = { widgetId: item.id, title: item.title };
		this.adminService.openWidgetAccessDialog(
			fakeWidget,
			() => {
				this.listItems();
			},
			this.viewRef,
		);
	}

	private initGrid(): void {
		let entityTypeString: string;
		if (this.entityType === 1) {
			entityTypeString = "widgets";
		} else if (this.entityType === 2) {
			entityTypeString = "pages";
		} else {
			entityTypeString = "banner widgets";
		}
		this.datagridOptions = {
			selectable: "multiple" as SohoDataGridSelectable,
			disableRowDeactivation: true,
			expandableRow: true,
			clickToSelect: false,
			rowReorder: !this.isReadOnly,
			columns: this.getColumns(),
			dataset: [],
			emptyMessage: {
				title: `No featured ${entityTypeString} found`,
				icon: Constants.adminEmptyDatagridIcon,
			},
		} as SohoDataGridOptions;
	}
}
