import { Component } from "@angular/core";
import { SohoModalDialogRef } from "ids-enterprise-ng";
import { ArrayUtil, IAutocompleteEntity } from "lime";
import {
	AutoCompleter,
	CommonDataService,
	PrincipalType,
	Templates,
} from "lime/core";

@Component({
	templateUrl: "./user-selector.html",
})
export class AdminUserSelectorComponent {
	dialog: SohoModalDialogRef<AdminUserSelectorComponent>;
	selectedUser: IAutocompleteEntity;
	searchStringGroup: string;
	autocompleteSource: Function;
	autocompleteTemplate: string;

	constructor(private readonly commonDataService: CommonDataService) {
		this.initAutocomplete();
	}

	selectUser(event: any): void {
		this.selectedUser = event && event.value ? event : null;
	}

	save() {
		this.dialog.close({ value: this.selectedUser });
	}

	private initAutocomplete(): void {
		const self = this;
		this.autocompleteSource = new AutoCompleter<IAutocompleteEntity[]>(
			(query) => self.commonDataService.searchEntity(PrincipalType.User, query),
			(response) => ArrayUtil.sortByProperty(response, "label"),
			self.commonDataService,
		).source;
		this.autocompleteTemplate = Templates.autocompleteEntity;
	}
}
