import { Component, EventEmitter, Output } from "@angular/core";
import { ArrayUtil } from "lime";
import {
	CoreUtil,
	DynamicItemType,
	IDynamicContainer,
	IDynamicItem,
} from "lime/core";
import { of } from "rxjs";
import { catchError } from "rxjs/operators";
import { DynamicUtil } from "../../../../util";
import { DynamicContainerListBase } from "../../dynamic-container/dynamic-container-list";
import { DynamicInformationContentDialog } from "./add-content-dialog";

@Component({
	selector: "lm-content-list-component",
	templateUrl: "../../dynamic-container/dynamic-container-list.html",
	styleUrls: ["../../dynamic-container/dynamic-container-list.scss"],
})
export class DynamicContentListComponent extends DynamicContainerListBase {
	@Output() contentAdded = new EventEmitter();
	contentType: string;

	ngOnInit() {
		this.updateEmptyProperty();
		this.initItems("Add Content", "", "Content type", "Content", "Label");
	}

	addLineBreak() {
		if (!this.canAdd()) {
			return;
		}
		const lineBreak: IDynamicItem = {
			eid: DynamicUtil.getNewEntityId(this.container),
			it: DynamicItemType.Linebreak,
		};
		this.pageService.addContainerEntity(this.container, lineBreak).subscribe();
	}

	addContent(itemType: DynamicItemType) {
		if (!this.canAdd() || this.isDialogOpen) {
			return;
		}
		this.isDialogOpen = true;

		const dialog = this.dialogService
			.modal(DynamicInformationContentDialog, this.viewContainerRef)
			.title("Add Content")
			.id("lm-a-dp-info-addcontent-dialog")
			.afterClose((content) => {
				this.isDialogOpen = false;
				if (content) {
					this.updateEmptyProperty();
				}
			});

		dialog
			.apply((component: DynamicInformationContentDialog) => {
				component.modalDialog = dialog;
				component.container = this.container;
				component.isEdit = false;
				component.containerLznEdited = component.container.lzn;
				component.item = { it: itemType };
			})
			.open();
	}

	editItem(isPermissionTab: boolean, content: IDynamicItem): void {
		if (this.isDialogOpen) {
			return;
		}
		this.isDialogOpen = true;

		const expressions = DynamicUtil.toExpressions(content, this.accessTitles);
		const dialog = this.dialogService
			.modal(DynamicInformationContentDialog, this.viewContainerRef)
			.title(`${this.isEditable ? "Edit" : "View"} Content`)
			.id("lm-a-dp-info-editcontent-dialog")
			.afterClose((updatedContent) => {
				this.isDialogOpen = false;
				if (updatedContent) {
					this.updateEmptyProperty();
				}
			});

		dialog
			.apply((component: DynamicInformationContentDialog) => {
				component.modalDialog = dialog;
				component.container = this.container;
				component.oldContent = content;
				component.item = content;
				component.selectedExpressions = expressions;
				component.isEdit = true;
				component.containerLznEdited = component.container.lzn;
				component.isPermissionTabOnInit = isPermissionTab;
				component.isEditable = this.isEditable;
			})
			.open();
	}

	deleteItems(
		items: IDynamicItem[],
		parentContainer?: IDynamicContainer,
	): void {
		const containerCopy = CoreUtil.copy(parentContainer || this.container);

		for (const item of items) {
			const removeIndex = ArrayUtil.indexByProperty(
				containerCopy.its,
				"eid",
				item.eid,
			);
			if (removeIndex > -1) {
				containerCopy.its.splice(removeIndex, 1);
			}
		}
		this.pageService
			.updateContainer(containerCopy, null, items)
			.pipe(
				// Ignore error since it's handled in service
				catchError(() => of()),
			)
			.subscribe(() => this.updateEmptyProperty());
	}

	getEntityCount(): number {
		return (
			(this.container.its && this.container.its.length) +
			(this.container.hds && this.container.hds.length)
		);
	}

	private updateEmptyProperty() {
		const containers = this.pageService.getPage().cts;
		const container = ArrayUtil.itemByProperty(
			containers,
			"eid",
			this.container.eid,
		);
		const hasContent = container.its && container.its.length > 0;
		if (this.isEmpty === hasContent) {
			this.contentAdded.emit();
		}
		this.isEmpty = !hasContent;
	}
}
