import { Component, EventEmitter, Output } from "@angular/core";
import { AdminPages, CoreBase } from "lime/core";
import { Observable } from "rxjs";
import { map } from "rxjs/operators";
import { AdminAccessService } from "./admin-access.service";
import { AdminRoutingService } from "./admin-routing.service";
import { AdminContext } from "./service";

/**
 * Admin Home Component
 */
@Component({
	selector: "lm-admin-home",
	templateUrl: "./home.html",
	styleUrls: ["./home.scss"],
})
export class AdminHomeComponent extends CoreBase {
	@Output() changeTab = new EventEmitter<any>();

	tenant$: Observable<string>;
	canNavigateTo$ = this.routingService.canNavigateTo$;

	AdminPages = AdminPages;

	constructor(
		private contextService: AdminContext,
		private accessService: AdminAccessService,
		private routingService: AdminRoutingService,
	) {
		super("AdminHomeComponent");

		this.tenant$ = this.contextService.tool$.pipe(map((tool) => tool.tenantId));
	}

	navigateTo(page: AdminPages) {
		this.routingService.navigateTo(page);
	}

	getCardText(
		page: AdminPages,
		editAccessText: string,
		readAccessText: string,
	) {
		return this.accessService
			.editable(page)
			.pipe(map((editAble) => (editAble ? editAccessText : readAccessText)));
	}
}
