import { Component, OnInit } from "@angular/core";
import { ArrayUtil, StringUtil } from "lime";
import {
	Constants,
	CoreUtil,
	DynamicImageAlignment,
	IDynamicContainer,
	IDynamicImage,
	ModalDialogBase,
} from "lime/core";
import { of } from "rxjs";
import { catchError } from "rxjs/operators";
import { IExpInfo } from "../../../../service";
import { DynamicPageAdminService } from "../../service";
import { DynamicUtil } from "../../util";
import { DynamicContainerListBase } from "./dynamic-container/dynamic-container-list";

@Component({
	selector: "lm-dynamic-image-list",
	templateUrl: "./dynamic-container/dynamic-container-list.html",
	styleUrls: ["./dynamic-container/dynamic-container-list.scss"],
})
export class DynamicImageListComponent
	extends DynamicContainerListBase
	implements OnInit
{
	alignment = DynamicImageAlignment;

	ngOnInit() {
		const buttonText = "Add Image";
		const buttonInfoText =
			"This component is empty. Start adding content by clicking " +
			buttonText +
			".";
		this.updateIsEmptyProperty();
		this.initItems(buttonText, buttonInfoText, "Image", "Alignment");
		this.infoHeader = {
			text: "Only one image will be displayed.",
			title: "Images",
		};
	}

	addItem() {
		if (!this.canAdd() || this.isDialogOpen) {
			return;
		}
		this.isDialogOpen = true;

		const dialog = this.dialogService
			.modal(DynamicImageDialog, this.viewContainerRef)
			.title("Add Image")
			.id("lm-a-dp-image-add-dialog")
			.afterClose((image) => {
				this.isDialogOpen = false;
				if (image) {
					this.updateIsEmptyProperty();
				}
			});

		dialog
			.apply((component: DynamicImageDialog) => {
				component.modalDialog = dialog;
				component.container = this.container;
				component.isEdit = false;
			})
			.open();
	}

	editItem(isPermissionTab: boolean, image: IDynamicImage): void {
		if (this.isDialogOpen) {
			return;
		}
		this.isDialogOpen = true;

		const expressions = DynamicUtil.toExpressions(image, this.accessTitles);
		const dialog = this.dialogService
			.modal(DynamicImageDialog, this.viewContainerRef)
			.title(`${this.isEditable ? "Edit" : "View"} Image`)
			.id("lm-a-dp-image-edit-dialog")
			.afterClose((updatedImage) => {
				this.isDialogOpen = false;
				if (updatedImage) {
					this.updateIsEmptyProperty();
				}
			});

		dialog
			.apply((component: DynamicImageDialog) => {
				component.modalDialog = dialog;
				component.container = this.container;
				component.oldImage = image;
				component.image = image;
				component.selectedExpressions = expressions;
				component.isEdit = true;
				component.isPermissionTabOnInit = isPermissionTab;
				component.isEditable = this.isEditable;
			})
			.open();
	}

	deleteItems(
		images: IDynamicImage[],
		parentContainer?: IDynamicContainer,
	): void {
		const containerCopy = CoreUtil.copy(parentContainer || this.container);

		for (const image of images) {
			const removeIndex = ArrayUtil.indexByProperty(
				containerCopy.ims,
				"eid",
				image.eid,
			);
			if (removeIndex > -1) {
				containerCopy.ims.splice(removeIndex, 1);
			}
		}
		this.pageService
			.updateContainer(containerCopy, null, images)
			.pipe(
				// Ignore error since it's handled in service
				catchError(() => of()),
			)
			.subscribe(() => this.updateIsEmptyProperty());
	}

	onCopy() {
		this.copySelected(this.container.ims);
	}

	onCut() {
		this.cutSelected(this.container.ims);
	}

	onDeleteSelected() {
		this.deleteSelectedItems(this.container.ims);
	}

	getEntityCount(): number {
		return this.container.ims && this.container.ims.length;
	}

	private updateIsEmptyProperty() {
		const containers = this.pageService.getPage().cts;
		const container = ArrayUtil.itemByProperty(
			containers,
			"eid",
			this.container.eid,
		);
		const hasImages = container.ims && container.ims.length > 0;
		this.isEmpty = !hasImages;
		this.clearSelectionCount();
	}
}

@Component({
	templateUrl: "./add-image.html",
})
export class DynamicImageDialog extends ModalDialogBase implements OnInit {
	isEdit: boolean;
	image: IDynamicImage;
	oldImage: IDynamicImage;
	container: IDynamicContainer;
	alignment = DynamicImageAlignment;
	url: string;
	selectedExpressions: IExpInfo[];
	expressions: IExpInfo[];
	listLabel = "Choose which set of users this image should be visible for.";
	urlMaxLength = Constants.dynPageUrlMaxLength;
	isSaveDisabled = true;
	isPermissionTabOnInit: boolean;
	isEditable = true;

	constructor(public dynamicPageService: DynamicPageAdminService) {
		super("DynamicImageDialog");
	}

	ngOnInit(): void {
		this.image = {
			u: null,
			al: DynamicImageAlignment.Fill,
			...this.image,
		};
		this.initModalDialog();
		this.setIsSaveDisabled();
	}

	getNewImageId(): string {
		return DynamicUtil.getNewEntityId(this.container);
	}

	setIsSaveDisabled(): void {
		this.isSaveDisabled = StringUtil.isNullOrWhitespace(this.image.u);
	}

	save() {
		if (!this.isEditable) {
			return;
		}

		if (!this.image.eid) {
			this.image.eid = this.getNewImageId();
		}
		const image = CoreUtil.copy(this.image);

		if (this.expressions) {
			image.as = 1;
			image.ais = DynamicUtil.toIds(this.expressions);
			image.op = DynamicUtil.getOperator(this.expressions);
		} else if (this.selectedExpressions) {
			image.as = null;
			image.ais = null;
		}
		if (this.isEdit) {
			this.submitSafe(
				this.dynamicPageService.editContainerEntity(
					this.container,
					image,
					this.oldImage,
				),
				false,
				true,
			).subscribe(() => this.modalDialog.close(image));
		} else {
			this.submitSafe(
				this.dynamicPageService.addContainerEntity(this.container, image),
				false,
				true,
			).subscribe(() => this.modalDialog.close(image));
		}
	}
}
