import { Component, OnInit } from "@angular/core";
import { SohoMessageService, SohoModalDialogRef } from "ids-enterprise-ng";
import { ArrayUtil, DialogButtonType } from "lime";
import { CoreUtil, IOperationResponse, ModalDialogBase } from "lime/core";
import {
	AdminContext,
	AdminService,
	IPropertyInfo,
	IPropertyInfoResponse,
} from "../service";

@Component({
	templateUrl: "./property.html",
})
export class AddEditPropertyComponent
	extends ModalDialogBase
	implements OnInit
{
	modalDialog: SohoModalDialogRef<AddEditPropertyComponent>;
	parameter: any;
	property: IPropertyInfo;
	maskOptions: SohoMaskOptions;
	isEdit: boolean;
	addEditBtnLabel: string;
	items: IPropertyInfo[] = [];

	private invalidNames: string[];

	constructor(
		messageService: SohoMessageService,
		private adminService: AdminService,
		private adminContext: AdminContext,
	) {
		super("AddEditPropertyComponent", messageService);
	}

	ngOnInit(): void {
		const dialogParameter = CoreUtil.copy(this.parameter);
		this.property = dialogParameter.property;
		this.isEdit = dialogParameter.isEdit;
		this.addEditBtnLabel = this.isEdit ? "Save" : "Add";
		this.invalidNames = [
			"productname",
			"version",
			"logicalid",
			"hostname",
			"context",
			"port",
			"usehttps",
			"tenantid",
		];
		this.maskOptions = {
			definitions: {
				i: /[a-z0-9\.\_]/,
			},
			pattern:
				"iiiiiiiiiiiiiiiiiiiiiiiiiiiiiiiiiiiiiiiiiiiiiiiiiiiiiiiiiiiiiiii", // max-length 64.
		};
		this.initModalDialog();
	}

	onOk(): void {
		if (this.isNameValid()) {
			this.setCanClose(false);
			if (this.isEdit) {
				this.updateProperty();
			} else {
				this.addProperty();
			}
		} else {
			this.showInvalidDialog();
		}
	}

	private isNameValid(): boolean {
		return !ArrayUtil.contains(
			this.invalidNames,
			this.property.propertyId.toLowerCase(),
		);
	}

	private showInvalidDialog(): void {
		const buttons = [
			{
				text: "Ok",
				id: "lm-a-prop-invalid-message-ok",
				click: (e, modal) => {
					modal.close();
				},
				isDefault: true,
			},
		];

		this.messageService
			.error()
			.title("Invalid name")
			.message(`The property name '${this.property.propertyId}' is not valid.`)
			.attributes({ name: "id", value: "lm-a-prop-invalid-message" })
			.buttons(buttons)
			.open();
	}

	private addProperty(): void {
		const property = this.property;
		const adminService = this.adminService;
		const existingProperty = ArrayUtil.itemByProperty(
			this.items,
			"propertyId",
			property.propertyId,
		);
		if (!existingProperty) {
			this.setBusy(true);
			const self = this;
			adminService.createProperty(property).subscribe(
				(r: IPropertyInfoResponse) => {
					r.content.changedByName = this.adminContext.get().userName;
					this.closeWithResult(DialogButtonType.Ok, r.content);
				},
				(r: IOperationResponse) => {
					adminService.handleError(r, "Could not add property.");
					self.setBusy(false);
					self.setCanClose(true);
				},
			);
		} else {
			this.setCanClose(true);
			this.showMessage(
				"Could not add property",
				"A property with that name already exists",
			);
		}
	}

	private updateProperty(): void {
		const adminService = this.adminService;
		const property = this.property;
		this.setBusy(true);
		adminService.updateProperty(this.property).subscribe(
			(response: IPropertyInfoResponse) => {
				const properties = this.items;
				const propIndex = ArrayUtil.indexByProperty(
					properties,
					"propertyId",
					property.propertyId,
				);
				properties[propIndex] = property;
				this.closeWithResult(DialogButtonType.Ok, response.content);
			},
			(r: IOperationResponse) => {
				this.setBusy(false);
				this.setCanClose(true);
				adminService.handleError(r);
			},
		);
	}
}
