import { Component, Input, OnInit } from "@angular/core";
import { SohoMessageService, SohoModalDialogRef } from "ids-enterprise-ng";
import { ArrayUtil, DialogButtonType } from "lime";
import { IAttributeInfo, ModalDialogBase } from "lime/core";
import {
	AdminService,
	AdminUtil,
	IExpInfo,
	IExpressionTestRequest,
} from "../service";

export interface ITestItem {
	label: string;
	selected: boolean;
	value?: string;
	type?: string;
	attribute?: IAttributeInfo;
	isAttribute?: boolean;
	isGroup?: boolean;
	isRole?: boolean;
}

export interface IPolicyTestOptions {
	expInfo: IExpInfo;
	attributes: { [key: string]: IAttributeInfo };
	roles: { [key: string]: string };
	groups: { [key: string]: string };
}

@Component({
	templateUrl: "./policy-test.html",
	styles: [
		`
			.field {
				padding-left: 1px;
			}
		`,
	],
})
export class PolicyTestComponent extends ModalDialogBase implements OnInit {
	modalDialog: SohoModalDialogRef<PolicyTestComponent>;
	options: IPolicyTestOptions;
	items: ITestItem[];
	@Input() isImpersonation = true;
	message: string;

	constructor(
		messageService: SohoMessageService,
		private readonly adminService: AdminService,
	) {
		super("PolicyTestComponent", messageService);
	}

	ngOnInit(): void {
		const options = this.options;
		const attributes = this.toAttributes(options.attributes);
		const roles = this.toItem(options.roles, true);
		const groups = this.toItem(options.groups, false);
		const items = attributes.concat(groups).concat(roles);
		ArrayUtil.sortByProperty(items, "label");
		this.items = items;
	}

	onClose(): void {
		this.closeWithResult(DialogButtonType.Ok, true);
	}

	onEvaluate(): void {
		this.message = null;
		const request = this.createRequest();
		this.setBusy(true);
		this.adminService.testExpression(request).subscribe(
			(response) => {
				this.message = "Evaluation result: " + response.content;
				this.setBusy(false);
			},
			() => {
				this.message = "Failed to evaluate security policy";
				this.setBusy(false);
			},
		);
	}

	private createRequest(): IExpressionTestRequest {
		const request: IExpressionTestRequest = {
			content: this.options.expInfo,
		};

		if (!this.isImpersonation) {
			return request;
		}

		this.addRequestItems(request);
		return request;
	}

	private addRequestItems(request: IExpressionTestRequest): void {
		const groups: string[] = [];
		const roles: string[] = [];
		const attributes: { [key: string]: string[] } = {};

		for (const item of this.items) {
			const isSelected = item.selected;
			if (item.isAttribute) {
				let value: string;
				if (item.type === "b") {
					value = isSelected ? "1" : "0";
				} else if (item.type === "d") {
					value = AdminUtil.getIsoDateString(item.value);
				} else {
					value = item.value;
				}
				if (value) {
					attributes[item.label] = [value];
				}
			} else if (isSelected) {
				if (item.isRole) {
					roles.push(item.label);
				} else if (item.isGroup) {
					groups.push(item.label);
				}
			}
		}

		request.attributes = attributes;
		request.groups = groups;
		request.roles = roles;
	}

	private toAttributes(values: { [key: string]: IAttributeInfo }): ITestItem[] {
		const items = [];
		for (const key of Object.keys(values)) {
			const attribute = values[key];
			items.push({
				label: attribute.name,
				selected: false,
				type: attribute.type,
				isAttribute: true,
			});
		}
		return items;
	}

	private toItem(
		values: { [key: string]: string },
		isRole: boolean,
	): ITestItem[] {
		const items = [];
		for (const key of Object.keys(values)) {
			items.push({
				label: key,
				selected: false,
				type: "b",
				isRole: isRole,
				isGroup: !isRole,
			});
		}
		return items;
	}
}
