import { Component, EventEmitter, Input, OnInit, Output } from "@angular/core";
import { CommonUtil } from "lime";
import { CoreBase } from "lime/core";

export enum MessageBannerLevel {
	Info,
	Warning,
	Error,
	Success,
}

export interface IMessageBannerAction {
	text: string;
	execute: () => void;
	icon?: string;
}

export interface IMessageBannerOptions {
	title?: string;
	message: string;
	level?: MessageBannerLevel;
	icon?: string;
	backgroundClass?: string;
	iconClass?: string;
	dismissable?: boolean;
	actions?: IMessageBannerAction[];
}

@Component({
	selector: "lm-admin-message-banner",
	templateUrl: "./message-banner.html",
	styleUrls: ["./message-banner.scss"],
})
export class MessageBannerComponent extends CoreBase implements OnInit {
	@Input() options: IMessageBannerOptions = { message: "" };
	@Output() dismissed = new EventEmitter<void>();

	constructor() {
		super("MessageBannerComponent");
	}

	ngOnInit(): void {
		if (!CommonUtil.isUndefined(this.options.level)) {
			this.setTheme();
		}
	}

	onDismiss() {
		this.dismissed.emit();
	}

	executeAction(action: IMessageBannerAction) {
		action.execute();
	}

	private setTheme() {
		let icon: string;
		let backgroundClass: string;
		let iconClass: string;

		switch (this.options.level) {
			case MessageBannerLevel.Success:
				icon = "success";
				backgroundClass = "lm-success-bg";
				iconClass = "lm-success-fg";
				break;
			case MessageBannerLevel.Error:
				icon = "error";
				backgroundClass = "lm-error-bg";
				iconClass = "lm-error-fg";
				break;
			case MessageBannerLevel.Warning:
				icon = "alert";
				backgroundClass = "lm-warn-bg";
				iconClass = "lm-warn-fg";
				break;
			case MessageBannerLevel.Info:
			default:
				icon = "info";
				backgroundClass = "lm-info-bg";
				iconClass = "lm-info-fg";
				break;
		}

		this.options.icon = icon;
		this.options.backgroundClass = backgroundClass;
		this.options.iconClass = iconClass;
	}
}
