import { Injectable } from "@angular/core";
import { ArrayUtil } from "lime";
import {
	CoreBase,
	CoreUtil,
	IOperationResponse,
	ISetting,
	ISettingItem,
	ISettingRule,
	LocaleDatePipe,
	SettingItemType,
	SettingsNames,
} from "lime/core";
import { AsyncSubject, combineLatest, forkJoin, Observable } from "rxjs";
import {
	debounceTime,
	distinctUntilChanged,
	map,
	shareReplay,
	tap,
} from "rxjs/operators";
import { SettingUtil } from "../admin";
import { AdminConstants, AdminContext, AdminService } from "../service";

const isFeatureEnabled = (featureName: string) =>
	map<ISetting[], boolean>((features) => {
		if (featureName === SettingsNames.featureBannerWidget) {
			// Banner is always enabled
			return true;
		}
		const feature = features.find(
			(setting) => setting.settingName === featureName,
		);
		const isEnabled = feature.value === "true";
		return isEnabled;
	});

@Injectable({
	providedIn: "root",
})
export class AdminSettingsService extends CoreBase {
	isRulesChanged: boolean;
	isSettingsChanged: boolean;

	tool$ = this.context.tool$.pipe(
		tap(() => {
			this.isRulesChanged = false;
			this.isSettingsChanged = false;
		}),
		shareReplay(1),
	);

	features$ = this.tool$.pipe(
		map((tool) => tool.settings.filter((feature) => this.isFeature(feature))),
	);

	featureItems$ = this.features$.pipe(
		map((features) => this.createFeatureItems(features)),
	);

	isBannerEnabled$ = this.features$.pipe(
		isFeatureEnabled(SettingsNames.featureBannerWidget),
		distinctUntilChanged(),
	);

	isDynamicPagesEnabled$ = this.features$.pipe(
		isFeatureEnabled(SettingsNames.featureDynamicPages),
		distinctUntilChanged(),
	);

	settings$ = this.tool$.pipe(
		map((tool) => tool.settings.filter((setting) => !this.isFeature(setting))),
	);

	settingItems$ = combineLatest(this.settings$, this.isBannerEnabled$).pipe(
		debounceTime(1),
		map(([settings, isBannerEnabled]) =>
			this.createSettingItems(settings, isBannerEnabled),
		),
	);

	private readonly settingsValidators = new Map<string, ISettingValidator>([
		[SettingsNames.adminContactInfo, new XssSettingValidator()],
		[SettingsNames.adminEmail, new XssSettingValidator()],
	]);

	constructor(
		private readonly context: AdminContext,
		private adminService: AdminService,
		private localeDatePipe: LocaleDatePipe,
	) {
		super("AdminSettingsService");
	}

	update(
		settingItems: ISettingItem[],
		settingsWithChangedRules: string[],
	): Observable<void> {
		const subject = new AsyncSubject<void>();
		if (!this.isSettingsValid(settingItems)) {
			subject.error(new Error("Settings are not valid."));
			return subject.asObservable();
		}

		if (!this.isRulesChanged && !this.isSettingsChanged) {
			subject.complete(); // Nothing to update
			return subject.asObservable();
		}

		const updates$: Observable<void>[] = [];

		if (this.isRulesChanged) {
			updates$.push(this.updateRules(settingItems, settingsWithChangedRules));
		}

		if (this.isSettingsChanged) {
			updates$.push(this.updateSettings(settingItems));
		}

		forkJoin(updates$).subscribe(
			() => {
				this.context.nextTool(false);
				subject.next();
				subject.complete();
			},
			(error) => {
				subject.error(error);
			},
		);
		return subject.asObservable();
	}

	isSettingsValid(settings: ISettingItem[]): boolean {
		return settings
			.filter((setting) => this.hasValidator(setting.settingName))
			.every((setting) => this.isValid(setting.settingName, setting.value));
	}

	isRulesValid(rules: ISettingRule[]): boolean {
		return rules
			.filter((rule) => this.hasValidator(rule.settingName))
			.every((rule) => this.isValid(rule.settingName, rule.value));
	}

	private hasValidator(name: string): boolean {
		return this.settingsValidators.has(name);
	}

	private isValid(name: string, value: any): boolean {
		return this.settingsValidators.get(name).isValid(value);
	}

	private computeSettings(
		sets: ISetting[],
		updatedSets: ISetting[],
		updater: (updatedSet: ISetting, setIndex: number) => void,
	) {
		for (const updatedSetting of updatedSets) {
			const settingsIndex = this.getSettingIndex(
				sets,
				updatedSetting.settingName,
			);
			updater(updatedSetting, settingsIndex);
		}
	}

	private updateRules(
		settingItems: ISettingItem[],
		settingNames: string[],
	): Observable<void> {
		const subject = new AsyncSubject<void>();
		const settingsWithUpdatedRules = settingNames.map((settingName) =>
			CoreUtil.copy(
				settingItems.find((setting) => setting.settingName === settingName),
			),
		);

		if (
			!settingsWithUpdatedRules.every((setting) =>
				this.isRulesValid(setting.rules),
			)
		) {
			subject.error(new Error("Setting rules are not valid."));
			return subject.asObservable();
		}

		const ruleUpdateRequests$ = settingsWithUpdatedRules.map((setting) => {
			setting.setting.rules = setting.rules;
			return this.adminService.updateSettingRules(
				CoreUtil.copy(setting.setting),
			);
		});

		forkJoin(ruleUpdateRequests$).subscribe(
			(responses: IOperationResponse[]) => {
				const settings = this.getSettings();
				const updatedSettings = responses.map(
					(response) => response.content as ISetting,
				);
				this.computeSettings(
					settings,
					updatedSettings,
					(updatedSetting, settingIndex) => {
						settings[settingIndex].rules = updatedSetting.rules;
					},
				);
				this.isRulesChanged = false;
				subject.next();
				subject.complete();
			},
			(error) => {
				subject.error(error);
			},
		);
		return subject.asObservable();
	}

	private updateSettings(settingItems: ISettingItem[]): Observable<void> {
		const subject = new AsyncSubject<void>();
		const settings = this.getSettings();
		this.adminService
			.updateSettings(this.getUpdatedSettings(settingItems))
			.subscribe(
				(response: IOperationResponse) => {
					const updatedSettings = response.content as ISetting[];
					this.computeSettings(
						settings,
						updatedSettings,
						(updatedSetting, settingIndex) => {
							updatedSetting.isChanged = false;
							settings[settingIndex] = updatedSetting;
						},
					);
					subject.next();
					subject.complete();
				},
				(error) => {
					subject.error(error);
				},
			);
		return subject.asObservable();
	}

	private getUpdatedSettings(settingItems: ISettingItem[]): ISetting[] {
		const settings = CoreUtil.copy(this.getSettings());
		return settings
			.filter(
				(setting) =>
					this.getSettingItemIndex(settingItems, setting.settingName) !== -1,
			)
			.map((setting) => {
				const item = this.getSettingItem(settingItems, setting.settingName);

				if (item && item.setting && item.setting.isChanged) {
					let value: string;
					if (item.type === "boolean") {
						value = item.value ? "true" : "false";
					} else {
						value = item.value;
					}

					setting.value = value;
					setting.isChanged = true;
				}

				return setting;
			})
			.filter((setting) => setting.isChanged);
	}

	private getSettingIndex(settings: ISetting[], settingName: string): number {
		return settings.map((setting) => setting.settingName).indexOf(settingName);
	}

	private getSettingItemIndex(
		settingItems: ISettingItem[],
		settingName: string,
	): number {
		return settingItems
			.map((settingItem) => settingItem.settingName)
			.indexOf(settingName);
	}

	private getSettingItem(
		settingItems: ISettingItem[],
		settingName: string,
	): ISettingItem {
		return settingItems.find(
			(settingItem) => settingItem.settingName === settingName,
		);
	}

	private isFeature(setting: ISetting): boolean {
		return setting.area === AdminConstants.featureArea;
	}

	private getSettings(): ISetting[] {
		return this.context.get().settings;
	}

	private createFeatureItems(features: ISetting[]): ISettingItem[] {
		return features.map((feature) => this.createFeatureItem(feature));
	}

	private createFeatureItem(feature: ISetting): ISettingItem {
		const value = feature.value;
		const descriptions = feature.descriptions;
		const descriptionCount = descriptions ? descriptions.length : 0;

		return {
			setting: feature, // Setting as on server side
			value: value === "true", // Current value in view
			values: [], // Possible values in view
			displayValue: value, // For objects/pages display label in grid
			rules: [], // Rules in view
			type: SettingItemType.typeBool, // Type in view
			changeDate: this.localeDatePipe.transform(feature.changeDate), // Change date in view
			changedByName: feature.changedByName, // Name in view
			settingName: feature.settingName, // Never changed, used for matching (save/discard) only
			noOfRules: 0,
			description1: descriptionCount > 0 ? descriptions[0] : "",
			description2: descriptionCount > 1 ? descriptions[1] : "",
			description3: descriptionCount > 2 ? descriptions[2] : "",
		};
	}

	private createSettingItems(
		settings: ISetting[],
		isBannerEnabled: boolean,
	): ISettingItem[] {
		return settings.map((setting) =>
			this.createSettingItem(setting, isBannerEnabled),
		);
	}

	private createSettingItem(
		setting: ISetting,
		isBannerEnabled: boolean,
	): ISettingItem {
		const itemType = setting.dataType;
		const value = setting.value;
		const values = setting.values || [];
		const settingName = setting.settingName;
		const descriptions = setting.descriptions;
		const descriptionCount = descriptions ? descriptions.length : 0;
		const rules = this.createRules(setting);

		if (setting.settingName === SettingsNames.enableBannerWidgetEdit) {
			setting.isVisible = isBannerEnabled;
		}

		return {
			setting: setting, // Setting as on server side
			value: this.resolveValue(value, itemType), // Current value in view
			values: values, // Possible values in view
			displayValue: this.resolveDisplayValue(value, settingName, values), // For objects/pages display label in grid
			rules: rules, // Rules in view
			type: this.resolveType(settingName, itemType, values), // Type in view
			changeDate: this.localeDatePipe.transform(setting.changeDate), // Change date in view
			changedByName: setting.changedByName, // Name in view
			settingName: settingName, // Never changed, used for matching (save/discard) only
			noOfRules: rules.length,
			description1: descriptionCount > 0 ? descriptions[0] : "",
			description2: descriptionCount > 1 ? descriptions[1] : "",
		};
	}

	private resolveValue(value: any, dataType: string): any {
		return dataType === SettingItemType.typeBool ? value === "true" : value;
	}

	private resolveDisplayValue(
		value: string,
		name: string,
		values: object[],
	): string {
		if (values && values.length) {
			const valueObject = ArrayUtil.itemByProperty(values, "value", value);
			if (valueObject) {
				return valueObject.label;
			}
		} else if (
			name === SettingsNames.mandatoryPages ||
			name === SettingsNames.defaultPage
		) {
			return SettingUtil.getPageDisplayValue(value);
		}
		return value;
	}

	private resolveType(
		name: string,
		dataType: string,
		values: object[],
	): string {
		if (values && values.length) {
			return SettingItemType.typeSelector;
		}
		switch (name) {
			case SettingsNames.maxUserPageCount:
			case SettingsNames.maxWidgetsOnPageCount:
				return SettingItemType.typeIntSelector;
			case SettingsNames.mandatoryPages:
				return SettingItemType.typeMandatoryPages;
			case SettingsNames.defaultPage:
				return SettingItemType.typeDefaultPages;
			case SettingsNames.adminContactInfo:
				return SettingsNames.adminContactInfo;
		}
		return dataType;
	}

	private createRules(setting: ISetting): ISettingRule[] {
		const rules = setting.rules ? CoreUtil.copy(setting.rules) : [];
		return rules.map((rule) => this.createRule(setting, rule));
	}

	private createRule(setting: ISetting, rule: ISettingRule): ISettingRule {
		const itemType = setting.dataType;
		const value = rule.value;
		const values = setting.values || [];
		const settingName = setting.settingName;

		rule.value = this.resolveValue(value, itemType);
		rule.displayValue = this.resolveDisplayValue(value, settingName, values);
		rule.displayChangeDate = this.localeDatePipe.transform(rule.changeDate);
		rule.ruleConnections = rule.ruleConnections || [];
		rule.affectedUsers = rule.ruleConnections.length;
		for (const connection of rule.ruleConnections) {
			connection.displayChangeDate = this.localeDatePipe.transform(
				connection.changeDate,
			);
		}

		return rule;
	}
}

interface ISettingValidator {
	isValid(value: any): boolean;
}

class XssSettingValidator implements ISettingValidator {
	isValid(value: string): boolean {
		const hasXss =
			value &&
			(value.indexOf("<script") >= 0 || value.indexOf("</script") >= 0);
		return !hasXss;
	}
}
