import { Injectable } from "@angular/core";
import { SohoToastService } from "ids-enterprise-ng";
import {
	CoreBase,
	DynamicContainerSubType,
	DynamicContainerType,
	IDynamicEntity,
	IDynamicEntityLocalizationMap,
} from "lime/core";
import { Observable, ReplaySubject } from "rxjs";

export interface IClipboardInfo extends IClipboardTypeInfo {
	items: IDynamicEntity[];
	lzn: IDynamicEntityLocalizationMap;
	originId: string;
}

export interface IClipboardTypeInfo {
	ct: DynamicContainerType;
	st: DynamicContainerSubType;
}

export interface IDynamicClipboardService {
	clipboardTypeInfo$: Observable<IClipboardTypeInfo>;
	setClipboard(info: IClipboardInfo): void;
	getClipboard(): IClipboardInfo;
	clearClipboard(): void;
}

@Injectable({
	providedIn: "root",
})
export class DynamicClipboardService
	extends CoreBase
	implements IDynamicClipboardService
{
	clipboardTypeInfo$: Observable<IClipboardTypeInfo>;

	private clipboardInfo: IClipboardInfo;
	private clipboardTypeSubject = new ReplaySubject<IClipboardTypeInfo>(1);

	constructor(private toastService: SohoToastService) {
		super("DynamicClipboardService");
		this.clipboardTypeInfo$ = this.clipboardTypeSubject.asObservable();
	}

	setClipboard(info: IClipboardInfo) {
		this.clipboardInfo = info;
		this.clipboardTypeSubject.next({ ct: info.ct, st: info.st });

		this.showToastNotification(!!info.originId);
	}

	getClipboard(): IClipboardInfo {
		return this.clipboardInfo;
	}

	clearClipboard() {
		this.clipboardInfo = null;
		this.clipboardTypeSubject.next(null);
	}

	private showToastNotification(isCut: boolean) {
		const noOfCopies = this.clipboardInfo.items.length;
		const itemText = noOfCopies === 1 ? "item" : "items";
		this.toastService.show({
			title: isCut ? "Cut" : "Copy",
			message: `${noOfCopies} ${itemText} ${
				isCut ? "cut" : "copied"
			} to the Clipboard`,
			position: SohoToastService.BOTTOM_RIGHT,
			timeout: 2000,
		});
	}
}
