import {
	Component,
	NgZone,
	OnInit,
	ViewChild,
	ViewContainerRef,
} from "@angular/core";
import {
	SohoDataGridComponent,
	SohoMessageService,
	SohoModalDialogService,
} from "ids-enterprise-ng";
import { AccessType, Constants, IPage, LanguageService } from "lime/core";
import { CustomFormatters } from "../admin";
import { AdminService, IPageSelectorOptions } from "../service";
import { AdminSettingsService } from "./admin-settings.service";
import { IPageItem, PageComponentBase } from "./runtime";

export interface IDefaultPageInfo {
	id: string;
	type: number;
}

export interface IDefaultPageItem extends IPageItem<IDefaultPageInfo> {
	type: string;
}

@Component({
	selector: "lm-admin-default-pages",
	templateUrl: "./default-pages.html",
})
export class DefaultPagesComponent
	extends PageComponentBase<IDefaultPageItem>
	implements OnInit
{
	@ViewChild("defaultPagesView", { read: ViewContainerRef, static: false })
	view: ViewContainerRef;

	@ViewChild("defaultPagesGrid", { static: false })
	datagrid: SohoDataGridComponent;

	constructor(
		readonly messageService: SohoMessageService,
		readonly languageService: LanguageService,
		readonly adminService: AdminService,
		readonly sohoModalDialogService: SohoModalDialogService,
		readonly zone: NgZone,
		readonly settingsService: AdminSettingsService,
	) {
		super(
			"DefaultPagesComponent",
			messageService,
			languageService,
			adminService,
			sohoModalDialogService,
			zone,
			settingsService,
		);
	}

	updateValue(): void {
		const items = this.items;
		const pages = [] as IDefaultPageInfo[];
		for (const item of items) {
			if (item) {
				const info = item.info;
				info.type = parseInt(item.type);
				pages.push(info);
			}
		}
		const value = { pages: pages };
		this.settingItem.value = JSON.stringify(value);
	}

	protected getDataGrid() {
		return this.datagrid;
	}

	protected getView(): ViewContainerRef {
		return this.view;
	}

	protected createItem(data: IPage): IDefaultPageItem {
		const pageData = data.data;
		return {
			id: pageData.id,
			info: this.createInfo(pageData.id),
			title: pageData.title,
			description: pageData.description,
			type: pageData.isDynamic
				? AccessType.Role.toString()
				: AccessType.Owner.toString(),
			isDynamic: pageData.isDynamic,
			accessState: data.accessState,
			err: this.getPageError(pageData),
		};
	}

	protected createSelectorOptions(): IPageSelectorOptions {
		return {
			title: this.settingItem.setting.label,
			isMultiSelect: true,
			excludeDynamic: false,
			noShowIds: this.items.map((page) => page.info.id),
		};
	}

	protected getCount(): number {
		return this.items.length;
	}

	protected initGrid(): void {
		const rowTemplate =
			'<div class="datagrid-cell-layout" style="overflow: hidden;"><span class="datagrid-textarea lm-white-space-normal">{{description}}</span></div>';

		const editableFunction = (row: number) => {
			const item = this.items[row];
			if (item && item.isDynamic) {
				return false;
			}
			return true;
		};

		this.datagridOptions = {
			idProperty: "id",
			rowTemplate: rowTemplate,
			rowReorder: true,
			selectable: "multiple" as SohoDataGridSelectable,
			editable: true,
			filterable: false,
			disableRowDeactivation: true,
			clickToSelect: false,
			columns: [
				this.getRowReorderColumn(),
				this.getSelectionColumn(),
				{
					width: 500,
					id: "adm-dp-col-title",
					field: "title",
					name: "Title",
					resizable: true,
					sortable: false,
					formatter: CustomFormatters.dynamicDisabledExpander,
				},
				{
					width: 150,
					id: "adm-dp-col-type",
					field: "type",
					name: "Type",
					align: "center",
					resizable: false,
					sortable: false,
					formatter: Formatters.Dropdown,
					editor: Soho.Editors.Dropdown,
					isEditable: editableFunction,
					options: [
						{
							label: "Private",
							value: "0",
						},
						{
							label: "Published",
							value: "100",
						},
					],
				},
				{
					width: 150,
					id: "adm-dp-col-permissions",
					field: "accessState",
					name: "Permissions",
					resizable: true,
					sortable: false,
					formatter: CustomFormatters.accessState,
				},
			],
			dataset: this.items,
			emptyMessage: {
				title:
					"No default pages configured. Click 'Add Pages' to configure default pages.",
				icon: Constants.adminEmptyDatagridIcon,
			},
		};
	}

	protected toItem(info: IDefaultPageInfo, counter: number): IDefaultPageItem {
		return {
			id: counter,
			title: info.id,
			info: info,
			type: `${info.type}`,
		};
	}

	protected toInfos(value: string): IDefaultPageInfo[] {
		if (value) {
			if (value.indexOf("{") >= 0) {
				const setting = JSON.parse(value);
				if (setting && setting.pages) {
					return setting.pages;
				}
			} else {
				// Legacy value format
				return value.split(",").map((s) => this.createInfo(s));
			}
		}
		return [];
	}

	private createInfo(id: string): IDefaultPageInfo {
		return {
			id: id,
			type: 0,
		};
	}
}
