import {
	Component,
	Directive,
	NgZone,
	OnInit,
	ViewChild,
	ViewContainerRef,
} from "@angular/core";
import {
	SohoDataGridComponent,
	SohoMessageService,
	SohoModalDialogService,
	SohoSearchFieldComponent,
} from "ids-enterprise-ng";
import { DialogButtonType, IDialogResult } from "lime";
import {
	DialogResponseCode,
	EntityCategory,
	EntityFilter,
	IEntityAccess,
	IImportOptions,
	IIntegerResponse,
	IOperationResponse,
	IWidgetCatalogRequest,
	IWidgetCatalogResponse,
	IWidgetInfo,
	IWidgetInfoResponse,
	LanguageService,
	WidgetService,
	WidgetSourcePipe,
} from "lime/core";
import { take } from "rxjs/operators";
import { CustomFormatters, GridUtil, WidgetUtilAdmin } from "../admin";
import { AdminListComponent, IAdminListOptions } from "../admin-list.component";
import { IMessageBannerOptions } from "../common/message-banner";
import {
	AdminContext,
	AdminService,
	AdminUtil,
	IAdminAction,
	IAdminTool,
} from "../service";
import { WidgetDetailsDialogComponent } from "./widget-details-dialog";

@Directive()
export class StandardWidgetsBaseComponent
	extends AdminListComponent<IWidgetInfo>
	implements OnInit
{
	@ViewChild("standardWidgetsDatagrid", { static: false })
	dataGrid: SohoDataGridComponent;

	@ViewChild(SohoSearchFieldComponent, { static: false })
	searchField: SohoSearchFieldComponent;

	actions: IAdminAction[] = [];

	idSort = "lmAdminStandardWidgetsSort";
	idShow = "lmAdminStandardWidgetsShow";
	idShowButton = "lm-admin-sw-show";
	idPermissions = "lmAdminStandardWidgetPermissions";
	idSearch = "admin-standard-widgets-searchfield";

	enablePortation = true;
	enableShow = true;

	showFilter = false;
	showShow = false;
	showImport = false;
	showExport = false;

	accessCopy: IEntityAccess[];
	widgetsGridOptions: any;
	includeAll = false;
	isCloud: boolean;

	messageBanner?: IMessageBannerOptions;
	angularJsWarning: string;

	private accessCopyWidgetId: string;
	private isDetailsOpen: boolean;

	constructor(
		className: string,
		messageService: SohoMessageService,
		languageService: LanguageService,
		adminService: AdminService,
		sohoModalDialogService: SohoModalDialogService,
		zone: NgZone,
		protected readonly adminContext: AdminContext,
		protected readonly widgetService: WidgetService,
		readonly viewRef: ViewContainerRef,
		options?: IAdminListOptions,
	) {
		super(
			className,
			"widget",
			messageService,
			languageService,
			adminService,
			sohoModalDialogService,
			zone,
			options,
		);
		this.showFilter = options && options.isFilter;
		this.datagridOptions = this.defaultOptions();
	}

	ngOnInit(): void {
		if (this.initializing) {
			this.adminContext.tool$.pipe(take(1)).subscribe((tool) => {
				this.isCloud = tool.isCloud;
				this.validateAngularJS(tool);
			});
		}

		this.calculateVisibility();
		this.actions = this.getActions();
		this.refresh();
	}

	getDataGrid(): SohoDataGridComponent {
		return this.dataGrid;
	}

	listItems(reload: boolean): void {
		if (this.isBusy) {
			return;
		}
		const self = this;
		const adminService = self.adminService;
		this.setBusy(true);

		if (reload) {
			this.hasMore = true;
			this.paging = null;
			this.items = [];
			this.clearSelection();
		}

		const orderBy = this.orderBy;
		const request: IWidgetCatalogRequest = {
			paging: this.paging,
			pageSize: this.pageSize,
			sortOrder: orderBy.order,
			sortBy: orderBy.entity,
			query: this.query,
		};

		// Set common active request filters
		this.setRequestFilters(request);

		if (this.includeAll) {
			request.includeAll = true;
		}

		adminService.listStandardWidgets(request).subscribe(
			(response: IWidgetCatalogResponse) => {
				const newItems = response.content;
				self.addItems(newItems, response.paging);
				self.updateCount(response.count, this.maxCount);
				self.setBusy(false);
			},
			(r: IOperationResponse) => {
				self.setBusy(false);
				self.onError(r);
			},
		);
	}

	/**
	 * Opens the widget access dialog.
	 */
	editAccess(): void {
		const widget = this.getSelectedItem();
		this.adminService.openWidgetAccessDialog(
			widget,
			(resp: IWidgetInfoResponse) => {
				if (resp && resp.content) {
					this.refresh();
				} else {
					this.onError(resp);
				}
			},
			this.viewRef,
		);
	}

	/**
	 * Copy access rights of a widget.
	 */
	copyAccess(): void {
		const widget = this.getSelectedItem();
		const self = this;
		const adminService = self.adminService;

		this.setBusy(true);
		adminService
			.getWidgetAccess({ id: widget.widgetId, accessList: [] })
			.subscribe(
				(r: IOperationResponse) => {
					self.accessCopy = WidgetUtilAdmin.getAccessCopy(r.content.accessList);
					self.accessCopyWidgetId = widget.widgetId;
					self.setBusy(false);
				},
				(r: IOperationResponse) => {
					self.adminService.handleError(r);
					self.setBusy(false);
				},
			);
	}

	/**
	 * Apply copied acces rights to selected widget(s).
	 *
	 * @params widget to edit. Otherwise use selected widgets in grid.
	 */
	applyAccessCopy(): void {
		const items = this.getSelectedItems();
		this.adminService.applyWidgetAccess(items, this.accessCopy, () => {
			this.refresh();
		});
	}

	/**
	 * Clear Or Replace With Access Copy
	 *
	 * If indicated with "isReplace", replaces access rights.
	 * Otherwise clear access rights of selected widgets.
	 *
	 * @params isReplace Boolean, true: replace, false: clear.
	 */
	clearOrReplaceWithAccessCopy(isReplace?: boolean): void {
		const items = this.getSelectedItems();
		this.adminService.clearOrReplaceWidgetAccess(
			items,
			isReplace,
			() => {
				this.refresh();
			},
			this.accessCopy,
		);
	}

	/**
	 * Install new and/or upgrade standard widgets
	 */
	import(): void {
		if (!this.enablePortation) {
			return;
		}

		const dialogTitle = "Install Standard Widgets";
		const adminService = this.adminService;
		const options: IImportOptions = {
			title: dialogTitle,
			operation: EntityCategory.standardWidget.toString(),
		};

		const self = this;
		adminService
			.openImportFilesDialog(options, this.viewRef)
			.subscribe((r: IDialogResult) => {
				const value = r.value;
				if (
					r.button === DialogButtonType.Yes &&
					value.responseCode === DialogResponseCode.Success
				) {
					this.adminService
						.showUploadCompleteDialog(dialogTitle, value.message)
						.subscribe((result: IDialogResult) => {
							if (result.button === DialogButtonType.Ok) {
								self.refresh();
							}
						});
				} else if (
					r.button === DialogButtonType.Yes &&
					value.responseCode === DialogResponseCode.Fail
				) {
					adminService.showUploadCompleteDialog(
						dialogTitle,
						value.message,
						true,
					);
				}
			});
	}

	/**
	 * Delete
	 *
	 * Creates list of selected widget IDs in grid and calls delete.
	 */
	onClickDelete(): void {
		const items = this.getSelectedItems();
		if (!items) {
			this.logWarning("No selection to delete");
			return;
		}
		if (items.length === 0) {
			this.logWarning("No selection to delete");
			return;
		}

		const widgetList: IWidgetInfo[] = items.map((widget) => {
			return { widgetId: widget.widgetId, version: widget.version };
		});

		const isMultiple = items.length > 1;
		const firstWidget = items[0];
		const title = isMultiple ? "Delete Widgets" : "Delete Widget";
		const message = isMultiple
			? "Are you sure that you want to remove the selected widgets? They will be removed for all users."
			: `Are you sure that you want to remove the widget '${firstWidget.title}'? It will be removed for all users.`;

		this.showConfirm(title, message).subscribe(() => {
			this.deleteWidgets(widgetList, title);
		});
	}

	/**
	 * Displays confirmation message to the user and deletes provided widgets on confirm.
	 *
	 * @params widgets List of widget IDs to delete, or single WidgetInfo of widget to delete.
	 */
	deleteWidgets(widgets: IWidgetInfo[], title: string): void {
		this.setBusy(true);

		this.widgetService.deleteStandard(widgets).subscribe(
			(r: IIntegerResponse) => {
				let responseMessage = "";
				const messageList = r.messageList;
				if (messageList) {
					for (const msg of messageList) {
						responseMessage += msg.message;
					}
				}
				this.adminService
					.showUploadCompleteDialog(title, responseMessage)
					.subscribe((result: IDialogResult) => {
						if (result.button === DialogButtonType.Ok) {
							if (r.content && r.content > 0) {
								this.refresh();
							}
						}
					});
				this.setBusy(false);
			},
			(r: IOperationResponse) => {
				this.setBusy(false);
				this.adminService.handleError(r, r.getErrorMessages());
			},
		);
	}

	showAll(all: boolean): void {
		const current = this.includeAll;
		if (all !== current) {
			this.includeAll = all;
			if (this.query) {
				this.isSearchActive = true;
			}
			this.refresh();
		}
	}

	onExpandRow(event: { detail: any; item: IWidgetInfo }): void {
		const container = $(event.detail)
			.find(".datagrid-row-detail-padding")
			.empty();
		const item: IWidgetInfo = event.item;

		let template: string = null;
		const description = this.escape(item.description);
		if (item.earlyInfo) {
			template = `<div class="datagrid-cell-layout">
				<span class="datagrid-textarea lm-white-space-normal">${description}<p class="lm-margin-md-t">${this.escape(
					item.earlyInfo,
				)}</p></span>
			`;
		} else {
			template = `<div class="datagrid-cell-layout">
				<span class="datagrid-textarea lm-white-space-normal">${description}</span>
			`;
		}

		if (item.widgetErrorInfo) {
			template += this.getErrorMessageTemplate(
				GridUtil.formatError(item.widgetErrorInfo.message),
			);
		}

		if (item.isDeprecated) {
			const message = item.deprecatedInfo
				? item.deprecatedInfo
				: "This widget has been deprecated and will soon be removed.";
			template += this.getErrorMessageTemplate(
				GridUtil.formatAlert(this.escape(message)),
			);
		}

		if (item.helpUrl && !this.hasReplacementTemplate(item.helpUrl)) {
			template += this.getLinkTemplate(item.helpUrl);
		}

		template += `</div>`;
		$(container).append($(template));
	}

	onClickExport(): void {
		if (!this.enablePortation) {
			return;
		}

		const items = this.getSelectedItems();
		if (!items) {
			this.logWarning("No selection to export");
			return;
		}
		if (items.length !== 1) {
			this.logWarning("Invalid selection to export. Multiselect not supported");
			return;
		}

		const widgetInfo = items[0];
		const title = "Export widget";
		const message = `Are you sure that you want to export ${widgetInfo.title}?`;

		this.showConfirm(title, message).subscribe(() => {
			this.adminService.exportStandardWidget(widgetInfo);
		});
	}

	onClickViewDetails(): void {
		if (this.isDetailsOpen) {
			return;
		}
		this.isDetailsOpen = true;

		const widget = this.getSelectedItem();
		const dialog = this.sohoDialogService
			.modal(WidgetDetailsDialogComponent, this.viewRef)
			.title("Widget Details")
			.id("lm-a-sw-details-dialog")
			.afterClose(() => {
				this.isDetailsOpen = false;
			});

		dialog
			.apply((component) => {
				component.dialog = dialog;
				component.widgetId = widget.widgetId;
				component.version = widget.version;
			})
			.open();
	}

	protected getActions(): IAdminAction[] {
		const actions = [];
		if (this.showExport) {
			actions.push({
				text: () => "Export (" + this.selectionCount + ")",
				icon: "export",
				enabled: () => this.selectionCount === 1,
				click: () => this.onClickExport(),
			});
		}
		if (!this.isCloud) {
			actions.push({
				text: () => "Delete (" + this.selectionCount + ")",
				icon: "delete",
				enabled: () => this.selectionCount === 1,
				click: () => this.onClickDelete(),
			});
			actions.push({ separator: true });
		}
		actions.push({
			text: () => "View Details",
			icon: "info-linear",
			enabled: () => this.selectionCount === 1,
			click: () => this.onClickViewDetails(),
		});
		return actions;
	}

	protected calculateVisibility(): void {
		this.showShow = this.enableShow && !this.isCloud;
		this.showImport = this.enablePortation && !this.isCloud;
		this.showExport = this.showImport;
	}

	protected validateAngularJS(tool: IAdminTool) {
		const count = tool.angularJsWidgetCount;
		if (count > 0) {
			this.angularJsWarning =
				"You have " +
				count +
				" AngularJS " +
				AdminUtil.pluralize("widget", count) +
				" installed. AngularJS widgets are no longer supported and must be migrated to Angular or jQuery implementations.";
		}
	}

	protected getColumns(): SohoDataGridColumn[] {
		const self = this;
		return [
			this.getSelectionColumn(),
			{
				width: 345,
				id: "adm-sw-col-t",
				field: "title",
				name: "Title",
				sortable: false,
				formatter: Formatters.Expander,
			},
			{
				width: 250,
				id: "adm-sw-col-wi",
				field: "widgetId",
				name: "Widget ID",
				sortable: false,
				formatter: (row, cell, value) => {
					const widgetInfo = self.items[row];
					const error = widgetInfo.widgetErrorInfo;
					if (error) {
						return GridUtil.formatError(value);
					}
					if (widgetInfo.isDeprecated) {
						return GridUtil.formatAlert(value);
					}
					return value;
				},
			},
			{
				width: 160,
				id: "adm-sw-col-cd",
				field: "changeDate",
				name: "Change date",
				sortable: false,
				formatter: CustomFormatters.date,
			},
			{
				width: 150,
				id: "adm-sw-col-s",
				field: "source",
				name: "Source",
				sortable: false,
				formatter: (row, cell, value) => {
					return (
						WidgetSourcePipe.map[value] +
						" (" +
						(self.items[row].displayVersion || self.items[row].version) +
						")"
					);
				},
			},
			{
				width: 150,
				id: "adm-sw-col-cbn",
				field: "changedByName",
				name: "Changed by",
				sortable: false,
				formatter: CustomFormatters.displayName,
			},
			{
				width: 140,
				id: "adm-sw-col-hr",
				field: "hasRestrictions",
				name: "Permissions",
				sortable: false,
				formatter: CustomFormatters.restricted,
			},
		];
	}

	protected getEmptyMessage(): string {
		return "No standard widgets found";
	}
}

@Component({
	selector: "lm-admin-standard-widgets",
	templateUrl: "./standard-widgets.html",
})
export class AdminStandardWidgetsComponent extends StandardWidgetsBaseComponent {
	constructor(
		messageService: SohoMessageService,
		languageService: LanguageService,
		adminService: AdminService,
		sohoModalDialogService: SohoModalDialogService,
		zone: NgZone,
		adminContext: AdminContext,
		widgetService: WidgetService,
		viewRef: ViewContainerRef,
	) {
		super(
			"AdminStandardWidgetsComponent",
			messageService,
			languageService,
			adminService,
			sohoModalDialogService,
			zone,
			adminContext,
			widgetService,
			viewRef,
			{
				isFilter: true,
				isUserFilter: false,
				filters: [
					{
						name: "Mobile",
						propertyName: "includeMobileOnly",
						value: true,
						type: EntityFilter.Custom,
					},
				],
			},
		);
	}
}
