export class AdminUtil {
	static getTimeZones(): ITimeZone[] {
		return timeZones;
	}

	static isReadOnlyUser(tool: IAdminTool) {
		return (
			tool.isSupportUser && !tool.isPageAdministrator && !tool.isAdministrator
		);
	}

	static pluralize(text: string, count: number) {
		if (count !== 1) {
			if (StringUtil.endsWith(text, "y")) {
				return text.substring(0, text.length - 1) + "ies";
			} else {
				return text + "s";
			}
		}
		return text;
	}

	static getIsoDateString(localeDateStringShort: string): string {
		try {
			const localeFormat = Soho.Locale.calendar().dateFormat.short;
			const localeDate = Soho.Locale.parseDate(
				localeDateStringShort,
				localeFormat,
				true,
			);
			const isoString = Soho.Locale.formatDate(localeDate, {
				pattern: "yyyyMMdd",
			});
			return isoString;
		} catch (ex) {
			return localeDateStringShort;
		}
	}

	static getLocaleDateStringShort(isoDateString: string): string {
		try {
			const localeDate = Soho.Locale.parseDate(isoDateString, "yyyyMMdd", true);
			const localeDateString = Soho.Locale.formatDate(localeDate, {
				date: "short",
			});
			return localeDateString;
		} catch (ex) {
			return isoDateString;
		}
	}

	static toIsoDateTimeLocal(date: Date): string {
		const offsetMs = date.getTimezoneOffset() * 60 * 1000;
		const msLocal = date.getTime() - offsetMs;
		const dateLocal = new Date(msLocal);
		const iso = dateLocal.toISOString();
		const isoLocal = iso.slice(0, 19);
		return isoLocal;
	}

	static getPendingChangeDate(): string {
		// Just return a placeholder since the data will be updated by the server
		return "*";
	}

	static getItemCountText(entityName: string, count: number): string {
		return (
			"Showing " + count + " " + AdminUtil.pluralize(entityName, count) + "."
		);
	}
}

