	searchRoles(query: string): Observable<IAutocompleteEntity[]> {
		const subject = new AsyncSubject<IAutocompleteEntity[]>();
		this.getRoles(false).subscribe(
			(response: IGroupInfoListResponse) => {
				if (response.content) {
					const queryLower = query.toLowerCase();
					// Search for the query among all roles
					const matches = ArrayUtil.findAll(
						response.content,
						(item: IGroupInfo) => {
							try {
								if (item) {
									if (
										item.id &&
										item.id.toLowerCase().indexOf(queryLower) !== -1
									) {
										return true;
									}
									// Autocomplete does not support finding hits in what will be the info field
								}
							} catch (error) {
								Log.error(this.logPrefix + "Failed to filter " + error);
							}
							return false;
						},
					);

					// Should we return all hits or filter out the first x set
					// For now returning the first 10 hits
					// Transform the groups to IAutocompleteEntity
					const result: IAutocompleteEntity[] = [];
					if (matches) {
						for (let i = 0; i < 10; i++) {
							const item = matches[i];
							if (item) {
								const entity: IAutocompleteEntity = {
									label: item.id || item.name,
									value: item.id,
									type: PrincipalType.Role,
								};
								if (item.name) {
									entity.info = item.name;
								}
								result.push(entity);
							}
						}
					}
					subject.next(result);
					subject.complete();
				} else {
					subject.error("No roles found");
				}
			},
			(errorResponse: IOperationResponse) => {
				subject.error(errorResponse);
			},
		);

		return subject.asObservable();
	}

