	applyWidgetAccess(
		widgets: IWidgetInfo[],
		accessCopy: IEntityAccess[],
		callback: Function,
	): void {
		const progressService = this.progressService;
		let existingAccess: IEntityAccess[];
		let nrOfWidgetsToUpdate = widgets.length;

		progressService.setBusy(true);
		for (const updateWidget of widgets) {
			this.getWidgetAccess({
				id: updateWidget.widgetId,
				accessList: [],
			}).subscribe(
				(r: IOperationResponse) => {
					existingAccess = r.content.accessList;
					for (const accessEntity of accessCopy) {
						const accessUpdateIndex = ArrayUtil.indexByProperty(
							existingAccess,
							"principal",
							accessEntity.principal,
						);
						if (accessUpdateIndex !== -1) {
							existingAccess[accessUpdateIndex] = accessEntity;
						} else {
							existingAccess.push(accessEntity);
						}
					}
					this.updateWidgetAccess({
						id: updateWidget.widgetId,
						accessList: existingAccess,
					}).subscribe(
						() => {
							nrOfWidgetsToUpdate -= 1;
							if (nrOfWidgetsToUpdate === 0) {
								progressService.setBusy(false);
								callback();
							}
						},
						(result: IOperationResponse) => {
							this.handleError(result);
							progressService.setBusy(false);
						},
					);
				},
				(r: IOperationResponse) => {
					this.handleError(r);
					progressService.setBusy(false);
				},
			);
		}
	}

