	applyPageAccess(
		pages: IPage[],
		accessCopy: IPageAccess,
		callback: Function,
	): void {
		const progressService = this.progressService;
		let existingAccess: IPageAccess;
		let existingAccessList: IEntityAccess[];
		let nrOfPagesToUpdate = pages.length;

		progressService.setBusy(true);
		for (const updatePage of pages) {
			this.getPageAccess(updatePage.data.id).subscribe(
				(r: IPageAccessResponse) => {
					existingAccess = r.content;
					existingAccessList = existingAccess.access || [];

					for (const entity of accessCopy.access) {
						const index = ArrayUtil.indexByPredicate(
							existingAccessList,
							(e) => {
								return CoreUtil.isAccess(e, entity);
							},
						);
						if (index !== -1) {
							entity.operation = EntityOperation.Update;
							existingAccessList[index] = entity;
						} else {
							entity.operation = EntityOperation.Create;
							existingAccessList.push(entity);
						}
					}

					existingAccess.access = existingAccessList;
					this.updatePageAccess(existingAccess).subscribe(
						(result: IPageResponse) => {
							nrOfPagesToUpdate -= 1;
							if (nrOfPagesToUpdate === 0) {
								progressService.setBusy(false);
								callback();
							}
						},
						(result: IOperationResponse) => {
							this.handleError(result);
							progressService.setBusy(false);
						},
					);
				},
				(r: IOperationResponse) => {
					this.handleError(r);
					progressService.setBusy(false);
				},
			);
		}
	}

	clearPageAccessPages(targetPageIds: string[]): Observable<any> {
		const subject = new Subject();
		this.clearPageAccessPagesSingleCallChain(
			targetPageIds,
			targetPageIds.length,
			subject,
		);
		return subject.asObservable();
	}

	clearPageAccessPagesSingleCallChain(
		targetPageIds: string[],
		totalCount: number,
		subject: Subject<any>,
	): void {
		const remainingCount = targetPageIds.length;
		if (remainingCount === 0) {
			this.progressService.setBusy(false);
			const message =
				totalCount === 1
					? "The page access has been cleared."
					: `The page access has been cleared on ${totalCount} pages`;
			this.sohoToastService.show(
				CoreUtil.getToastOptions("Access cleared", message),
			);
			subject.complete();
			return;
		}
		const nextPageId = targetPageIds.pop();
		this.clearPageAccess(nextPageId).subscribe(
			(response) => {
				if (response.hasError()) {
					subject.error("Clear failed for page " + nextPageId);
					this.showClearAccessFailed(remainingCount, totalCount);
					return;
				}
				Log.info("Cleared selection for page with ID " + nextPageId);
				// Continue with the next page
				this.clearPageAccessPagesSingleCallChain(
					targetPageIds,
					totalCount,
					subject,
				);
			},
			(error) => {
				Log.error("Failed to clear page access", error);
				subject.error("Clear failed for page " + nextPageId + " " + error);
				this.showClearAccessFailed(remainingCount, totalCount);
				return;
			},
		);
	}

	replacePageAccess(
		sourceAccess: IPageAccess,
		targetPageIds: string[],
		totalCount: number,
	): Observable<any> {
		const subject = new Subject();
		this.replacePageAccessSingleCallChain(
			sourceAccess,
			targetPageIds,
			totalCount,
			subject,
		);
		return subject.asObservable();
	}

	createPageAccessReplaceInput(
		sourceAccess: IPageAccess,
		existingPageAccess: IPageAccess,
	): IPageAccess {
		const existingAccessList = existingPageAccess.access;
		if (!existingAccessList || existingAccessList.length === 0) {
			const sourceCopy = CoreUtil.copy(sourceAccess);
			sourceCopy.pageId = existingPageAccess.pageId;
			return sourceCopy;
		}

		const outputPageAccess: IPageAccess = {
			pageId: existingPageAccess.pageId,
			access: [],
		};

		const sourceAccessList = sourceAccess.access;

		for (let i = 0; i < existingAccessList.length; i++) {
			const entity = existingAccessList[i];
			const index = ArrayUtil.indexByPredicate(sourceAccessList, (e) => {
				return CoreUtil.isAccess(e, entity);
			});
			let resultEntity: IEntityAccess;
			if (index === -1) {
				resultEntity = CoreUtil.copy(entity);
				resultEntity.operation = EntityOperation.Delete;
			} else {
				const sourceEntity = sourceAccessList[index];
				resultEntity = CoreUtil.copy(sourceEntity);
				resultEntity.operation = EntityOperation.Update;
			}
			outputPageAccess.access.push(resultEntity);
		}

		// Add all new pages from the source
		for (let j = 0; j < sourceAccessList.length; j++) {
			const sourceItem = sourceAccessList[j];
			const resultIndex = ArrayUtil.indexByPredicate(
				outputPageAccess.access,
				(e) => {
					return CoreUtil.isAccess(e, sourceItem);
				},
			);
			const alreadyAdded = resultIndex !== -1;
			if (!alreadyAdded) {
				const addedEntity = CoreUtil.copy(sourceAccessList[j]);
				addedEntity.operation = EntityOperation.Create;
				outputPageAccess.access.push(addedEntity);
			}
		}
		return outputPageAccess;
	}

