	/**
	 * Unselects grid item and return nr of selected items.
	 * @param item
	 * @param gridApi
	 * @returns number of select items
	 */
	unselectGridItem(item, gridApi): number {
		if (
			item &&
			gridApi &&
			ArrayUtil.containsByProperty(
				gridApi.selection.getSelectedRows(),
				"$$hashKey",
				item.$$hashKey,
			)
		) {
			gridApi.selection.toggleRowSelection(item);
			gridApi.selection.getSelectedRows();
			return gridApi.selection.getSelectedRows().length;
		}
		return 0;
	}

	/**
	 * Get Delete Page Options
	 *
	 * Creates and returns options for delete page dialog.
	 */
	getDeletePageOptions(
		pages: IPage[],
		isPrivate: boolean,
		isDeleteForAllUsers?: boolean,
	): IMessageDialogOptions {
		if (isDeleteForAllUsers) {
			return this.getDeletePageForUsersOptions(pages[0]);
		}

		const pagesList = pages.map((page) => {
			return page.data.id;
		});
		const isMultiple = pagesList.length > 1;
		const title = isMultiple ? "Delete Pages" : "Delete Page";
		let message = isMultiple
			? "Are you sure that you want to delete the selected pages?"
			: "Are you sure that you want to delete the page?";
		if (!isPrivate) {
			message =
				message +
				(isMultiple
					? " They will be deleted for all users."
					: " It will be deleted for all users.");
		}
		const options: IMessageDialogOptions = {
			title: title,
			message: message,
			standardButtons: StandardDialogButtons.YesNo,
		};

		return options;
	}

