@Component({
	selector: "lm-operation-messages",
	templateUrl: "./operation-message-list.html",
	styleUrls: ["./operation-message-list.scss"],
})
export class AdminOperationMessageListComponent {
	@Input() statusMessageList: MessageInfo[];
	@Input() errorMessageList: ErrorInfo[];
	@Input() isCompleted = false;

	hasIcon(severity: number): boolean {
		return (
			severity === AdminConstants.severityInfo ||
			severity === AdminConstants.severitySuccess ||
			severity === AdminConstants.severityWarning ||
			severity === AdminConstants.severityError
		);
	}

	getIcon(severity: number): string {
		switch (severity) {
			case AdminConstants.severityInfo: // Info
				return "info";
			case AdminConstants.severitySuccess: // Success
				return "success";
			case AdminConstants.severityWarning: // Warn
				return "alert";
			case AdminConstants.severityError: // Error
				return "error";
			default: // No icon
				return "";
		}
	}

	isStatusMessage(message: MessageInfo): boolean {
		return message.severity && message.severity > 0;
	}

	isLastMessage(): boolean {
		return (
			this.isCompleted &&
			!(this.errorMessageList && this.errorMessageList.length)
		);
	}
}

@Component({
	templateUrl: "./operation-message-dialog.html",
})
export class AdminOperationMessageDialog extends ModalDialogBase {
	initialMessage: string;
	initialMessageInfo: MessageInfo;
	statusMessageList: MessageInfo[] = [];
	errorMessageList: ErrorInfo[] = [];
	operation: Observable<IOperationResponse>;
	responseCode: number;
	isOperationComplete = false;
	timeOut = 4000;

	constructor() {
		super("AdminOperationMessageDialog");
	}

	ngOnInit() {
		if (this.initialMessage) {
			this.initialMessageInfo = {
				message: this.initialMessage,
				code: 0,
				isTranslated: false,
			};
		}
		if (this.initialMessageInfo) {
			this.statusMessageList.push(this.initialMessageInfo);
		}
	}

	ngAfterViewInit() {
		this.startOperation();
	}

	startOperation() {
		if (this.operation) {
			this.operation.subscribe(
				(response: IOperationResponse) => {
					if (response) {
						this.statusMessageList = response.messageList;
						if (this.initialMessageInfo) {
							this.statusMessageList.unshift(this.initialMessageInfo);
						}
						this.errorMessageList = response.errorList;
						if (!response.hasError()) {
							this.responseCode = DialogResponseCode.Success;
						} else {
							this.responseCode = DialogResponseCode.Fail;
						}
					} else {
						this.responseCode = DialogResponseCode.Fail;
					}
					this.isOperationComplete = true;
				},
				(response: IOperationResponse) => {
					this.errorMessageList = response.errorList;
					this.errorMessageList.forEach((error) => {
						error.severity = AdminConstants.severityError;
					});
					this.responseCode = DialogResponseCode.Fail;
					this.isOperationComplete = true;
				},
			);
		}
	}

	close() {
		this.closeWithResult(DialogButtonType.Ok, this.responseCode);
	}
}

export interface IMultiOperationOptions {
	customSuccessfulMessage?: (count: number) => string;
	customFailedMessage?: (count: number) => string;
	entityname: string;
	operationName: string;
	operations: Observable<IOperationResponse>[];
}

@Component({
	templateUrl: `multi-operation-dialog.html`,
	styleUrls: ["./operation-message-list.scss"],
	changeDetection: ChangeDetectionStrategy.OnPush,
})
export class AdminMultiOperationDialog extends ModalDialogBase {
	options: IMultiOperationOptions;
	operationCount: number;
	cancelled: "false" | "user" | "error" = "false";
	isComplete = false;
	successful = 0;
	failed = 0;
	skipped = 0;

	progressMessage: string;
	successfulMessage: string;
	failedMessage: string;
	failedDetails: string;
	skippedMessage: string;

	constructor(public detector: ChangeDetectorRef) {
		super("AdminMultiOperationDialog");
	}

	ngAfterViewInit() {
		const operations = this.options.operations;
		this.operationCount = operations ? operations.length : 0;
		this.nextOperation();
	}

	/**
	 * Recursivly executes the next operation in the operations array. Stops if cancelled or all operations
	 * have been executed. Updates counters and messages for successful, failed and skipped operations.
	 * Operations are executed in sequence and next operation is not executed before previous one has finished.
	 */
	nextOperation() {
		const operations = this.options.operations;
		this.isComplete = !operations || operations.length === 0;
		this.updateProgress();
		if (!this.isOperationCancelled() && !this.isComplete) {
			const operation = operations.shift();
			operation.subscribe(
				() => {
					this.updateSuccessful();
					this.nextOperation();
				},
				(r: IOperationResponse) => {
					this.updateFailed(r);
					this.nextOperation();
				},
			);
		}
	}

	updateProgress() {
		const processed = this.successful + this.failed;
		this.progressMessage = `Processed ${processed}/${
			this.operationCount
		} ${AdminUtil.pluralize(this.options.entityname, this.operationCount)}.`;
		if (this.isComplete) {
			this.progressMessage = `${this.progressMessage} Operation completed.`;
		} else if (this.isOperationCancelled()) {
			this.progressMessage = `${this.progressMessage} Operation was cancelled ${
				this.cancelled === "error" ? "due to an error" : "by the user"
			}.`;
		}
		this.detector.markForCheck();
	}

	updateSuccessful() {
		this.successful++;
		const options = this.options;
		if (options.customSuccessfulMessage) {
			this.successfulMessage = options.customSuccessfulMessage(this.successful);
		} else {
			const operation = options.operationName;
			this.successfulMessage = `${this.successful} ${AdminUtil.pluralize(
				options.entityname,
				this.successful,
			)}
				${operation}${operation.endsWith("e") ? "d" : "ed"}.`;
		}
	}

	updateFailed(r: IOperationResponse) {
		this.failed++;
		const options = this.options;
		if (options.customFailedMessage) {
			this.failedMessage = options.customFailedMessage(this.failed);
		} else {
			this.failedMessage = `Failed to ${options.operationName} ${
				this.failed
			} ${AdminUtil.pluralize(options.entityname, this.failed)}.`;
		}
		this.addErrorDetails(r);
	}

	addErrorDetails(r: IOperationResponse) {
		if (r.errorList && r.errorList.length > 0) {
			r.errorList.forEach((element) => {
				const message = element.message;
				if (message) {
					if (!this.failedDetails) {
						this.failedDetails = message;
					} else {
						// Only add if the message does not already exist
						if (!this.failedDetails.includes(message)) {
							this.failedDetails = this.failedDetails + " " + message;
						}
					}
				}
			});
		}
	}

	updateSkipped(count: number) {
		this.skipped += count;
		this.skippedMessage = `Skipped ${this.skipped} ${AdminUtil.pluralize(
			this.options.entityname,
			this.skipped,
		)}.`;
	}

	cancelOperation(isError?: boolean) {
		isError ? (this.cancelled = "error") : (this.cancelled = "user");
		this.updateSkipped(this.options.operations.length);
	}

	isOperationCancelled(): boolean {
		return this.cancelled === "error" || this.cancelled === "user";
	}
}

