import { Component } from "@angular/core";
import { IAttributeInfo, ModalDialogBase } from "lime/core";

@Component({
	template: `
		<lm-user-properties
			(selectedProperty)="onPropertySelect($event)"></lm-user-properties>
		<div class="modal-buttonset">
			<button class="btn-modal" (click)="close()">Cancel</button>
			<button
				class="btn-modal-primary"
				[disabled]="!selected"
				(click)="closeWithSelected(selected)">
				OK
			</button>
		</div>
	`,
})
export class UserPropertiesListDialog extends ModalDialogBase {
	selected: IAttributeInfo;

	constructor() {
		super("UserPropertiesListDialog");
	}

	ngOninit() {
		this.initModalDialog();
	}

	onPropertySelect(selected: IAttributeInfo): void {
		this.selected = selected;
	}

	closeWithSelected(selected) {
		if (selected && selected.name) {
			this.modalDialog.close(selected);
		} else {
			this.logDebug(
				"closeWithSelected: selected property or property name is undefined.",
			);
		}
	}
}
