import { Component, OnInit } from "@angular/core";
import { FormControl, FormGroup, Validators } from "@angular/forms";
import { ArrayUtil } from "lime";
import {
	Constants,
	CoreUtil,
	IDynamicContainer,
	IDynamicWeb,
	ModalDialogBase,
} from "lime/core";
import { of } from "rxjs";
import { catchError } from "rxjs/operators";
import { IExpInfo } from "scripts/lime/admin/service";
import { DynamicPageAdminService } from "../../service";
import { DynamicUtil } from "../../util";
import { DynamicContainerListBase } from "./dynamic-container/dynamic-container-list";

@Component({
	selector: "lm-dynamic-web-list",
	templateUrl: "./dynamic-container/dynamic-container-list.html",
	styleUrls: ["./dynamic-container/dynamic-container-list.scss"],
})
export class DynamicWebListComponent
	extends DynamicContainerListBase
	implements OnInit
{
	ngOnInit() {
		const buttonText = "Add Web Page";
		const buttonInfoText =
			"This component is empty. Start adding content by clicking " +
			buttonText +
			".";
		this.initItems(buttonText, buttonInfoText, "URL", "Action");
		this.infoHeader = {
			text: "Only one web page will be displayed.",
			title: "Web pages",
		};
		this.update();
	}

	addItem() {
		if (!this.canAdd() || this.isDialogOpen) {
			return;
		}
		this.isDialogOpen = true;

		const dialog = this.dialogService
			.modal(DynamicWebDialog, this.viewContainerRef)
			.title("Add Web Page")
			.id("lm-a-dp-web-add-dialog")
			.afterClose((addedWeb) => {
				this.isDialogOpen = false;
				if (addedWeb) {
					this.update();
				}
			});

		dialog
			.apply((component: DynamicWebDialog) => {
				component.modalDialog = dialog;
				component.container = this.container;
				component.isEdit = false;
			})
			.open();
	}

	editItem(isPermissionTab: boolean, web: IDynamicWeb): void {
		if (this.isDialogOpen) {
			return;
		}
		this.isDialogOpen = true;

		const dialog = this.dialogService
			.modal(DynamicWebDialog, this.viewContainerRef)
			.title(`${this.isEditable ? "Edit" : "View"} Web Page`)
			.id("lm-a-dp-web-edit-dialog")
			.afterClose((editedWeb) => {
				this.isDialogOpen = false;
				if (editedWeb) {
					this.update();
				}
			});

		dialog
			.apply((component: DynamicWebDialog) => {
				component.modalDialog = dialog;
				component.container = this.container;
				component.oldWeb = web;
				component.web = web;
				component.selectedExpressions = DynamicUtil.toExpressions(
					web,
					this.accessTitles,
				);
				component.isEdit = true;
				component.isPermissionTabOnInit = isPermissionTab;
				component.isEditable = this.isEditable;
			})
			.open();
	}

	deleteItems(
		webLinks: IDynamicWeb[],
		parentContainer?: IDynamicContainer,
	): void {
		const containerCopy = CoreUtil.copy(parentContainer || this.container);

		for (const web of webLinks) {
			const removeIndex = ArrayUtil.indexByProperty(
				containerCopy.wbs,
				"eid",
				web.eid,
			);
			if (removeIndex > -1) {
				containerCopy.wbs.splice(removeIndex, 1);
			}
		}
		this.pageService
			.updateContainer(containerCopy, null, webLinks)
			.pipe(
				// Ignore error since it's handled in service
				catchError(() => of()),
			)
			.subscribe(() => this.update());
	}

	getEntityCount(): number {
		return this.container.wbs && this.container.wbs.length;
	}

	onCopy() {
		this.copySelected(this.container.wbs);
	}

	onCut() {
		this.cutSelected(this.container.wbs);
	}

	onDeleteSelected() {
		this.deleteSelectedItems(this.container.wbs);
	}

	private update() {
		const container = this.container;
		this.isEmpty = !(container.wbs && container.wbs.length > 0);
		this.clearSelectionCount();
	}
}

@Component({
	templateUrl: "./add-web.html",
})
export class DynamicWebDialog extends ModalDialogBase implements OnInit {
	web: IDynamicWeb;
	oldWeb: IDynamicWeb;
	isEdit: boolean;
	isPermissionTabOnInit: boolean;
	container: IDynamicContainer;
	urlMaxLength = Constants.dynPageUrlMaxLength;
	selectedExpressions: IExpInfo[];
	expressions: IExpInfo[];
	listLabel = "Choose which set of users this web page should be visible for.";
	showLaunchUrl: boolean;
	isEditable = true;

	form = new FormGroup({
		action: new FormControl<ActionValue>("none", [
			Validators.required,
			Validators.maxLength(Constants.dynPageUrlMaxLength),
		]),
		launchUrl: new FormControl(),
		url: new FormControl(null, Validators.required),
	});

	constructor(public dynamicPageService: DynamicPageAdminService) {
		super("DynamicWebDialog");

		this.form.controls.action.valueChanges.subscribe((value) =>
			this.actionValueChanged(value),
		);
	}

	ngOnInit(): void {
		this.web = { ...this.web };
		this.initFormValues();
		this.initModalDialog();
	}

	save() {
		if (!this.isEditable) {
			return;
		}

		if (!this.web.eid) {
			this.web.eid = DynamicUtil.getNewEntityId(this.container);
		}
		this.readFormValues();
		const web = CoreUtil.copy(this.web);

		if (this.expressions) {
			web.as = 1;
			web.ais = DynamicUtil.toIds(this.expressions);
			web.op = DynamicUtil.getOperator(this.expressions);
		} else if (this.selectedExpressions) {
			web.as = null;
			web.ais = null;
		}
		if (this.isEdit) {
			this.submitSafe(
				this.dynamicPageService.editContainerEntity(
					this.container,
					web,
					this.oldWeb,
				),
				false,
				true,
			).subscribe(() => this.modalDialog.close(web));
		} else {
			this.submitSafe(
				this.dynamicPageService.addContainerEntity(this.container, web),
				false,
				true,
			).subscribe(() => this.modalDialog.close(web));
		}
	}

	private actionValueChanged(value: ActionValue) {
		const launchUrl = this.form.controls.launchUrl;
		if (value === "launch") {
			launchUrl.setValidators(Validators.required);
			this.showLaunchUrl = true;
		} else {
			launchUrl.clearValidators();
			this.showLaunchUrl = false;
		}
		launchUrl.updateValueAndValidity({ onlySelf: true });
	}

	private initFormValues() {
		const controls = this.form.controls;
		controls.url.setValue(this.web.u);
		controls.launchUrl.setValue(this.web.lu);

		const action = controls.action;
		action.setValue("none");
		if (this.web.er) {
			action.setValue("refresh");
		} else if (this.web.lu) {
			action.setValue("launch");
		} else {
			action.setValue("none");
		}
		this.actionValueChanged(action.value);
	}

	private readFormValues() {
		const controls = this.form.controls;
		this.web.u = controls.url.value;

		const actionValue = controls.action.value;
		const launchUrlValue = controls.launchUrl.value;
		this.web.lu = actionValue === "launch" ? launchUrlValue : null;
		this.web.er = actionValue === "refresh";
	}
}

type ActionValue = "launch" | "none" | "refresh";
