import {
	ChangeDetectionStrategy,
	ChangeDetectorRef,
	Component,
	EventEmitter,
	NgZone,
	Output,
	ViewChild,
} from "@angular/core";
import {
	SohoDataGridComponent,
	SohoMessageService,
	SohoModalDialogService,
} from "ids-enterprise-ng";
import {
	AttributeCategory,
	CommonDataService,
	Constants,
	IAttributeInfo,
	IAttributeListResponse,
	LanguageService,
} from "lime/core";
import { CustomFormatters } from "../../../admin";
import { AdminListComponent } from "../../../admin-list.component";
import { AdminService } from "../../../service";

@Component({
	selector: "lm-user-properties",
	template: `
		<div
			class="lm-display-flex"
			soho-tabs
			(beforeActivated)="updateSelectedCategory($event)">
			<div soho-tab-list-container>
				<ul soho-tab-list>
					<li soho-tab>
						<a
							soho-tab-title
							tabId="Additional"
							[id]="attributeCategories.Additional"
							>Additional</a
						>
					</li>
					<li soho-tab>
						<a
							soho-tab-title
							tabId="Standard"
							[id]="attributeCategories.Standard"
							>Standard</a
						>
					</li>
				</ul>
			</div>
			<button
				soho-button="icon"
				icon="refresh"
				(click)="refresh()"
				soho-tooltip
				title="Refresh">
				<span class="audible">Refresh</span>
			</button>
		</div>
		<div
			soho-datagrid
			#propertiesDataGrid
			id="gridSelectProperty"
			[gridOptions]="datagridOptions"
			[data]="datagridOptions.dataset"
			(selected)="updateSelection($event.rows)"></div>
	`,
	changeDetection: ChangeDetectionStrategy.OnPush,
})
export class UserPropertiesListComponent extends AdminListComponent {
	@ViewChild("propertiesDataGrid", { static: false })
	dataGrid: SohoDataGridComponent;
	@Output() selectedProperty = new EventEmitter<IAttributeInfo>();
	selectedCategory = AttributeCategory.Standard;
	attributeCategories = AttributeCategory;

	constructor(
		messageService: SohoMessageService,
		languageService: LanguageService,
		adminService: AdminService,
		sohoModalDialogService: SohoModalDialogService,
		zone: NgZone,
		readonly commonService: CommonDataService,
		private changeDetector: ChangeDetectorRef,
	) {
		super(
			"DynamicUserPropertiesComponent",
			"user property",
			messageService,
			languageService,
			adminService,
			sohoModalDialogService,
			zone,
		);
	}

	ngOnInit(): void {
		this.initGrid();
		this.refresh();
	}

	getDataGrid(): SohoDataGridComponent {
		return this.dataGrid;
	}

	updateSelection(args: any[]): void {
		super.updateSelection(args);
		this.selectedProperty.emit(this.selected);
	}

	listItems(reload?: boolean): void {
		const observable = this.commonService.listAttributes(reload);
		this.withBusy(observable).subscribe(
			(response: IAttributeListResponse) => {
				if (response && response.content) {
					this.updateItems(response.content);
					this.updateDataSet();
					this.changeDetector.detectChanges();
				}
			},
			(response: IAttributeListResponse) => {
				this.onError(response);
			},
		);
	}

	updateSelectedCategory(event: SohoTabsEvent) {
		const newCategory = event.tab | event.tab.id;
		if (this.selectedCategory !== newCategory) {
			if (this.selected && this.dataGrid) {
				this.dataGrid.unSelectAllRows();
			}
			this.selectedCategory = newCategory;
			this.updateDataSet();
		}
	}

	updateDataSet() {
		this.datagridOptions.dataset = this.items.filter((item) => {
			return item.category === this.selectedCategory;
		});
	}

	private initGrid(): void {
		const options = {
			selectable: "single" as SohoDataGridSelectable,
			rowHeight: "medium" as SohoDataGridRowHeight,
			disableRowDeactivation: true,
			clickToSelect: false,
			columns: [
				this.getSelectionColumn(),
				{
					width: 205,
					id: "adm-up-col-p",
					field: "name",
					name: "Property",
					sortable: false,
					resizable: true,
				},
				{
					width: 200,
					id: "adm-up-col-dt",
					field: "type",
					name: "Data type",
					sortable: false,
					resizable: true,
					formatter: CustomFormatters.propertyDataType,
				},
			],
			dataset: [],
			emptyMessage: {
				title: "No user properties found",
				icon: Constants.adminEmptyDatagridIcon,
			},
		};
		this.datagridOptions = options;
	}
}
