import { Component, Input } from "@angular/core";
import { CoreBase } from "lime/core";
import {
	MemoFrequencyType,
	MemoIteration,
	MemoMonth,
	MemoWeekDay,
	MemoWeekOrdinal,
} from "./core";

@Component({
	selector: "lm-admin-memo-date-yearly",
	templateUrl: "./date-yearly.html",
})
export class MemoDateYearlyComponent extends CoreBase {
	@Input() iteration: MemoIteration;

	Months = MemoMonth;
	FrequencyTypes = MemoFrequencyType;
	WeekOrdinals = MemoWeekOrdinal;
	WeekDays = MemoWeekDay;

	constructor() {
		super("MemoDateYearlyComponent");
	}

	onFocus($event: any): void {
		$event.target.select();
	}
}
