import {
	Component,
	NgZone,
	OnInit,
	ViewChild,
	ViewContainerRef,
} from "@angular/core";
import {
	SohoDataGridComponent,
	SohoMessageService,
	SohoModalDialogService,
} from "ids-enterprise-ng";
import { DialogButtonType, IDialogResult } from "lime";
import {
	Constants,
	ContextService,
	CoreUtil,
	IPage,
	LanguageService,
} from "lime/core";
import { CustomFormatters } from "../admin";
import { DateRangeFormatter } from "../core";
import { AdminService, AdminUtil, IPageSelectorOptions } from "../service";
import { AdminSettingsService } from "./admin-settings.service";
import { DateRangeComponent, IDateRange } from "./date-range";
import { IPageItem, PageComponentBase } from "./runtime";

export interface IMandatoryPageSetting {
	pages: IMandatoryPageInfo[];
	strategy?: number;
}

export interface IMandatoryPageInfo {
	id: string;
	from?: number; // Legacy, required for backwards compatibility
	to?: number; // Legacy, required for backwards compatibility
	dateRange: IDateRange;
	primary: boolean;
}

export interface IMandatoryPageItem extends IPageItem<IMandatoryPageInfo> {
	primary: boolean;
}

class DateRangeFormatterMandatoryPages {
	static alertLimitMilliSeconds = 86400000; // 24 hours

	static format(row, cell, value, col, rowData, api): string {
		const info = rowData.info as IMandatoryPageInfo;
		const from = info.from;
		const to = info.to;
		const status = info.dateRange ? info.dateRange.sts : null;

		return DateRangeFormatter.format({
			closeToEndLimitMilliSeconds:
				DateRangeFormatterMandatoryPages.alertLimitMilliSeconds,
			fromDate: from,
			toDate: to,
			status: status,
			isFutureMessage: "Page is not yet active",
			isActiveCloseExpireMessage: "Page expires soon",
			isActiveMessage: "Page is active",
			isExpiredMessage: "Page has expired",
		});
	}
}

@Component({
	selector: "lm-admin-mandatory-pages",
	templateUrl: "./mandatory-pages.html",
})
export class MandatoryPagesComponent
	extends PageComponentBase<IMandatoryPageItem>
	implements OnInit
{
	@ViewChild("mandatoryPagesView", { read: ViewContainerRef, static: false })
	view: ViewContainerRef;

	@ViewChild("mandatoryPagesGrid", { static: false })
	datagrid: SohoDataGridComponent;

	isFirst: boolean;

	constructor(
		readonly messageService: SohoMessageService,
		readonly languageService: LanguageService,
		readonly adminService: AdminService,
		readonly sohoModalDialogService: SohoModalDialogService,
		readonly zone: NgZone,
		readonly settingsService: AdminSettingsService,
		private readonly contextService: ContextService,
	) {
		super(
			"MandatoryPagesComponent",
			messageService,
			languageService,
			adminService,
			sohoModalDialogService,
			zone,
			settingsService,
		);
	}

	setDateRange(item: IMandatoryPageItem): void {
		const info = item.info;
		const dateRange = CoreUtil.copy(info.dateRange);

		const dialog = this.sohoModalDialogService
			.modal(DateRangeComponent, this.view)
			.title("Set date range")
			.id("lm-a-daterange-dialog")
			.afterClose((result: IDialogResult) => {
				if (result && result.button === DialogButtonType.Ok) {
					const value = result.value as IDateRange;
					info.dateRange = value;
					this.updateValue();
					this.refreshItems();
				}
			});

		dialog
			.apply((component) => {
				component.modalDialog = dialog;
				component.dateRange = dateRange;
			})
			.open();
	}

	updateValue(): void {
		const pages = [] as IMandatoryPageInfo[];
		for (const item of this.items) {
			if (item) {
				const info = item.info;
				info.primary = item.primary;
				pages.push(info);
			}
		}

		const value = { pages: pages } as IMandatoryPageSetting;
		if (this.isFirst) {
			value.strategy = 1;
		}
		this.settingItem.value = JSON.stringify(value);
	}

	protected getView(): ViewContainerRef {
		return this.view;
	}

	protected getDataGrid() {
		return this.datagrid;
	}

	protected createItem(data: IPage, counter: number) {
		const pageData = data.data;
		return {
			id: counter,
			info: this.createInfo(pageData.id),
			title: pageData.title,
			description: pageData.description,
			primary: false,
			accessState: data.accessState,
			err: this.getPageError(pageData),
		};
	}

	protected createSelectorOptions(): IPageSelectorOptions {
		return {
			title: this.settingItem.setting.label,
			isMultiSelect: true,
			noShowIds: this.items.map((page) => page.info.id),
		};
	}

	protected initGrid(): void {
		const rowTemplate =
			'<div class="datagrid-cell-layout" style="overflow: hidden;"><span class="datagrid-textarea lm-white-space-normal">{{description}}</span></div>';
		this.datagridOptions = {
			idProperty: "id",
			rowTemplate: rowTemplate,
			rowReorder: true,
			selectable: "multiple" as SohoDataGridSelectable,
			editable: true,
			filterable: false,
			disableRowDeactivation: true,
			clickToSelect: false,
			columns: [
				this.getRowReorderColumn(),
				this.getSelectionColumn(),
				{
					width: 77,
					id: "adm-mp-col-range",
					field: "range",
					align: "center",
					name: "Status",
					resizable: false,
					sortable: false,
					formatter: DateRangeFormatterMandatoryPages.format,
				},
				{
					width: 500,
					id: "adm-mp-col-title",
					field: "title",
					name: "Title",
					resizable: true,
					sortable: false,
					formatter: CustomFormatters.dynamicDisabledExpander,
				},
				{
					width: 100,
					id: "adm-mp-col-primary",
					field: "primary",
					name: "Primary",
					align: "center",
					resizable: false,
					sortable: false,
					formatter: Formatters.Checkbox,
					editor: Soho.Editors.Checkbox,
				},
				{
					width: 150,
					id: "adm-mp-col-permissions",
					field: "accessState",
					name: "Permissions",
					resizable: true,
					sortable: false,
					formatter: CustomFormatters.accessState,
				},
			],
			dataset: this.items,
			emptyMessage: {
				title:
					"No mandatory pages configured. Click 'Add Pages' to configure mandatory pages.",
				icon: Constants.adminEmptyDatagridIcon,
			},
		};
	}

	protected toItem(
		info: IMandatoryPageInfo,
		counter: number,
	): IMandatoryPageItem {
		return {
			id: counter,
			title: info.id,
			info: info,
			primary: !!info.primary,
		};
	}

	protected toInfos(value: string): IMandatoryPageInfo[] {
		if (value) {
			if (value.indexOf("{") >= 0) {
				const setting = CoreUtil.tryParse<IMandatoryPageSetting>(value);
				if (setting) {
					this.isFirst = setting.strategy === 1;
					const pages = setting.pages;
					if (pages) {
						this.convertLegacyDate(pages);
						this.evaluateDateRangeStatus(pages);
						return pages;
					}
				}
			} else {
				// Legacy value format
				return value.split(",").map((s) => this.createInfo(s));
			}
		}
		return [];
	}

	private refreshItems(): void {
		this.updateItems(this.items.slice());
	}

	private createInfo(id: string): IMandatoryPageInfo {
		return {
			id: id,
			dateRange: this.getDefaultDateRange(),
			primary: false,
		};
	}

	private evaluateDateRangeStatus(pageInfos: IMandatoryPageInfo[]) {
		const toEvaluate = pageInfos
			.filter((page) => page.dateRange)
			.map((page) => page.dateRange)
			.filter((dateRange) => dateRange.from || dateRange.to);
		this.adminService.getDateRangeStatus(toEvaluate).subscribe(
			(response) => {
				const content = response ? response.content : null;
				if (content && content.length === toEvaluate.length) {
					for (const dateRange of toEvaluate) {
						dateRange.sts = content.shift().sts;
					}
				}
			},
			() => {
				for (const daterange of toEvaluate) {
					daterange.sts = 0;
				}
			},
		);
	}

	private convertLegacyDate(pageInfos: IMandatoryPageInfo[]) {
		for (const page of pageInfos) {
			if ((page.from || page.to) && !page.dateRange) {
				page.dateRange = this.getDefaultDateRange();
			}
			if (page.from) {
				page.dateRange.from = AdminUtil.toIsoDateTimeLocal(new Date(page.from));
				page.from = 0;
			}
			if (page.to) {
				page.dateRange.to = AdminUtil.toIsoDateTimeLocal(new Date(page.to));
				page.to = 0;
			}
		}
	}

	private getDefaultDateRange() {
		return {
			from: null,
			to: null,
			tz: this.contextService.getContext().getInforStdTimeZone() || "UTC",
		} as IDateRange;
	}
}
