import {
	Directive,
	Input,
	NgZone,
	OnInit,
	ViewContainerRef,
} from "@angular/core";
import {
	SohoMessageService,
	SohoModalDialogRef,
	SohoModalDialogService,
} from "ids-enterprise-ng";
import { ArrayUtil, DialogButtonType, HtmlUtil, IDialogResult } from "lime";
import {
	Constants,
	IPage,
	IPageData,
	IPageError,
	IPageSettingInfo,
	IPageSettingInfoListResponse,
	ISettingItem,
	LanguageService,
	PageError,
} from "lime/core";
import { finalize, take } from "rxjs/operators";
import { GridUtil } from "../admin";
import { AdminListComponent } from "../admin-list.component";
import { AdminService, IPageSelectorOptions } from "../service";
import { AdminSettingsService } from "./admin-settings.service";
import { IDefaultPageInfo } from "./default-pages";
import { IMandatoryPageInfo } from "./mandatory-pages";

export interface IPageItem<T = IMandatoryPageInfo | IDefaultPageInfo> {
	id: number | string;
	title: string;
	info: T;
	accessState?: number;
	isDynamic?: boolean;
	description?: string;
	err?: IPageError;
}

@Directive()
export abstract class PageComponentBase<T extends IPageItem>
	extends AdminListComponent<T>
	implements OnInit
{
	@Input()
	settingItem: ISettingItem;

	@Input()
	dialog: SohoModalDialogRef<any>;

	protected maxPages = 20;
	protected isDialogOpen: boolean;

	private isDynamicPagesEnabled: boolean;

	constructor(
		logPrefix: string,
		readonly messageService: SohoMessageService,
		readonly languageService: LanguageService,
		readonly adminService: AdminService,
		readonly sohoModalDialogService: SohoModalDialogService,
		readonly zone: NgZone,
		readonly settingsService: AdminSettingsService,
	) {
		super(
			logPrefix,
			"page",
			messageService,
			languageService,
			adminService,
			sohoModalDialogService,
			zone,
		);
	}

	ngOnInit(): void {
		this.initGrid();
		this.listItems();
		this.settingsService.isDynamicPagesEnabled$
			.pipe(take(1))
			.subscribe((isEnabled) => (this.isDynamicPagesEnabled = isEnabled));
	}

	openPageSelector() {
		if (!this.canAddPage() || this.isDialogOpen) {
			return;
		}

		this.isDialogOpen = true;
		this.isBusy = true;
		const options = this.createSelectorOptions();

		const observable = this.adminService.openPageSelectorDialog(
			options,
			"Add Pages",
			this.getView(),
			null,
		);
		observable
			.pipe(
				finalize(() => {
					this.isDialogOpen = false;
					this.isBusy = false;
				}),
			)
			.subscribe((r: IDialogResult) => {
				const value = r.value as IPage[];
				if (value && r.button === DialogButtonType.Ok) {
					this.addPages(value);
					this.updateValue();
				}
			});
	}

	onExpandRow(event: { detail: any; item: T }): void {
		const item = event.item;
		const container = $(event.detail)
			.find(".datagrid-row-detail-padding")
			.empty();
		let template = `<div class="datagrid-cell-layout">
				<span class="datagrid-textarea lm-white-space-normal">${HtmlUtil.escapeStringForHtml(
					item.description,
				)}</span>`;

		if (item.err && item.err.pageError === PageError.DynamicPagesFeatureOff) {
			template += this.getErrorMessageTemplate(
				GridUtil.formatAlert(Constants.dynPageFeatureOffMsg, true),
			);
		}

		template += `</div>`;
		$(container).append($(template));
	}

	onRowReordered(event: SohoDataGridRowReorderedEvent) {
		this.updateValue();
	}

	listItems(): void {
		const items = this.toItems(this.settingItem.value);
		if (items.length === 0) {
			return;
		}

		const idList = items
			.map((item) => {
				return item.info.id;
			})
			.join(",");

		this.isBusy = true;
		this.adminService.getPageSettingInfo(idList).subscribe(
			(r: IPageSettingInfoListResponse) => {
				const pages = r.content;
				this.initItems(items, pages);
				this.setBusy(false);
			},
			() => {
				this.showPageLoadError();
				this.initItems(items, []);
				this.setBusy(false);
			},
		);
	}

	deletePages(): void {
		const selection = this.selection;
		if (!selection) {
			return;
		}

		const items = this.items.slice();
		for (const item of selection) {
			ArrayUtil.remove(items, item.data);
		}
		this.getDataGrid().unSelectAllRows();
		this.count = items.length;
		this.updateItems(items);
		this.updateValue();
	}

	abstract updateValue(): void;

	protected abstract createItem(data: IPage, counter: number): T;

	protected abstract toItem(
		info: IMandatoryPageInfo | IDefaultPageInfo,
		counter: number,
	): T;

	protected abstract toInfos(
		value: string,
	): IMandatoryPageInfo[] | IDefaultPageInfo[];

	protected abstract getView(): ViewContainerRef;

	protected abstract initGrid(): void;

	protected abstract createSelectorOptions(): IPageSelectorOptions;

	protected getPageError(data: IPageData): IPageError {
		if (data.isDynamic && !this.isDynamicPagesEnabled) {
			return {
				message: Constants.dynPageFeatureOffMsg,
				pageError: PageError.DynamicPagesFeatureOff,
			};
		}
		return null;
	}

	protected toItems(value: string): T[] {
		const infos = this.toInfos(value);
		const items: T[] = [];

		let counter = 1;
		for (const info of infos) {
			items.push(this.toItem(info, counter));
			counter++;
		}

		return items;
	}

	protected initItems(items: T[], pages: IPageSettingInfo[]): void {
		for (const item of items) {
			const id = item.info.id;
			const page = ArrayUtil.itemByPredicate(pages, (p) => p.id === id);
			if (page) {
				item.title = page.title || "Missing page (" + id + ")";
				item.description = page.description;
				item.accessState = page.accessState;
				item.isDynamic = page.isDynamic;
				item.err = this.getPageError(page);
			} else {
				item.title = item.info.id;
				item.description = "";
			}
		}
		this.count = items.length;
		this.updateItems(items);
	}

	protected addPages(selectedItems: IPage[]): void {
		if (!selectedItems) {
			return;
		}

		let items = this.items.slice();
		let counter = items.length + 1;
		for (const selectedItem of selectedItems) {
			const data = selectedItem.data;
			if (ArrayUtil.indexByPredicate(items, (i) => i.info.id === data.id) < 0) {
				items.push(this.createItem(selectedItem, counter));
				counter++;
			}
		}

		const max = this.maxPages;
		if (items.length > max) {
			items = items.slice(0, max);
			this.showMaxCountMessage();
		}
		this.count = items.length;
		this.updateItems(items);
	}

	protected canAddPage(): boolean {
		if (this.count >= this.maxPages) {
			this.showMaxCountMessage();
			return false;
		}
		return true;
	}

	protected showMaxCountMessage(): void {
		this.showError(
			"Maximum number of pages reached",
			"The maximum number of pages is " + this.maxPages,
		);
	}

	protected showPageLoadError(): void {
		this.showError(
			"Unable to load page titles",
			"Page IDs are shown instead of titles.",
		);
	}

	protected getRowReorderColumn(): SohoDataGridColumn {
		return {
			width: 80,
			id: "rowReorder",
			field: "id",
			align: "center",
			sortable: false,
			formatter: Formatters.RowReorder,
		};
	}
}
