import { Component } from "@angular/core";
import { DialogService } from "lime";
import { Constants, DynamicPageAreaKey } from "lime/core";
import { of } from "rxjs";
import { catchError } from "rxjs/operators";
import { DynamicPageAdminService } from "../service";

@Component({
	templateUrl: "./add-component-dialog.html",
	styleUrls: ["./add-component-dialog.scss"],
})
export class AddDynamicComponentDialog {
	area: DynamicPageAreaKey = "main";
	experimentalTooltip = Constants.dynPageExperimentalFeatureMsg;

	constructor(
		private readonly pageService: DynamicPageAdminService,
		private readonly dialogService: DialogService,
	) {}

	addLinkList(shortCut?: boolean) {
		const subType = shortCut ? 1 : 0;
		this.pageService
			.addLinkList(this.area, subType)
			.pipe(
				// Ignore error since it's handled in service
				catchError(() => of()),
			)
			.subscribe(() =>
				this.showToast(`A ${shortCut ? "shortcuts" : "link list"}`),
			);
	}

	addImage() {
		this.pageService
			.addImage(this.area)
			.pipe(
				// Ignore error since it's handled in service
				catchError(() => of()),
			)
			.subscribe(() => this.showToast("An image"));
	}

	addItems() {
		this.pageService
			.addItems(this.area)
			.pipe(
				// Ignore error since it's handled in service
				catchError(() => of()),
			)
			.subscribe(() => this.showToast("An information"));
	}

	addWidget() {
		this.pageService
			.addWidget(this.area)
			.pipe(
				// Ignore error since it's handled in service
				catchError(() => of()),
			)
			.subscribe(() => this.showToast("A widget"));
	}

	addWeb() {
		this.pageService
			.addWeb(this.area)
			.pipe(
				// Ignore error since it's handled in service
				catchError(() => of()),
			)
			.subscribe(() => this.showToast("A web"));
	}

	addText() {
		this.pageService
			.addText(this.area)
			.pipe(
				// Ignore error since it's handled in service
				catchError(() => of()),
			)
			.subscribe(() => this.showToast("A text"));
	}

	private showToast(componentMsg: string): void {
		this.dialogService.showToast({
			title: "Component added",
			message: `${componentMsg} component has been added to the ${this.area} area`,
		});
	}
}
