export interface ISortInfo {
	index: number;
	element?: any;
	area?: DynamicPageAreaKey;
}

export interface IContainerFilter {
	type: {
		links: boolean;
		shortcuts: boolean;
		images: boolean;
		items: boolean;
		widgets: boolean;
		webs: boolean;
		texts: boolean;
	};
	access: IStringMap;
}

export interface IStringToAccessError {
	[key: string]: IAccessError[];
}

export interface IAccessErrorMap {
	parents: IStringToAccessError;
	errors: IStringToAccessError;
}

export interface IAccessError {
	type: AccessErrorType;
	aid: string;
}

export enum AccessErrorType {
	Missing = 1,
	Invalid,
	Parent,
}

const getAreaContainers =
	(areaKey: DynamicPageAreaKey) => (page?: IDynamicPageAdmin) => {
		const area =
			(page && page.ly && page.ly.areas && page.ly.areas[areaKey]) || [];
		const containers = (page && page.cts) || [];
		const areaContainers: IDynamicContainer[] = [];

		for (const entry of area) {
			const container = containers.find(
				(container) => container.eid === entry.id,
			);
			if (container) {
				areaContainers.push(container);
			}
		}

		return areaContainers;
	};

@Component({
	selector: "lm-dynamic-page-editor",
	templateUrl: "./dynamic-page-editor.html",
	styleUrls: ["./dynamic-page-editor.scss", "./dynamic-page-editor-rtl.scss"],
})
export class DynamicPageEditor
	extends CoreBase
	implements OnDestroy, OnInit, AfterViewInit
{
	@ViewChildren(DynamicAccordion) accordions: QueryList<DynamicAccordion>;
	accessTitles: IStringMap = {};
	dynContainerIdentifiers = DynContainerIdentifiers;
	dynContainerTypes = DynamicContainerType;
	dynColorTypes = DynamicColorType;
	defaultSetting: IDynamicPageSetting;
	bannerQuery = "";
	mainQuery = "";
	policyQuery = "";
	filter = {
		type: {
			links: false,
			shortcuts: false,
			images: false,
			items: false,
			widgets: false,
			webs: false,
		},
		access: {},
	};
	showBannerArea: boolean;
	showRepair = true;
	isEditable = true;
	defaultTitle = "Untitled";
	defaultAccessFiltersLimit = 5;
	accessFiltersLimit = this.defaultAccessFiltersLimit;
	componentFilters$ = this.filterService.componentFilters$;
	accessFilters$ = this.filterService.accessFilters$;
	page = this.pageService.editedPage;
	noPolicyKey = DynamicUtil.noPolicyKey;
	allUsersText = DynamicUtil.allUsersText;
	repairMessageOptions: IMessageBannerOptions = {
		message: DynamicUtil.repairPageText,
		level: MessageBannerLevel.Warning,
		dismissable: true,
		actions: [
			{
				icon: "import",
				text: "Import policies",
				execute: () => this.openImportPolicies(),
			},
			{
				icon: "wrench",
				text: "Repair",
				execute: () => this.repairPageAccess(),
			},
		],
	};

	mainContainers: Observable<IDynamicContainer[]> = this.page.pipe(
		tap((page) => (this.isEditable = page && !page.isReadOnly)),
		map(getAreaContainers("main")),
	);

	bannerContainers: Observable<IDynamicContainer[]> = this.page.pipe(
		map(getAreaContainers("banner")),
	);

	settings: Observable<IDynamicPageSetting[]> = this.page.pipe(
		map((page) => {
			if (page) {
				const settingsOrdered = [];
				for (const entry of page.seto) {
					const setting = page.sets.find((setting) => setting.eid === entry.id);
					if (setting) {
						settingsOrdered.push(setting);
					}
				}
				return settingsOrdered;
			}
		}),
		tap((settings) => {
			if (settings) {
				this.defaultSetting = settings[settings.length - 1];
				this.defaultColor = UIUtil.numberToHexCode(this.defaultSetting.cl);
			}
		}),
	);

	accessErrorMap: Observable<IAccessErrorMap> =
		this.pageService.evaluateAccess.pipe(
			withLatestFrom(this.bannerContainers, this.mainContainers, this.settings),
			map((collection) => {
				const accessErrors: IAccessErrorMap = { parents: {}, errors: {} };
				const accessList = collection[0];
				const bannerCts = collection[1];
				const mainCts = collection[2];
				const settings = collection[3];

				const validateAccess = (
					entities: IDynamicContainer[],
					area: string,
					parentId?: string,
				) => {
					for (const entity of entities) {
						const ais = entity.ais;
						if (ais) {
							for (const id of ais) {
								const access = ArrayUtil.itemByProperty(accessList, "exid", id);
								if (!access || access.ec) {
									addAccessError(accessErrors.parents, area, {
										type: AccessErrorType.Parent,
										aid: id,
									});
									if (parentId) {
										addAccessError(accessErrors.parents, parentId, {
											type: AccessErrorType.Parent,
											aid: id,
										});
									}
									const keyId = parentId ? parentId + entity.eid : entity.eid;
									addAccessError(
										accessErrors.errors,
										keyId,
										access
											? { type: AccessErrorType.Invalid, aid: id }
											: { type: AccessErrorType.Missing, aid: id },
									);
								}
							}
						}
						if (entity.hds) {
							validateAccess(entity.hds, area, entity.eid);
						}
						if (entity.ims) {
							validateAccess(entity.ims, area, entity.eid);
						}
						if (entity.its) {
							validateAccess(entity.its, area, entity.eid);
						}
						if (entity.ws) {
							validateAccess(entity.ws, area, entity.eid);
						}
						if (entity.wbs) {
							validateAccess(entity.wbs, area, entity.eid);
						}
						if (entity.txts) {
							validateAccess(entity.txts, area, entity.eid);
						}
					}
				};

				const addAccessError = (
					collection: IStringToAccessError,
					key: string,
					error: IAccessError,
				) => {
					if (!collection[key]) {
						collection[key] = [];
					}
					collection[key].push(error);
				};

				validateAccess(bannerCts, "banner");
				validateAccess(mainCts, "main");
				validateAccess(settings, "settings");
				return accessErrors;
			}),
			shareReplay(1),
		);

	missingAccesses: Observable<string[]> = this.accessErrorMap.pipe(
		map((collection) => {
			const missingAis = [];
			if (collection) {
				const accessErrors = collection.errors;
				for (const key in accessErrors) {
					const entries = accessErrors[key];
					entries.forEach((entry) => {
						if (
							entry.type === AccessErrorType.Missing &&
							!ArrayUtil.contains(missingAis, entry.aid)
						) {
							missingAis.push(entry.aid);
						}
					});
				}
			}
			return missingAis;
		}),
	);

	headerWidth = "100%";
	defaultColor: string;
	saveText: string;
	policyInvalidText = AdminConstants.policyInvalidText;
	sortOptions: ISortOptions = {
		localeOptions: {},
	};
	experimentalTooltip = Constants.dynPageExperimentalFeatureMsg;

	private handlingResize: boolean;
	private sortStartInfo: ISortInfo;
	private unsubscribers = [];
	private isSettingDialogOpen: boolean;
	private subscriptions = new Subscription();
	private ViewOnlyModeHeader = "View only mode";
	private ViewOnlyModeSuffix = " in view only mode.";

	constructor(
		private readonly pageService: DynamicPageAdminService,
		private readonly dialogService: SohoModalDialogService,
		private readonly viewContainerRef: ViewContainerRef,
		private readonly adminService: AdminService,
		private readonly filterService: DynamicFilterService,
		protected adminContext: AdminContext,
		messageService: SohoMessageService,
		private settingsService: AdminSettingsService,
	) {
		super("DynamicPageEditor", messageService);
		this.accessTitles = pageService.getAccessTitles();
		this.initDefaults(adminContext);
		this.subscriptions.add(
			this.settingsService.features$.subscribe((features) => {
				this.updateSettingControlledValues(features);
			}),
		);
	}

	ngOnInit() {
		window.addEventListener("resize", this);
		this.unsubscribers.push(
			this.adminService.onAppMenuCollapsed().on(() => {
				this.headerWidth = "100%";
			}),
		);

		this.unsubscribers.push(
			this.adminService.onAppMenuExpanded().on((timeout) => {
				setTimeout(() => {
					this.handleResize();
				}, timeout);
			}),
		);

		this.handleResize();
		this.pageService.nextEditorToggled(true);
		this.pageService.saveStateChanged.subscribe((stateText) => {
			this.saveText = stateText;
		});

		this.pageService.filterEntityDeleted.subscribe((filterEntitiesDeleted) => {
			for (const filter of filterEntitiesDeleted) {
				delete this.filter[filter.filterScope][filter.filterEntity];
			}
		});
	}

	ngAfterViewInit(): void {
		combineLatest(this.mainContainers, this.bannerContainers, this.settings)
			.pipe(
				take(1),
				tap((collection) => {
					this.expandInitial(collection);
				}),
			)
			.subscribe();
	}

	ngOnDestroy() {
		this.logDebug("ngOnDestroy");
		window.removeEventListener("resize", this);
		this.unsubscribers.forEach((unsubscribe) => {
			unsubscribe();
		});
		this.pageService.nextEditorToggled(false);
		this.subscriptions.unsubscribe();
	}

	handleEvent(event: Event) {
		if (event.type === "resize") {
			this.handleResize();
		}
	}

	handleResize() {
		if (!this.handlingResize) {
			this.handlingResize = true;
			const self = this;
			setTimeout(() => {
				const currentWidth = $("#lmAdmCnt").outerWidth();
				if (currentWidth > 0) {
					self.headerWidth = currentWidth + "px";
				} else {
					// Case for when being in preview, admin-container is then hidden (0 width)
					const appMenu = $("#application-menu");
					const appMenuWidth =
						appMenu.css("display") === "none" ? 0 : appMenu.outerWidth();
					self.headerWidth = $(window).width() - appMenuWidth + "px";
				}
				self.handlingResize = false;
			}, 100);
		}
	}

	addSetting(): void {
		this.openAddEditSetting();
	}

	editSetting(setting: IDynamicPageSetting, openPermissions?: boolean): void {
		if (openPermissions && !DynamicUtil.hasAccess(setting)) {
			return;
		}
		this.openAddEditSetting({
			setting,
			openPermissions,
		});
	}

	openAddEditSetting(editInfo?: {
		setting: IDynamicPageSetting;
		openPermissions: boolean;
	}): void {
		if (this.isSettingDialogOpen) {
			return;
		}
		this.isSettingDialogOpen = true;
		const title = editInfo ? (this.isEditable ? "Edit" : "View") : "Add";

		const dialogRef = this.dialogService
			.modal(DynamicPageSettingsDialog, this.viewContainerRef)
			.id("dyn-p-settings-mdl")
			.title(title + " Configuration");

		dialogRef
			.apply((comp: DynamicPageSettingsDialog) => {
				comp.modalDialog = dialogRef;
				comp.isEdit = editInfo ? true : false;
				comp.settings = editInfo ? editInfo.setting : undefined;
				comp.expressions = editInfo
					? DynamicUtil.toExpressions(editInfo.setting, this.accessTitles)
					: undefined;
				comp.editInfo = editInfo;
				comp.isEnabled = this.isEditable;
			})
			.afterClose(() => {
				this.isSettingDialogOpen = false;
			})
			.open();
	}

	add(area: DynamicPageAreaKey) {
		const dialogRef = this.dialogService
			.modal(AddDynamicComponentDialog, this.viewContainerRef)
			.title("Add Component")
			.id("lm-dp-addcomp-dialog")
			.buttons([
				{
					text: "Close",
					click: () => dialogRef.close(),
					id: "lm-a-dp-ac-close-btn",
				},
			])
			.apply((component) => (component.area = area))
			.open();
	}

	close() {
		this.pageService.closeEditor();
	}

	deleteSetting(setting: IDynamicPageSetting) {
		this.showConfirm(
			"Confirm Delete",
			"Are you sure that you want to delete the configuration?",
		).subscribe(() => {
			this.pageService
				.deleteSetting(setting)
				.pipe(
					// Ignore error since it's handled in service
					catchError(() => of()),
				)
				.subscribe();
		});
	}

	openContainerSettings(
		container: IDynamicContainer,
		area: DynamicPageAreaKey,
	) {
		const dialogRef = this.dialogService
			.modal(DynamicContainerSettingsDialog, this.viewContainerRef)
			.title(`${this.isEditable ? "Edit" : "View"} Settings`)
			.id("dyn-p-cont-settings-mdl");
		dialogRef
			.apply((component) => {
				component.modalDialog = dialogRef;
				component.container = { ...container };
				component.isMainAreaContainer = area === "main";
				component.isEditable = this.isEditable;
			})
			.open();
	}

	deleteContainer(container: IDynamicContainer, area: DynamicPageAreaKey) {
		const title = container.t || this.defaultTitle;
		this.showConfirm(
			"Confirm Delete",
			"Are you sure that you want to delete '" + title + "'?",
		).subscribe(() => {
			this.pageService
				.deleteContainer(container, area)
				.pipe(
					// Ignore error since it's handled in service
					catchError(() => of()),
				)
				.subscribe();
		});
	}

	editContainerAccess(container: IDynamicContainer) {
		const expressions = DynamicUtil.toExpressions(container, this.accessTitles);

		const dialogRef = this.dialogService
			.modal(DynamicPermissionsDialogComponent, this.viewContainerRef)
			.title(`${this.isEditable ? "Select" : "View"} Security Policy`)
			.id("lm-dp-cont-access-dialog")
			.afterClose((result) => {
				if (result) {
					const newExpressions = result.value;
					const operator = result.operator;
					if (newExpressions) {
						const updatedContainer = {
							...container,
							...{
								as: 1,
								ais: DynamicUtil.toIds(newExpressions),
								op: operator,
							},
						};
						this.pageService
							.updateContainer(updatedContainer, container)
							.pipe(
								// Ignore error since it's handled in service
								catchError(() => of()),
							)
							.subscribe();
					} else if (expressions) {
						this.pageService
							.updateContainer(
								{ ...container, ...{ as: null, ais: null } },
								container,
							)
							.pipe(
								// Ignore error since it's handled in service
								catchError(() => of()),
							)
							.subscribe();
					}
				}
			});

		dialogRef
			.apply((component) => {
				component.modalDialog = dialogRef;
				component.listLabel =
					"Choose which set of users this component should be visible for.";
				component.selectedExpressions = expressions;
				component.operator = container.op;
				component.showOperator = true;
				component.isEditable = this.isEditable;
			})
			.open();
	}

	repairPageAccess() {
		if (!this.isEditable) {
			this.showMessage(
				this.ViewOnlyModeHeader,
				"Repair of policies is not allowed" + this.ViewOnlyModeSuffix,
			);
			return;
		}
		const page = this.pageService.getPage();
		const pageId = page.pid;
		this.missingAccesses.pipe(take(1)).subscribe((ids: string[]) => {
			if (ids && ids.length) {
				const dialog = this.dialogService
					.modal(AdminOperationMessageDialog, this.viewContainerRef)
					.title("Repair Page")
					.id("lm-dp-repair-dialog")
					.afterClose((result: IDialogResult) => {
						if (
							result &&
							result.value &&
							result.value === DialogResponseCode.Success
						) {
							this.pageService
								.editPage(pageId)
								.subscribe(
									() =>
										(this.accessTitles = this.pageService.getAccessTitles()),
								);
						}
					});
				dialog
					.apply((component) => {
						component.modalDialog = dialog;
						component.operation = this.pageService.repairPage(pageId, ids);
						component.initialMessage = "Starting repair operation...";
					})
					.open();
			} else {
				this.showError(
					"Unable to repair",
					"There are no missing security policies.",
				);
			}
		});
	}

	openImportPolicies() {
		if (!this.isEditable) {
			this.showMessage(
				this.ViewOnlyModeHeader,
				"Import of policies is not allowed" + this.ViewOnlyModeSuffix,
			);
		} else {
			this.adminService
				.openPolicyImportDialog(this.viewContainerRef)
				.subscribe();
		}
	}

	preview() {
		this.pageService.preview();
	}

	previewAsUser() {
		this.getPreviewer().previewAsUser();
	}

	previewAsPolicy() {
		this.getPreviewer().previewAsPolicy();
	}

	onComponentDropped(info: {
		subType: number;
		type: DynamicContainerType;
		area: DynamicPageAreaKey;
		index: number;
	}) {
		let addContainer$: Observable<string>;
		switch (info.type) {
			case DynamicContainerType.Links:
				addContainer$ = this.pageService.addLinkList(
					info.area,
					info.subType,
					info.index,
				);
				break;
			case DynamicContainerType.Image:
				addContainer$ = this.pageService.addImage(info.area, info.index);
				break;
			case DynamicContainerType.Items:
				addContainer$ = this.pageService.addItems(info.area, info.index);
				break;
			case DynamicContainerType.Widget:
				addContainer$ = this.pageService.addWidget(info.area, info.index);
				break;
			case DynamicContainerType.Web:
				addContainer$ = this.pageService.addWeb(info.area, info.index);
				break;
			case DynamicContainerType.Text:
				addContainer$ = this.pageService.addText(info.area, info.index);
				break;
			default:
				this.logError(`Invalid container type: ${info.type}`);
				return;
		}
		addContainer$
			.pipe(
				// Ignore error since it's handled in service
				catchError(() => of()),
			)
			.subscribe();
	}

	collapseAll(): void {
		const accordions = this.accordions.toArray();
		const collapseAccordion = (entity: string) => {
			const accordionForEntity = accordions.find(
				(accordion) => accordion.entity === entity,
			);
			if (accordionForEntity) {
				accordionForEntity.collapse();
			}
		};

		collapseAccordion("main");
		if (this.showBannerArea) {
			collapseAccordion("banner");
		}
	}

	expandInitial(
		collection: (IDynamicContainer | IDynamicPageSetting)[][],
	): void {
		const bannerAreaEmpty = !collection[1].length;
		const mainAreaEmpty = !collection[0].length;
		const isEmptyOrNewPage =
			bannerAreaEmpty && mainAreaEmpty && collection[2].length === 1;

		if (isEmptyOrNewPage) {
			this.expandMainArea();
		} else {
			if (!bannerAreaEmpty) {
				this.expandBannerArea();
			}
			if (!mainAreaEmpty) {
				this.expandMainArea();
			}
		}
	}

	expandMainArea(): void {
		this.accordions.toArray()[2].expand();
	}

	expandBannerArea(): void {
		this.accordions.toArray()[1].expand();
	}

	expandSettings(): void {
		this.accordions.toArray()[0].expand();
	}

	trackContainersBy(index: number, container: IDynamicContainer): string {
		return container.eid;
	}

	onSortStart(info: ISortInfo): void {
		this.sortStartInfo = info;
	}

	updateLayout(sortStopInfo: ISortInfo): void {
		const sortStartInfo = this.sortStartInfo;

		this.page
			.pipe(
				take(1),
				map((page) => {
					const areas = page.ly.areas;
					const originArea = areas[sortStartInfo.area];
					const targetKey = sortStopInfo.area;
					if (targetKey) {
						// Changed area
						const layoutEntry = originArea[sortStartInfo.index];
						if (layoutEntry) {
							this.validateAreaTarget(page, layoutEntry, targetKey);

							if (areas[targetKey]) {
								areas[targetKey].splice(sortStopInfo.index, 0, layoutEntry);
							} else {
								areas[targetKey] = [layoutEntry];
							}
							originArea.splice(sortStartInfo.index, 1);
						} else {
							throw new Error("No entry");
						}
					} else if (originArea.length > 1) {
						// Move within same area
						ArrayUtil.move(
							originArea,
							this.sortStartInfo.index,
							sortStopInfo.index,
						);
					} else {
						// Don't sort in originArea when only one element
						throw new Error("No sort changes");
					}
					return page;
				}),
				switchMap((page) => this.pageService.updatePage(page)),
				catchError(() => {
					// Revert view changes from sortable
					cancelSort(sortStopInfo);
					return of();
				}),
			)
			.subscribe(() => {
				if (sortStopInfo.area) {
					this.pageService.nextEvaluateAccess();
				}
			});

		function cancelSort(sortStopInfo: ISortInfo) {
			if (sortStopInfo.element) {
				sortStopInfo.element.sortable("cancel");
			} else {
				this.sortStartInfo.element.sortable("cancel");
			}
		}
	}

	updateSettingsOrder(sortStopInfo: ISortInfo): void {
		const page = this.pageService.getPageClone();
		ArrayUtil.move(page.sets, this.sortStartInfo.index, sortStopInfo.index);
		this.pageService
			.updatePage(page)
			.pipe(
				catchError(() => {
					// Revert view changes from sortable
					sortStopInfo.element.sortable("cancel");
					return of();
				}),
			)
			.subscribe();
	}

	updateItemOrder(sortStopInfo: ISortInfo, container: IDynamicContainer): void {
		const containerCopy = CoreUtil.copy(container);
		const items = this.getContainerItems(containerCopy, sortStopInfo);
		ArrayUtil.move(items, this.sortStartInfo.index, sortStopInfo.index);
		this.pageService
			.updateContainer(containerCopy)
			.pipe(
				catchError(() => {
					// Revert view changes from sortable
					sortStopInfo.element.sortable("cancel");
					return of();
				}),
			)
			.subscribe();
	}

	getComponentTypeColor(type: DynamicContainerType, subType?: number): string {
		let color = "";
		switch (type) {
			case DynamicContainerType.Image:
				color = "#f6d67b";
				break;
			case DynamicContainerType.Links: {
				if (subType === 1) {
					color = "#c0ede3";
				} else {
					color = "#ede3fc";
				}
				break;
			}
			case DynamicContainerType.Text:
				color = "#f6b97b";
				break;
			case DynamicContainerType.Items:
				color = "#cbebf4";
				break;
			case DynamicContainerType.Widget:
				color = "#f4bcbc";
				break;
			case DynamicContainerType.Web:
				color = "#c0e8ac";
				break;
			default:
				this.logError(`Invalid container type ${type}`);
		}

		return color;
	}

	getComponentTypeLabel(type: DynamicContainerType, subType?: number): string {
		return DynamicUtil.getComponentTypeLabel(type, subType);
	}

	getAccessText(entity: IDynamicEntity): string {
		return DynamicUtil.entityAccessText(entity, this.accessTitles);
	}

	getAccessError(entity: IDynamicEntity): string {
		return DynamicUtil.entityErrorText(entity.ais, this.accessTitles);
	}

	changeAccessFiltersLimit(): void {
		if (this.accessFiltersLimit === this.defaultAccessFiltersLimit) {
			this.accessFiltersLimit = undefined;
		} else {
			this.accessFiltersLimit = this.defaultAccessFiltersLimit;
		}
	}

	disableAccessFilter(accessKey: string) {
		const filter = this.filter;
		filter.access[accessKey] = false;
		this.filter = { ...filter }; // Trigger change detection on filter-item input
	}

	get showAllUsersFilter(): boolean {
		const query = this.policyQuery;
		return (
			!query || this.allUsersText.toLowerCase().includes(query.toLowerCase())
		);
	}

	private getPreviewer(): DynamicPreviewer {
		return new DynamicPreviewer(
			this.viewContainerRef,
			this.dialogService,
			this.adminService,
			this.pageService,
		);
	}

	private initDefaults(adminContext: IAdminContext) {
		this.showBannerArea = true;
		const adminTool = adminContext.get();
		if (adminTool) {
			this.updateSettingControlledValues(adminTool.settings);
		}
	}

	private updateSettingControlledValues(settings: ISetting[]) {
		this.showBannerArea = true;
	}

	private validateAreaTarget(
		page: IDynamicPageAdmin,
		sourceLayout: IDynamicEntityLayout,
		targetKey: DynamicPageAreaKey,
	): void {
		if (DynamicUtil.isValidAreaTarget(page, sourceLayout, targetKey)) {
			return;
		}

		const title = "Unable to drop component";
		const message =
			"The component contains one or more widgets that are not allowed in the target area.";
		this.showError(title, message);

		throw new Error("Invalid target " + targetKey);
	}

	private getContainerItems(
		container: IDynamicContainer,
		sortStopInfo: ISortInfo,
	): IDynamicEntity[] {
		switch (container.ct) {
			case DynamicContainerType.Links:
				return container.its;
			case DynamicContainerType.Image:
				return container.ims;
			case DynamicContainerType.Widget:
				return container.ws;
			case DynamicContainerType.Web:
				return container.wbs;
			case DynamicContainerType.Text:
				return container.txts;
			case DynamicContainerType.Items:
				// Temp solution to check whether the container has hds and/or its
				if (container.hds.length > 0) {
					// if has its
					if (this.sortStartInfo.index > container.hds.length - 1) {
						this.sortStartInfo.index -= container.hds.length;
						// Prevents from moving item to headers
						const stopIndex = sortStopInfo.index - container.hds.length;
						sortStopInfo.index =
							stopIndex < 0 ? this.sortStartInfo.index : stopIndex;

						return container.its;
					} else {
						// Prevents from moving header to items
						if (sortStopInfo.index > container.hds.length - 1) {
							sortStopInfo.index = this.sortStartInfo.index;
						}
						return container.hds;
					}
				} else {
					return container.its;
				}
		}
	}
}

