@Directive({
	selector: "[draggable-component]",
})
export class DraggableComponent implements OnInit {
	private readonly element: JQuery;

	constructor(elementRef: ElementRef) {
		this.element = $(elementRef.nativeElement);
	}

	ngOnInit() {
		(this.element as any).draggable({
			revert: "true",
			helper: "clone",
			containment: "#lmAdmCnt",
		});
	}
}

@Directive({
	selector: "[droppable-component]",
})
export class DroppableComponent implements OnInit {
	@Input() area: DynamicPageAreaKey;
	@Input() dropIndex: number;
	@Output() onDropped = new EventEmitter<any>();

	private readonly element: JQuery;

	constructor(
		elementRef: ElementRef,
		private zone: NgZone,
	) {
		this.element = $(elementRef.nativeElement);
	}

	ngOnInit() {
		(this.element as any).droppable({
			drop: (event, ui) => {
				let type;
				let subType = 0;
				const id = ui.draggable.attr("id");
				if (id === DynContainerIdentifiers.LINK_LIST) {
					type = DynamicContainerType.Links;
				} else if (id === DynContainerIdentifiers.SHORTCUT) {
					type = DynamicContainerType.Links;
					subType = 1;
				} else if (id === DynContainerIdentifiers.IMAGE) {
					type = DynamicContainerType.Image;
				} else if (id === DynContainerIdentifiers.ITEMS) {
					type = DynamicContainerType.Items;
				} else if (id === DynContainerIdentifiers.WIDGET) {
					type = DynamicContainerType.Widget;
				} else if (id === DynContainerIdentifiers.WEB) {
					type = DynamicContainerType.Web;
				} else if (id === DynContainerIdentifiers.TEXT) {
					type = DynamicContainerType.Text;
				}

				this.zone.run(() => {
					this.onDropped.emit({
						type: type,
						subType: subType,
						area: this.area,
						index: this.dropIndex,
					});
				});
			},
			accept: ".draggable-component",
			tolerance: "intersect",
			greedy: true,
		});
	}
}

@Directive({
	selector: "[sortable-component]",
})
export class SortableComponent implements OnInit {
	@Input() isContainer = false;
	@Input() area: DynamicPageAreaKey;
	@Output() onSortStart = new EventEmitter<ISortInfo>();
	@Output() onComponentSorted = new EventEmitter<ISortInfo>();

	private readonly element: JQuery;

	constructor(
		elementRef: ElementRef,
		private zone: NgZone,
	) {
		this.element = $(elementRef.nativeElement);
	}

	ngOnInit() {
		const element = this.element;
		const isContainer = this.isContainer;
		const items = isContainer
			? ".container-wrapper"
			: ".list-item:not(.default-config)";

		const options: any = {
			axis: "y",
			items: isContainer ? `> ${items}` : items,
			cursor: "move",
			handle: isContainer
				? "lm-dynamic-accordion-header > svg[icon='drag']"
				: "svg[icon='drag']",
			start: (event, ui) => {
				const startIndex = element.find(items).index(ui.item);
				this.zone.run(() =>
					this.onSortStart.emit({
						element: element,
						index: startIndex,
						area: this.area,
					}),
				);
			},
			update: (event, ui) => {
				const dropIndex = element.find(items).index(ui.item);

				if (dropIndex >= 0 && !ui.sender) {
					this.zone.run(() =>
						this.onComponentSorted.emit({ element: element, index: dropIndex }),
					);
				}
			},
		};

		if (isContainer) {
			options.receive = (event, ui) => {
				const dropIndex = element.find(items).index(ui.item);
				this.zone.run(() =>
					this.onComponentSorted.emit({ index: dropIndex, area: this.area }),
				);
			};
			options.connectWith =
				"lm-dynamic-accordion-pane[sortable-component][droppable-component]";
		}

		(element as any).sortable(options);
	}
}

@Pipe({ name: "refineBy" })
export class EntityRefineByPipe implements PipeTransform {
	transform(
		entities: IDynamicEntity[],
		filter: IContainerFilter,
		parentContainer?: IDynamicContainer,
	): IDynamicContainer[] {
		let typeActive, accessActive;
		for (const entry in filter.type) {
			if (filter.type[entry]) {
				typeActive = true;
				break;
			}
		}

		for (const entry in filter.access) {
			if (filter.access[entry]) {
				accessActive = true;
				break;
			}
		}

		if (!typeActive && !accessActive) {
			return entities;
		}

		const types = filter.type;
		return entities.filter((entity) => {
			if (this.isEntityAccess(entity, filter.access)) {
				return true;
			}

			const container = parentContainer || (entity as IDynamicContainer);
			const type = container.ct;
			const typeMatch =
				(type === DynamicContainerType.Links &&
					container.st === DynamicContainerSubType.Shortcuts &&
					types.shortcuts) ||
				(type === DynamicContainerType.Links && types.links && !container.st) ||
				(type === DynamicContainerType.Image && types.images) ||
				(type === DynamicContainerType.Items && types.items) ||
				(type === DynamicContainerType.Widget && types.widgets) ||
				(type === DynamicContainerType.Text && types.texts) ||
				(type === DynamicContainerType.Web && types.webs);

			if (typeMatch) {
				return true;
			}

			if (accessActive && !parentContainer) {
				if (this.isEntitiesAccess(container.ims, filter.access)) {
					return true;
				}
				if (this.isEntitiesAccess(container.its, filter.access)) {
					return true;
				}
				if (this.isEntitiesAccess(container.hds, filter.access)) {
					return true;
				}
				if (this.isEntitiesAccess(container.ws, filter.access)) {
					return true;
				}
				if (this.isEntitiesAccess(container.wbs, filter.access)) {
					return true;
				}
				if (this.isEntitiesAccess(container.txts, filter.access)) {
					return true;
				}
			}
		});
	}

	private isEntitiesAccess(
		entities: IDynamicEntity[],
		access: IStringMap,
	): boolean {
		if (entities) {
			for (const entity of entities) {
				if (this.isEntityAccess(entity, access)) {
					return true;
				}
			}
		}
		return false;
	}

	private isEntityAccess(entity: IDynamicEntity, access: IStringMap): boolean {
		const ids = entity.ais;
		if (ids) {
			for (const id of ids) {
				if (access[id]) {
					return true;
				}
			}
		} else {
			return !!access[DynamicUtil.noPolicyKey];
		}
		return false;
	}
}

@Pipe({ name: "searchFilter" })
export class EntitySearchPipe implements PipeTransform {
	transform(
		entities: IDynamicEntity[],
		query: string,
		accessTitles: string[],
	): IDynamicContainer[] {
		if (!query.length) {
			return entities;
		}

		const isMatch = (text: string): boolean => {
			return text && text.toLowerCase().indexOf(query.toLowerCase()) >= 0;
		};

		const isAccessMatch = (entity: IDynamicEntity) => {
			const ais = entity.ais;
			if (ais) {
				for (const id of ais) {
					if (isMatch(accessTitles[id])) {
						return true;
					}
				}
			}
			return false;
		};

		const isSearchHit = (entity: IDynamicEntity) => {
			const titleMatch = isMatch(entity.t);
			const accessMatch = isAccessMatch(entity);
			const urlMatch = isMatch((entity as IDynamicItem).u);

			return titleMatch || accessMatch || urlMatch;
		};

		return entities.filter((entity) => {
			if (isSearchHit(entity)) {
				return true;
			}

			const isContainer = (entity as IDynamicContainer).ct ? true : false;
			if (isContainer) {
				const container = entity as IDynamicContainer;
				const links = container.its || [];
				for (const link of links) {
					if (isSearchHit(link)) {
						return true;
					}
				}

				const images = container.ims || [];
				for (const image of images) {
					if (isSearchHit(image)) {
						return true;
					}
				}
			}
		});
	}
}

@Pipe({ name: "searchPolicyFilter" })
export class PolicySearchPipe implements PipeTransform {
	transform(accesses: IDynamicAccess[], query: string): IDynamicAccess[] {
		if (!query.length) {
			return accesses;
		}
		return accesses.filter((access) => {
			return (
				access.t && access.t.toLowerCase().indexOf(query.toLowerCase()) >= 0
			);
		});
	}
}

export class DynContainerIdentifiers {
	static IMAGE = "lm-a-dp-di";
	static SHORTCUT = "lm-a-dp-sc";
	static LINK_LIST = "lm-a-dp-dl";
	static ITEMS = "lm-a-dp-du";
	static WIDGET = "lm-a-dp-dw";
	static WEB = "lm-a-dp-wb";
	static TEXT = "lm-a-dp-tx";
}
