import { Component, OnInit } from "@angular/core";
import { SohoMessageService } from "ids-enterprise-ng";
import { ArrayUtil } from "lime";
import {
	Constants,
	CoreUtil,
	DynamicItemSettingsDialog,
	IDynamicContainer,
	IDynamicEntityLocalization,
	IDynamicText,
} from "lime/core";
import { Observable, of } from "rxjs";
import { catchError } from "rxjs/operators";
import { IExpInfo } from "scripts/lime/admin/service";
import { DynamicPageAdminService } from "../../service";
import { DynamicUtil } from "../../util";
import { DynamicContainerListBase } from "./dynamic-container/dynamic-container-list";

@Component({
	selector: "lm-dynamic-text-list",
	templateUrl: "./dynamic-container/dynamic-container-list.html",
	styleUrls: ["./dynamic-container/dynamic-container-list.scss"],
})
export class DynamicTextListComponent
	extends DynamicContainerListBase
	implements OnInit
{
	ngOnInit() {
		const buttonText = "Add Text";
		const buttonInfoText =
			"This component is empty. Start adding content by clicking " +
			buttonText +
			".";
		this.initItems(buttonText, buttonInfoText, "Text", "");
		this.infoHeader = {
			text: "Only one text will be displayed.",
			title: "Texts",
		};
		this.isExperimental = true;
		this.update();
	}

	addItem() {
		if (!this.canAdd() || this.isDialogOpen) {
			return;
		}
		this.isDialogOpen = true;

		const dialog = this.dialogService
			.modal(DynamicTextDialog, this.viewContainerRef)
			.title("Add Text")
			.id("lm-a-dp-text-add-dialog")
			.afterClose((addedText) => {
				this.isDialogOpen = false;
				if (addedText) {
					this.update();
				}
			});

		dialog
			.apply((component: DynamicTextDialog) => {
				component.modalDialog = dialog;
				component.container = this.container;
				component.containerLznEdited = component.container.lzn;
				component.isEdit = false;
			})
			.open();
	}

	editItem(isPermissionTab: boolean, text: IDynamicText): void {
		if (this.isDialogOpen) {
			return;
		}
		this.isDialogOpen = true;

		const dialog = this.dialogService
			.modal(DynamicTextDialog, this.viewContainerRef)
			.title(`${this.isEditable ? "Edit" : "View"} Text`)
			.id("lm-a-dp-text-edit-dialog")
			.afterClose((editedText) => {
				this.isDialogOpen = false;
				if (editedText) {
					this.update();
				}
			});

		dialog
			.apply((component: DynamicTextDialog) => {
				component.modalDialog = dialog;
				component.container = this.container;
				component.oldText = text;
				component.text = text;
				component.selectedExpressions = DynamicUtil.toExpressions(
					text,
					this.accessTitles,
				);
				component.containerLznEdited = component.container.lzn;
				component.isEdit = true;
				component.isPermissionTabOnInit = isPermissionTab;
				component.isEditable = this.isEditable;
			})
			.open();
	}

	deleteItems(
		texts: IDynamicText[],
		parentContainer?: IDynamicContainer,
	): void {
		const containerCopy = CoreUtil.copy(parentContainer || this.container);

		for (const text of texts) {
			const removeIndex = ArrayUtil.indexByProperty(
				containerCopy.txts,
				"eid",
				text.eid,
			);
			if (removeIndex > -1) {
				containerCopy.txts.splice(removeIndex, 1);
			}
		}
		this.pageService
			.updateContainer(containerCopy, null, texts)
			.pipe(
				// Ignore error since it's handled in service
				catchError(() => of()),
			)
			.subscribe(() => this.update());
	}

	getEntityCount(): number {
		return this.container.txts && this.container.txts.length;
	}

	onCopy() {
		this.copySelected(this.container.txts);
	}

	onCut() {
		this.cutSelected(this.container.txts);
	}

	onDeleteSelected() {
		this.deleteSelectedItems(this.container.txts);
	}

	private update() {
		const containers = this.pageService.getPage().cts;
		const container = ArrayUtil.itemByProperty<IDynamicContainer>(
			containers,
			"eid",
			this.container.eid,
		);
		this.isEmpty = !(container.txts && container.txts.length > 0);
		this.clearSelectionCount();
	}
}

@Component({
	templateUrl: "./add-text.html",
})
export class DynamicTextDialog
	extends DynamicItemSettingsDialog
	implements OnInit
{
	text: IDynamicText;
	oldText: IDynamicText;
	isEdit: boolean;
	container: IDynamicContainer;
	textMaxLength = Constants.dynTextMaxLength;
	selectedExpressions: IExpInfo[];
	expressions: IExpInfo[];
	listLabel = "Choose which set of users this text should be visible for.";

	constructor(
		public dynamicPageService: DynamicPageAdminService,
		sohoMessageService: SohoMessageService,
	) {
		super("DynamicTextDialog", sohoMessageService);
	}

	ngOnInit(): void {
		this.text = { ...this.text };
		this.item = this.text;
		this.initLocalizations();

		this.optionsItems = [
			{
				name: "tx",
				label: "Text",
				labelId: "lm-a-dp-aetx-at-tx-lbl",
				valueId: "lm-a-dp-aetx-at-tx-inp",
				maxLength: this.textMaxLength,
				isMarkdown: true,
				defaultValue: this.text.tx,
			},
		];

		this.initModalDialog();
	}

	hasInvalidTranslation(lang: IDynamicEntityLocalization): boolean {
		// Has no optional translations
		return false;
	}

	getEmptyTranslateablePropertyNames(): string[] {
		// Has no optional translations
		return [];
	}

	save() {
		if (!this.isEditable) {
			return;
		}
		const text = this.toText();
		const container = this.toContainer(text);
		const observable = this.toObservable(container, text);
		this.submitSafe(observable, false, true).subscribe(() =>
			this.modalDialog.close(text),
		);
	}

	canSave(): boolean {
		return !this.isBusy && this.hasText();
	}

	private hasText(): boolean {
		const text = this.text.tx;
		return !!(text && text.trim());
	}

	private toText(): IDynamicText {
		const text = CoreUtil.copy(this.text);
		if (!text.eid) {
			text.eid = DynamicUtil.getNewEntityId(this.container);
		}

		if (this.expressions) {
			text.as = 1;
			text.ais = DynamicUtil.toIds(this.expressions);
			text.op = DynamicUtil.getOperator(this.expressions);
		} else if (this.selectedExpressions) {
			text.as = null;
			text.ais = null;
		}

		return text;
	}

	private toContainer(text: IDynamicText): IDynamicContainer {
		const container = CoreUtil.copy(this.container);
		container.lzn = null;
		if (this.itemLznEdited) {
			container.lzn = this.getContainerLocalizations(
				this.itemLznEdited,
				text.eid,
			);
		}
		return container;
	}

	private toObservable(
		container: IDynamicContainer,
		text: IDynamicText,
	): Observable<string> {
		if (this.isEdit) {
			return this.dynamicPageService.editContainerEntityWithLocalization(
				container,
				text,
				this.oldText,
				this.container,
			);
		}
		return this.dynamicPageService.addContainerEntity(container, text);
	}
}
