import { Component, Input, OnInit } from "@angular/core";
import { ArrayUtil } from "lime";
import { CoreBase } from "lime/core";
import { MemoIteration, MemoWeekDay } from "./core";

@Component({
	selector: "lm-admin-memo-date-weekly",
	templateUrl: "./date-weekly.html",
})
export class MemoDateWeeklyComponent extends CoreBase implements OnInit {
	@Input() iteration: MemoIteration;

	dayCheckboxes: IWeekDayCheckbox[];

	constructor() {
		super("MemoDateWeeklyComponent");
	}

	ngOnInit(): void {
		this.setupCheckboxes();
	}

	onFocus($event: any): void {
		$event.target.select();
	}

	checkboxChanged(checkbox: IWeekDayCheckbox) {
		this.iteration.weekDays[checkbox.dayIndex] = checkbox.checked ? 1 : 0;
	}

	firstDayChanged() {
		this.setupCheckboxes();
	}

	get recurEvery(): number {
		return this.iteration.every;
	}

	set recurEvery(value: number) {
		this.iteration.every = value;
	}

	private setupCheckboxes() {
		const checkboxes = [
			{
				checked: Boolean(this.iteration.weekDays[0]),
				day: MemoWeekDay.Monday,
				dayIndex: 0,
				id: "lm-a-mm-dr-rec-weekly-Monday",
				label: "Monday",
			},
			{
				checked: Boolean(this.iteration.weekDays[1]),
				day: MemoWeekDay.Tuesday,
				dayIndex: 1,
				id: "lm-a-mm-dr-rec-weekly-Tuesday",
				label: "Tuesday",
			},
			{
				checked: Boolean(this.iteration.weekDays[2]),
				day: MemoWeekDay.Wednesday,
				dayIndex: 2,
				id: "lm-a-mm-dr-rec-weekly-Wednesday",
				label: "Wednesday",
			},
			{
				checked: Boolean(this.iteration.weekDays[3]),
				day: MemoWeekDay.Thursday,
				dayIndex: 3,
				id: "lm-a-mm-dr-rec-weekly-Thursday",
				label: "Thursday",
			},
			{
				checked: Boolean(this.iteration.weekDays[4]),
				day: MemoWeekDay.Friday,
				dayIndex: 4,
				id: "lm-a-mm-dr-rec-weekly-Friday",
				label: "Friday",
			},
			{
				checked: Boolean(this.iteration.weekDays[5]),
				day: MemoWeekDay.Saturday,
				dayIndex: 5,
				id: "lm-a-mm-dr-rec-weekly-Saturday",
				label: "Saturday",
			},
			{
				checked: Boolean(this.iteration.weekDays[6]),
				day: MemoWeekDay.Sunday,
				dayIndex: 6,
				id: "lm-a-mm-dr-rec-weekly-Sunday",
				label: "Sunday",
			},
		];
		this.dayCheckboxes = sortCheckboxes(
			checkboxes,
			this.iteration.firstDayOfWeek,
		);
	}
}

function sortCheckboxes(
	checkboxes: IWeekDayCheckbox[],
	firstDayOfWeek: MemoWeekDay,
): IWeekDayCheckbox[] {
	const shifts = checkboxes.findIndex((box) => box.day === firstDayOfWeek);
	return ArrayUtil.rotateLeft(checkboxes, shifts);
}

interface IWeekDayCheckbox {
	label: string;
	id: string;
	checked?: boolean;
	dayIndex: number;
	day: MemoWeekDay;
}
