import {
	AfterViewInit,
	Component,
	Input,
	Pipe,
	PipeTransform,
	ViewChild,
	ViewContainerRef,
} from "@angular/core";
import {
	SohoDropDownComponent,
	SohoMessageService,
	SohoModalDialogRef,
	SohoModalDialogService,
} from "ids-enterprise-ng";
import {
	ArrayUtil,
	CommonUtil,
	DialogButtonType,
	IAutocompleteEntity,
} from "lime";
import {
	AutoCompleter,
	IAttributeInfo,
	IAttributeListResponse,
	ModalDialogBase,
} from "lime/core";
import {
	AttributeCategory,
	IOperationResponse,
	PrincipalType,
	Templates,
} from "../../core/base/core";
import { CommonDataService } from "../../core/service";
import {
	AdminContext,
	AdminService,
	AdminUtil,
	IExpInfo,
	IExpNode,
} from "../service";
import { IPolicyTestOptions, PolicyTestComponent } from "./policy-test";

export enum Matches {
	Any = "||",
	All = "&&",
}

export enum Entities {
	Attribute = 0,
	Role = 1,
	Group = 2,
}

export interface IOperator {
	value: string;
	label: string;
	types: string;
}

export interface IValueEntry {
	entity?: Entities;
	attr?: IAttributeInfoEx;
	operator?: string;
	value?: string | boolean;
	match?: Matches;
	children?: IValueEntry[];
	invalidAttribute?: boolean;
	invalidAttributeValue?: boolean;
	id: string;
}

export interface IPolicy {
	id: string;
	name: string;
	match: Matches;
	value: IValueEntry[];
}

export interface IAttributeInfoEx extends IAttributeInfo {
	hasValues?: boolean;
}

@Pipe({ name: "operatorPipe" })
export class OperatorPipe implements PipeTransform {
	transform(
		operators: IOperator[],
		entity: Entities,
		attrType: string,
		hasValues: boolean,
		isMulti: boolean,
	): any[] {
		let ops = [];
		if (entity !== Entities.Attribute) {
			const groupOrRoleType = "{g}{r}";
			ops = operators.filter((operator) =>
				operator.types.includes(groupOrRoleType),
			);
		} else {
			if (hasValues) {
				attrType += isMulti ? "mv" : "v";
			}
			const filter = "{" + attrType + "}";
			ops = operators.filter((operator) => operator.types.includes(filter));
		}
		return ops;
	}
}

export class PolicyUtil {
	static operators: IOperator[] = [
		{ value: "==", label: "Equals", types: "{n}{s}{bv}{sv}" },
		{ value: "!=", label: "Not equals", types: "{n}{s}{bv}{sv}" },
		{ value: "==", label: "On", types: "{d}" },
		{ value: "!=", label: "Not on", types: "{d}" },
		{ value: "m", label: "Member of", types: "{g}{r}" },
		{ value: "!m", label: "Not member of", types: "{g}{r}" },
		{ value: "sc", label: "Contains", types: "{s}" },
		{ value: "ss", label: "Starts with", types: "{s}{g}{r}" },
		{ value: "se", label: "Ends with", types: "{s}" },
		{ value: ">", label: "Greater than", types: "{n}" },
		{ value: ">=", label: "Greater than or equal", types: "{n}" },
		{ value: "<", label: "Less than", types: "{n}" },
		{ value: "<=", label: "Less than or equal", types: "{n}" },
		{ value: ">", label: "After", types: "{d}" },
		{ value: ">=", label: "On or after", types: "{d}" },
		{ value: "<", label: "Before", types: "{d}" },
		{ value: "<=", label: "On or before", types: "{d}" },
		{ value: "mc", label: "Contains", types: "{smv}" },
		{ value: "!mc", label: "Does not contain", types: "{smv}" },
	];

	// Converts a schema to a format that client can handle/render/edit
	static getClientSchema(
		serverSchema: IExpInfo,
		attributes: IAttributeInfo[],
	): IPolicy {
		const entityMap = {
			r: Entities.Role,
			g: Entities.Group,
			a: Entities.Attribute,
		};

		const first = (value: string) => {
			return value && value.length > 0 ? value.charAt(0) : null;
		};

		const isRoleOrGroup = (fnc: string) => {
			const firstChar = first(fnc);
			return firstChar === "r" || firstChar == "g";
		};

		const fncToEntity = (fnc: string) => {
			return entityMap[first(fnc)] || "";
		};

		const clientEntries: IValueEntry[] = [];
		let entity: Entities;
		let operator: string;
		let attrName: string;
		let attrType: string;
		let value: any;

		const recursive = (schema: IExpNode, entries) => {
			const serverExpressions = schema.c;
			for (const exp of serverExpressions) {
				if (exp.v === "()") {
					const entry = {
						match: exp.c[0].v,
						children: [],
						id: CommonUtil.random(5),
					};
					entries.push(entry);
					recursive(exp.c[0], entry.children);
				} else {
					let fnc = exp.c[0].v;
					if (isRoleOrGroup(fnc)) {
						attrName = null;
						entity = fncToEntity(fnc);
						operator = fnc.length == 2 ? "ss" : exp.v === "==" ? "m" : "!m";
						value = exp.c[0].c[0].v;
					} else {
						if (fnc === "sc" || fnc === "ss" || fnc === "se" || fnc === "mc") {
							value = exp.c[0].c[1].v;
							if (fnc === "mc") {
								attrName = exp.c[0].c[0].v;
								if (exp.v == "!=") {
									fnc = "!mc";
								}
								attrType = "s";
							} else {
								attrName = exp.c[0].c[0].c[0].v;
								attrType = fnc[0];
							}
							operator = fnc;
						} else {
							const val = exp.c[1].v;
							let clientVal = val;
							if (fnc === "ad") {
								clientVal = AdminUtil.getLocaleDateStringShort(val);
							}
							value = clientVal;
							attrName = exp.c[0].c[0].v;
							attrType = fnc[1];
							operator = exp.v;
						}
						entity = Entities.Attribute;
					}

					entries.push({
						entity: entity,
						operator: operator,
						value: value,
						attr: attrName
							? ArrayUtil.itemByProperty(attributes, "name", attrName) || {
									name: attrName,
									type: attrType,
							  }
							: null,
						id: CommonUtil.random(5),
					});
				}
			}
		};

		recursive(serverSchema.expression, clientEntries);
		return {
			id: serverSchema.expressionId || CommonUtil.random(),
			name: serverSchema.title,
			match: (serverSchema.expression.v || Matches.All) as Matches,
			value: clientEntries,
		};
	}

	// Convert back to server schema format
	static getServerSchema(policy: IPolicy): IExpInfo {
		const schemaEntries: IExpNode[] = [];
		const trueValue: IExpNode = { t: "n", v: "1" };
		const toString = (value: any): IExpNode => {
			return { t: "s", v: value };
		};
		const toOp = (name: string, children: any[]): IExpNode => {
			return { t: "op", v: name, c: children };
		};
		const toFunction = (name: string, children: any[]): IExpNode => {
			return { t: "fnc", v: name, c: children };
		};
		const toMemberOf = (name: string, value: any): IExpNode[] => {
			return [toFunction(name, [toString(value)]), trueValue];
		};

		const recursive = (entries: IValueEntry[], serverEntries: IExpNode[]) => {
			for (const entry of entries) {
				let v: string;
				let c: any;

				if (entry.match) {
					const subLevel: IExpNode[] = [];
					recursive(entry.children, subLevel);
					c = [toOp(entry.match, subLevel)];
					serverEntries.push(toOp("()", c));
				} else {
					let operator = entry.operator;
					if (["ss", "se", "sc", "m", "mc"].indexOf(operator) !== -1) {
						v = "==";
					} else if (operator === "!m") {
						v = "!=";
					} else if (operator === "!mc") {
						v = "!=";
						operator = "mc";
					} else {
						v = operator;
					}

					const entity = entry.entity;
					let value = entry.value;

					if (entity === Entities.Role) {
						// Role
						const rf = operator == "ss" ? "rs" : "r";
						c = toMemberOf(rf, value);
					} else if (entity === Entities.Group) {
						// Group
						const gf = operator == "ss" ? "gs" : "g";
						c = toMemberOf(gf, value);
					} else {
						// Attribute
						const attr = entry.attr;
						const attrName = attr.name;
						const attrType = attr.type;

						if (operator == "mc") {
							// Multi-attribute
							c = [
								toFunction("mc", [toString(attrName), toString(value)]),
								trueValue,
							];
						} else if (
							attrType !== "s" ||
							operator === "==" ||
							operator === "!="
						) {
							const isDate = attrType === "d";
							value = isDate
								? AdminUtil.getIsoDateString(value as string)
								: value;
							const valueType = isDate ? "s" : attrType;
							c = [
								toFunction(`a${attrType}`, [toString(attrName)]),
								{ t: valueType, v: value },
							];
						} else {
							c = [
								toFunction(operator, [
									toFunction("as", [toString(attrName)]),
									toString(value),
								]),
								trueValue,
							];
						}
					}

					serverEntries.push(toOp(v, c));
				}
			}
		};

		recursive(policy.value, schemaEntries);

		return {
			title: policy.name,
			expression: toOp(policy.match, schemaEntries),
		};
	}

	static getOperators(): IOperator[] {
		return this.operators;
	}

	static getEditorTitle(mode: PolicyEditorMode): string {
		let title = "";

		switch (mode) {
			case PolicyEditorMode.Add:
				title = "Add Security Policy";
				break;
			case PolicyEditorMode.Edit:
			case PolicyEditorMode.Copy:
				title = "Edit Security Policy";
				break;
			case PolicyEditorMode.View:
			default:
				title = "View Security Policy";
		}

		return title;
	}
}

export enum PolicyEditorMode {
	Add,
	Edit,
	Copy,
	View,
}

@Component({
	templateUrl: "./policy.html",
	styleUrls: ["./policy.scss"],
})
export class EditPolicyComponent
	extends ModalDialogBase
	implements AfterViewInit
{
	@ViewChild("policyViewRef", { read: ViewContainerRef, static: false })
	policyView: ViewContainerRef;

	modalDialog: SohoModalDialogRef<EditPolicyComponent>;
	attributes: IAttributeInfo[] = [];
	policyEdit: IExpInfo;
	policy: IPolicy = {} as IPolicy;
	roleSource: Function;
	groupSource: Function;
	autocompleteTemplate: string;
	operators = PolicyUtil.getOperators();
	mode: PolicyEditorMode;
	isViewMode: boolean;
	private readonly maxEntriesPerPolicy = 25;

	constructor(
		messageService: SohoMessageService,
		private readonly commonDataService: CommonDataService,
		private readonly adminContext: AdminContext,
		private readonly adminService: AdminService,
		private readonly sohoModalDialogService: SohoModalDialogService,
	) {
		super("EditPolicyComponent", messageService);
	}

	ngOnInit(): void {
		this.isViewMode = this.mode === PolicyEditorMode.View;
	}

	ngAfterViewInit(): void {
		this.initModalDialog();
		this.setBusy(true);
		this.commonDataService.listAttributes().subscribe(
			(response: IAttributeListResponse) => {
				this.postInit(response.content);
			},
			() => {
				this.postInit([]);
			},
		);
	}

	onOk(): void {
		if (this.isPolicyValid()) {
			this.save();
		} else {
			if (this.isPolicyEmpty()) {
				this.showMessageInvalidEmpty();
			} else if (this.isOnlyASingleGroup()) {
				this.showMessageInvalidOneGroup();
			} else {
				this.showMessageInvalid();
			}
		}
	}

	test(): void {
		if (this.isPolicyValid()) {
			const options = this.createTestOptions();
			const dialog = this.sohoModalDialogService
				.modal(PolicyTestComponent, this.policyView)
				.title("Security Policy Tester")
				.id("lm-a-sp-policytester-dialog");
			dialog
				.apply((component) => {
					component.modalDialog = dialog;
					component.options = options;
				})
				.open();
		} else {
			this.showMessageInvalid();
		}
	}

	onEntityChanged(
		entry: IValueEntry,
		entityDropdown: SohoDropDownComponent,
	): void {
		entry.attr = null;
		entry.operator = null;
		entry.value = null;
		this.setAttributeValid(entry);

		// Temporary workaround for IDS issue #229
		entityDropdown.updated();
	}

	onAttributeChanged(
		entry: IValueEntry,
		attributeDropdown: SohoDropDownComponent,
	): void {
		entry.operator = null;
		entry.value = null;
		this.setAttributeValid(entry);

		// Temporary workaround for IDS issue #229
		attributeDropdown.updated();
	}

	onOperatorChanged(entry: IValueEntry): void {}

	onAutoSelect(event: Event, entry: IValueEntry): void {
		// This should not be necessary but ngModel does not work when selecting the value in the auto complete.
		// It binds to the entered value, not the selected value.
		const object = event[2];
		if (object && object.value) {
			entry.value = object.value;
		}
	}

	deleteEntry(parent, entry: IValueEntry, isGroupEntry): void {
		ArrayUtil.remove(parent, entry);

		if (!parent.length) {
			if (isGroupEntry) {
				const emptyGroup = this.policy.value.find(
					(expression) => expression.children && !expression.children.length,
				);
				ArrayUtil.remove(this.policy.value, emptyGroup);
			}
		}
	}

	addEntry(
		parent?: IValueEntry[],
		insertAfter?: IValueEntry,
		index?: number,
	): void {
		const canAdd = !this.isMaxEntries();
		if (!canAdd) {
			this.messageService
				.message({
					title: "Unable to add expression",
					message:
						"The max limit has been reached (" + this.maxEntriesPerPolicy + ")",
					buttons: [
						{
							text: "OK",
							id: "lm-a-sp-maxlimit-message-ok",
							click: (e, modal) => {
								modal.close(true);
							},
							isDefault: true,
						},
					],
					attributes: { name: "id", value: "lm-a-sp-maxlimit-message" },
				})
				.open();
			return;
		}

		if (!parent) {
			parent = this.policy.value;
		}

		parent.push({
			entity: Entities.Attribute,
			operator: null,
			value: null,
			attr: null,
			id: this.getId(),
		});

		if (insertAfter) {
			const insertIndex = ArrayUtil.indexOf(parent, insertAfter) + 1;
			ArrayUtil.move(parent, parent.length - 1, insertIndex);
		}
	}

	addGroup(entry: IValueEntry, index: number): void {
		const topEntries = this.policy.value;
		topEntries.push({
			match: Matches.All,
			children: [{ ...entry }],
			id: this.getId(),
		});

		ArrayUtil.move(topEntries, parent.length - 1, index);
		ArrayUtil.remove(topEntries, entry);
	}

	deleteGroup(group: IValueEntry): void {
		ArrayUtil.remove(this.policy.value, group);
	}

	moveToTop(parent: IValueEntry[], entry: IValueEntry): void {
		const topEntries = this.policy.value;
		topEntries.push(entry);
		ArrayUtil.remove(parent, entry);
		if (!parent.length) {
			const emptyGroup = topEntries.find(
				(expression) => expression.children && !expression.children.length,
			);
			ArrayUtil.remove(topEntries, emptyGroup);
		}
	}

	getId(): string {
		return CommonUtil.random(5);
	}

	setAttributeValid(entry: IValueEntry): void {
		entry.invalidAttribute = false;
		entry.invalidAttributeValue = false;
	}

	private postInit(attributes: IAttributeInfo[]): void {
		this.setBusy(false);

		this.attributes = attributes.filter(
			(attribute) => attribute.category === AttributeCategory.Additional,
		);
		this.extendAttributes();

		const policyEdit = this.policyEdit;
		if (policyEdit && policyEdit.expression.c) {
			this.policy = PolicyUtil.getClientSchema(policyEdit, this.attributes);
			this.validateAttributes();
		} else {
			this.policy = this.createNewPolicy();
			this.addEntry(this.policy.value);
		}

		this.setupSources();
	}

	private save(): void {
		const expInfo = PolicyUtil.getServerSchema(this.policy);
		const isEdit = this.mode === PolicyEditorMode.Edit;

		if (isEdit) {
			if (!this.isPolicyChanged(expInfo)) {
				this.showMessageUnchanged();
				return;
			}

			expInfo.expressionId = this.policy.id;
		}

		this.setBusy(true);
		const request = { content: expInfo };
		const service = this.adminService;
		const observable = isEdit
			? service.updateExpression(request)
			: service.createExpression(request);
		observable.subscribe(
			(response) => {
				if (isEdit && !response.content.changeDate) {
					// Unchanged after server-side trimming
					this.showMessageUnchanged();
					this.setBusy(false);
				} else {
					this.closeWithResult(DialogButtonType.Ok, response.content);
				}
			},
			(response: IOperationResponse) => {
				this.adminService.handleError(response, response.getErrorMessages());
				this.setBusy(false);
			},
		);
	}

	private isPolicyChanged(updated: IExpInfo): boolean {
		const existing = this.policyEdit;
		if (existing && updated) {
			if (existing.title !== updated.title) {
				return true;
			}
			const existingExpression = JSON.stringify(existing.expression);
			const updatedExpression = JSON.stringify(updated.expression);
			const isChanged = existingExpression !== updatedExpression;
			return isChanged;
		}
		return true;
	}

	private isPolicyValid(): boolean {
		let isValid = true;

		// Top level must have values
		if (this.isPolicyEmpty()) {
			return false;
		}

		if (this.isOnlyASingleGroup()) {
			return false;
		}

		const validateEntries = (entries: IValueEntry[]) => {
			for (const entry of entries) {
				if (entry.children) {
					validateEntries(entry.children);
				} else {
					const noValue = !entry.value || !entry.value?.toString()?.trim();
					const invalidAttr =
						entry.invalidAttribute || entry.invalidAttributeValue;
					const emptyField =
						!entry.operator ||
						(entry.entity === Entities.Attribute && !entry.attr);
					if (noValue || invalidAttr || emptyField) {
						isValid = false;
						break;
					}
				}
			}
		};

		validateEntries(this.policy.value);
		return isValid;
	}

	private isPolicyEmpty() {
		return !this.policy.value || this.policy.value.length == 0;
	}

	private isOnlyASingleGroup() {
		if (this.policy.value && this.policy.value.length == 1) {
			const child = this.policy.value[0];
			if (child.match) {
				// It's a group and the top level has only one entry
				return true;
			}
		}
		return;
	}

	private validateAttributes(): void {
		const attributes = this.attributes;
		const hasValidAttribute = (entry: IValueEntry): boolean => {
			return (
				!entry.attr ||
				ArrayUtil.containsByProperty(attributes, "name", entry.attr.name)
			);
		};

		const hasValidAttributeValue = (entry: IValueEntry): boolean => {
			const attributeInfo: IAttributeInfo = ArrayUtil.itemByProperty(
				attributes,
				"name",
				entry.attr.name,
			);
			const values = attributeInfo.values;
			if (values && values.length) {
				return (
					!entry.value ||
					ArrayUtil.containsByProperty(values, "val", entry.value)
				);
			} else {
				return true;
			}
		};

		const validateEntries = (entries: IValueEntry[]) => {
			for (const entry of entries) {
				if (entry.children) {
					validateEntries(entry.children);
				} else if (entry.attr) {
					if (!hasValidAttribute(entry)) {
						entry.invalidAttribute = true;
					} else if (!hasValidAttributeValue(entry)) {
						entry.invalidAttributeValue = true;
					}
				}
			}
		};

		validateEntries(this.policy.value);
	}

	private extendAttributes(): void {
		this.attributes = this.attributes.map((attribute) => {
			return {
				...attribute,
				hasValues: attribute.values && attribute.values.length ? true : false,
			};
		});
	}

	private createTestOptions(): IPolicyTestOptions {
		const attributes = {};
		const roles = {};
		const groups = {};

		const iterateEntries = (items: IValueEntry[]) => {
			for (const entry of items) {
				if (entry.children) {
					iterateEntries(entry.children);
				} else {
					const entity = entry.entity;
					const value = entry.value as string;
					if (entity == Entities.Attribute) {
						const attribute = entry.attr;
						attributes[attribute.name] = attribute;
					} else if (entity == Entities.Role) {
						roles[value] = value;
					} else if (entity == Entities.Group) {
						groups[value] = value;
					}
				}
			}
		};

		iterateEntries(this.policy.value);

		const expInfo = PolicyUtil.getServerSchema(this.policy);
		return {
			expInfo: expInfo,
			attributes: attributes,
			groups: groups,
			roles: roles,
		};
	}

	private createNewPolicy(): IPolicy {
		return { id: CommonUtil.random(), name: "", match: Matches.All, value: [] };
	}

	private isMaxEntries(): boolean {
		let count = 0;

		for (const entry of this.policy.value) {
			if (entry.children && entry.children.length) {
				count += entry.children.length;
			} else {
				count++;
			}
		}

		return count >= this.maxEntriesPerPolicy;
	}

	private setupSources(): void {
		const self = this;

		this.roleSource = new AutoCompleter<IAutocompleteEntity[]>(
			(query) => self.commonDataService.searchEntity(PrincipalType.Role, query),
			(response) => ArrayUtil.sortByProperty(response, "label"),
			self.commonDataService,
		).source;

		this.groupSource = new AutoCompleter<IAutocompleteEntity[]>(
			(query) =>
				self.commonDataService.searchEntity(
					PrincipalType.DistributionGroup,
					query,
				),
			(response) => ArrayUtil.sortByProperty(response, "label"),
			self.commonDataService,
		).source;

		this.autocompleteTemplate = Templates.autocompleteEntity;
	}

	private showMessageInvalid(): void {
		this.showError(
			"Invalid policy",
			"One or more rules are invalid, or have an empty value.",
		);
	}
	private showMessageInvalidEmpty(): void {
		this.showError(
			"Invalid policy",
			"There are no rules in this policy. Please add a rule.",
		);
	}
	private showMessageInvalidOneGroup(): void {
		this.showError("Invalid policy", "Invalid group. Move rules to top level.");
	}
	private showMessageUnchanged(): void {
		this.showMessage(
			"No changes detected",
			"No changes that requires saving were detected.",
		);
	}
}

@Component({
	selector: "lm-invalid-policy-attribute",
	template: `
		<button
			soho-button="icon"
			icon="alert"
			extraIconClass="icon-alert"
			soho-tooltip
			trigger="click"
			placement="left"
			[popover]="true"
			[content]="'#lm-a-sp-attribute-error' + entry.id"></button>
		<div [id]="'lm-a-sp-attribute-error' + entry.id" class="hidden">
			<fieldset>
				<legend>
					<svg soho-icon icon="alert" [alert]="true"></svg>
					Invalid rule
				</legend>
				<div class="summary-form">
					<small>{{ removedText }}</small>
					<ng-container *ngIf="isAttribute">
						<div class="field lm-margin-xl-t">
							<span class="label">User property</span>
							<span class="data">{{ entry.attr.name }}</span>
						</div>
						<div>
							<span class="label">Condition</span>
							<span class="data">{{ operatorLabel }}</span>
						</div>
					</ng-container>

					<div class="field" [class.lm-margin-xl-t]="!isAttribute">
						<span class="label">Value</span>
						<span class="data">{{ entry.value }}</span>
					</div>
					<small>{{ selectNewText }}</small>
				</div>
			</fieldset>
		</div>
	`,
	styles: [
		`
			:host {
				position: absolute;
				right: -40px;
				top: 5px;
			}

			button[soho-button="icon"] {
				margin-right: 0;
			}

			legend .icon {
				top: 0;
			}
		`,
	],
})
export class InvalidAttributeComponent {
	@Input() entry: IValueEntry;
	@Input() operators: IOperator[];

	removedText: string;
	selectNewText: string;
	operatorLabel: string;
	isAttribute: boolean;

	ngOnInit(): void {
		const isAttribute = this.entry.invalidAttribute;
		const removedItemName = isAttribute
			? "user property"
			: "user property value";
		this.removedText = `The previously selected ${removedItemName} has been removed:`;
		this.selectNewText = `Please select a new ${removedItemName}, or remove the rule.`;

		if (isAttribute) {
			this.operatorLabel = ArrayUtil.itemByProperty(
				this.operators,
				"value",
				this.entry.operator,
			).label;
		}

		this.isAttribute = isAttribute;
	}
}
