import {
	Component,
	Input,
	NgZone,
	OnInit,
	ViewChild,
	ViewContainerRef,
} from "@angular/core";
import {
	SohoDataGridComponent,
	SohoMessageService,
	SohoModalDialogService,
} from "ids-enterprise-ng";
import { DialogService, HtmlUtil, IDialogResult, StringUtil } from "lime";
import {
	ContentImportComponent,
	DialogResponseCode,
	EntityFilter,
	IDynamicPreviewOptions,
	IImportOptions,
	ILanguageInfo,
	IOperationResponse,
	LanguageService,
} from "lime/core";
import { Observable, Subscription, of } from "rxjs";
import { catchError } from "rxjs/operators";
import { CustomFormatters } from "../../admin";
import { AdminListComponent } from "../../admin-list.component";
import { LanguageSelectorDialog } from "../../language-selector";
import {
	AdminContext,
	AdminService,
	AdminUtil,
	ExpressionFilterTarget,
	IExpInfoFilter,
} from "../../service";
import { ArchiveCreateDialog } from "../archive/create";
import { ArchiveSingleEntityDialog } from "../archive/single-entity";
import {
	DynamicPageState,
	IDynamicAccess,
	IDynamicPage,
	IDynamicPageInfo,
	IDynamicPageInfoResponseAdmin,
	IDynamicPageListRequest,
	IDynamicPageListResponse,
	IDynamicPublishRequest,
} from "./core";
import { DynamicPageImportDialog } from "./dynamic-page-import-dialog";
import { DynamicPageSettingsDialog } from "./editor/settings/basic";
import { DynamicPreviewer } from "./preview";
import { DynamicPublishDialogComponent } from "./publish-dialog";
import { DynamicPageAdminService } from "./service";

@Component({
	selector: "lm-admin-dynamic-pages",
	templateUrl: "./dynamic-pages.html",
})
export class AdminDynamicPagesComponent
	extends AdminListComponent<IDynamicPageInfo>
	implements OnInit
{
	@Input()
	set expressionFilter(expInfo: IExpInfoFilter) {
		if (!this.isValidExpressionFilter(expInfo)) {
			this.logInfo("Ignoring Expression filter change");
			return;
		}

		if (expInfo != null) {
			this.logInfo("Expression filter set to " + expInfo.expressionId);
		}
		this._expressionFilter = expInfo;
		if (expInfo == null || !expInfo.title) {
			this.expressionFilterTitle = null;
		} else {
			this.expressionFilterTitle = expInfo.title;
		}
		if (this.isInitialized) {
			// Clear standard filter and loads item
			this.clearAllFiltersOptional(false);
		}
	}
	get expressionFilter(): IExpInfoFilter {
		return this._expressionFilter;
	}
	@ViewChild("dynamicPagesDatagrid", { static: false })
	dataGrid: SohoDataGridComponent;

	expressionFilterTitle = "";

	/* NOTE: Cannot use inferred types here because https://github.com/Microsoft/TypeScript/issues/9944
	which has been fixed somewhere between Typescript 2.7.2 and 2.92 */
	editedPage: Observable<IDynamicPage> = this.dynamicPageService.editedPage;

	private editorSubscription: Subscription;
	private restoredUnsubscriber: () => void;

	private _expressionFilter: IExpInfoFilter = null;
	private isInitialized = false;
	private isAddOpen: boolean;

	constructor(
		messageService: SohoMessageService,
		languageService: LanguageService,
		adminService: AdminService,
		sohoModalDialogService: SohoModalDialogService,
		zone: NgZone,
		public dynamicPageService: DynamicPageAdminService,
		readonly viewContainerRef: ViewContainerRef,
		private readonly dialogService: DialogService,
		private readonly adminContext: AdminContext,
	) {
		super(
			"AdminDynamicPagesComponent",
			"page",
			messageService,
			languageService,
			adminService,
			sohoModalDialogService,
			zone,
			{
				isFilter: true,
				isOwnerFilter: false,
				isOtherUserFilter: false,
				isRestrictionFilter: false,
				filters: [
					{
						name: "Checked out",
						propertyName: "lock",
						value: 9,
						type: EntityFilter.Custom,
					},
					{
						name: "Checked out by...",
						propertyName: "checkedOutId",
						isUser: true,
						type: EntityFilter.Custom,
					},
					{
						name: "Draft",
						propertyName: "state",
						value: DynamicPageState.Draft,
						type: EntityFilter.Custom,
					},
					{
						name: "Published",
						propertyName: "state",
						value: DynamicPageState.Published,
						type: EntityFilter.Custom,
					},
					{
						name: "Published (Edited)",
						propertyName: "state",
						value: DynamicPageState.PublishedEdited,
						type: EntityFilter.Custom,
					},
				],
			},
		);

		this.editorSubscription = dynamicPageService.editorToggled.subscribe(
			(isOpen) => {
				this.onEditorToggled(isOpen);
			},
		);

		this.restoredUnsubscriber = adminService.onArchiveRestored().on(() => {
			this.refresh();
		});

		this.initGrid();
	}

	ngOnInit() {
		const tool = this.adminContext.get();
		if (tool) {
			this.currentUser = tool.userId;
			this.isReadOnly = AdminUtil.isReadOnlyUser(tool);
		}
		this.refresh();
		this.isInitialized = true;
	}

	ngOnDestroy(): void {
		this.editorSubscription.unsubscribe();
		this.restoredUnsubscriber();
	}

	isValidExpressionFilter(expFilter: IExpInfoFilter) {
		return (
			expFilter &&
			(expFilter.filterTarget === ExpressionFilterTarget.All ||
				expFilter.filterTarget === ExpressionFilterTarget.DynamicPages)
		);
	}

	getDataGrid(): SohoDataGridComponent {
		return this.dataGrid;
	}

	getTitle(): string {
		const selected = this.selected;
		if (
			selected &&
			selected.lock === 1 &&
			selected.changedBy !== this.currentUser
		) {
			return "This page has been checked out by another user";
		}
		return "Actions";
	}

	addPage() {
		if (this.isAddOpen) {
			return;
		}
		this.isAddOpen = true;

		this.logDebug("Adding page");
		const dialogRef = this.sohoDialogService
			.modal(DynamicPageSettingsDialog, this.viewContainerRef)
			.id("dyn-p-settings-mdl")
			.title("Page Settings")
			.afterClose(() => {
				this.isAddOpen = false;
			});

		dialogRef.apply((comp: DynamicPageSettingsDialog) => {
			comp.modalDialog = dialogRef;
			comp.isCreate = true;
			comp.isCreatePage = true;
		});
		dialogRef.open();
	}

	checkOutPage(page: IDynamicPageInfo, isForced?: boolean) {
		if (isForced) {
			const title = "Confirm force check out";
			const message =
				"Are you sure that you want to force check out of the page '" +
				page.title +
				"' that is currently checked out by '" +
				page.changedByName +
				"'?";
			this.showConfirm(title, message).subscribe(() => {
				this.checkOutInternal(page, true);
			});
			return;
		}

		this.checkOutInternal(page);
	}

	checkInPage(page: IDynamicPageInfo) {
		this.logDebug(`Checking in page ${page.pageId}`);
		const title = "Check in";
		const observable = this.dynamicPageService.checkInPage(page.pageId);
		this.withBusy(observable).subscribe(
			(response: IDynamicPageInfoResponseAdmin) => {
				this.updateSelected(response.content);
				this.showToast(title, `'${page.title}' was checked in.`);
			},
			(response: IOperationResponse) => {
				this.handleError(title, "Unable to check in page.", response);
			},
		);
	}

	editPage(page: IDynamicPageInfo) {
		this.logDebug(`Editing page ${page.pageId}`);
		this.dynamicPageService
			.editPage(page.pageId)
			.pipe(
				// Ignore error since it's handled in service
				catchError(() => of()),
			)
			.subscribe();
	}

	viewPage(page: IDynamicPageInfo) {
		this.logDebug(`View page ${page.pageId}`);
		this.dynamicPageService
			.viewPage(page.pageId)
			.pipe(
				// Ignore error since it's handled in service
				catchError(() => of()),
			)
			.subscribe();
	}

	publishPage(page: IDynamicPageInfo): void {
		const dialogRef = this.sohoDialogService
			.modal(DynamicPublishDialogComponent, this.viewContainerRef)
			.title("Publish Dynamic Page")
			.id("lm-a-dp-publish-dialog")
			.afterClose((result: IDialogResult) => {
				if (result) {
					this.executePublish(result.value as IDynamicPageInfo);
				}
			});
		dialogRef
			.apply((component) => {
				component.modalDialog = dialogRef;
				component.page = page;
			})
			.open();
	}

	importPageLocalization(page: IDynamicPageInfo): void {
		const title = "Import Translation";
		const options = this.importOptions(title);
		options.content = "language";

		const confirmMessage = `This import will replace language translations for '${page.title}'. Are you sure you want to continue?`;

		this.showConfirm(title, confirmMessage).subscribe(() => {
			this.openImportDialog(options, page);
		});
	}

	openImportPageDialog(page?: IDynamicPageInfo): void {
		const isReplacement = page && page.pageId;
		const title =
			"Import Page" + (isReplacement ? " As Replacement" : " As New");
		const options = this.importOptions(title);
		const confirmTitle = isReplacement ? "Import as replacement" : null;

		const confirmMessage = isReplacement
			? `This import will replace '${page.title}'. Are you sure you want to continue?`
			: null;

		if (isReplacement) {
			this.showConfirm(confirmTitle, confirmMessage).subscribe(() => {
				this.openImportDialog(options, page);
			});
		} else {
			this.openImportDialog(options, page);
		}
	}

	exportPage(page: IDynamicPageInfo): void {
		this.dynamicPageService.exportPage(page.title, page.pageId, false);
	}

	exportPageLocalization(page: IDynamicPageInfo): void {
		const dialog = this.sohoDialogService
			.modal(LanguageSelectorDialog, this.viewContainerRef)
			.title("Export Translation")
			.id("lm-a-dp-exporttranslation-dialog")
			.afterClose((selected: ILanguageInfo[]) => {
				if (selected) {
					const languages = StringUtil.join(selected, (l) => l.tag);
					this.dynamicPageService.exportPageLocalization(
						page.title,
						page.pageId,
						languages,
					);
				}
			});

		dialog
			.apply((component) => {
				component.dialog = dialog;
				component.description =
					"Select the languages that you want to export for translation.";
			})
			.open();
	}

	onClickDiscard(page: IDynamicPageInfo): void {
		const title = "Confirm Discard";
		const message = `Are you sure that you want to discard all changes to the page '${page.title}'?`;
		this.showConfirm(title, message).subscribe(() => {
			const id = page.pageId;
			this.logDebug(`Deleting draft page ${id}`);

			const observable = this.dynamicPageService.deleteDraftPage(id);
			this.withBusy(observable).subscribe(
				(response) => {
					const updatedPageList = this.getUpdatedPageList(response.content);
					this.updateItems(updatedPageList);
				},
				(response: IOperationResponse) => {
					this.handleError(
						"Discard",
						"Unable to discard page changes.",
						response,
					);
				},
			);
		});
	}

	onClickDelete(page: IDynamicPageInfo): void {
		const title = "Confirm Delete";
		const message = `Are you sure that you want to delete the page '${page.title}'?`;
		this.showConfirm(title, message).subscribe(() => {
			this.deletePage(page);
		});
	}

	listItems(reload: boolean): void {
		const request: IDynamicPageListRequest = this.createRequest(
			reload,
		) as IDynamicPageListRequest;
		if (!request) {
			return;
		}

		// Check for special filter
		if (this._expressionFilter != null) {
			request.expressionId = this._expressionFilter.expressionId;
		}

		const observable = this.dynamicPageService.listPages(request);
		this.withBusy(observable).subscribe(
			(response: IDynamicPageListResponse) => {
				this.addItems(response.content, response.paging);
				this.updateCount(response.count, response.maxCountAllowed);
			},
			(r: IDynamicPageListResponse) => {
				this.onError(r);
			},
		);
	}

	openCreateArchiveDialog(page: IDynamicPageInfo): void {
		this.logDebug("Archiving a page");
		if (page.state !== DynamicPageState.Published) {
			this.showError(
				"Archive Page",
				"Page needs to be published to be archived.",
			);
			return;
		}
		const id = page.pageId;
		const title = page.title;

		const dialog = this.sohoDialogService
			.modal(ArchiveCreateDialog, this.viewContainerRef)
			.title("Archive Page")
			.id("dyn-p-archive-mdl");

		dialog
			.apply((component) => {
				component.modalDialog = dialog;
				component.baseUrl = "/admin/dynamic/page";
				component.entityId = id;
				component.entityTitle = title;
			})
			.open();
	}

	openEntityArchiveDialog(page: IDynamicPageInfo) {
		const dialog = this.sohoDialogService
			.modal(ArchiveSingleEntityDialog, this.viewContainerRef)
			.title(`Archive for Page '${HtmlUtil.escapeStringForHtml(page.title)}'`)
			.id("lm-a-dp-rst-selectarc-dialog")
			.afterClose((r) => {
				if (r) {
					this.refresh();
				}
			});

		dialog
			.apply((component) => {
				component.dialog = dialog;
				component.entityId = page.pageId;
			})
			.open();
	}

	onClickClearPolicyFilter() {
		this.clearExpressionFilter();
		this.clearAllFilters();
	}

	clearExpressionFilter(): void {
		this._expressionFilter = null;
	}

	preview(page: IDynamicPageInfo): void {
		const options = this.getPreviewOptions(page);
		this.dynamicPageService.preview(options);
	}

	previewAsUser(page: IDynamicPageInfo): void {
		const options = this.getPreviewOptions(page);
		this.getPreviewer().previewAsUser(options);
	}

	protected initGrid(): void {
		const options = this.defaultOptions();
		options.selectable = "single" as SohoDataGridSelectable;
		options.expandableRow = false;
		this.datagridOptions = options;
	}

	protected getColumns(): SohoDataGridColumn[] {
		return [
			this.getSelectionColumn(),
			{
				width: 205,
				id: "adm-dp-col-t",
				field: "title",
				name: "Title",
				sortable: false,
				resizable: true,
			},
			{
				width: 304,
				id: "adm-dp-col-d",
				field: "description",
				name: "Description",
				sortable: false,
				resizable: true,
			},
			{
				width: 200,
				id: "adm-dp-col-cd",
				field: "changeDate",
				name: "Change date",
				sortable: false,
				resizable: true,
				formatter: CustomFormatters.date,
			},
			{
				width: 173,
				id: "adm-dp-col-cbn",
				field: "changedByName",
				name: "Changed by",
				sortable: false,
				resizable: true,
				formatter: CustomFormatters.displayName,
			},
			{
				width: 173,
				id: "adm-dp-col-lbn",
				field: "",
				name: "Checked out by",
				sortable: false,
				resizable: true,
				formatter: (row, cell, value, col) => {
					const item = this.items[row];
					return item && item.lock === 1
						? CustomFormatters.displayName(null, null, item.changedByName, null)
						: "";
				},
			},
			{
				width: 140,
				id: "adm-dp-col-s",
				field: "state",
				name: "Status",
				sortable: false,
				resizable: true,
				formatter: CustomFormatters.dynamicPageStatus,
			},
		];
	}

	protected getEmptyMessage(): string {
		return "No dynamic pages found";
	}

	protected clearCustomFilter() {
		this.clearExpressionFilter();
	}

	private getPreviewer(): DynamicPreviewer {
		return new DynamicPreviewer(
			this.viewContainerRef,
			this.sohoDialogService,
			this.adminService,
			this.dynamicPageService,
		);
	}

	private getPreviewOptions(page: IDynamicPageInfo): IDynamicPreviewOptions {
		return {
			pageId: page.pageId,
			isDraft: true,
		} as IDynamicPreviewOptions;
	}

	private onEditorToggled(isOpen: boolean): void {
		if (!isOpen) {
			this.refresh();
		}
	}

	private deletePage(page: IDynamicPageInfo): void {
		const id = page.pageId;
		this.logDebug(`Deleting page ${id}`);

		this.setBusy(true);
		this.dynamicPageService.deletePage(id).subscribe(
			() => {
				this.setBusy(false);
				this.refresh();
			},
			(response: IOperationResponse) => {
				this.setBusy(false);
				this.handleError("Delete", "Unable to delete page.", response);
			},
		);
	}

	private checkOutInternal(page: IDynamicPageInfo, isForced?: boolean) {
		this.logDebug(`Checking out page ${page.pageId}`);
		const title = "Check out";
		const observable = this.dynamicPageService.checkOutPage(
			page.pageId,
			isForced,
		);
		this.withBusy(observable).subscribe(
			(response: IDynamicPageInfoResponseAdmin) => {
				this.updateSelected(response.content);
				const toastMessage = isForced
					? `'${page.title}' was forcibly checked out.`
					: `'${page.title}' was checked out.`;
				this.showToast(title, toastMessage);
			},
			(response: IOperationResponse) => {
				const message = isForced
					? "Unable to forcibly check out page."
					: "Unable to check out page.";
				this.handleError(title, message, response);
			},
		);
	}

	private updateSelected(info: IDynamicPageInfo): void {
		this.setBusy(false);
		const index = this.getIndex(info);
		if (index < 0) {
			return;
		}

		this.items[index] = info;
		this.dataGrid.updateRow(index, info);
		this.dataGrid.selectRow(index);
	}

	private executePublish(page: IDynamicPageInfo): void {
		const id = page.pageId;
		this.logDebug(`Publishing page ${id}`);

		let access: IDynamicAccess[] = null;
		if (page.accesses) {
			access = page.accesses;
		}

		const request = {
			pid: id,
			accs: access,
		} as IDynamicPublishRequest;

		const observable = this.dynamicPageService.publishPage(request);
		this.withBusy(observable)
			.pipe(
				// Ignore error since it's handled in service
				catchError(() => of()),
			)
			.subscribe((response: IDynamicPageInfoResponseAdmin) => {
				const info = response.content;
				const updatedPageList = this.getUpdatedPageList(info);
				this.updateItems(updatedPageList);
				this.showToast(
					"Page published",
					`'${info.title}' was published to the catalog.`,
				);
			});
	}

	private importOptions(title: string): IImportOptions {
		return {
			url: "/admin",
			title: title,
			operation: "importdynamic",
			buttonText: "Import",
			acceptFileExtension: ".zip",
		} as IImportOptions;
	}

	private openImportDialog(
		importOptions: IImportOptions,
		page?: IDynamicPageInfo,
	): void {
		const dialog = this.sohoDialogService
			.modal(ContentImportComponent, this.viewContainerRef)
			.title(importOptions.title)
			.id("lm-a-dp-import-dialog")
			.afterClose((result: IDialogResult) => {
				if (
					result &&
					result.value.responseCode === DialogResponseCode.Success
				) {
					setTimeout(() => {
						// setTimeOut is needed, else the next modal wont be opened
						if (page && page.pageId) {
							this.logDebug("Importing as replacement");
							this.startImport(page.pageId, importOptions.content);
						} else {
							this.logDebug("Importing as new");
							this.startImport();
						}
					}, 0);
				}
			});

		dialog
			.apply((component) => {
				component.dialog = dialog;
				component.options = importOptions;
			})
			.open();
	}

	private startImport(pageId?: string, content?: string) {
		const dialog = this.sohoDialogService
			.modal(DynamicPageImportDialog, this.viewContainerRef)
			.title("Importing")
			.id("lm-a-dp-import-result-dialog")
			.afterClose((result: IDialogResult) => {
				this.refresh();
			});
		dialog
			.apply((component) => {
				component.modalDialog = dialog;
				pageId !== null
					? (component.pageId = pageId)
					: (component.pageId = null);
				component.operation = "import";
				// component.content = content;
			})
			.open();
	}

	private showToast(title: string, message: string): void {
		this.dialogService.showToast({
			title: title,
			message: message,
		});
	}

	private getUpdatedPageList(
		updatedInfo: IDynamicPageInfo,
	): IDynamicPageInfo[] {
		return this.items.map((pageInfo) =>
			pageInfo.pageId === updatedInfo.pageId ? updatedInfo : pageInfo,
		);
	}

	private getIndex(info: IDynamicPageInfo): number {
		const items = this.items;
		for (let i = 0; i < items.length; i++) {
			if (items[i].pageId === info.pageId) {
				return i;
			}
		}
		return -1;
	}

	private handleError(
		title: string,
		message: string,
		response: IOperationResponse,
	) {
		if (response && response.hasError() && !response.hasGenericError()) {
			this.showError(title, `${response.getErrorMessages()}`);
		} else {
			this.showError(title, message);
		}
	}
}
