import { Injectable } from "@angular/core";
import { AdminPages, ContainerService, CoreBase } from "lime/core";
import { BehaviorSubject, combineLatest, merge, Observable, zip } from "rxjs";
import {
	distinct,
	distinctUntilChanged,
	map,
	mergeAll,
	scan,
	shareReplay,
	take,
	tap,
} from "rxjs/operators";
import { AdminAccessService } from "./admin-access.service";
import { AdminFeatureService } from "./admin-feature.service";
import { AdminService } from "./service";

@Injectable({
	providedIn: "root",
})
export class AdminRoutingService extends CoreBase {
	private nextPageSubject = new BehaviorSubject<AdminPages>(AdminPages.Home);
	currentPage$: Observable<AdminPages> = this.nextPageSubject.pipe(
		distinctUntilChanged(), // No need to emit if we switch to the same page.
		tap((page) => this.adminService.setLastVisitedTab(page)), // TODO: This property can probably be moved into this service
		shareReplay(1), // Let several observers share instead of emitting on each subscribe.
	);
	isAdminClosed$ = this.containerService.admin$.pipe(
		map((value) => value.isClose),
		distinctUntilChanged(),
	);
	openedPages$ = combineLatest(
		this.currentPage$.pipe(distinct()),
		this.isAdminClosed$,
	).pipe(
		scan((acc, [page, isClosed]: [AdminPages, boolean]) => {
			isClosed ? acc.clear() : acc.set(page, true);
			return acc;
		}, new Map<AdminPages, boolean>()),
	);
	canNavigateTo$ = merge(
		adminPagesAsArray.map((page) => this.canNavigateToPage$(page)),
	).pipe(
		mergeAll(),
		scan(
			(acc, [page, canNavigate]: [AdminPages, boolean]) => {
				acc[page] = canNavigate;
				return acc;
			},
			{} as { [page: number]: boolean },
		),
		shareReplay(1),
	);

	constructor(
		private accessService: AdminAccessService,
		private featureService: AdminFeatureService,
		private adminService: AdminService,
		private containerService: ContainerService,
	) {
		super("AdminRoutingService");
	}

	navigateTo(page: AdminPages): void {
		this.isAuthorized$(page)
			.pipe(take(1))
			.subscribe((isAuthorized) => {
				if (isAuthorized) {
					this.nextPageSubject.next(page);
				} else {
					this.logInfo(
						`User is not authorized to access ${AdminPages[page]}. Defaulting to Home.`,
					);
					this.nextPageSubject.next(AdminPages.Home);
				}
			});
	}

	private canNavigateToPage$(
		page: AdminPages,
	): Observable<[AdminPages, boolean]> {
		// Use zip since both services emits when tool is reloaded.
		return zip(
			this.accessService.readable(page),
			this.featureService.isFeatureEnabled(page),
			(readable, featureEnabled) =>
				[page, readable && featureEnabled] as [AdminPages, boolean],
		).pipe(
			// Unchanged access is not emitted
			distinctUntilChanged(([, prevVal], [, val]) => prevVal === val),
		);
	}

	private isAuthorized$(page: AdminPages): Observable<boolean> {
		return zip(
			this.accessService.readable(page),
			this.featureService.isFeatureEnabled(page),
			(readable, featureEnabled) => readable && featureEnabled,
		);
	}
}

/**
 * Get Enum of AdminPages as array
 * https://stackoverflow.com/questions/39372804/typescript-how-to-loop-through-enum-values-for-display-in-radio-buttons
 */
const adminPagesAsArray = Object.keys(AdminPages)
	.filter((key) => isNaN(Number(AdminPages[key as any])))
	.map((page) => Number(page));
