import { Component, EventEmitter, Input, Output } from "@angular/core";
import { ArrayUtil } from "lime";
import { MemoWeekDay } from "./core";

@Component({
	selector: "lm-admin-memo-weekday-select",
	templateUrl: "./weekday-select.html",
})
export class MemoWeekdaySelectComponent {
	@Input() model: MemoWeekDay;
	@Output() modelChange = new EventEmitter<MemoWeekDay>();

	weekdays = localeSortedWeekDays();
}

/**
 * Weekdays sorted according to the SOHO locale
 */
function localeSortedWeekDays(): IWeekDayOption[] {
	const weekdays: IWeekDayOption[] = [
		{ value: MemoWeekDay.Sunday, label: "Sunday" },
		{ value: MemoWeekDay.Monday, label: "Monday" },
		{ value: MemoWeekDay.Tuesday, label: "Tuesday" },
		{ value: MemoWeekDay.Wednesday, label: "Wednesday" },
		{ value: MemoWeekDay.Thursday, label: "Thursday" },
		{ value: MemoWeekDay.Friday, label: "Friday" },
		{ value: MemoWeekDay.Saturday, label: "Saturday" },
	];
	return ArrayUtil.rotateLeft(weekdays, getLocaleFirstDayOfWeek());
}

/**
 * Get the first day of the week, where 0=sunday, 1=monday...6=saturday
 */
function getLocaleFirstDayOfWeek(): number {
	// SOHO days are 0|undefined|null=Sunday, 1=Monday ... 6=Saturday
	// Memo days are 1=Monday ... 6=Saturday, 7=Sunday
	// TODO: Remove the types (and type assertion) below when firstDayofWeek is added to IDS typings.
	type SohoWeekDay = 0 | 1 | 2 | 3 | 4 | 5 | 6 | undefined | null;
	interface SohoExtendedCalendar {
		firstDayofWeek?: SohoWeekDay;
	}

	return (Soho.Locale.calendar() as SohoExtendedCalendar).firstDayofWeek || 0;
}

interface IWeekDayOption {
	value: MemoWeekDay;
	label: string;
}
