import { Component, Input } from "@angular/core";
import { CoreBase } from "lime/core";
import { MemoFrequencyType, MemoIteration, MemoWeekOrdinal } from "./core";

@Component({
	selector: "lm-admin-memo-date-monthly",
	templateUrl: "./date-monthly.html",
})
export class MemoDateMonthlyComponent extends CoreBase {
	@Input() iteration: MemoIteration;

	FrequencyTypes = MemoFrequencyType;
	WeekOrdinals = MemoWeekOrdinal;

	constructor() {
		super("MemoDateMonthlyComponent");
	}

	onFocus($event: any): void {
		$event.target.select();
	}
}
