import {
	Directive,
	HostListener,
	Input,
	QueryList,
	ViewChildren,
	ViewContainerRef,
} from "@angular/core";
import { SohoMessageService, SohoModalDialogService } from "ids-enterprise-ng";
import { CommonUtil, StringUtil } from "lime";
import {
	Constants,
	CoreUtil,
	DynamicColorType,
	DynamicPageAreaKey,
	IDynamicContainer,
	IDynamicEntity,
	IDynamicEntityLocalizationMap,
	IStringMap,
	LazyTypeService,
} from "lime/core";
import { of } from "rxjs";
import { catchError, map, tap } from "rxjs/operators";
import {
	DynamicClipboardService,
	IClipboardInfo,
} from "../../../clipboard.service";
import { DynamicPageAdminService } from "../../../service";
import { DynamicUtil } from "../../../util";
import { IAccessErrorMap, IContainerFilter } from "../../dynamic-page-editor";
import { DynamicListItemComponent } from "./dynamic-container-item";

export interface IInfoHeader {
	title: string;
	text: string;
}

@Directive()
export abstract class DynamicContainerListBase {
	get isEmpty(): boolean {
		return this._isEmpty;
	}

	set isEmpty(value: boolean) {
		this._isEmpty = value;
	}
	@ViewChildren(DynamicListItemComponent) listItems =
		new QueryList<DynamicListItemComponent>();

	@Input() area: DynamicPageAreaKey;
	@Input() accessTitles: IStringMap;
	@Input() accessErrors: IAccessErrorMap;
	@Input() container: IDynamicContainer;
	@Input() query: string;
	@Input() filter: IContainerFilter;
	@Input() isEditable: boolean;
	@Input() isHeader?: boolean;
	@Input() isContent?: boolean;
	@Input() itemContainerEmpty: boolean;
	@Input() infoHeader?: IInfoHeader;
	@Input() isExperimental?: boolean;
	colorTypes = DynamicColorType;

	h1: string;
	h2: string;
	h3: string;
	h4: string;
	addItemText: string;
	addSecondItemText: string;
	addItemMessage: string;
	selectionCount = 0;
	componentLabel = "item";
	automationIdentifier = "lm-a-dp";
	popupId = `lm-a-dp-im-${CommonUtil.random()}`;
	showPaste$ = this.clipboardService.clipboardTypeInfo$.pipe(
		tap((typeInfo) => {
			if (!typeInfo) {
				this.clearSelection();
			}
		}),
		map(
			(typeInfo) =>
				typeInfo &&
				typeInfo.ct === this.container.ct &&
				typeInfo.st === this.container.st,
		),
	);

	experimentalTooltip = Constants.dynPageExperimentalFeatureMsg;

	protected _isEmpty = true;

	protected isDialogOpen: boolean;
	private shiftSelectAnchor: number;
	private readonly maxSelected = 10;

	constructor(
		protected viewContainerRef: ViewContainerRef,
		protected dialogService: SohoModalDialogService,
		protected pageService: DynamicPageAdminService,
		protected lazyTypeService: LazyTypeService,
		protected messageService: SohoMessageService,
		protected clipboardService: DynamicClipboardService,
	) {}

	@HostListener("window:keydown.escape")
	protected clearClipboard() {
		this.clearCut();
		this.clearSelection();
		this.clipboardService.clearClipboard();
	}

	protected abstract getEntityCount(): number;

	protected initItems(
		addItemName: string,
		addItemMessage: string,
		h1: string,
		h2: string,
		h3?: string,
		h4?: string,
	): void {
		this.addItemText = addItemName;
		this.addItemMessage = addItemMessage;
		this.h1 = h1;
		this.h2 = h2;
		if (h3) {
			this.h3 = h3;
		}
		if (h4) {
			this.h4 = h4;
		}
		if (this.container?.ct) {
			this.componentLabel = DynamicUtil.getComponentTypeLabel(
				this.container.ct,
				this.container.st,
			);
			//TODO check for component title?
			this.automationIdentifier =
				"lm-a-dp-" +
				this.area +
				"-" +
				StringUtil.formatTextForId(this.componentLabel, "component");
		}
	}

	protected canAdd(isDuplicate?: boolean): boolean {
		if (!this.isEditable) {
			return false;
		}
		const limit = Constants.dynMaxEntitiesInContainer;
		const entityCount = this.getEntityCount();
		const canAdd = entityCount < limit;
		if (!canAdd) {
			this.messageService
				.message({
					title: `Unable to ${isDuplicate ? "duplicate" : "add"} item`,
					message: `The max limit has been reached (${limit}).`,
					buttons: [
						{
							text: "OK",
							id: "lm-a-dp-maxlimit-message-ok",
							click: (e, modal) => {
								modal.close(true);
							},
							isDefault: true,
						},
					],
					attributes: { name: "id", value: "lm-a-dp-maxlimit-message" },
				})
				.open();
			return false;
		}
		return true;
	}

	protected addItem(): void {}
	protected editItem(isPermissionTab: boolean, item: IDynamicEntity): void {}
	protected deleteItems(
		items: IDynamicEntity[],
		parentContainer?: IDynamicContainer,
	): void {}
	protected duplicateItem(item: IDynamicEntity, isHeader?: boolean): void {
		if (!this.canAdd(true)) {
			return;
		}
		const container = this.container;
		const itemCopy = CoreUtil.copy(item);
		itemCopy.eid = DynamicUtil.getNewEntityId(container);

		const containerCopy = CoreUtil.copy(container);
		this.pageService
			.addContainerEntity(containerCopy, itemCopy, isHeader)
			.pipe(
				// Ignore error since it's handled in service
				catchError(() => of()),
			)
			.subscribe();
	}

	protected updateSelection(event: MouseEvent, clickIndex: number) {
		if (!event.shiftKey) {
			this.shiftSelectAnchor = clickIndex;
		}

		let selectionCount = 0;

		this.listItems.forEach((item, index) => {
			if (
				isSelected(index, item, this.shiftSelectAnchor) &&
				selectionCount < this.maxSelected
			) {
				item.setSelected(true);
				selectionCount++;
			} else {
				item.setSelected(false);
			}
		});

		this.selectionCount = selectionCount;

		function isSelected(
			index: number,
			item: DynamicListItemComponent,
			anchor: number,
		): boolean {
			return (
				selectedByClick(index, item.isSelected) ||
				selectedByCtrl(index, item.isSelected) ||
				selectedByShift(index, anchor)
			);
		}

		function selectedByClick(itemIndex: number, isSelected: boolean): boolean {
			return clickIndex === itemIndex && !isSelected;
		}

		function selectedByCtrl(itemIndex: number, isSelected: boolean): boolean {
			return event.ctrlKey && isSelected && clickIndex !== itemIndex;
		}

		function selectedByShift(itemIndex: number, anchor: number): boolean {
			return (
				event.shiftKey && (inRange(itemIndex, anchor) || itemIndex === anchor)
			);
		}

		function inRange(itemIndex: number, anchor: number): boolean {
			return (
				itemIndex >= Math.min(anchor, clickIndex) &&
				itemIndex <= Math.max(anchor, clickIndex)
			);
		}
	}

	protected copySelected(entities: IDynamicEntity[]): void {
		const selectedItems = this.getSelectedItems();
		this.setClipboardInfo(entities, selectedItems);
		this.clearCut();
	}

	protected cutSelected(entities: IDynamicEntity[]) {
		const selectedItems = this.getSelectedItems();
		this.setClipboardInfo(entities, selectedItems, this.container.eid);
		for (const selected of selectedItems) {
			selected.setCut(true);
		}
	}

	protected pasteEntities() {
		const pasteInfo = this.clipboardService.getClipboard();
		const pasteItems = pasteInfo.items;
		const container = this.container;

		if (pasteAllowed()) {
			let entityCount = this.getEntityCount();
			const limit = Constants.dynMaxEntitiesInContainer;
			const itemsToAdd = pasteItems.filter(() => {
				entityCount++;
				return entityCount <= limit;
			});

			let lznToAdd = pasteInfo.lzn;
			if (itemsToAdd.length < pasteItems.length) {
				lznToAdd = this.getLznForItems(itemsToAdd, pasteInfo.lzn);
			}

			this.pageService
				.addContainerEntityCopies(container, itemsToAdd, lznToAdd)
				.subscribe(() => {
					this.isEmpty = false;
					if (pasteInfo.originId) {
						this.deleteCutItems();
					}
					this.clipboardService.clearClipboard();
				});
		}

		function pasteAllowed(): boolean {
			return (
				pasteItems &&
				pasteItems.length &&
				pasteInfo.ct === container.ct &&
				pasteInfo.st === container.st
			);
		}
	}

	protected clearSelectionCount() {
		this.selectionCount = 0;
	}

	protected deleteItem(item: IDynamicEntity) {
		this.deleteItems([item]);
	}

	protected deleteSelectedItems(entities: IDynamicEntity[]) {
		const selectedItems = this.listItems.filter((item) => item.isSelected);
		const itemsToDelete = entities.filter(
			(entity) =>
				entity.eid &&
				selectedItems.some((selected) => selected.eid === entity.eid),
		);
		this.deleteItems(itemsToDelete);
	}

	private deleteCutItems() {
		const clipboardInfo = this.clipboardService.getClipboard();
		const cutOrigin = this.pageService
			.getPage()
			.cts.find((ct) => ct.eid === clipboardInfo.originId);

		if (cutOrigin) {
			this.deleteItems(clipboardInfo.items, cutOrigin);
		}
	}

	private getLznForItems(
		items: IDynamicEntity[],
		lzn: IDynamicEntityLocalizationMap,
	) {
		const lznCopy = CoreUtil.copy(lzn);
		for (const langKey in lznCopy) {
			delete lznCopy[langKey].t;
			if (lznCopy[langKey].its) {
				for (const itemKey in lznCopy[langKey].its) {
					if (!items.some((item) => item.eid === itemKey)) {
						delete lznCopy[langKey].its[itemKey];
						if (!Object.keys(lznCopy[langKey].its).length) {
							delete lznCopy[langKey];
						}
					}
				}
			} else {
				delete lznCopy[langKey];
			}
		}
		return lznCopy;
	}

	private setClipboardInfo(
		entities: IDynamicEntity[],
		selectedItems: DynamicListItemComponent[],
		originId?: string,
	) {
		const clipboardItems = entities.filter((entity) =>
			selectedItems.some((selected) => selected.eid === entity.eid),
		);

		if (clipboardItems.length) {
			const clipboardInfo: IClipboardInfo = {
				items: clipboardItems,
				lzn: this.getLznForItems(clipboardItems, this.container.lzn),
				ct: this.container.ct,
				st: this.container.st,
				originId: originId,
			};
			this.clipboardService.setClipboard(clipboardInfo);
		}
	}

	private clearSelection() {
		this.listItems.forEach((item) => item.setSelected(false));
		this.clearSelectionCount();
	}

	private clearCut() {
		this.listItems.forEach((item) => item.setCut(false));
	}

	private getSelectedItems(): DynamicListItemComponent[] {
		return this.listItems.filter((item) => item.isSelected);
	}
}
