import {
	Component,
	EventEmitter,
	Input,
	OnInit,
	Output,
	Pipe,
	PipeTransform,
} from "@angular/core";
import { CommonUtil } from "lime";
import {
	Constants,
	DynamicColorType,
	DynamicItemType,
	IStringMap,
} from "lime/core";
import { DynamicPageAdminService } from "../../../service";
import { DynamicUtil } from "../../../util";
import { IAccessErrorMap } from "../../dynamic-page-editor";

@Component({
	selector: "lm-dynamic-list-item",
	styleUrls: ["./dynamic-container-list.scss"],
	templateUrl: "./dynamic-container-item.html",
})
export class DynamicListItemComponent implements OnInit {
	@Input() h1: string;
	@Input() clt = 1;
	@Input() it: DynamicItemType = 1;
	@Input() h2?: string;
	@Input() h3?: string;
	@Input() h4?: string;
	@Input() icon?: string;
	@Input() iconColor?: string;
	@Input() isNormal?: boolean;
	@Input() ais?: string[];
	@Input() eid?: string;
	@Input() imgUrl?: string;
	@Input() isContent?: boolean;
	@Input() isHeader?: boolean;
	@Input() canDuplicate?: boolean;
	@Input() customColor?: number;
	@Input() accessErrors?: IAccessErrorMap;
	@Input() parentId?: string;
	@Input() isEditable = true;
	@Input() automationIdentifier: string;

	@Output() deleteItem = new EventEmitter();
	@Output() editItem = new EventEmitter();
	@Output() duplicateItem = new EventEmitter();
	@Output() updateSelection = new EventEmitter();

	isItemContainer: boolean;
	isImageComponent: boolean;
	isHeaderColorBar: boolean;
	isColorTypeInherit: boolean;
	isColorTypeCustom: boolean;
	isColorTypeNone: boolean;
	isHeaderWithCustomColor: boolean;
	isEmptyTextContent: boolean;
	isEmptyHeaderHeading: boolean;
	isLinkWithCustomColor: boolean;
	isContentEmpty: boolean;
	isLinebreak: boolean;
	popupId = `lm-a-dp-lm-${CommonUtil.random()}`;
	accessValueText: string;
	accessErrorText: string;
	accessTitles: IStringMap;
	colorTypes = DynamicColorType;
	contentTypes = DynamicItemType;
	imageFallback = Constants.dynBrokenImageFallback;
	isSelected: boolean;
	isCut: boolean;
	uniqueId: string;
	itemAutoIdentifier: string;

	constructor(readonly pageService: DynamicPageAdminService) {
		this.accessTitles = pageService.getAccessTitles();
	}

	ngOnInit() {
		this.isHeaderWithCustomColor =
			this.clt === this.colorTypes.Custom && this.isHeader;
		this.isColorTypeCustom = this.clt === this.colorTypes.Custom;
		this.isColorTypeNone = this.clt === this.colorTypes.None;
		this.isColorTypeInherit =
			this.clt === this.colorTypes.InheritPage ||
			this.clt === this.colorTypes.InheritParent;
		this.isImageComponent = this.imgUrl && !this.isHeader;
		this.isHeaderColorBar = !this.imgUrl || this.isHeader;
		this.isItemContainer = this.isContent || this.isHeader;
		this.isEmptyTextContent = !this.h3 && this.it === this.contentTypes.Text;
		this.isEmptyHeaderHeading = !this.h3 && this.isHeader;
		this.isLinkWithCustomColor =
			this.h3 &&
			this.it === this.contentTypes.Link &&
			this.isColorTypeCustom &&
			!this.isHeader;
		this.isContentEmpty = !this.h2 && this.it !== this.contentTypes.Linebreak;
		this.isLinebreak = this.it === this.contentTypes.Linebreak;
		this.uniqueId = `${this.parentId}-${this.eid}`;
		if (!this.isEditable) {
			this.canDuplicate = false;
		}

		this.setAccessInfo();
		this.setAutomationId();
	}

	onSelected($event: MouseEvent) {
		if (!this.isEditable) {
			return;
		}
		this.updateSelection.emit({
			shiftKey: $event.shiftKey,
			ctrlKey: $event.ctrlKey || $event.metaKey,
		});
	}

	setSelected(isSelected: boolean) {
		this.isSelected = isSelected;
	}

	setCut(isCut: boolean) {
		this.isCut = isCut;
	}

	private setAccessInfo(): void {
		let errorText: string;
		let valueText = DynamicUtil.allUsersText;

		const ids = this.ais;
		if (ids) {
			if (this.accessErrors) {
				const errorCode = this.accessErrors.errors[this.parentId + this.eid];
				if (errorCode) {
					errorText = DynamicUtil.entityErrorText(ids, this.accessTitles);
				}
			}
			valueText = DynamicUtil.idsAccessText(ids, this.accessTitles);
		}
		this.accessValueText = valueText;
		this.accessErrorText = errorText;
	}

	private setAutomationId(): void {
		this.itemAutoIdentifier = this.automationIdentifier + "-item";
	}
}

@Pipe({ name: "lmGetContentTypeName" })
export class GetContentTypeNamePipe implements PipeTransform {
	transform(value: DynamicItemType): string {
		switch (value) {
			case DynamicItemType.Link:
				return "Link";
			case DynamicItemType.Attribute:
				return "User property";
			case DynamicItemType.Text:
				return "Text";
			default:
				return "";
		}
	}
}

@Pipe({ name: "lmGetColorTypeName" })
export class GetColorTypeNamePipe implements PipeTransform {
	transform(value: DynamicColorType): string {
		switch (value) {
			case DynamicColorType.None:
				return "None";
			case DynamicColorType.InheritPage:
				return "Page color";
			case DynamicColorType.Custom:
				return "Custom color";
			case DynamicColorType.InheritParent:
				return "Component icon color";
			default:
				return "";
		}
	}
}
