import {
	AfterViewInit,
	Component,
	ElementRef,
	EventEmitter,
	Input,
	NgZone,
	Output,
	Predicate,
	ViewChild,
	ViewContainerRef,
} from "@angular/core";
import {
	SohoMessageService,
	SohoModalDialogService,
	SohoSwapListComponent,
} from "ids-enterprise-ng";
import { CommonUtil, HtmlUtil, IDialogResult } from "lime";
import {
	BrowserStorageService,
	Constants,
	CoreBase,
	IOperationResponse,
	IPagingInfo,
	IStringListResponse,
} from "lime/core";
import { Observable, Subject, combineLatest, fromEvent, timer } from "rxjs";
import {
	bufferTime,
	concatAll,
	debounceTime,
	distinct,
	distinctUntilChanged,
	filter,
	finalize,
	map,
	scan,
	share,
	skipUntil,
	startWith,
	switchMap,
	take,
} from "rxjs/operators";
import {
	EditPolicyComponent,
	PolicyEditorMode,
	PolicyUtil,
} from "../../../../policies/policy";
import {
	AdminConstants,
	AdminContext,
	AdminService,
	IExpInfo,
	IExpressionListRequest,
	IExpressionListResponse,
	IExpressionResponse,
} from "../../../../service";
import { DynamicPageAdminService } from "../../service";
import { DynamicUtil } from "../../util";

export interface ISwapData extends SohoSwapListOptions {
	recentItemsLength?: number;
}
export interface IEditInfo {
	expressionId: string;
	inSelectedList: boolean;
	index: number;
}
export interface IBrokenPolicyTooltip {
	header: string;
	message: string;
	invalidTitles?: string[];
}

const notInSwapArray =
	(items: SohoSwapListItem[]) => (item: SohoSwapListItem) => {
		return !items.some(
			(selected) => selected.value.expressionId === item.value.expressionId,
		);
	};
const collect =
	(time: number, minSize = 0) =>
	<T>(source: Observable<T>) =>
		source.pipe(
			bufferTime(time),
			filter((arr) => arr.length > minSize),
		);
const filterDistinct = () => (source: Observable<IExpInfo[]>) =>
	source.pipe(
		filter((items) => !!items),
		concatAll(),
		distinct((item) => item.expressionId),
		collect(100),
	);
@Component({
	selector: "lm-dynamic-permissions",
	templateUrl: "./permissions.html",
	styleUrls: ["./permissions.scss"],
})
export class DynamicPermissionsComponent
	extends CoreBase
	implements AfterViewInit
{
	@ViewChild(SohoSwapListComponent, { static: false })
	swapList: SohoSwapListComponent;

	@Input() listLabel: string;
	@Input() selected: IExpInfo[] = [];
	@Input() selectedExpressions: IExpInfo[];
	@Input() showRecent = true;
	@Input() operator = "||";
	@Input() showOperator = false;

	@Output() selectedChange = new EventEmitter<IExpInfo[]>();

	selectedLabel = "";
	query = "";
	hasSelection = false;
	items: IExpInfo[] = [];
	recentItems: SohoSwapListItem[] = [];
	isBusy: boolean;
	paging: IPagingInfo;
	isSwapping: boolean;
	editInfo: IEditInfo;
	isAdministrator$: Observable<boolean>;
	idAttr = { name: "id", value: "lm-a-ssp-s" }; //s to avoid duplicate 'swaplist' in generated ids.

	pageAccess$ = this.pageService.pageAccess;
	invalidPageAccessIds$ = this.pageAccess$.pipe(
		filter((accesses) => !!accesses),
		map((accesses) =>
			accesses.filter((access) => access.ec).map((access) => access.exid),
		),
	);
	unchekedIds$ = combineLatest(
		this.selectedChange.asObservable(),
		this.pageAccess$,
	).pipe(
		filter(([selection]) => !!selection),
		map(([selection, existingAccess]) => {
			if (existingAccess) {
				return selection.filter(
					(sel) =>
						!existingAccess
							.map((existing) => existing.exid)
							.includes(sel.expressionId),
				);
			} else {
				return selection;
			}
		}),
	);
	checkedInvalidIds$ = this.unchekedIds$.pipe(
		filterDistinct(), // Filter previously validated ids
		switchMap((items) => this.validatePolicies(items)),
		scan((acc, newInvalid) => [...acc, ...newInvalid], [] as string[]), // Save all invalid ids
		startWith([] as string[]),
		share(),
	);
	invalidSelections$ = combineLatest(
		this.selectedChange.asObservable(),
		this.invalidPageAccessIds$,
		this.checkedInvalidIds$,
	).pipe(
		map(([selections, existing, manual]) =>
			this.getInvalidSelection(selections, [...existing, ...manual]),
		),
	);
	missingSelections$ = this.selectedChange.pipe(
		map((selection) => this.getMissingSelection(selection)),
	);
	brokenPoliciesMessage$ = combineLatest(
		this.invalidSelections$,
		this.missingSelections$,
	).pipe(
		map(([invalid, missing]) => {
			if ((invalid && invalid.length) || (missing && missing.length)) {
				return this.getBrokenPoliciesMessage(invalid, missing);
			} else {
				return null;
			}
		}),
	);

	private readonly maxPolicies = Constants.MaxPolicies;
	private readonly pageSize = 15;
	private readonly maxRecentItems = 5;
	private hasMore: boolean;
	private searchQueryChanged = new Subject<string>();
	private accessTitles = this.pageService.getAccessTitles();
	private isDialogOpen: boolean;

	constructor(
		private adminService: AdminService,
		private sohoDialogService: SohoModalDialogService,
		private pageService: DynamicPageAdminService,
		private element: ElementRef,
		private storageService: BrowserStorageService,
		private ngZone: NgZone,
		messageService: SohoMessageService,
		private readonly viewRef: ViewContainerRef,
		adminContext: AdminContext,
	) {
		super("DynamicPermissionsComponent", messageService);
		this.isAdministrator$ = adminContext.tool$.pipe(
			map((tool) => tool.isAdministrator),
		);
	}

	ngOnInit() {
		this.searchQueryChanged
			.pipe(
				debounceTime(500),
				distinctUntilChanged(),
				switchMap((query: string) => {
					this.query = query;
					this.paging = undefined;
					this.items = [];
					this.isBusy = true;
					const request = this.createRequest(query);
					return this.adminService
						.listExpressions(request)
						.pipe(finalize(() => (this.isBusy = false)));
				}),
			)
			.subscribe((response) => {
				this.onPoliciesLoaded(response);
			});
	}

	ngAfterViewInit(): void {
		const selected = this.selectedExpressions || [];

		if (selected.length) {
			this.updatedSelectedItems(selected);
			this.selectedChange.emit(selected);
		} else {
			this.selectedExpressions = selected;
		}

		this.swapList.selectedItems = selected.map((item) =>
			this.toSwapListItem(item),
		);
		this.subscribeToListScroll();

		if (this.showRecent) {
			this.getRecentlyUsedAccesses().subscribe((recentAccesses: IExpInfo[]) => {
				this.recentItems = recentAccesses.map((item) =>
					this.toSwapListItem(item),
				);
				this.loadPolicies();
			});
		} else {
			this.loadPolicies();
		}

		if (this.operator !== "&&") {
			this.operator = "||";
		}
	}

	openExpressionEditor(mode: PolicyEditorMode, editableItem?: IExpInfo): void {
		if (this.isDialogOpen) {
			return;
		}
		this.isDialogOpen = true;

		const title = PolicyUtil.getEditorTitle(mode);
		const dialog = this.sohoDialogService
			.modal(EditPolicyComponent, this.viewRef)
			.id("lm-a-dp-editpolicy-dialog")
			.title(title)
			.suppressEnterKey(true)
			.afterClose((r: IDialogResult) => {
				this.isDialogOpen = false;
				const newInfo: IExpInfo = r ? (r.value as IExpInfo) : null;
				if (newInfo) {
					if (editableItem) {
						this.onExpressionEdited(newInfo);
					} else {
						this.onExpressionAdded(newInfo);
					}
				}
			});
		dialog
			.apply((component) => {
				component.modalDialog = dialog;
				component.mode = mode;
				component.policyEdit = editableItem;
			})
			.open();
	}

	onAdd() {
		this.openExpressionEditor(PolicyEditorMode.Add);
	}

	onEdit() {
		this.openExistingPolicy(PolicyEditorMode.Edit);
	}

	onView() {
		this.openExistingPolicy(PolicyEditorMode.View);
	}

	openExistingPolicy(mode: PolicyEditorMode) {
		if (this.isBusy || this.isDialogOpen) {
			return;
		}
		this.isBusy = true;

		this.adminService
			.getExpression({ content: this.editInfo.expressionId })
			.pipe(finalize(() => (this.isBusy = false)))
			.subscribe(
				(response: IExpressionResponse) => {
					this.openExpressionEditor(mode, response.content);
				},
				(r: IOperationResponse) => {
					this.adminService.handleError(r);
				},
			);
	}

	onBeforeSwap(): void {
		this.isSwapping = true;
	}

	onSwapUpdate(): void {
		this.isSwapping = false;
		const swapData = this.getSwapListData();
		this.updateSwapList(swapData);
		this.setItemsDivider(swapData.recentItemsLength);

		this.emitSelectionChange(swapData.selected);
	}

	onOperatorChange(): void {
		this.updatedSelectedItems(this.selectedExpressions);
	}

	getSwapListData(): ISwapData {
		const isMax = this.isMax();
		let selectedSwapItems = this.swapList.selectedItems;

		if (isMax) {
			selectedSwapItems = selectedSwapItems.slice(0, this.maxPolicies);
		}

		let recentSwapItems = this.recentItems.filter(
			notInSwapArray(selectedSwapItems),
		);

		if (this.query) {
			recentSwapItems = recentSwapItems.filter(
				(recent) =>
					recent.text.toLowerCase().indexOf(this.query.toLowerCase()) >= 0,
			);
		}

		if (isMax) {
			recentSwapItems = recentSwapItems.map((recent) => ({
				...recent,
				disabled: true,
			}));
		}

		const availableSwapItems = this.items
			.map((item) => this.toSwapListItem(item))
			.filter(notInSwapArray([...selectedSwapItems, ...recentSwapItems]));

		return {
			available: [...recentSwapItems, ...availableSwapItems],
			selected: selectedSwapItems,
			recentItemsLength: recentSwapItems.length,
		};
	}

	attachListClickHandler() {
		const swapData = this.getSwapListData();
		const listItems = $(this.element.nativeElement).find("li");
		listItems.off("click").click((e) => {
			if (!listItems.hasClass("is-selected")) {
				this.setEditInfo(e, swapData);
			} else {
				this.editInfo = null;
			}
		});
	}

	clearSearch(): void {
		this.query = "";
		this.loadPolicies(true);
	}

	onSearch(query: string) {
		this.searchQueryChanged.next(query);
	}

	private setEditInfo(event: JQuery.ClickEvent, swapData: ISwapData) {
		const selected = $(event.currentTarget);
		const index = selected.index();
		const inSelectedList =
			selected.closest("soho-swaplist-card").attr("type") === "selected";
		const item = inSelectedList
			? swapData.selected[index]
			: swapData.available[index];

		if (item) {
			this.editInfo = {
				expressionId: item.value.expressionId,
				inSelectedList: inSelectedList,
				index: index,
			};
		}
	}

	private emitSelectionChange(selected: SohoSwapListItem[]): void {
		const selectedExpressions = selected.map((selected) => selected.value);
		this.updatedSelectedItems(selectedExpressions);
		this.ngZone.run(() =>
			this.selectedChange.next(
				selectedExpressions.length ? selectedExpressions : null,
			),
		);
	}

	private loadPolicies(reset?: boolean, query?: string): void {
		this.isBusy = true;
		if (reset) {
			this.paging = undefined;
			this.items = [];
		}
		const request = this.createRequest(query);
		this.adminService
			.listExpressions(request)
			.pipe(finalize(() => (this.isBusy = false)))
			.subscribe((response) => this.onPoliciesLoaded(response));
	}

	private subscribeToListScroll(): void {
		const listView: HTMLElement =
			this.element.nativeElement.querySelector(".listview");
		fromEvent(listView, "scroll")
			.pipe(
				debounceTime(100),
				filter(() => this.hasMore && !this.isSwapping),
				map(() => this.isScrolledBottom(listView)),
				filter(Boolean),
				skipUntil(timer(100)),
			)
			.subscribe(() => {
				this.loadPolicies(false, this.query);
			});
	}

	private setItemsDivider(noOfRecents: number): void {
		if (noOfRecents) {
			const lastRecent = this.element.nativeElement.querySelector(
				`li:nth-child(${noOfRecents})`,
			);
			lastRecent.classList.add("recent-expression-border");
		}
	}

	private isScrolledBottom(element: HTMLElement): boolean {
		return (
			element.scrollTop + element.offsetHeight + 150 >= element.scrollHeight
		);
	}

	private toSwapListItem(expression: IExpInfo): SohoSwapListItem {
		return {
			id: CommonUtil.random(4),
			value: expression,
			text: expression.title,
			disabled: this.isMax(),
		};
	}

	private isMax(): boolean {
		const selected = this.swapList.selectedItems;
		return selected && selected.length >= this.maxPolicies;
	}

	private onExpressionAdded(expression: IExpInfo): void {
		if (!this.isMax()) {
			const selectedItems = this.swapList.selectedItems;
			selectedItems.push(this.toSwapListItem(expression));
			this.updateSwapList({
				available: this.swapList.availableItems,
				selected: selectedItems,
			});
			this.emitSelectionChange(selectedItems);
		}

		this.loadPolicies(true);
	}

	private onExpressionEdited(expression: IExpInfo) {
		if (this.editInfo.inSelectedList) {
			this.swapList.selectedItems =
				this.swapList.selectedItems.map(checkUpdateTitle);
			this.emitSelectionChange(this.swapList.selectedItems);
		}

		this.recentItems = this.recentItems.map(checkUpdateTitle);

		function checkUpdateTitle(item: SohoSwapListItem): SohoSwapListItem {
			if (item.value.expressionId === expression.expressionId) {
				item.text = expression.title;
				item.value.title = expression.title;
			}
			return item;
		}

		this.editInfo = null;
		this.loadPolicies(true);
	}

	private onPoliciesLoaded(response: IExpressionListResponse): void {
		this.paging = response.paging;
		this.hasMore = !response.paging.standardEnd;

		this.items = this.items.concat(response.content);

		const swapData = this.getSwapListData();
		this.updateSwapList(swapData);
		this.setItemsDivider(swapData.recentItemsLength);
	}

	private updateSwapList(data: ISwapData): void {
		this.swapList.updateDataset({
			available: data.available,
			selected: data.selected,
		});
		this.editInfo = null;
		this.attachListClickHandler();
	}

	private createRequest(query?: string): IExpressionListRequest {
		const request: IExpressionListRequest = query
			? { query: query, paging: this.paging }
			: { paging: this.paging };
		return { ...request, pageSize: this.pageSize };
	}

	private updatedSelectedItems(items: IExpInfo[]): void {
		this.selectedExpressions = items;
		const titles = this.accessTitles;
		for (const item of items) {
			if (this.isMissing(item)) {
				delete titles[item.expressionId];
			} else {
				titles[item.expressionId] = item.title;
			}
			item.operator = this.operator || "||";
		}
	}

	private getRecentlyUsedAccesses(): Observable<IExpInfo[]> {
		const recentAccesses =
			this.storageService.getLocalStorageItem<string[]>(
				this.pageService.recentAccessesStorageKey,
			) || [];
		const accessTitles = this.accessTitles;
		return this.pageService.pageAccess.pipe(
			take(1),
			map((pageAccesses) => {
				if (pageAccesses) {
					return recentAccesses
						.filter((access) =>
							pageAccesses.some((pageAccess) => pageAccess.exid === access),
						)
						.map((recent) => ({
							title: accessTitles[recent],
							expressionId: recent,
						}))
						.slice(0, this.maxRecentItems);
				} else {
					return [];
				}
			}),
		);
	}

	private validatePolicies(expInfos: IExpInfo[]): Observable<string[]> {
		return this.adminService
			.validateExpressions(expInfos.map((item) => item.expressionId))
			.pipe(
				map((response: IStringListResponse) => {
					if (response && response.content) {
						return response.content;
					} else {
						return [];
					}
				}),
			);
	}

	private getInvalidSelection = (
		selections: IExpInfo[],
		invalidIds: string[],
	): IExpInfo[] => {
		return this.getBrokenSelection(selections, (value) =>
			invalidIds.includes(value.expressionId),
		);
	};

	private getMissingSelection = (selections: IExpInfo[]): IExpInfo[] => {
		return this.getBrokenSelection(
			selections,
			(value) => !this.accessTitles[value.expressionId],
		);
	};

	private getBrokenSelection = (
		selections: IExpInfo[],
		predicate: Predicate<IExpInfo>,
	) => {
		if (selections) {
			const brokenSelection = selections.filter((selected) => {
				return predicate(selected);
			});
			return brokenSelection.length ? brokenSelection : null;
		} else {
			return null;
		}
	};

	private getBrokenPoliciesMessage(
		invalid: IExpInfo[],
		missing: IExpInfo[],
	): IBrokenPolicyTooltip {
		const invalidText = AdminConstants.policyMissingOrInvalidText;
		if (!isEmpty(invalid) && !isEmpty(missing)) {
			return missingAndInvalid();
		}

		if (!isEmpty(invalid) && isEmpty(missing)) {
			if (isSingle(invalid)) {
				return singleInvalidMessage();
			}
			return multiInvalidMessage();
		}

		if (isEmpty(invalid) && !isEmpty(missing)) {
			if (isSingle(missing)) {
				return singleMissingMessage();
			}
			return multiMissingMessage();
		}
		return null;

		function singleMissingMessage(): IBrokenPolicyTooltip {
			return {
				header: "Missing policy",
				message:
					`There is a policy that is selected that is missing. Look for 'Missing policy' and remove it.` +
					` ${invalidText}`,
			};
		}

		function multiMissingMessage(): IBrokenPolicyTooltip {
			return {
				header: "Missing policies",
				message:
					`There are ${missing.length} selected policies that are missing.` +
					` Look for 'Missing policy' and remove them. ${invalidText}`,
			};
		}

		function missingAndInvalid(): IBrokenPolicyTooltip {
			return {
				header: "Missing and invalid policies",
				message: `There are issues with ${
					invalid.length + missing.length
				} selected policies. Please review all
					selected policies. ${invalidText}`,
				invalidTitles: invalid.map((item) =>
					HtmlUtil.escapeStringForHtml(item.title),
				),
			};
		}

		function singleInvalidMessage(): IBrokenPolicyTooltip {
			return {
				header: "Invalid policy",
				message:
					`The selected policy '${HtmlUtil.escapeStringForHtml(
						invalid[0].title,
					)}' is invalid. ` +
					`It may have rules with a user property that does not exist. Please review it.`,
			};
		}

		function multiInvalidMessage(): IBrokenPolicyTooltip {
			const count = invalid.length;
			return {
				header: "Invalid policies",
				message:
					`There are issues with ${count} selected security policies. ` +
					`Please review all selected policies. ${invalidText}`,
				invalidTitles: invalid.map((item) =>
					HtmlUtil.escapeStringForHtml(item.title),
				),
			};
		}

		function isEmpty<T>(arr: T[]): boolean {
			return !arr || !arr.length;
		}
		function isSingle<T>(arr: T[]): boolean {
			return arr && arr.length === 1;
		}
	}

	private isMissing(expInfo: IExpInfo) {
		return (
			expInfo &&
			expInfo.title === DynamicUtil.missingPolicyText &&
			!expInfo.expression
		);
	}
}
