import { Component, OnInit } from "@angular/core";
import { SohoModalDialogRef } from "ids-enterprise-ng";
import {
	ArrayUtil,
	CommonUtil,
	DialogButtonType,
	IAutocompleteEntity,
	IDialogResult,
} from "lime";
import {
	AutoCompleter,
	CommonDataService,
	CoreBase,
	CoreUtil,
	ISettingRule,
	ISettingRuleConnection,
	IUserListResponse,
	PrincipalType,
	Templates,
} from "lime/core";
import { SettingUtil } from "../admin";
import { AdminService, AdminUtil } from "../service";

interface IRuleAddConnectionParameter {
	isUser: boolean;
	userName: string;
	rule: ISettingRule;
}

@Component({
	templateUrl: "./rule-connection.html",
})
export class RuleAddConnectionComponent extends CoreBase implements OnInit {
	dialog: SohoModalDialogRef<RuleAddConnectionComponent>;
	parameter: IRuleAddConnectionParameter;
	ruleConnections: ISettingRuleConnection[] = [];
	roleInput: string;
	existsMessage = "";
	isUser: boolean;
	autocompleteRoleSource: Function;
	autocompleteRoleTemplate: string;
	autocompleteRoleFilterMode: string;
	autocompleteUserSource: Function;
	autocompleteUserTemplate: string;

	private userName: string;
	private rule: ISettingRule;
	private lastConnection: ISettingRuleConnection;

	constructor(
		private adminService: AdminService,
		private commonDataService: CommonDataService,
	) {
		super("RuleAddConnectionComponent");
		this.initAutocomplete();
	}

	ngOnInit(): void {
		const parameter = this.parameter;
		this.rule = CoreUtil.copy(parameter.rule) as ISettingRule;
		this.userName = parameter.userName;
		this.isUser = parameter.isUser;
	}

	onOk(): void {
		if (this.ruleConnections.length > 0) {
			this.addConnections();
			const result: IDialogResult = {
				button: DialogButtonType.Ok,
				value: {
					rule: this.rule,
					displayChangeDate: AdminUtil.getPendingChangeDate(),
					changedBy: this.userName,
				},
			};
			this.dialog.close(result);
		} else {
			this.dialog.close();
		}
	}

	onSelectAutocomplete(item: IAutocompleteEntity) {
		if (CommonUtil.isUndefined(item) || CommonUtil.isUndefined(item.value)) {
			return;
		}

		const name = item.value as string;
		const principalType = item.type as PrincipalType;
		const isUser = principalType === PrincipalType.User;
		const connection = {
			name: name,
			isUser: isUser,
			displayName: item.label ? item.label : name,
			info: item.info || name,
		} as ISettingRuleConnection;

		const existing = this.isExisting(connection);
		const isSame = SettingUtil.isSameConnection(
			connection,
			this.lastConnection,
		);
		this.lastConnection = connection;

		if (existing) {
			// Never add duplicates
			// Don't show message if same connection added twice in a row which can happen due to IDS controls
			if (!isSame) {
				this.existsMessage = isUser
					? "User already added"
					: "Role already added";
			}
			return;
		}

		this.addConnection(connection);
	}

	addRole(): void {
		const name = this.roleInput;
		const connection = {
			name: name,
			isUser: false,
			displayName: name,
			info: name,
		};

		if (this.isExisting(connection)) {
			this.existsMessage = "Role already added";
			return;
		}

		this.addConnection(connection);
	}

	remove(connection: ISettingRuleConnection): void {
		const connections = this.ruleConnections;
		const index = connections.indexOf(connection);
		connections.splice(index, 1);
	}

	private addConnection(connection: ISettingRuleConnection): void {
		this.existsMessage = "";
		this.roleInput = "";
		this.ruleConnections.push(connection);
	}

	private isExisting(connection: ISettingRuleConnection): boolean {
		return (
			SettingUtil.hasConnection(this.ruleConnections, connection) ||
			SettingUtil.hasConnection(this.rule.ruleConnections, connection)
		);
	}

	private initAutocomplete(): void {
		const self = this;

		// User
		this.autocompleteUserSource = new AutoCompleter<IUserListResponse>(
			(query) => self.commonDataService.searchUsers(query),
			(response) =>
				ArrayUtil.sortByProperty(
					CoreUtil.getEntityArray(PrincipalType.User, response.content),
					"label",
				),
			self.commonDataService,
		).source;
		this.autocompleteUserTemplate = Templates.autocompleteEntity;

		// Role
		this.autocompleteRoleSource = new AutoCompleter<IAutocompleteEntity[]>(
			(query) => self.adminService.searchRoles(query),
			(response) => ArrayUtil.sortByProperty(response, "label"),
			self.commonDataService,
		).source;
		this.autocompleteRoleTemplate = Templates.autocompleteEntity;
		this.autocompleteRoleFilterMode = "contains";
	}

	private addConnections(): void {
		this.ruleConnections.forEach((newConnection) => {
			newConnection.displayChangeDate = AdminUtil.getPendingChangeDate();
			newConnection.changedByName = this.userName;
			this.rule.ruleConnections.push(newConnection);
		});
	}
}
