import {
	Component,
	EventEmitter,
	NgZone,
	OnInit,
	Output,
	ViewChild,
	ViewContainerRef,
} from "@angular/core";
import {
	SohoDataGridComponent,
	SohoMessageService,
	SohoModalDialogService,
	SohoToastService,
} from "ids-enterprise-ng";
import { ArrayUtil } from "lime";
import {
	AccessState,
	AccessUtil,
	AdminPages,
	ContainerService,
	IOperationResponse,
	IPage,
	IPageAccess,
	IPageCatalogRequest,
	IPageCatalogResponse,
	IPagePreviewOptions,
	LanguageService,
	PageService,
	ProgressService,
	SettingsNames,
} from "lime/core";
import { AsyncSubject, Subscription } from "rxjs";
import { take } from "rxjs/operators";
import { CustomFormatters } from "../admin";
import { AdminListComponent } from "../admin-list.component";
import { AdminContext, AdminService, PageType } from "../service";
import { AdminSettingsService } from "../settings/admin-settings.service";

@Component({
	selector: "lm-admin-standard-pages",
	templateUrl: "./standard-pages.html",
})
export class AdminStandardPagesComponent
	extends AdminListComponent<IPage>
	implements OnInit
{
	@ViewChild("standardPagesDatagrid", { static: false })
	dataGrid: SohoDataGridComponent;

	@Output() onGoToFeatures = new EventEmitter<AdminPages>();

	accessCopy: IPageAccess;
	featureStandardPagesOn: boolean;

	private subscriptions = new Subscription();

	constructor(
		messageService: SohoMessageService,
		languageService: LanguageService,
		adminService: AdminService,
		sohoModalDialogService: SohoModalDialogService,
		zone: NgZone,
		private adminContext: AdminContext,
		private pageService: PageService,
		private toastService: SohoToastService,
		private readonly progressService: ProgressService,
		private readonly containerService: ContainerService,
		private readonly viewRef: ViewContainerRef,
		private readonly settingsService: AdminSettingsService,
	) {
		super(
			"AdminStandardPagesComponent",
			"page",
			messageService,
			languageService,
			adminService,
			sohoModalDialogService,
			zone,
		);

		this.subscriptions.add(
			this.settingsService.features$.subscribe((features) => {
				const setting = ArrayUtil.itemByProperty(
					features,
					"settingName",
					SettingsNames.featureStandardPages,
				);
				if (setting) {
					this.featureStandardPagesOn = setting.value === "true";
				}
			}),
		);
		this.initGrid();
	}

	ngOnInit() {
		if (this.initializing) {
			this.adminContext.tool$.pipe(take(1)).subscribe((tool) => {
				this.featureStandardPagesOn = tool.featureStandardPages;
			});
		}

		this.refresh();
	}

	ngOnDestroy() {
		this.subscriptions.unsubscribe();
	}

	getDataGrid(): SohoDataGridComponent {
		return this.dataGrid;
	}

	/**
	 * Checks if the currently selected pages can be enabled.
	 */
	canEnable(): boolean {
		return this.checkSelection((page: IPage) => {
			return (
				page.accessState === AccessState.None ||
				page.accessState === AccessState.Restricted
			);
		});
	}

	/**
	 * Checks if the currently selected pages can be disabled.
	 */
	canDisable(): boolean {
		return this.checkSelection((page: IPage) => {
			return (
				page.accessState === AccessState.Everyone ||
				page.accessState === AccessState.Restricted
			);
		});
	}

	listItems(reload: boolean): void {
		if (this.isBusy) {
			return;
		}

		const self = this;
		const adminService = self.adminService;
		this.setBusy(true);

		if (reload) {
			this.hasMore = true;
			this.paging = null;
			this.items = [];
			this.clearSelection();
		}

		const orderBy = this.orderBy;
		const query = this.getQuery();
		const request: IPageCatalogRequest = {
			paging: this.paging,
			pageSize: this.pageSize,
			sortOrder: orderBy.order,
			sortBy: orderBy.entity,
			query: query,
		};

		adminService.listStandardPages(request).subscribe(
			(response: IPageCatalogResponse) => {
				const newItems = response.content;
				self.addItems(newItems, response.paging);
				self.updateCount(response.count, this.maxCount);
				self.setBusy(false);
			},
			(r: IOperationResponse) => {
				self.setBusy(false);
				self.onError(r);
			},
		);
	}

	enable(): void {
		this.executeAction(
			this.enablePages,
			"Enable standard pages",
			this.getAreYouSureMessage("enable"),
		);
	}

	disable(): void {
		this.executeAction(
			this.disablePages,
			"Disable standard pages",
			this.getAreYouSureMessage("disable"),
		);
	}

	reset(): void {
		this.executeAction(
			this.resetPagesAccess,
			"Reset standard page permissions",
			this.getAreYouSureMessage("reset"),
		);
	}

	publishCopy(): void {
		const page = this.getSelectedItem();
		const self = this;
		this.adminService.publishStandardCopy(page.data.id).subscribe(
			(response: IOperationResponse) => {
				if (response.hasError()) {
					self.adminService.handleError(response, "Unable to publish copy");
				} else {
					self.clearSelection();
					self.toastService.show({
						title: "Published Copy",
						message: `A published copy of ${page.data.title} has been created.`,
						position: SohoToastService.BOTTOM_RIGHT,
					});
				}
			},
			(r: IOperationResponse) => {
				self.adminService.handleError(r);
			},
		);
	}

	publishExisting(): void {
		const page = this.getSelectedItem();
		const options = {
			title: "Select published page",
			isMultiSelect: false,
			pageType: PageType.Published,
			noShowIds: [page.data.id],
			includeStandard: false,
			excludeDynamic: true,
		};

		const callback = (selectedPages) => {
			const subject = new AsyncSubject<any>();
			const targetId = selectedPages[0].data.id;
			const sourceId = page.data.id;
			if (sourceId === targetId) {
				this.adminService.showError(
					"Unable to publish to existing page",
					"Same source as target",
				);
				return;
			}
			const self = this;

			this.adminService.publishToExisting(sourceId, targetId).subscribe(
				(response: IOperationResponse) => {
					if (response.hasError()) {
						const message = `Unable to publish page with id:${sourceId} to existing page with id:${targetId}`;
						self.adminService.handleError(response, message);
						subject.error(null);
					} else {
						self.clearSelection();
						self.toastService.show({
							title: "Published to Existing",
							message: "Published page was succesfully updated.",
							position: SohoToastService.BOTTOM_RIGHT,
						});
						subject.next(null);
						subject.complete();
					}
				},
				() => {
					self.adminService.showError(
						"Unable to publish to existing page",
						"The requested operation failed.",
					);
					subject.error(null);
				},
			);

			return subject.asObservable();
		};

		this.adminService.openPageSelectorDialog(
			options,
			"Publish to existing Page",
			this.viewRef,
			callback,
		);
	}

	preview(): void {
		const page = this.getSelectedItem();
		const isDisabled = page.accessState === AccessState.None;
		const service = this.containerService;
		const options = {
			pageId: page.data.id,
			isDuplicatable: !isDisabled,
			isAddable: !isDisabled,
			notifyMingle: true,
			onClose: () => {
				service.showAdmin();
			},
		} as IPagePreviewOptions;

		this.progressService.onNextNotBusy(() =>
			service.hideAdmin(AdminPages.StandardPages),
		);
		this.pageService.previewPage(options);
	}

	/**
	 * Exports selected pages.
	 */
	onExport(): void {
		const pagesToExport = this.getSelectedItems();
		this.adminService.exportStandardPages(pagesToExport);
		this.clearSelection();
	}

	exportAll(): void {
		// Not to be implemented at this time
	}

	editAccess(): void {
		const page = this.getSelectedItem();
		if (!page) {
			return;
		}
		const options = AccessUtil.standardPages(this.languageService, page);
		options.callback = () => this.refresh();
		this.adminService.openPageAccessDialog(options, this.viewRef);
	}

	/**
	 * Go to the Features page
	 */
	goToFeaturesPage(event): void {
		event.preventDefault(); // Prevent reload
		this.onGoToFeatures.emit(AdminPages.Features);
	}

	openInCatalog() {
		this.pageService.showPageCatalog(this.getSelectedItem());
		this.containerService.hideAdmin(this.adminService.getLastVisitedTab());
	}

	protected getColumns(): SohoDataGridColumn[] {
		return [
			this.getSelectionColumn(),
			{
				width: 545,
				id: "adm-sp-col-t",
				field: "data.title",
				name: "Title",
				sortable: false,
				formatter: CustomFormatters.dynamicDisabledExpander,
			},
			{
				width: 300,
				id: "adm-sp-col-i",
				field: "data.id",
				name: "Content ID",
				sortable: false,
				formatter: CustomFormatters.text,
			},
			{
				width: 240,
				id: "adm-sp-col-cd",
				field: "data.changeDate",
				name: "Change date",
				sortable: false,
				formatter: CustomFormatters.date,
			},
			{
				width: 110,
				id: "adm-sp-col-as",
				field: "accessState",
				name: "Permissions",
				sortable: false,
				formatter: CustomFormatters.accessState,
			},
		];
	}

	protected getEmptyMessage(): string {
		return "No standard pages found";
	}

	protected getRowTemplate(): string {
		return '<div class="datagrid-cell-layout"><span class="datagrid-textarea lm-white-space-normal">{{data.description}}</span></div>';
	}

	private checkSelection(predicate: (page: IPage) => boolean): boolean {
		const pages = this.getSelectedItems();
		if (pages.length > 0) {
			for (const page of pages) {
				if (!predicate(page)) {
					return false;
				}
			}
			return true;
		}
		return false;
	}

	private enablePages(pages: IPage[], self: AdminStandardPagesComponent): void {
		const adminService = self.adminService;
		adminService.enableStandardPages(pages).subscribe(
			(r: IOperationResponse) => {
				self.refresh();
				self.toastService.show({
					title: "",
					position: SohoToastService.BOTTOM_RIGHT,
					message:
						pages.length > 1
							? "The pages have been enabled."
							: pages[0].data.title + " has been enabled.",
				});
				self.clearSelection();
			},
			(r: IOperationResponse) => {
				self.setBusy(false);
				adminService.handleError(
					r,
					pages.length > 1
						? "Unable to enable the selected pages."
						: "Unable to enable " + pages[0].data.title,
				);
			},
		);
	}

	private disablePages(
		pages: IPage[],
		self: AdminStandardPagesComponent,
	): void {
		const adminService = self.adminService;
		adminService.disableStandardPages(pages).subscribe(
			(r: IOperationResponse) => {
				self.refresh();
				self.toastService.show({
					title: "",
					position: SohoToastService.BOTTOM_RIGHT,
					message:
						pages.length > 1
							? "The pages have been disabled."
							: pages[0].data.title + " has been disabled.",
				});
				self.clearSelection();
			},
			(r: IOperationResponse) => {
				self.setBusy(false);
				adminService.handleError(
					r,
					pages.length > 1
						? "Unable to disable the selected pages."
						: "Unable to disable " + pages[0].data.title,
				);
			},
		);
	}

	private resetPagesAccess(
		pages: IPage[],
		self: AdminStandardPagesComponent,
	): void {
		const adminService = self.adminService;
		adminService.resetStandardPagesAccess(pages).subscribe(
			(r: IOperationResponse) => {
				self.refresh();
				self.toastService.show({
					title: "",
					position: SohoToastService.BOTTOM_RIGHT,
					message:
						pages.length > 1
							? "The pages have been reset."
							: pages[0].data.title + " has been reset.",
				});
				self.clearSelection();
			},
			(r: IOperationResponse) => {
				self.setBusy(false);
				adminService.handleError(
					r,
					pages.length > 1
						? "Unable to reset the selected pages."
						: "Unable to reset " + pages[0].data.title,
				);
			},
		);
	}

	private executeConfirmed(
		action: Function,
		title: string,
		message: string,
	): void {
		this.showConfirm(title, message).subscribe(() => {
			action();
		});
	}

	private getAreYouSureMessage(action: string): string {
		const pages = this.getSelectedItems();
		const title = pages[0].data.title;
		const isMultiplePages = pages.length > 1;
		let message = "";

		switch (action) {
			case "enable": {
				message = isMultiplePages
					? "Are you sure that you want to enable the selected pages?"
					: "Are you sure that you want to enable " + title + "?";
				break;
			}
			case "disable": {
				message = isMultiplePages
					? "Are you sure that you want to disable the selected pages?"
					: "Are you sure that you want to disable " + title + "?";
				break;
			}
			case "reset": {
				message = isMultiplePages
					? "Are you sure that you want to reset the permissions of the selected pages?"
					: "Are you sure that you want to reset the permissions of " +
					  title +
					  "?";
				break;
			}
		}

		return message;
	}

	private executeAction(
		actionFunction: Function,
		title: string,
		message: string,
	): void {
		const pages = this.getSelectedItems();
		message = this.getConfirmMessage(message, pages);
		const action = () => {
			actionFunction(pages, this);
		};

		this.executeConfirmed(action, title, message);
	}

	private getConfirmMessage(message: string, pages: IPage[]): string {
		const hasRestrictions = this.checkSelection((page: IPage) => {
			return page.accessState === AccessState.Restricted;
		});

		if (hasRestrictions) {
			message = message + " Existing permissions will be replaced.";
		}
		return message;
	}

	private showErrorMessage(
		title: string,
		message: string,
		r?: IOperationResponse,
	): void {
		this.showError(title, message);
		if (r && r.hasMessage()) {
			this.logError(r.toErrorLog());
		}
	}

	private initGrid(): void {
		this.datagridOptions = this.defaultOptions();
	}
}
