import { Component } from "@angular/core";
import { IDynamicPreviewOptions, IStringMap } from "lime/core";
import { IDynamicAccess } from "../core";
import { DynamicPageAdminService } from "../service";

export interface IPolicyItem {
	access: IDynamicAccess;
	selected: boolean;
}

@Component({
	templateUrl: "./preview-dialog.html",
})
export class PreviewDialog {
	items: IPolicyItem[] = [];
	isAllSelected = false;

	constructor(pageService: DynamicPageAdminService) {
		const page = pageService.getPage();
		const titles = pageService.getAccessTitles();
		this.addItems(page.accs || [], titles);
	}

	onSelectAll(value: boolean) {
		for (const item of this.items) {
			item.selected = value;
		}
	}

	getPreviewOptions(): IDynamicPreviewOptions {
		const results = {} as Map<string, boolean>;
		for (const item of this.items) {
			results[item.access.exid] = item.selected;
		}
		return { results: results };
	}

	private addItems(access: IDynamicAccess[], titles: IStringMap): void {
		for (const item of access) {
			if (!item.t) {
				item.t = titles[item.exid];
			}
			this.items.push({ access: item, selected: false });
		}
	}
}
